static void applyValidatedSystemEpoch(uint32_t epoch) {
  if (epoch < 1577836800UL || epoch >= 2524608000UL) return;
  timeval tv{};
  tv.tv_sec = static_cast<time_t>(epoch);
  tv.tv_usec = 0;
  settimeofday(&tv, nullptr);
}
