bool scanZoomDirs(const String &root, int preferredZoom, int &bestZoom, int &minZoom, int &maxZoom) {
  bestZoom = preferredZoom;
  minZoom = 255;
  maxZoom = -1;
  if (!sdReady) {
    return false;
  }
  FsFile dir = SD.open(root.c_str());
  if (!dir || !dir.isDirectory()) {
    if (dir) {
      dir.close();
    }
    return false;
  }
  int bestUnder = -1;
  int bestAny = -1;
  for (;;) {
    FsFile entry = dir.openNextFile();
    if (!entry) {
      break;
    }
    if (entry.isDirectory()) {
      char nameBuf[128];
      if (entry.getName(nameBuf, sizeof(nameBuf)) == 0) {
        entry.close();
        continue;
      }
      String name = nameBuf;
      int slash = name.lastIndexOf('/');
      if (slash >= 0) {
        name = name.substring(slash + 1);
      }
      bool digits = name.length() > 0;
      for (size_t i = 0; i < name.length(); ++i) {
        if (!isDigit(name[i])) {
          digits = false;
          break;
        }
      }
      if (digits) {
        int value = name.toInt();
        if (value < minZoom) {
          minZoom = value;
        }
        if (value > maxZoom) {
          maxZoom = value;
        }
        if (value > bestAny) {
          bestAny = value;
        }
        if (value <= preferredZoom && value > bestUnder) {
          bestUnder = value;
        }
      }
    }
    entry.close();
  }
  dir.close();
  if (maxZoom < 0) {
    return false;
  }
  if (bestUnder >= 0) {
    bestZoom = bestUnder;
  } else if (bestAny >= 0) {
    bestZoom = bestAny;
  }
  return true;
}

void resolveTileRootAndZoom() {
  tileRoot = kTileRoot;
  int chosenZoom = kDefaultZoom;
  int minZoom = kDefaultZoom;
  int maxZoom = kDefaultZoom;
  bool found = scanZoomDirs(tileRoot, kDefaultZoom, chosenZoom, minZoom, maxZoom);
  if (!found) {
    String nested = String(kTileRoot) + "/tiles";
    int nestedZoom = kDefaultZoom;
    int nestedMin = kDefaultZoom;
    int nestedMax = kDefaultZoom;
    if (scanZoomDirs(nested, kDefaultZoom, nestedZoom, nestedMin, nestedMax)) {
      tileRoot = nested;
      chosenZoom = nestedZoom;
      minZoom = nestedMin;
      maxZoom = nestedMax;
      found = true;
    }
  }
  mapZoom = static_cast<uint8_t>(chosenZoom);
  mapMinZoom = static_cast<uint8_t>(minZoom);
  mapMaxZoom = static_cast<uint8_t>(maxZoom);
  if (!found) {
    mapZoom = kDefaultZoom;
    mapMinZoom = kDefaultZoom;
    mapMaxZoom = kDefaultZoom;
  } else {
    if (mapMinZoom < kUserMinZoom) {
      mapMinZoom = kUserMinZoom;
    }
    if (mapMaxZoom < mapMinZoom) {
      mapMaxZoom = mapMinZoom;
    }
    if (mapZoom < mapMinZoom) {
      mapZoom = mapMinZoom;
    }
    if (mapZoom > mapMaxZoom) {
      mapZoom = mapMaxZoom;
    }
  }
  debugPrint("TILES: root=%s zoom=%u range=%u..%u", tileRoot.c_str(), mapZoom, mapMinZoom, mapMaxZoom);
  if (!queuedFromMapDownload) {
    mapDirty = true;
  }
  mapTilesDrawn = false;
  lastMapTileViewValid = false;
}

bool lockSd(uint32_t timeoutMs) {
  if (usbMscActive) {
    return false;
  }
  if (!sdMutex) {
    return true;
  }
  uint32_t startMs = millis();
  TickType_t ticks = timeoutMs > 0 ? pdMS_TO_TICKS(timeoutMs) : 0;
  bool ok = xSemaphoreTakeRecursive(sdMutex, ticks) == pdTRUE;
  uint32_t waitMs = millis() - startMs;
  if ((!ok || waitMs >= kSdLockWarnMs) && (millis() - lastSdLockWarnMs >= kSdLockWarnIntervalMs)) {
    lastSdLockWarnMs = millis();
    debugPrint("SD: lock %s wait=%lu", ok ? "slow" : "fail", static_cast<unsigned long>(waitMs));
  }
  return ok;
}

void unlockSd() {
  if (sdMutex) {
    xSemaphoreGiveRecursive(sdMutex);
  }
}

const char *optionalAppPackageId(uint8_t index) {
  switch (index) {
    case kAppAirplanesIndex: return "com.achindustries.optional.aircraft_radar";
    case kAppGhostIndex: return "com.achindustries.optional.ghost_box";
    case kAppRfWatchIndex: return "com.achindustries.optional.rf_watch";
    case kAppIpCamsIndex: return "com.achindustries.optional.deploy_cam";
    case kAppDroneIndex: return "com.achindustries.optional.drone_detection";
    default: return nullptr;
  }
}

bool isCoreAppIndex(uint8_t index) {
  switch (index) {
    case kAppTripsIndex:
    case kAppCalendarIndex:
    case kAppCameraIndex:
    case kAppGalleryIndex:
    case kAppWeatherIndex:
    case kAppRfScanIndex:
    case kAppRecorderIndex:
    case kAppAudioIndex:
    case kAppLoraIndex:
    case kAppNotesIndex:
    case kAppCarIndex:
    case kAppBleKeyboardIndex:
    case kAppGamesIndex:
    case kAppSystemHealthIndex:
    case kAppFileTransferIndex:
      return true;
    default:
      return false;
  }
}

bool isResponderSdPackageInstalled(const char *id) {
  if (!id || !id[0]) {
    return false;
  }
  for (uint8_t i = 0; i < responderSdPackageCount; ++i) {
    if (responderSdPackages[i].valid && strcmp(responderSdPackages[i].id, id) == 0) {
      return true;
    }
  }
  return false;
}

void cleanupObsoleteSeededSdApps() {
  const char *obsoletePath = "/apps/hello_responder";
  if (SD.exists(obsoletePath)) {
    bool removed = deletePathRecursive(obsoletePath);
    debugPrint("APPREG: obsolete seeded package cleanup path=%s removed=%u",
               obsoletePath, removed ? 1U : 0U);
  }
}

bool isAppVisibleInMenu(uint8_t index) {
  if (index >= kAppCount) {
    return false;
  }
  if (isCoreAppIndex(index)) {
    return true;
  }
  return isResponderSdPackageInstalled(optionalAppPackageId(index));
}

void rebuildAppMenuVisibleList() {
  appMenuVisibleCount = 0;
  for (uint8_t i = 0; i < kAppCount; ++i) {
    if (isAppVisibleInMenu(i)) {
      appMenuVisibleIndices[appMenuVisibleCount++] = i;
    }
  }
  if (appMenuVisibleCount == 0) {
    appMenuVisibleIndices[appMenuVisibleCount++] = kAppSystemHealthIndex;
  }
  appMenuVisiblePageCount =
      static_cast<uint8_t>((appMenuVisibleCount + kAppsPerPage - 1) / kAppsPerPage);
  if (appMenuVisiblePageCount == 0) {
    appMenuVisiblePageCount = 1;
  }
  if (appMenuPage >= appMenuVisiblePageCount) {
    appMenuPage = static_cast<uint8_t>(appMenuVisiblePageCount - 1);
  }
  bool selectionVisible = false;
  for (uint8_t i = 0; i < appMenuVisibleCount; ++i) {
    if (appMenuVisibleIndices[i] == appMenuKeyboardSelection) {
      selectionVisible = true;
      break;
    }
  }
  if (!selectionVisible) {
    uint8_t pos = min<uint8_t>(appMenuPage * kAppsPerPage, appMenuVisibleCount - 1);
    appMenuKeyboardSelection = appMenuVisibleIndices[pos];
  }
  appMenuVisibleDirty = false;
}

int appMenuVisiblePositionForIndex(uint8_t index) {
  if (appMenuVisibleDirty) {
    rebuildAppMenuVisibleList();
  }
  for (uint8_t i = 0; i < appMenuVisibleCount; ++i) {
    if (appMenuVisibleIndices[i] == index) {
      return i;
    }
  }
  return -1;
}

void selectAppMenuVisiblePosition(int pos) {
  if (appMenuVisibleDirty) {
    rebuildAppMenuVisibleList();
  }
  if (appMenuVisibleCount == 0) {
    return;
  }
  pos = max<int>(0, min<int>(pos, appMenuVisibleCount - 1));
  appMenuKeyboardSelection = appMenuVisibleIndices[pos];
  appMenuPage = static_cast<uint8_t>(pos / kAppsPerPage);
}

void scanResponderSdAppPackages(const char *reason) {
  responderSdAppRootReady = false;
  responderSdPackageCount = 0;
  responder::clearExternalAppManifests(responderSdPackages, responder::kMaxDiscoveredAppPackages);
  if (!sdReady || usbMscActive) {
    debugPrint("APPREG: SD app scan skipped reason=%s sd=%u msc=%u",
               reason ? reason : "?", sdReady ? 1U : 0U, usbMscActive ? 1U : 0U);
    return;
  }
  if (!lockSd(500)) {
    debugPrint("APPREG: SD app scan lock failed reason=%s", reason ? reason : "?");
    return;
  }
  if (!SD.exists(responder::kSdAppRoot)) {
    if (!SD.mkdir(responder::kSdAppRoot)) {
      debugPrint("APPREG: SD app root create failed path=%s", responder::kSdAppRoot);
      unlockSd();
      return;
    }
    debugPrint("APPREG: SD app root created path=%s", responder::kSdAppRoot);
  }
  responderSdAppRootReady = true;
  cleanupObsoleteSeededSdApps();
  FsFile root = SD.open(responder::kSdAppRoot, FILE_READ);
  if (!root || !root.isDirectory()) {
    debugPrint("APPREG: SD app root open failed path=%s", responder::kSdAppRoot);
    if (root) root.close();
    unlockSd();
    return;
  }
  while (responderSdPackageCount < responder::kMaxDiscoveredAppPackages) {
    FsFile entry = root.openNextFile();
    if (!entry) break;
    if (entry.isDirectory()) {
      char nameBuf[128];
      if (entry.getName(nameBuf, sizeof(nameBuf)) == 0) {
        entry.close();
        continue;
      }
      String packageName = nameBuf;
      int slash = packageName.lastIndexOf('/');
      if (slash >= 0) {
        packageName = packageName.substring(slash + 1);
      }
      String packagePath = String(responder::kSdAppRoot) + "/" + packageName;
      String manifestPath = packagePath + "/" + responder::kAppManifestFile;
      if (SD.exists(manifestPath.c_str())) {
        responder::ExternalAppManifest &manifest = responderSdPackages[responderSdPackageCount];
        if (responder::loadExternalAppManifest(SD, packagePath, manifestPath, manifest)) {
          ++responderSdPackageCount;
          debugPrint("APPREG: SD package id=%s name=%s version=%s api=%lu perms=%u path=%s",
                     manifest.id, manifest.name, manifest.version,
                     static_cast<unsigned long>(manifest.minimumApiVersion),
                     static_cast<unsigned>(manifest.permissionCount), manifest.path);
        } else {
          debugPrint("APPREG: SD package invalid manifest=%s", manifestPath.c_str());
        }
      }
    }
    entry.close();
  }
  root.close();
  unlockSd();
  debugPrint("APPREG: SD app scan reason=%s root=%s packages=%u",
             reason ? reason : "?", responder::kSdAppRoot,
             static_cast<unsigned>(responderSdPackageCount));
  appMenuVisibleDirty = true;
}

void abortTileDownload() {
#if ENABLE_WIFI
  if (!tileDownloadActive && !tileDownloadQueued) {
    return;
  }
  debugPrint("DL: abort");
  finishTileDownload(false);
  tileDownloadSecureClient.stop();
  tileDownloadPlainClient.stop();
#endif
}

void startTileDownloadTask() {
  if (!kUseTileDownloadTask) {
    return;
  }
  if (tileDownloadTaskHandle) {
    return;
  }
  tileDownloadTaskStop = false;
  xTaskCreatePinnedToCore(tileDownloadTask, "tile_dl", 8192, nullptr,
                          kTileDownloadTaskPriority, &tileDownloadTaskHandle, 0);
}

void requestTileDownloadTaskStop() {
  tileDownloadTaskStop = true;
  abortTileDownload();
}

bool isWaypointAppVisible(uint8_t appIndex) {
  return screen == SCREEN_WAYPOINTS && appSelected == appIndex && !screenDimmed;
}

bool isFocusedWaypointApp() {
  return screen == SCREEN_WAYPOINTS && appSelected != kAppMenuIndex && !screenDimmed;
}

bool isRtlSdrAppSelected() {
  return screen == SCREEN_WAYPOINTS &&
          (appSelected == kAppAirplanesIndex || appSelected == kAppGhostIndex ||
           appSelected == kAppRfScanIndex || appSelected == kAppDroneIndex) &&
         !screenDimmed;
}

bool isUsbHostAppSelected() {
  return isRtlSdrAppSelected() || isWaypointAppVisible(kAppCarIndex);
}

bool isUsbHostForegroundAllowed() {
  return screen == SCREEN_USB || usbRecoveryPhase != UsbRecoveryPhase::IDLE ||
         isUsbHostAppSelected() ||
         usbDebugForcedOwner != UsbHostOwner::NONE;
}

UsbHostOwner requestedUsbOwner() {
  if (usbDebugForcedOwner != UsbHostOwner::NONE) return usbDebugForcedOwner;
  if (isWaypointAppVisible(kAppCarIndex)) return UsbHostOwner::ELM327;
  if (isWaypointAppVisible(kAppAirplanesIndex) &&
      (aircraftAdsbRequested || aircraftAdsbActive || rtlSdrAutoStartStreamRequested)) {
    return UsbHostOwner::ADS_B;
  }
  if (isWaypointAppVisible(kAppRfScanIndex)) {
    return UsbHostOwner::RTL_SDR;
  }
  if (isWaypointAppVisible(kAppDroneIndex)) {
    return UsbHostOwner::RTL_SDR;
  }
  if (isWaypointAppVisible(kAppGhostIndex) &&
      (ghostScanRunning || rtlSdrAutoStartStreamRequested || rtlSdrGhostResumeAfterUsbDrop)) {
    return UsbHostOwner::RTL_SDR;
  }
  return UsbHostOwner::NONE;
}

void suspendWifiForSdr() {
#if ENABLE_WIFI
  wifiDisabledForSdr = false;
  if (wifiScanInProgress) {
    stopWifiScan();
  }
  abortTileDownload();
  if (mapDownload.active) {
    stopMapDownload();
  }
  if (wifiEnabled || wifiStackReady) {
    // USB host and ESP-Hosted contend for the same small internal/DMA heap.  Do not
    // let the UI toggle cooldown leave Wi-Fi alive while usb_host_install runs.
    wifiTransition = false;
    lastWifiToggleMs = millis() - kWifiToggleCooldownMs;
    abortTileDownload();
    if (mapDownload.active) {
      stopMapDownload();
    }
    if (wifiScanInProgress) {
      stopWifiScan();
    }
    WiFi.setAutoReconnect(false);
    WiFi.disconnect(true, true);
    WiFi.mode(WIFI_OFF);
    wifiEnabled = false;
    wifiAvailable = false;
    wifiStackReady = false;
    wifiScanInProgress = false;
    wifiNetworkCount = 0;
    wifiDirty = true;
    delay(500);
    wifiDisabledForSdr = true;
    debugPrint("USBHOST: Wi-Fi hard-suspended for USB host internal=%lu largest=%lu dma=%lu",
               static_cast<unsigned long>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)),
               static_cast<unsigned long>(heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)),
               static_cast<unsigned long>(heap_caps_get_free_size(MALLOC_CAP_DMA)));
  }
#endif
}

void restoreWifiAfterSdr() {
#if ENABLE_WIFI
  static bool deferredLogged = false;
  static uint32_t restoreWaitStartMs = 0;
  static bool lowMemoryReconnectScheduled = false;
  if (wifiDisabledForSdr) {
    UsbHostSnapshot snapshot = usbHostManager.snapshot();
    if (rtlSdrHostInstalled || snapshot.hostInstalled || snapshot.owner != UsbHostOwner::NONE) {
      if (!deferredLogged) {
        debugPrint("USBHOST: Wi-Fi restore deferred until USB host shutdown");
        deferredLogged = true;
      }
      return;
    }
    deferredLogged = false;
    static uint32_t lastMemoryWaitLogMs = 0;
    uint32_t internal = heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    uint32_t largest = heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
    uint32_t dma = heap_caps_get_free_size(MALLOC_CAP_DMA);
    if (wifiStackReady) {
      restoreWaitStartMs = 0;
      lowMemoryReconnectScheduled = false;
      wifiDisabledForSdr = false;
      wifiBootEnablePending = true;
      wifiBootEnableAfterMs = millis() + 500;
      debugPrint("USBHOST: Wi-Fi warm restore scheduled internal=%lu largest=%lu dma=%lu",
                 static_cast<unsigned long>(internal), static_cast<unsigned long>(largest),
                 static_cast<unsigned long>(dma));
      return;
    }
    if (internal < kWifiEnablePreferredInternalBytes ||
        largest < kWifiEnableGuardedLargestBytes ||
        dma < kWifiEnableGuardedDmaBytes) {
      uint32_t now = millis();
      if (restoreWaitStartMs == 0) restoreWaitStartMs = now;
      if (now - lastMemoryWaitLogMs >= 5000UL) {
        lastMemoryWaitLogMs = now;
        debugPrint("USBHOST: Wi-Fi restore waiting memory internal=%lu largest=%lu dma=%lu",
                   static_cast<unsigned long>(internal), static_cast<unsigned long>(largest),
                   static_cast<unsigned long>(dma));
      }
      if (!lowMemoryReconnectScheduled && now - restoreWaitStartMs >= 7000UL) {
        lowMemoryReconnectScheduled = true;
        restoreWaitStartMs = now;
        wifiBootEnablePending = false;
        wifiBootEnableAfterMs = 0;
        debugPrint("USBHOST: Wi-Fi restore requires clean profile; low memory internal=%lu largest=%lu dma=%lu",
                   static_cast<unsigned long>(internal), static_cast<unsigned long>(largest),
                   static_cast<unsigned long>(dma));
        // Remaining in the modal here is a deadlock: wifiDisabledForSdr stays
        // asserted, so the blocking RF/USB exit path can never complete.  Use
        // the existing black-screen Wi-Fi profile transition only as the
        // low-memory fallback.  Healthy exits still reconnect in place.
        requestWifiBoot(true);
      }
      return;
    }
    restoreWaitStartMs = 0;
    lowMemoryReconnectScheduled = false;
    wifiDisabledForSdr = false;
    wifiBootEnablePending = true;
    wifiBootEnableAfterMs = millis() + 1500;
    debugPrint("USBHOST: Wi-Fi restore scheduled after USB session");
  } else {
    restoreWaitStartMs = 0;
    lowMemoryReconnectScheduled = false;
  }
  if (wifiCrashSafeMode && wifiBootEnablePending) {
    wifiBootEnablePending = false;
    wifiBootEnableAfterMs = 0;
    if (!wifiCrashAutoEnableBlockedLogged) {
      wifiCrashAutoEnableBlockedLogged = true;
      debugPrint("WIFI: auto restore blocked after low-DMA hosted crash; enable manually");
    }
  }
#endif
}

static void requestUsbAccessoryRelease(const char *reason) {
#if HAS_USB_HOST
  usbAccessoryReleaseRequested = true;
  if (rtlSdrClientHandle) {
    usb_host_client_unblock(rtlSdrClientHandle);
  }
  debugPrint("USBHOST: release requested%s%s", reason ? " " : "", reason ? reason : "");
#else
  (void)reason;
#endif
}

void enterWifiRestoreModal(const char *detail);

void releaseSdrAppResources() {
  bool blockForWifiRestore = false;
#if HAS_USB_HOST
  blockForWifiRestore = wifiDisabledForSdr;
  rfScanRunning = false;
  rfAudioSettingsOpen = false;
  ghostScanRunning = false;
  airplanesAutoRefresh = false;
  aircraftAdsbActive = false;
  aircraftAdsbRequested = false;
  rtlSdrAutoStartStreamRequested = false;
  rtlSdrAutoStartRequestedMs = 0;
  stopRfSdrStream();
  M5.Speaker.stop(0);
  M5.Speaker.end();
  // Closing an SDR app must request the coordinated host shutdown, not only
  // release its logical owner.  A release-only request leaves the USB client
  // installed, which prevents Wi-Fi restoration and strands the loading modal.
  stopRtlSdrHost();
  requestUsbAccessoryRelease("sdr app exit");
  UsbHostSnapshot usb = usbHostManager.snapshot();
  if (usb.owner != UsbHostOwner::NONE) {
    usbHostManager.release(usb.owner, millis());
  }
#endif
  restoreWifiAfterSdr();
  if (blockForWifiRestore && wifiDisabledForSdr) {
    sdrWifiRestoreBlocking = true;
    sdrWifiRestoreStartedMs = millis();
    enterWifiRestoreModal("RTL-SDR app closed");
    debugPrint("USBHOST: SDR exit Wi-Fi restore modal active");
  }
}

bool isAudioPlaybackSensitive() {
  return isWaypointAppVisible(kAppAudioIndex) && audioPreviewPlaying;
}

bool isAudioRealtimeSensitive() {
  return isAudioPlaybackSensitive() ||
         (isWaypointAppVisible(kAppRecorderIndex) && (recorderRunning || recorderTaskHandle));
}

// A fresh road-speed fix temporarily protects the foreground from operations
// that can block for seconds (notably SD tile prefetch). Keep a short hold
// after the last fresh speed report so a brief GPS/RMC gap while driving does
// not immediately re-enable background work.
static uint32_t vehicleMotionHoldUntilMs = 0;
#if ENABLE_SERIAL_CMDS
static int8_t vehicleMotionDebugOverride = -1;
#endif

static bool vehicleMotionActive(uint32_t now) {
#if ENABLE_SERIAL_CMDS
  if (vehicleMotionDebugOverride >= 0) return vehicleMotionDebugOverride != 0;
#endif
  constexpr float kVehicleMotionKmph = 8.0f;
  constexpr uint32_t kFreshSpeedMaxAgeMs = 3000;
  constexpr uint32_t kMotionHoldMs = 15000;
  if (gps.speed.isValid() && gps.speed.age() <= kFreshSpeedMaxAgeMs &&
      gps.speed.kmph() >= kVehicleMotionKmph) {
    vehicleMotionHoldUntilMs = now + kMotionHoldMs;
    return true;
  }
  return vehicleMotionHoldUntilMs != 0 &&
         static_cast<int32_t>(vehicleMotionHoldUntilMs - now) > 0;
}

void stopHiddenAppWork() {
  if (!isWaypointAppVisible(kAppAudioIndex) && audioWavOpen) {
    closeAudioPlayback();
  }
  if (!isWaypointAppVisible(kAppRecorderIndex) && (recorderRunning || recorderTaskHandle)) {
    stopAudioRecorder();
  }
  if (!isWaypointAppVisible(kAppGhostIndex)) {
    ghostScanRunning = false;
  }
  if (!isWaypointAppVisible(kAppRfScanIndex) && !isWaypointAppVisible(kAppDroneIndex)) {
    rfScanRunning = false;
  }
  if (!isWaypointAppVisible(kAppAirplanesIndex)) {
    airplanesAutoRefresh = false;
    aircraftAdsbRequested = false;
  }
  if (!isRtlSdrAppSelected()) {
    stopRfSdrStream();
  }
  if (!isWaypointAppVisible(kAppAudioIndex)) {
    audioLogRunning = false;
  }
  if (!isUsbHostForegroundAllowed()) {
    stopUsbGameStorage();
#if HAS_USB_HOST
    UsbHostSnapshot usb = usbHostManager.snapshot();
    if ((rtlSdrHostInstalled || usb.hostInstalled || usb.owner != UsbHostOwner::NONE) &&
        !rtlSdrHostStopRequested && !usbAccessoryReleaseRequested) {
      stopRtlSdrHost();
      requestUsbAccessoryRelease("background policy");
      usbHostManager.release(usb.owner, millis());
    }
#endif
  }
}

void updateTaskManager() {
  stopHiddenAppWork();
  bool focusWaypointApp = isFocusedWaypointApp();
  bool focusCameraApp = focusWaypointApp &&
                        (appSelected == kAppCameraIndex || appSelected == kAppGalleryIndex);
  bool deployCamPerformanceMode = isWaypointAppVisible(kAppIpCamsIndex) &&
                                  (ipCamLiveActive || ipCamViewBusy ||
                                   ipCamMode == IpCamMode::LIVE);
  cameraFocusModeEnabled = focusCameraApp;
  focusedAppModeEnabled = focusWaypointApp;
  backgroundTaskProcessingEnabled = !screenDimmed && !focusWaypointApp;
  focusedDownloadThrottleEnabled = focusWaypointApp && !focusCameraApp && !deployCamPerformanceMode;
  bool lockAllowsDownloads = screenDimmed && dimWakePrompt;
  bool foregroundDownloadScreen =
      (screen == SCREEN_MAIN || screen == SCREEN_DOWNLOAD || screen == SCREEN_MAP_DL);
  bool keepDownloadsAlive =
      mapDownload.active || tileDownloadActive || (tileDownloadQueued && queuedFromMapDownload);
  bool gamePerformanceMode = isWaypointAppVisible(kAppGamesIndex) &&
                             (gameBoyRunning || gbaRunning);
  bool allowDownloads = !focusCameraApp && !gamePerformanceMode && !deployCamPerformanceMode &&
                        (keepDownloadsAlive || foregroundDownloadScreen || lockAllowsDownloads);
  bool vehicleMoving = vehicleMotionActive(millis());
  if (vehicleMoving && screen == SCREEN_MAIN) {
    // Navigation and GPS rendering win over background tile I/O while driving.
    allowDownloads = false;
  }
  if (usbMscActive) {
    allowDownloads = false;
  }
  tileDownloadProcessingEnabled = allowDownloads;
  mapDownloadProcessingEnabled = allowDownloads;
  if (!allowDownloads) {
    bool stopDownloadsForPerformance = focusCameraApp || gamePerformanceMode ||
                                       deployCamPerformanceMode || screenDimmed || vehicleMoving;
    if (stopDownloadsForPerformance) {
      requestTileDownloadTaskStop();
      if (mapDownload.active && !vehicleMoving) {
        stopMapDownload();
      }
    }
    return;
  }
  startTileDownloadTask();
}

bool isBusy() {
  bool busy = false;
  if (mapDownloadProcessingEnabled && mapDownload.active) {
    busy = true;
  }
  if (tileDownloadProcessingEnabled && (tileDownloadActive || tileDownloadQueued)) {
    busy = true;
  }
#if ENABLE_WIFI
  if (wifiTransition) {
    busy = true;
  }
  if (wifiAvailable && (wifiEnabled || wifiTransition) && wifiScanInProgress) {
    busy = true;
  }
#endif
  return busy;
}

BusyIndicatorInfo buildBusyIndicatorInfo(const Rect &bounds, uint8_t textSize) {
  BusyIndicatorInfo info = {};
  info.textSize = textSize;
  const char spinnerChars[] = "|/-\\";
  info.label[0] = 'B';
  info.label[1] = 'U';
  info.label[2] = 'S';
  info.label[3] = 'Y';
  info.label[4] = ' ';
  info.label[5] = spinnerChars[(millis() / 200) % 4];
  info.label[6] = '\0';

  M5.Display.setTextSize(textSize);
  int16_t textW = static_cast<int16_t>(M5.Display.textWidth(info.label));
  int16_t textH = static_cast<int16_t>(M5.Display.fontHeight());
  int16_t padX = 10;
  int16_t padY = 5;
  int16_t boxW = static_cast<int16_t>(textW + padX * 2);
  int16_t boxH = static_cast<int16_t>(textH + padY * 2);
  int16_t boxX = static_cast<int16_t>(bounds.x + bounds.w / 2 - boxW / 2);
  int16_t boxY = static_cast<int16_t>(bounds.y + 6);
  int16_t minX = static_cast<int16_t>(bounds.x + 2);
  int16_t maxX = static_cast<int16_t>(bounds.x + bounds.w - 2);
  if (boxX < minX) {
    boxX = minX;
  }
  if (boxX + boxW > maxX) {
    boxX = static_cast<int16_t>(maxX - boxW);
  }
  if (boxX < minX) {
    boxX = minX;
  }
  info.rect = {boxX, boxY, boxW, boxH};
  return info;
}

void drawBusyIndicatorInfo(const BusyIndicatorInfo &info) {
  M5.Display.setTextSize(info.textSize);
  M5.Display.fillRect(info.rect.x, info.rect.y, info.rect.w, info.rect.h, colors.black);
  bool flashOn = (millis() / kBusyFlashMs) % 2 == 0;
  uint16_t boxColor = flashOn ? colors.amber : colors.amberDim;
  M5.Display.drawRect(info.rect.x, info.rect.y, info.rect.w, info.rect.h, boxColor);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.drawString(info.label, info.rect.x + info.rect.w / 2,
                        info.rect.y + info.rect.h / 2);
  M5.Display.setTextDatum(TL_DATUM);
}

void drawBusyIndicatorTopCenter(uint8_t textSize) {
  bool uiDrawBusy = uiDrawBusyUntilMs != 0 && millis() < uiDrawBusyUntilMs;
  if (!isBusy() && !uiDrawBusy) {
    return;
  }
  Rect bounds = {0, 0, screenW, screenH};
  BusyIndicatorInfo info = buildBusyIndicatorInfo(bounds, textSize);
  drawBusyIndicatorInfo(info);
}

void drawTextureRect(const Rect &r, int16_t step = 8, int16_t dot = 2) {
  if (r.w <= 0 || r.h <= 0) {
    return;
  }
  int16_t x0 = max<int16_t>(0, r.x);
  int16_t y0 = max<int16_t>(0, r.y);
  int16_t x1 = min<int16_t>(static_cast<int16_t>(r.x + r.w - 1),
                             static_cast<int16_t>(screenW - 1));
  int16_t y1 = min<int16_t>(static_cast<int16_t>(r.y + r.h - 1),
                             static_cast<int16_t>(screenH - 1));
  if (x1 - x0 < 2 || y1 - y0 < 2) {
    return;
  }
  for (int16_t ty = static_cast<int16_t>(y0 + 2); ty <= y1 - 2; ty += step) {
    for (int16_t tx = static_cast<int16_t>(x0 + 2); tx <= x1 - 2; tx += step) {
      M5.Display.fillRect(tx, ty, dot, dot, colors.amberDim);
    }
  }
}

void updateWifiTransition(uint32_t now) {
#if ENABLE_WIFI
  if (!wifiTransition) {
    return;
  }
  if (now < wifiTransitionUntilMs) {
    return;
  }
  wifiTransition = false;
  statusDirty = true;
  downloadMenuDirty = true;
  mapDownloadStatusDirty = true;
  wifiDirty = true;
#else
  (void)now;
#endif
}

Rect arrowBackgroundRect(int16_t cx, int16_t cy) {
  int16_t size = static_cast<int16_t>(max<int16_t>(mapMarkerSize * 3, 72));
  size = static_cast<int16_t>(size + kArrowBackMargin * 2);
  if (size > kArrowBackMaxSize) {
    size = kArrowBackMaxSize;
  }
  int16_t x = static_cast<int16_t>(cx - size / 2);
  int16_t y = static_cast<int16_t>(cy - size / 2);
  int16_t right = static_cast<int16_t>(mapX + mapW);
  int16_t bottom = static_cast<int16_t>(mapY + mapH);
  if (x < mapX) {
    x = mapX;
  }
  if (y < mapY) {
    y = mapY;
  }
  if (x + size > right) {
    size = static_cast<int16_t>(right - x);
  }
  if (y + size > bottom) {
    size = static_cast<int16_t>(bottom - y);
  }
  if (size < 1) {
    return {0, 0, 0, 0};
  }
  return {x, y, size, size};
}

bool captureArrowBackground(const Rect &r) {
  if (!arrowBackBuffer) {
    arrowBackBuffer = static_cast<uint16_t *>(heap_caps_malloc(
        kArrowBackMaxSize * kArrowBackMaxSize * sizeof(uint16_t),
        MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
    if (!arrowBackBuffer) {
      arrowBackValid = false;
      return false;
    }
  }
  if (r.w <= 0 || r.h <= 0) {
    arrowBackValid = false;
    return false;
  }
  if (r.w > kArrowBackMaxSize || r.h > kArrowBackMaxSize) {
    arrowBackValid = false;
    return false;
  }
  M5.Display.readRect(r.x, r.y, r.w, r.h, arrowBackBuffer);
  arrowBackRect = r;
  arrowBackValid = true;
  return true;
}

void restoreArrowBackground() {
  if (!arrowBackValid || arrowBackRect.w <= 0 || arrowBackRect.h <= 0) {
    return;
  }
  M5.Display.pushImage(arrowBackRect.x, arrowBackRect.y, arrowBackRect.w, arrowBackRect.h,
                       arrowBackBuffer);
}

bool inRect(const Rect &r, int16_t x, int16_t y) {
  return x >= r.x && x < (r.x + r.w) && y >= r.y && y < (r.y + r.h);
}

bool inMapArea(int16_t x, int16_t y) {
  return x >= mapX && x < (mapX + mapW) && y >= mapY && y < (mapY + mapH);
}

bool isRectValid(const Rect &r) {
  return r.w > 0 && r.h > 0;
}

Rect unionRect(const Rect &a, const Rect &b) {
  if (!isRectValid(a)) {
    return b;
  }
  if (!isRectValid(b)) {
    return a;
  }
  int32_t left = min<int32_t>(a.x, b.x);
  int32_t top = min<int32_t>(a.y, b.y);
  int32_t right = max<int32_t>(a.x + a.w, b.x + b.w);
  int32_t bottom = max<int32_t>(a.y + a.h, b.y + b.h);
  return {static_cast<int16_t>(left), static_cast<int16_t>(top),
          static_cast<int16_t>(right - left), static_cast<int16_t>(bottom - top)};
}

Rect intersectRect(const Rect &a, const Rect &b) {
  int32_t left = max<int32_t>(a.x, b.x);
  int32_t top = max<int32_t>(a.y, b.y);
  int32_t right = min<int32_t>(a.x + a.w, b.x + b.w);
  int32_t bottom = min<int32_t>(a.y + a.h, b.y + b.h);
  int32_t w = right - left;
  int32_t h = bottom - top;
  if (w <= 0 || h <= 0) {
    return {0, 0, 0, 0};
  }
  return {static_cast<int16_t>(left), static_cast<int16_t>(top),
          static_cast<int16_t>(w), static_cast<int16_t>(h)};
}

Rect clampRectToMap(const Rect &r) {
  int32_t left = max<int32_t>(mapX, r.x);
  int32_t top = max<int32_t>(mapY, r.y);
  int32_t right = min<int32_t>(mapX + mapW, r.x + r.w);
  int32_t bottom = min<int32_t>(mapY + mapH, r.y + r.h);
  int32_t w = right - left;
  int32_t h = bottom - top;
  if (w <= 0 || h <= 0) {
    return {0, 0, 0, 0};
  }
  return {static_cast<int16_t>(left), static_cast<int16_t>(top),
          static_cast<int16_t>(w), static_cast<int16_t>(h)};
}

void applyZoomDelta(int delta) {
  debugPrint("ZOOM: request delta=%d zoom=%u range=%u..%u", delta, mapZoom, mapMinZoom, mapMaxZoom);
  if (delta > 0) {
    uint8_t nextZoom = static_cast<uint8_t>(mapZoom + 1);
    if (tileZoomDirExists(nextZoom)) {
      drawMapZoomLoadingIndicator(nextZoom);
      mapZoom = nextZoom;
      if (mapZoom > mapMaxZoom) {
        mapMaxZoom = mapZoom;
      }
      lastManualZoomMs = millis();
      double centerLat = 0.0;
      double centerLon = 0.0;
      if (getMapCenter(centerLat, centerLon)) {
        geoToWorldPixels(centerLat, centerLon, mapZoom, lastMapCenterX, lastMapCenterY);
        lastMapHasFix = true;
      }
      mapDirty = true;
      mapTilesDrawn = false;
      lastMapTileViewValid = false;
      statusDirty = true;
      debugPrint("ZOOM: forced to %u range=%u..%u", mapZoom, mapMinZoom, mapMaxZoom);
      return;
    }
  }
  if (delta > 0) {
    uint8_t nextZoom = static_cast<uint8_t>(mapZoom + 1);
    if (tileZoomDirExists(nextZoom) && nextZoom > mapMaxZoom) {
      mapMaxZoom = nextZoom;
    }
  }
  if (delta != 0) {
    bool wantsHigher = delta > 0;
    bool wantsLower = delta < 0;
    int target = static_cast<int>(mapZoom) + delta;
    if ((wantsHigher && target > mapMaxZoom) || (wantsLower && target < mapMinZoom)) {
      refreshTileZoomRange(true);
      if (wantsHigher && target > mapMaxZoom && tileZoomDirExists(static_cast<uint8_t>(target))) {
        mapMaxZoom = static_cast<uint8_t>(target);
      }
    }
  }
  int target = static_cast<int>(mapZoom) + delta;
  if (target < mapMinZoom) {
    target = mapMinZoom;
  }
  if (target > mapMaxZoom) {
    target = mapMaxZoom;
  }
  if (target == mapZoom) {
    debugPrint("ZOOM: no change target=%d zoom=%u range=%u..%u", target, mapZoom, mapMinZoom, mapMaxZoom);
    return;
  }
  drawMapZoomLoadingIndicator(static_cast<uint8_t>(target));
  mapZoom = static_cast<uint8_t>(target);
  lastManualZoomMs = millis();
  double centerLat = 0.0;
  double centerLon = 0.0;
  if (getMapCenter(centerLat, centerLon)) {
    geoToWorldPixels(centerLat, centerLon, mapZoom, lastMapCenterX, lastMapCenterY);
    lastMapHasFix = true;
  }
  mapDirty = true;
  mapTilesDrawn = false;
  lastMapTileViewValid = false;
  statusDirty = true;
  debugPrint("ZOOM: applied zoom=%u range=%u..%u", mapZoom, mapMinZoom, mapMaxZoom);
}

void drawRecordTripButton() {
  if (recordTripButton.w <= 0 || recordTripButton.h <= 0) {
    return;
  }
  uint16_t bg = tripActive ? colors.redDim : colors.black;
  uint16_t fg = tripActive ? colors.red : colors.amber;
  M5.Display.fillRect(recordTripButton.x, recordTripButton.y, recordTripButton.w,
                      recordTripButton.h, bg);
  M5.Display.drawRect(recordTripButton.x, recordTripButton.y, recordTripButton.w,
                      recordTripButton.h, fg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(fg, bg);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("TRIP", recordTripButton.x + recordTripButton.w / 2,
                        recordTripButton.y + recordTripButton.h / 2);
}

void drawRecenterMapButton() {
  if (recenterMapButton.w <= 0 || recenterMapButton.h <= 0) {
    return;
  }
  uint16_t fg = mapFollowPaused ? colors.red : colors.amber;
  M5.Display.fillRect(recenterMapButton.x, recenterMapButton.y, recenterMapButton.w,
                      recenterMapButton.h, colors.black);
  M5.Display.drawRect(recenterMapButton.x, recenterMapButton.y, recenterMapButton.w,
                      recenterMapButton.h, fg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(fg, colors.black);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.drawString(mapFollowPaused ? "RECENTER" : "FOLLOW",
                        recenterMapButton.x + recenterMapButton.w / 2,
                        recenterMapButton.y + recenterMapButton.h / 2);
  M5.Display.setTextDatum(TL_DATUM);
}

void drawZoomControls() {
  uint16_t fgIn = mapZoom < mapMaxZoom ? colors.amber : colors.amberDim;
  uint16_t fgOut = mapZoom > mapMinZoom ? colors.amber : colors.amberDim;
  uint16_t bg = colors.black;

  M5.Display.fillRect(zoomInButton.x, zoomInButton.y, zoomInButton.w, zoomInButton.h, bg);
  M5.Display.drawRect(zoomInButton.x, zoomInButton.y, zoomInButton.w, zoomInButton.h, fgIn);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(fgIn, bg);
  M5.Display.setTextSize(kButtonTextSize + 1);
  M5.Display.drawString("+", zoomInButton.x + zoomInButton.w / 2, zoomInButton.y + zoomInButton.h / 2);

  M5.Display.fillRect(zoomOutButton.x, zoomOutButton.y, zoomOutButton.w, zoomOutButton.h, bg);
  M5.Display.drawRect(zoomOutButton.x, zoomOutButton.y, zoomOutButton.w, zoomOutButton.h, fgOut);
  M5.Display.setTextColor(fgOut, bg);
  M5.Display.drawString("-", zoomOutButton.x + zoomOutButton.w / 2, zoomOutButton.y + zoomOutButton.h / 2);

  int16_t badgeW = zoomOutButton.w;
  int16_t badgeH = zoomOutButton.h;
  int16_t badgeX = zoomOutButton.x;
  int16_t badgeY = static_cast<int16_t>(zoomOutButton.y + zoomOutButton.h + kControlColumnGap);
  if (isRectValid(zoomIndicatorRect)) {
    badgeX = zoomIndicatorRect.x;
    badgeY = zoomIndicatorRect.y;
    badgeW = zoomIndicatorRect.w;
    badgeH = zoomIndicatorRect.h;
  }
  M5.Display.fillRect(badgeX, badgeY, badgeW, badgeH, bg);
  M5.Display.drawRect(badgeX, badgeY, badgeW, badgeH, colors.amberDim);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(colors.amber, bg);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.drawString("Z " + String(mapZoom), badgeX + badgeW / 2, badgeY + badgeH / 2);

  if (millis() - lastAutoZoomAppliedMs <= kAutoZoomTagMs) {
    int16_t tagH = 20;
    int16_t tagW = badgeW;
    int16_t tagX = badgeX;
    int16_t tagY = static_cast<int16_t>(badgeY + badgeH + 4);
    bool fitsBelow = tagY + tagH <= mapY + mapH;
    if (isRectValid(recordTripButton)) {
      fitsBelow = fitsBelow && tagY + tagH <= recordTripButton.y - 4;
    }
    if (fitsBelow) {
      M5.Display.fillRect(tagX, tagY, tagW, tagH, bg);
      M5.Display.drawRect(tagX, tagY, tagW, tagH, colors.amberDim);
      M5.Display.setTextDatum(MC_DATUM);
      M5.Display.setTextColor(colors.amberDim, bg);
      M5.Display.setTextSize(kSmallTextSize);
      M5.Display.drawString("AUTO", tagX + tagW / 2, tagY + tagH / 2);
    }
  }

  drawRecordTripButton();
}


bool configureWifiPins() {
#if ENABLE_WIFI
  if (wifiPinsConfigured) {
    return true;
  }
  if (!WiFi.setPins(WIFI_SDIO_CLK_PIN, WIFI_SDIO_CMD_PIN, WIFI_SDIO_D0_PIN, WIFI_SDIO_D1_PIN,
                    WIFI_SDIO_D2_PIN, WIFI_SDIO_D3_PIN, WIFI_RESET_PIN)) {
    debugPrint("WIFI: setPins failed");
    return false;
  }
  wifiPinsConfigured = true;
  debugPrint("WIFI: pins clk=%d cmd=%d d0=%d d1=%d d2=%d d3=%d rst=%d", WIFI_SDIO_CLK_PIN,
             WIFI_SDIO_CMD_PIN, WIFI_SDIO_D0_PIN, WIFI_SDIO_D1_PIN, WIFI_SDIO_D2_PIN,
             WIFI_SDIO_D3_PIN, WIFI_RESET_PIN);
  return true;
#else
  return false;
#endif
}

void resetWifiModule() {
#if ENABLE_WIFI
#if WIFI_BOOT_DRIVE
  if (WIFI_BOOT_PIN >= 0) {
    pinMode(WIFI_BOOT_PIN, OUTPUT);
#if WIFI_BOOT_ACTIVE_HIGH
    digitalWrite(WIFI_BOOT_PIN, HIGH);
#else
    digitalWrite(WIFI_BOOT_PIN, LOW);
#endif
    delay(5);
  }
#endif
  if (WIFI_RESET_PIN < 0) {
#if WIFI_BOOT_DRIVE
    if (WIFI_BOOT_PIN >= 0) {
      pinMode(WIFI_BOOT_PIN, INPUT);
    }
#endif
    return;
  }
  pinMode(WIFI_RESET_PIN, OUTPUT);
#if WIFI_RESET_ACTIVE_LOW
  digitalWrite(WIFI_RESET_PIN, LOW);
  delay(80);
  digitalWrite(WIFI_RESET_PIN, HIGH);
#else
  digitalWrite(WIFI_RESET_PIN, HIGH);
  delay(80);
  digitalWrite(WIFI_RESET_PIN, LOW);
#endif
  delay(200);
#if WIFI_BOOT_DRIVE
  if (WIFI_BOOT_PIN >= 0) {
    pinMode(WIFI_BOOT_PIN, INPUT);
  }
#endif
#endif
}

bool drawPngFromSd(const char *path, int32_t x, int32_t y, int32_t maxW = 0, int32_t maxH = 0) {
  if (!sdReady) {
    return false;
  }
  if (!lockSd(20)) {
    return false;
  }
  FsFile f = SD.open(path, FILE_READ);
  if (!f) {
    unlockSd();
    return false;
  }
  lgfx::DataWrapperT<FsFile> data(&f);
  bool ok = M5.Display.drawPng(&data, x, y, maxW, maxH);
  f.close();
  unlockSd();
  return ok;
}

bool drawFittedPngFromSd(const char *path) {
  if (!sdReady || !lockSd(20)) {
    return false;
  }
  FsFile f = SD.open(path, FILE_READ);
  if (!f) {
    unlockSd();
    return false;
  }
  lgfx::DataWrapperT<FsFile> data(&f);
  bool ok = M5.Display.drawPng(&data, 0, 0, screenW, screenH, 0, 0,
                               0.0f, 0.0f, lgfx::datum_t::top_center);
  f.close();
  unlockSd();
  return ok;
}

static bool drawCachedMenuBackground(const char *path, M5Canvas *&canvas,
                                     const char *menuName) {
  (void)path;
  (void)menuName;
  int16_t contentH = static_cast<int16_t>(screenH - navH);
  if (canvas && canvas->width() == screenW && canvas->height() == contentH) {
    canvas->pushSprite(0, 0);
    return true;
  }
  return false;
}

static bool prepareCachedMenuBackground(const char *path, M5Canvas *&canvas,
                                        const char *menuName) {
  int16_t contentH = static_cast<int16_t>(screenH - navH);
  if (canvas && canvas->width() == screenW && canvas->height() == contentH) {
    return true;
  }
  if (canvas) {
    canvas->deleteSprite();
    delete canvas;
    canvas = nullptr;
  }
  canvas = new (std::nothrow) M5Canvas(&M5.Display);
  if (!canvas) {
    return drawFittedPngFromSd(path);
  }
  canvas->setColorDepth(16);
  canvas->setPsram(true);
  if (!canvas->createSprite(screenW, contentH)) {
    delete canvas;
    canvas = nullptr;
    return false;
  }
  canvas->fillScreen(colors.black);
  bool ok = false;
  if (sdReady && lockSd(100)) {
    FsFile f = SD.open(path, FILE_READ);
    if (f) {
      lgfx::DataWrapperT<FsFile> data(&f);
      ok = canvas->drawPng(&data, 0, 0, screenW, contentH, 0, 0,
                           0.0f, 0.0f, lgfx::datum_t::top_center);
      f.close();
    }
    unlockSd();
  }
  if (!ok) {
    canvas->deleteSprite();
    delete canvas;
    canvas = nullptr;
    return false;
  }
  canvas->setScrollRect(0, 0, screenW, contentH, colors.black);
  canvas->scroll(kMenuBackgroundShiftPx, 0);
  debugPrint("UI: cached %s background psram=%u", menuName,
             static_cast<unsigned>(ESP.getFreePsram()));
  return true;
}

static bool prepareLockScreenBackground() {
  if (lockScreenBackgroundCanvas && lockScreenBackgroundCanvas->width() == screenW &&
      lockScreenBackgroundCanvas->height() == screenH) {
    return true;
  }
  if (lockScreenBackgroundCanvas) {
    lockScreenBackgroundCanvas->deleteSprite();
    delete lockScreenBackgroundCanvas;
    lockScreenBackgroundCanvas = nullptr;
  }
  lockScreenBackgroundCanvas = new (std::nothrow) M5Canvas(&M5.Display);
  if (!lockScreenBackgroundCanvas) return false;
  lockScreenBackgroundCanvas->setColorDepth(16);
  lockScreenBackgroundCanvas->setPsram(true);
  if (!lockScreenBackgroundCanvas->createSprite(screenW, screenH)) {
    delete lockScreenBackgroundCanvas;
    lockScreenBackgroundCanvas = nullptr;
    return false;
  }
  lockScreenBackgroundCanvas->fillScreen(colors.black);
  bool ok = false;
  if (sdReady && lockSd(150)) {
    FsFile f = SD.open(kLockScreenBackgroundPath, FILE_READ);
    if (f) {
      lgfx::DataWrapperT<FsFile> data(&f);
      ok = lockScreenBackgroundCanvas->drawPng(
          &data, 0, 0, screenW, screenH, 0, 0, 0.0f, 0.0f, lgfx::datum_t::top_center);
      f.close();
    }
    unlockSd();
  }
  if (!ok) {
    lockScreenBackgroundCanvas->deleteSprite();
    delete lockScreenBackgroundCanvas;
    lockScreenBackgroundCanvas = nullptr;
    debugPrint("UI: lock background unavailable path=%s", kLockScreenBackgroundPath);
    return false;
  }
  debugPrint("UI: cached LOCK background psram=%u",
             static_cast<unsigned>(ESP.getFreePsram()));
  return true;
}

