void loadTileServer() {
  tileServerBase = "";
  tileServerKey = "";
  tileServerRoot = "";
  tileServerStyle = "";
  tileStyleIndex = -1;
  prefs.begin("responder", true);
  tileServerKey = prefs.getString("tile_api_key", "");
  prefs.end();
  if (!sdReady) {
    return;
  }
  if (!lockSd(200)) {
    return;
  }
  if (!SD.exists(kTileServerPath)) {
    unlockSd();
    return;
  }
  FsFile f = SD.open(kTileServerPath, FILE_READ);
  if (!f) {
    unlockSd();
    return;
  }
  tileServerBase = f.readStringUntil('\n');
  tileServerBase.trim();
  f.close();

  const char *keyPath = "/tile_key.txt";
  if (tileServerKey.length() == 0 && SD.exists(keyPath)) {
    FsFile kf = SD.open(keyPath, FILE_READ);
    if (kf) {
      tileServerKey = kf.readStringUntil('\n');
      tileServerKey.trim();
      kf.close();
    }
  }
  if (tileServerKey.length() == 0) {
    int qPos = tileServerBase.indexOf('?');
    if (qPos >= 0 && qPos + 1 < tileServerBase.length()) {
      String query = tileServerBase.substring(qPos + 1);
      int pos = 0;
      while (pos < query.length()) {
        int amp = query.indexOf('&', pos);
        if (amp < 0) {
          amp = query.length();
        }
        String token = query.substring(pos, amp);
        int eq = token.indexOf('=');
        if (eq > 0 && eq + 1 < token.length()) {
          String name = token.substring(0, eq);
          name.toLowerCase();
          if (name == "apikey" || name == "key" || name == "token") {
            tileServerKey = token.substring(eq + 1);
            tileServerKey.trim();
            if (tileServerKey.length() > 0) {
              debugPrint("TILES: key loaded from tile_server.txt");
            }
            break;
          }
        }
        pos = amp + 1;
      }
    }
  }

  if (tileServerBase.length() > 0) {
    const char *host = "tile.thunderforest.com";
    int hostPos = tileServerBase.indexOf(host);
    if (hostPos >= 0) {
      int hostEnd = hostPos + static_cast<int>(strlen(host));
      tileServerRoot = tileServerBase.substring(0, hostEnd);
      String style;
      int slashPos = tileServerBase.indexOf('/', hostEnd);
      if (slashPos >= 0 && slashPos + 1 < tileServerBase.length()) {
        int nextSlash = tileServerBase.indexOf('/', slashPos + 1);
        if (nextSlash > 0) {
          style = tileServerBase.substring(slashPos + 1, nextSlash);
        } else {
          style = tileServerBase.substring(slashPos + 1);
        }
      }
      style.trim();
      int query = style.indexOf('?');
      if (query >= 0) {
        style = style.substring(0, query);
      }
      if (style.length() == 0) {
        style = "mobile-atlas";
      }
      if (SD.exists(kTileStylePath)) {
        FsFile sf = SD.open(kTileStylePath, FILE_READ);
        if (sf) {
          String overrideStyle = sf.readStringUntil('\n');
          overrideStyle.trim();
          if (overrideStyle.length() > 0) {
            style = overrideStyle;
          }
          sf.close();
        }
      }
      tileServerStyle = style;
      for (size_t i = 0; i < kTileStyleCount; ++i) {
        if (tileServerStyle == kTileStyles[i]) {
          tileStyleIndex = static_cast<int>(i);
          break;
        }
      }
      applyTileStyle(false);
    }
  }
  debugPrint("TILES: server=%s style=%s key=%d", tileServerBase.c_str(), tileServerStyle.c_str(),
             tileServerKey.length() > 0 ? 1 : 0);
  unlockSd();
}

static bool savePublicMapApiKey() {
  publicMapApiKeyDraft.trim();
  if (publicMapApiKeyDraft.length() > 192) {
    publicApiKeysStatus = "KEY TOO LONG";
    publicApiKeysDirty = true;
    return false;
  }
  prefs.begin("responder", false);
  size_t written = prefs.putString("tile_api_key", publicMapApiKeyDraft);
  prefs.end();
  if (publicMapApiKeyDraft.length() > 0 && written == 0) {
    publicApiKeysStatus = "SAVE FAILED";
    publicApiKeysDirty = true;
    return false;
  }
  tileServerKey = publicMapApiKeyDraft;
  publicMapApiKeyEditing = false;
  publicApiKeysStatus = tileServerKey.length() ? "SAVED TO DEVICE" : "KEY CLEARED";
  publicApiKeysDirty = true;
  debugPrint("APIKEYS: map credential updated present=%u", tileServerKey.length() ? 1U : 0U);
  return true;
}

void loadWaypoints() {
  waypointCount = 0;
  waypointsScrollIndex = 0;
  waypointsSelectedIndex = -1;
  if (!sdReady) {
    return;
  }
  if (!lockSd(200)) {
    return;
  }
  if (!SD.exists(kWaypointPath)) {
    unlockSd();
    return;
  }
  FsFile f = SD.open(kWaypointPath, FILE_READ);
  if (!f) {
    unlockSd();
    return;
  }
  while (f.available() && waypointCount < kMaxWaypoints) {
    String line = f.readStringUntil('\n');
    line.trim();
    if (line.length() == 0) {
      continue;
    }
    int c1 = line.indexOf(',');
    int c2 = line.indexOf(',', c1 + 1);
    if (c1 < 0 || c2 < 0) {
      continue;
    }
    Waypoint &wp = waypoints[waypointCount++];
    String name = line.substring(0, c1);
    name.toCharArray(wp.name, sizeof(wp.name));
    wp.lat = line.substring(c1 + 1, c2).toDouble();
    wp.lon = line.substring(c2 + 1).toDouble();
  }
  f.close();
  unlockSd();
  waypointsDirty = true;
}

size_t readTripLogTail(String *lines, size_t maxLines) {
  if (!sdReady || maxLines == 0) {
    return 0;
  }
  if (!lockSd(200)) {
    return 0;
  }
  if (!SD.exists(kTripLogPath)) {
    unlockSd();
    return 0;
  }
  FsFile f = SD.open(kTripLogPath, FILE_READ);
  if (!f) {
    unlockSd();
    return 0;
  }
  size_t count = 0;
  while (f.available()) {
    String line = f.readStringUntil('\n');
    line.trim();
    if (line.length() == 0) {
      continue;
    }
    if (line.startsWith("ts_ms,")) {
      continue;
    }
    if (count < maxLines) {
      lines[count++] = line;
    } else {
      for (size_t i = 1; i < maxLines; ++i) {
        lines[i - 1] = lines[i];
      }
      lines[maxLines - 1] = line;
    }
  }
  f.close();
  unlockSd();
  return count;
}

bool saveWaypoints() {
  if (!sdReady) {
    return false;
  }
  if (!lockSd(200)) {
    return false;
  }
  if (SD.exists(kWaypointPath)) {
    SD.remove(kWaypointPath);
  }
  FsFile f = SD.open(kWaypointPath, FILE_WRITE);
  if (!f) {
    unlockSd();
    return false;
  }
  for (size_t i = 0; i < waypointCount; ++i) {
    f.print(waypoints[i].name);
    f.print(',');
    f.print(waypoints[i].lat, 6);
    f.print(',');
    f.println(waypoints[i].lon, 6);
  }
  f.close();
  unlockSd();
  return true;
}

void addWaypoint() {
  beginWaypointNameEntry();
}

void beginWaypointNameEntry() {
  if (waypointCount >= kMaxWaypoints) {
    setAppToast("LOCATION LIST FULL");
    return;
  }
  if (lastGpsFixValid) {
    waypointPendingLat = lastGpsFixLat;
    waypointPendingLon = lastGpsFixLon;
  } else if (gps.location.isValid()) {
    waypointPendingLat = gps.location.lat();
    waypointPendingLon = gps.location.lng();
  } else {
    setAppToast("LOCATION NOT READY");
    return;
  }
  waypointNameInput = "";
  waypointNameEntryActive = true;
  waypointNameEntrySaving = false;
  waypointNameEntrySaved = false;
  waypointNameEntryFailed = false;
  waypointEmptyEnterArmed = false;
  waypointEmptyEnterMs = 0;
  waypointNameNoticeUntilMs = 0;
  drawWaypointNameModal();
}

void commitWaypointNameEntry() {
  if (!waypointNameEntryActive || waypointNameEntrySaving || waypointCount >= kMaxWaypoints) return;
  waypointNameEntrySaving = true;
  waypointNameEntrySaved = false;
  waypointNameEntryFailed = false;
  drawWaypointNameModal();

  Waypoint &wp = waypoints[waypointCount];
  String cleanName = waypointNameInput;
  cleanName.trim();
  cleanName.replace(",", " ");
  cleanName.toCharArray(wp.name, sizeof(wp.name));
  wp.lat = waypointPendingLat;
  wp.lon = waypointPendingLon;
  ++waypointCount;
  bool saved = saveWaypoints();
  if (!saved) {
    --waypointCount;
    waypointNameEntryFailed = true;
    debugPrint("MAP: location save failed");
  } else {
    waypointNameEntrySaved = true;
    waypointsDirty = true;
    debugPrint("MAP: location saved named=%u", cleanName.length() ? 1U : 0U);
  }
  waypointNameEntrySaving = false;
  waypointNameNoticeUntilMs = millis() + (saved ? 850UL : 1800UL);
  drawWaypointNameModal();
}

void updateWaypointNameEntry(uint32_t now) {
  if (!waypointNameEntryActive) return;
  if (waypointEmptyEnterArmed && now - waypointEmptyEnterMs > 1500UL) {
    waypointEmptyEnterArmed = false;
    drawWaypointNameModal();
  }
  if (waypointNameNoticeUntilMs != 0 &&
      static_cast<int32_t>(now - waypointNameNoticeUntilMs) >= 0) {
    waypointNameEntryActive = false;
    waypointNameEntrySaved = false;
    waypointNameEntryFailed = false;
    waypointNameNoticeUntilMs = 0;
    mapDirty = true;
    statusDirty = true;
  }
}

void deleteLastWaypoint() {
  if (waypointCount == 0) {
    return;
  }
  --waypointCount;
  saveWaypoints();
  if (waypointCount == 0) {
    waypointsSelectedIndex = -1;
    waypointsScrollIndex = 0;
    mapLocSelectedIndex = -1;
    mapLocScrollIndex = 0;
    mapNavTargetIndex = -1;
  } else {
    int maxIndex = static_cast<int>(waypointCount - 1);
    if (waypointsSelectedIndex > maxIndex) {
      waypointsSelectedIndex = maxIndex;
    }
    if (waypointsScrollIndex > maxIndex) {
      waypointsScrollIndex = maxIndex;
    }
    if (mapLocSelectedIndex > maxIndex) {
      mapLocSelectedIndex = maxIndex;
    }
    if (mapLocScrollIndex > maxIndex) {
      mapLocScrollIndex = maxIndex;
    }
    if (mapNavTargetIndex > maxIndex) {
      mapNavTargetIndex = -1;
    }
  }
  waypointsDirty = true;
}

static void clearMeshMapTarget() {
  meshMapFocusIndex = -1;
  meshNavTargetIndex = -1;
}

void loadSavedNetworks() {
#if ENABLE_WIFI
  savedCredCount = 0;
  prefs.begin("responder", true);
  savedCredCount = prefs.getUChar("count", 0);
  savedCredCount = min(savedCredCount, kMaxSavedNetworks);
  int tz = prefs.getInt("tz", 99);
  clockOffsetManual = prefs.getBool("tz_manual", false);
  if (tz >= kTimeZoneMinOffset && tz <= kTimeZoneMaxOffset) {
    storedClockOffsetHours = tz;
    storedClockOffsetValid = true;
    clockOffsetHours = tz;
    clockOffsetValid = true;
  } else {
    storedClockOffsetValid = false;
  }
  uint8_t dlMin = prefs.getUChar("dl_min", mapDownloadMinZoomSel);
  uint8_t dlMax = prefs.getUChar("dl_max", mapDownloadMaxZoomSel);
  if (dlMin < kDownloadMinZoom) {
    dlMin = kDownloadMinZoom;
  }
  if (dlMax > kDownloadMaxZoom) {
    dlMax = kDownloadMaxZoom;
  }
  if (dlMax < dlMin) {
    dlMax = dlMin;
  }
  mapDownloadMinZoomSel = dlMin;
  mapDownloadMaxZoomSel = dlMax;
  int region = prefs.getInt("dl_region", mapDownloadSelected);
  int totalRegions = static_cast<int>(sizeof(kMapRegions) / sizeof(kMapRegions[0]));
  if (region < 0 || region >= totalRegions) {
    region = 0;
  }
  mapDownloadSelected = region;
  for (size_t i = 0; i < savedCredCount; ++i) {
    String keyS = String("s") + String(i);
    String keyP = String("p") + String(i);
    savedCreds[i].ssid = prefs.getString(keyS.c_str(), "");
    savedCreds[i].pass = prefs.getString(keyP.c_str(), "");
  }
  debugPrint("WIFI: saved networks=%u", static_cast<unsigned>(savedCredCount));
  uint32_t cachedEpoch = prefs.getUInt("last_epoch", 0);
  if (cachedEpoch >= 1577836800UL && cachedEpoch < 2524608000UL) {
    cachedEpochSeconds = cachedEpoch;
    cachedEpochValid = true;
    cachedEpochSetMs = millis();
    applyValidatedSystemEpoch(cachedEpoch);
  } else {
    cachedEpochValid = false;
  }
  prefs.end();
#else
  savedCredCount = 0;
  wifiAvailable = false;
#endif
}

