  if (lat < 38.41241892) return 47; if (lat < 39.92256684) return 46;
  if (lat < 41.38651832) return 45; if (lat < 42.80914012) return 44;
  if (lat < 44.19454951) return 43; if (lat < 45.54626723) return 42;
