  if (lat < 51.89342469) return 37; if (lat < 53.09516153) return 36;
  if (lat < 54.27817472) return 35; if (lat < 55.44378444) return 34;
  if (lat < 56.59318756) return 33; if (lat < 57.72747354) return 32;
