    M5.Display.drawRect(static_cast<int16_t>(rect.x + 3), static_cast<int16_t>(rect.y + 3),
                        static_cast<int16_t>(rect.w - 6), static_cast<int16_t>(rect.h - 6),
                        colors.amberDim);
