void drawWeatherTravelInfo() {
  int16_t top = static_cast<int16_t>(appTopBarRect.h + 8);
  int16_t bottom = static_cast<int16_t>(screenH - navH - 8);
  if (bottom <= top) {
    weatherTravelDirty = false;
    return;
  }

  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kSmallTextSize + 1);
  int16_t lineH = static_cast<int16_t>(M5.Display.fontHeight() + 4);
  top = static_cast<int16_t>(top + lineH + 6);

  size_t iconLines = 0;
  const char *const *icon = weatherIconForCode(weatherValid ? weatherCode : -1, iconLines);
  int16_t iconLineH = static_cast<int16_t>(M5.Display.fontHeight() + 2);
  int16_t iconW = 0;
  for (size_t i = 0; i < iconLines; ++i) {
    iconW = max<int16_t>(iconW, static_cast<int16_t>(M5.Display.textWidth(icon[i])));
  }
  int16_t iconH = static_cast<int16_t>(iconLineH * iconLines);
  int16_t iconX = 12;
  int16_t iconY = top;

  int16_t textX = static_cast<int16_t>(iconX + iconW + 12);
  int16_t textY = iconY;
  int16_t textMaxW = static_cast<int16_t>(screenW - 12 - textX);
  bool stackText = textMaxW < 80;
  if (stackText) {
    textX = 12;
    textY = static_cast<int16_t>(iconY + iconH + 6);
  }

  M5.Display.setTextSize(kWifiTextSize + 1);
  int16_t mainLineH = static_cast<int16_t>(M5.Display.fontHeight() + 6);
  M5.Display.setTextSize(kSmallTextSize + 1);
  lineH = static_cast<int16_t>(M5.Display.fontHeight() + 4);
  int16_t infoStartY = static_cast<int16_t>(textY + mainLineH);
  if (weatherValid && lastWeatherMs > 0) {
    infoStartY = static_cast<int16_t>(infoStartY + lineH);
  }

  size_t travelLines = 0;
  const char *const *travelIcon = weatherTravelIcon(weatherTraveling, travelLines);
  int16_t travelLineH = static_cast<int16_t>(M5.Display.fontHeight() + 2);
  int16_t travelW = 0;
  for (size_t i = 0; i < travelLines; ++i) {
    travelW = max<int16_t>(travelW, static_cast<int16_t>(M5.Display.textWidth(travelIcon[i])));
  }
  int16_t travelIconH = static_cast<int16_t>(travelLineH * travelLines);

  const char *travelLabel = weatherTraveling ? "TRAVEL" : "CITY";
  M5.Display.setTextSize(kSmallTextSize);
  int16_t labelH = static_cast<int16_t>(M5.Display.fontHeight() + 2);
  int16_t labelW = static_cast<int16_t>(M5.Display.textWidth(travelLabel));
  int16_t travelH = static_cast<int16_t>(travelIconH + labelH);
  int16_t travelRectW = max<int16_t>(travelW, labelW);
  int16_t travelRight = static_cast<int16_t>(screenW / 2 - 6);
  int16_t travelX = static_cast<int16_t>(travelRight - travelRectW);
  if (travelX < 0) {
    travelX = 0;
  }
  int16_t travelTop = max<int16_t>(infoStartY,
                                   static_cast<int16_t>(iconY + iconH + 8));
  int16_t travelY = travelTop;
  if (travelY + travelH > bottom) {
    travelY = static_cast<int16_t>(bottom - travelH);
  }
  if (travelY < top) {
    travelY = top;
  }
  Rect nextRect = {travelX, travelY, travelRectW, travelH};
  if (isRectValid(weatherInfoRect)) {
    bool overlap =
        !(nextRect.x + nextRect.w <= weatherInfoRect.x ||
          weatherInfoRect.x + weatherInfoRect.w <= nextRect.x ||
          nextRect.y + nextRect.h <= weatherInfoRect.y ||
          weatherInfoRect.y + weatherInfoRect.h <= nextRect.y);
    if (overlap) {
      int16_t shiftedY = static_cast<int16_t>(weatherInfoRect.y - travelH - 8);
      if (shiftedY >= top) {
        travelY = shiftedY;
        if (travelY + travelH > bottom) {
          travelY = static_cast<int16_t>(bottom - travelH);
        }
        if (travelY < top) {
          travelY = top;
        }
        nextRect.y = travelY;
      }
    }
  }
  Rect clearRect = unionRect(weatherTravelRect, nextRect);
  if (isRectValid(clearRect)) {
    M5.Display.fillRect(clearRect.x, clearRect.y, clearRect.w, clearRect.h, colors.black);
  }

  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kSmallTextSize + 1);
  M5.Display.setTextColor(colors.amber, colors.black);
  for (size_t i = 0; i < travelLines; ++i) {
    int16_t y = static_cast<int16_t>(travelY + static_cast<int16_t>(i * travelLineH));
    M5.Display.drawString(travelIcon[i], travelX, y);
  }
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  int16_t labelY = static_cast<int16_t>(travelY + travelIconH + 2);
  M5.Display.drawString(travelLabel, travelX, labelY);

  weatherTravelRect = nextRect;
  weatherTravelDirty = false;
}

bool initCameraMclk() {
  if (cameraMclkReady) {
    return true;
  }
  // Let the Arduino LEDC allocator pick a free timer/channel.
  if (!ledcAttach(kCameraMclkPin, kCameraMclkFreq, LEDC_TIMER_1_BIT)) {
    return false;
  }
  ledcWrite(kCameraMclkPin, 1);
  cameraMclkReady = true;
  return true;
}

void setCameraError(const char *reason) {
  if (!cameraError || cameraErrorDetail != reason) {
    cameraError = true;
    cameraErrorDetail = reason;
    cameraPreviewDirty = true;
    cameraUiDirty = true;
    cameraNeedsFullRedraw = true;
  }
  cameraNextRetryMs = millis() + kCameraRetryDelayMs;
  debugPrint("CAM: error %s", reason ? reason : "unknown");
}

bool configureCameraIspDefaults() {
  if (!kCameraForceIspDemosaic && !kCameraForceIspBf) {
    return true;
  }
  int fd = open(ESP_VIDEO_ISP1_DEVICE_NAME, O_RDWR);
  if (fd < 0) {
    debugPrint("CAM: isp open failed err=%d", errno);
    return false;
  }
  bool ok = true;
  if (kCameraForceIspDemosaic) {
    esp_video_isp_demosaic_t demosaic = {};
    demosaic.enable = true;
    demosaic.gradient_ratio = kCameraIspDemosaicGrad;
    v4l2_ext_controls controls = {};
    v4l2_ext_control control = {};
    controls.ctrl_class = V4L2_CID_USER_CLASS;
    controls.count = 1;
    controls.controls = &control;
    control.id = V4L2_CID_USER_ESP_ISP_DEMOSAIC;
    control.p_u8 = reinterpret_cast<uint8_t *>(&demosaic);
    if (ioctl(fd, VIDIOC_S_EXT_CTRLS, &controls) != 0) {
      debugPrint("CAM: isp demosaic set failed err=%d", errno);
      ok = false;
    }
  }
  if (kCameraForceIspBf) {
    esp_video_isp_bf_t bf = {};
    bf.enable = true;
    bf.level = kCameraIspBfLevel;
    for (int x = 0; x < ISP_BF_TEMPLATE_X_NUMS; ++x) {
      for (int y = 0; y < ISP_BF_TEMPLATE_Y_NUMS; ++y) {
        bf.matrix[x][y] = 1;
      }
    }
    if (ISP_BF_TEMPLATE_X_NUMS >= 3 && ISP_BF_TEMPLATE_Y_NUMS >= 3) {
      bf.matrix[1][1] = 4;
      bf.matrix[0][1] = 2;
      bf.matrix[1][0] = 2;
      bf.matrix[1][2] = 2;
      bf.matrix[2][1] = 2;
    }
    v4l2_ext_controls controls = {};
    v4l2_ext_control control = {};
    controls.ctrl_class = V4L2_CID_USER_CLASS;
    controls.count = 1;
    controls.controls = &control;
    control.id = V4L2_CID_USER_ESP_ISP_BF;
    control.p_u8 = reinterpret_cast<uint8_t *>(&bf);
    if (ioctl(fd, VIDIOC_S_EXT_CTRLS, &controls) != 0) {
      debugPrint("CAM: isp bf set failed err=%d", errno);
      ok = false;
    }
  }
  close(fd);
  if (ok) {
    debugPrint("CAM: isp defaults applied");
  }
  return ok;
}

bool initCameraPipeline() {
  if (cameraPipelineReady) {
    return true;
  }
  if (!initCameraMclk()) {
    return false;
  }

  int sccbPort = M5.In_I2C.getPort();
  int sccbSda = M5.In_I2C.getSDA();
  int sccbScl = M5.In_I2C.getSCL();
  if (sccbPort < 0) {
    sccbPort = kCameraSccbPort;
    sccbSda = kCameraSccbSda;
    sccbScl = kCameraSccbScl;
  }
  if (sccbSda < 0 || sccbScl < 0) {
    sccbSda = kCameraSccbSda;
    sccbScl = kCameraSccbScl;
  }

  esp_video_init_csi_config_t csi_config = {};
  // Reuse the Arduino I2C driver (M5.In_I2C) to avoid acquiring the bus twice.
  // SCCB_ARDUINO_OVERRIDE treats the handle as an I2C port number.
  csi_config.sccb_config.init_sccb = false;
  csi_config.sccb_config.i2c_handle =
      reinterpret_cast<i2c_master_bus_handle_t>(static_cast<uintptr_t>(sccbPort));
  csi_config.sccb_config.freq = kCameraSccbFreq;
  csi_config.reset_pin = -1;
  csi_config.pwdn_pin = -1;

  esp_video_init_config_t cam_config = {};
  cam_config.csi = &csi_config;
  cam_config.dvp = nullptr;
  cam_config.jpeg = nullptr;
  cam_config.isp = nullptr;

  if (esp_video_init(&cam_config) != ESP_OK) {
    return false;
  }
  configureCameraIspDefaults();
  cameraPipelineReady = true;
  return true;
}

static void cameraFormatToString(uint32_t format, char out[5]) {
  out[0] = static_cast<char>(format & 0xFF);
  out[1] = static_cast<char>((format >> 8) & 0xFF);
  out[2] = static_cast<char>((format >> 16) & 0xFF);
  out[3] = static_cast<char>((format >> 24) & 0xFF);
  out[4] = '\0';
}

static ppa_srm_color_mode_t cameraPpaColorModeForFormat(uint32_t format) {
  switch (format) {
    case V4L2_PIX_FMT_YUV420:
      return PPA_SRM_COLOR_MODE_YUV420;
    case V4L2_PIX_FMT_RGB565:
      return PPA_SRM_COLOR_MODE_RGB565;
    default:
      return PPA_SRM_COLOR_MODE_RGB565;
  }
}

static size_t alignToCacheLine(size_t size) {
  return (size + kCacheLineBytes - 1) & ~(kCacheLineBytes - 1);
}

static size_t cameraExpectedFrameSize(uint32_t format, uint32_t width, uint32_t height,
                                      uint32_t bytesPerLine) {
  size_t stride = bytesPerLine ? static_cast<size_t>(bytesPerLine) : static_cast<size_t>(width);
  switch (format) {
    case V4L2_PIX_FMT_YUV420:
      return stride * height * 3 / 2;
    case V4L2_PIX_FMT_RGB565:
    default:
      if (bytesPerLine == 0) {
        stride = static_cast<size_t>(width) * 2;
      }
      return stride * height;
  }
}

static void logCameraFormat(const char *devicePath, const char *label, const v4l2_format &fmt) {
  char fourcc[5] = {};
  cameraFormatToString(fmt.fmt.pix.pixelformat, fourcc);
  debugPrint("CAM: %s %s fmt %ux%u %s bpl=%u size=%u", devicePath, label, fmt.fmt.pix.width,
             fmt.fmt.pix.height, fourcc, fmt.fmt.pix.bytesperline, fmt.fmt.pix.sizeimage);
}

static uint32_t clampU32(uint32_t value, uint32_t minValue, uint32_t maxValue) {
  if (value < minValue) {
    return minValue;
  }
  if (value > maxValue) {
    return maxValue;
  }
  return value;
}

static uint32_t clampStepU32(uint32_t value, uint32_t minValue, uint32_t maxValue, uint32_t step) {
  uint32_t clamped = clampU32(value, minValue, maxValue);
  if (step == 0 || clamped <= minValue) {
    return minValue;
  }
  return minValue + ((clamped - minValue) / step) * step;
}

static bool chooseCameraFrameSize(int fd, uint32_t pixelFormat, uint32_t desiredW,
                                  uint32_t desiredH, uint32_t *outW, uint32_t *outH) {
  v4l2_frmsizeenum fsize = {};
  fsize.pixel_format = pixelFormat;
  bool found = false;
  uint32_t bestW = 0;
  uint32_t bestH = 0;
  uint64_t bestScore = 0;
  uint64_t bestArea = 0;
  uint64_t desiredArea = static_cast<uint64_t>(desiredW) * desiredH;
  for (fsize.index = 0; ioctl(fd, VIDIOC_ENUM_FRAMESIZES, &fsize) == 0; ++fsize.index) {
    if (fsize.type == V4L2_FRMSIZE_TYPE_DISCRETE) {
      uint32_t w = fsize.discrete.width;
      uint32_t h = fsize.discrete.height;
      uint64_t aspectDiff =
          (static_cast<uint64_t>(w) * desiredH > static_cast<uint64_t>(h) * desiredW)
              ? (static_cast<uint64_t>(w) * desiredH - static_cast<uint64_t>(h) * desiredW)
              : (static_cast<uint64_t>(h) * desiredW - static_cast<uint64_t>(w) * desiredH);
      uint64_t area = static_cast<uint64_t>(w) * h;
      uint64_t areaDiff = (area > desiredArea) ? (area - desiredArea) : (desiredArea - area);
      uint64_t score = aspectDiff * (desiredArea ? desiredArea : 1) + areaDiff;
      if (!found || score < bestScore || (score == bestScore && area < bestArea)) {
        bestScore = score;
        bestArea = area;
        bestW = w;
        bestH = h;
        found = true;
      }
      continue;
    }
    if (fsize.type == V4L2_FRMSIZE_TYPE_STEPWISE || fsize.type == V4L2_FRMSIZE_TYPE_CONTINUOUS) {
      uint32_t w =
          (fsize.type == V4L2_FRMSIZE_TYPE_STEPWISE)
              ? clampStepU32(desiredW, fsize.stepwise.min_width, fsize.stepwise.max_width,
                             fsize.stepwise.step_width)
              : clampU32(desiredW, fsize.stepwise.min_width, fsize.stepwise.max_width);
      uint32_t h =
          (fsize.type == V4L2_FRMSIZE_TYPE_STEPWISE)
              ? clampStepU32(desiredH, fsize.stepwise.min_height, fsize.stepwise.max_height,
                             fsize.stepwise.step_height)
              : clampU32(desiredH, fsize.stepwise.min_height, fsize.stepwise.max_height);
      if (outW) {
        *outW = w;
      }
      if (outH) {
        *outH = h;
      }
      debugPrint("CAM: size range %ux%u..%ux%u step=%ux%u -> %ux%u", fsize.stepwise.min_width,
                 fsize.stepwise.min_height, fsize.stepwise.max_width, fsize.stepwise.max_height,
                 fsize.stepwise.step_width, fsize.stepwise.step_height, w, h);
      return true;
    }
  }
  if (found) {
    if (outW) {
      *outW = bestW;
    }
    if (outH) {
      *outH = bestH;
    }
    debugPrint("CAM: picked size %ux%u", bestW, bestH);
  }
  return found;
}

int openCameraDeviceAtPath(const char *devicePath, uint32_t pixelFormat, v4l2_format *out_fmt) {
  const int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
  int fd = open(devicePath, O_RDWR);
  if (fd < 0) {
    debugPrint("CAM: open %s failed err=%d", devicePath, errno);
    return -1;
  }
  v4l2_capability capability = {};
  if (ioctl(fd, VIDIOC_QUERYCAP, &capability) != 0) {
    debugPrint("CAM: querycap %s failed err=%d", devicePath, errno);
    close(fd);
    return -1;
  }
  v4l2_format fmt = {};
  fmt.type = type;
  if (ioctl(fd, VIDIOC_G_FMT, &fmt) != 0) {
    debugPrint("CAM: get fmt %s failed err=%d", devicePath, errno);
    close(fd);
    return -1;
  }
  logCameraFormat(devicePath, "default", fmt);
  const uint32_t desiredW = kCameraWidth;
  const uint32_t desiredH = kCameraHeight;
  uint32_t targetW = desiredW;
  uint32_t targetH = desiredH;
  if (!chooseCameraFrameSize(fd, pixelFormat, desiredW, desiredH, &targetW, &targetH)) {
    targetW = fmt.fmt.pix.width;
    targetH = fmt.fmt.pix.height;
  }
  const bool needSet =
      fmt.fmt.pix.pixelformat != pixelFormat || fmt.fmt.pix.width != targetW ||
      fmt.fmt.pix.height != targetH;
  if (needSet) {
    v4l2_format set_fmt = {};
    set_fmt.type = type;
    set_fmt.fmt.pix.width = targetW;
    set_fmt.fmt.pix.height = targetH;
    set_fmt.fmt.pix.pixelformat = pixelFormat;
    if (ioctl(fd, VIDIOC_S_FMT, &set_fmt) != 0) {
      if (fmt.fmt.pix.pixelformat != pixelFormat) {
        debugPrint("CAM: set fmt %s failed err=%d", devicePath, errno);
        close(fd);
        return -1;
      }
      debugPrint("CAM: set fmt %s failed err=%d (keeping default)", devicePath, errno);
    } else {
      fmt.type = type;
      if (ioctl(fd, VIDIOC_G_FMT, &fmt) != 0) {
        debugPrint("CAM: get fmt (after set) %s failed err=%d", devicePath, errno);
        close(fd);
        return -1;
      }
      logCameraFormat(devicePath, "active", fmt);
    }
  }
  if (fmt.fmt.pix.pixelformat != pixelFormat) {
    debugPrint("CAM: %s format mismatch", devicePath);
    close(fd);
    return -1;
  }
  size_t expected =
      cameraExpectedFrameSize(fmt.fmt.pix.pixelformat, fmt.fmt.pix.width, fmt.fmt.pix.height,
                              fmt.fmt.pix.bytesperline);
  if (fmt.fmt.pix.sizeimage && expected && fmt.fmt.pix.sizeimage < expected) {
    debugPrint("CAM: %s sizeimage too small (%u < %u)", devicePath, fmt.fmt.pix.sizeimage,
               static_cast<unsigned>(expected));
    close(fd);
    return -1;
  }
  if (out_fmt) {
    *out_fmt = fmt;
  }
  return fd;
}

int openCameraDevice(uint32_t pixelFormat, v4l2_format *out_fmt) {
  if (kCameraUseIspDevice) {
    int fd = openCameraDeviceAtPath(ESP_VIDEO_ISP1_DEVICE_NAME, pixelFormat, out_fmt);
    if (fd >= 0) {
      debugPrint("CAM: using %s", ESP_VIDEO_ISP1_DEVICE_NAME);
      return fd;
    }
  }
  int fd = openCameraDeviceAtPath(ESP_VIDEO_MIPI_CSI_DEVICE_NAME, pixelFormat, out_fmt);
  if (fd >= 0) {
    debugPrint("CAM: using %s", ESP_VIDEO_MIPI_CSI_DEVICE_NAME);
  }
  return fd;
}

bool startCameraDevice() {
  if (cameraDevice.fd >= 0) {
    return true;
  }
  v4l2_format fmt = {};
  int fd = openCameraDevice(V4L2_PIX_FMT_RGB565, &fmt);
  if (fd < 0) {
    fd = openCameraDevice(V4L2_PIX_FMT_YUV420, &fmt);
  }
  if (fd < 0) {
    return false;
  }
  uint32_t prevW = cameraDevice.width;
  uint32_t prevH = cameraDevice.height;
  cameraDevice.fd = fd;
  cameraDevice.width = fmt.fmt.pix.width ? fmt.fmt.pix.width : kCameraWidth;
  cameraDevice.height = fmt.fmt.pix.height ? fmt.fmt.pix.height : kCameraHeight;
  cameraDevice.pixel_format =
      fmt.fmt.pix.pixelformat ? fmt.fmt.pix.pixelformat : V4L2_PIX_FMT_RGB565;
  cameraDevice.bytes_per_line = fmt.fmt.pix.bytesperline;
  cameraDevice.size_image = fmt.fmt.pix.sizeimage;
  cameraInputColorMode = cameraPpaColorModeForFormat(cameraDevice.pixel_format);
  size_t expected =
      cameraExpectedFrameSize(cameraDevice.pixel_format, cameraDevice.width, cameraDevice.height,
                              cameraDevice.bytes_per_line);
  cameraInputSize = cameraDevice.size_image ? cameraDevice.size_image : expected;
  cameraStrideWarned = false;
  if (cameraInputColorMode == PPA_SRM_COLOR_MODE_YUV420) {
    debugPrint("CAM: using YUV420 input");
  }
  if (cameraDevice.width != prevW || cameraDevice.height != prevH) {
    updateLayout();
    cameraPreviewClearNeeded = true;
  }

  v4l2_requestbuffers req = {};
  req.count = 2;
  req.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
  req.memory = V4L2_MEMORY_MMAP;
  if (ioctl(cameraDevice.fd, VIDIOC_REQBUFS, &req) != 0) {
    debugPrint("CAM: reqbufs failed err=%d", errno);
    stopCameraDevice();
    return false;
  }
  for (int i = 0; i < 2; ++i) {
    v4l2_buffer buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;
    buf.index = i;
    if (ioctl(cameraDevice.fd, VIDIOC_QUERYBUF, &buf) != 0) {
      debugPrint("CAM: querybuf %d failed err=%d", i, errno);
      stopCameraDevice();
      return false;
    }
    cameraDevice.buffer_length[i] = buf.length;
    void *mapped =
        mmap(nullptr, buf.length, PROT_READ | PROT_WRITE, MAP_SHARED, cameraDevice.fd, buf.m.offset);
    if (mapped == MAP_FAILED) {
      debugPrint("CAM: mmap %d failed err=%d", i, errno);
      stopCameraDevice();
      return false;
    }
    cameraDevice.buffer[i] = reinterpret_cast<uint8_t *>(mapped);
    if (ioctl(cameraDevice.fd, VIDIOC_QBUF, &buf) != 0) {
      debugPrint("CAM: qbuf %d failed err=%d", i, errno);
      stopCameraDevice();
      return false;
    }
  }
  int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
  if (ioctl(cameraDevice.fd, VIDIOC_STREAMON, &type) != 0) {
    debugPrint("CAM: streamon failed err=%d", errno);
    stopCameraDevice();
    return false;
  }
  return true;
}

void stopCameraDevice() {
  if (cameraDevice.fd < 0) {
    return;
  }
  int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
  ioctl(cameraDevice.fd, VIDIOC_STREAMOFF, &type);
  for (int i = 0; i < 2; ++i) {
    if (cameraDevice.buffer[i] && cameraDevice.buffer_length[i] > 0) {
      munmap(cameraDevice.buffer[i], cameraDevice.buffer_length[i]);
    }
    cameraDevice.buffer[i] = nullptr;
    cameraDevice.buffer_length[i] = 0;
  }
  cameraDevice.bytes_per_line = 0;
  cameraDevice.size_image = 0;
  cameraInputSize = 0;
  cameraInputColorMode = PPA_SRM_COLOR_MODE_RGB565;
  close(cameraDevice.fd);
  cameraDevice.fd = -1;
}

bool initCameraPpa() {
  if (cameraPpaHandle) {
    return true;
  }
  ppa_client_config_t config = {};
  config.oper_type = PPA_OPERATION_SRM;
  config.max_pending_trans_num = 1;
  if (ppa_register_client(&config, &cameraPpaHandle) != ESP_OK) {
    cameraPpaHandle = nullptr;
    return false;
  }
  return true;
}

void deinitCameraPpa() {
  if (cameraPpaHandle) {
    ppa_unregister_client(cameraPpaHandle);
    cameraPpaHandle = nullptr;
  }
}

bool ensureCameraFrameBuffer() {
  if (cameraFrame) {
    return true;
  }
  cameraFrameSize = alignToCacheLine(
      static_cast<size_t>(cameraCaptureWidth()) * static_cast<size_t>(cameraCaptureHeight()) * 2);
  cameraFrame = reinterpret_cast<uint8_t *>(
      heap_caps_aligned_alloc(kCacheLineBytes, cameraFrameSize, MALLOC_CAP_SPIRAM | MALLOC_CAP_DMA));
  if (!cameraFrame) {
    return false;
  }
  memset(cameraFrame, 0, cameraFrameSize);
  return true;
}

bool ensureCameraPreviewBuffer() {
  int16_t w = cameraPreviewDrawRect.w;
  int16_t h = cameraPreviewDrawRect.h;
  if (w <= 0 || h <= 0) {
    return false;
  }
  size_t needed = static_cast<size_t>(w) * static_cast<size_t>(h) * 2;
  size_t alignedNeeded = alignToCacheLine(needed);
  if (cameraPreviewFrame && cameraPreviewFrameBack && cameraPreviewFrameW == w &&
      cameraPreviewFrameH == h && cameraPreviewFrameSize == alignedNeeded) {
    return true;
  }
  if (cameraPreviewFrame) {
    heap_caps_free(cameraPreviewFrame);
    cameraPreviewFrame = nullptr;
  }
  if (cameraPreviewFrameBack) {
    heap_caps_free(cameraPreviewFrameBack);
    cameraPreviewFrameBack = nullptr;
  }
  cameraPreviewFrame = reinterpret_cast<uint8_t *>(
      heap_caps_aligned_alloc(kCacheLineBytes, alignedNeeded, MALLOC_CAP_SPIRAM | MALLOC_CAP_DMA));
  cameraPreviewFrameBack = reinterpret_cast<uint8_t *>(
      heap_caps_aligned_alloc(kCacheLineBytes, alignedNeeded, MALLOC_CAP_SPIRAM | MALLOC_CAP_DMA));
  if (!cameraPreviewFrame || !cameraPreviewFrameBack) {
    if (cameraPreviewFrame) {
      heap_caps_free(cameraPreviewFrame);
      cameraPreviewFrame = nullptr;
    }
    if (cameraPreviewFrameBack) {
      heap_caps_free(cameraPreviewFrameBack);
      cameraPreviewFrameBack = nullptr;
    }
    cameraPreviewFrameSize = 0;
    cameraPreviewFrameW = 0;
    cameraPreviewFrameH = 0;
    cameraPreviewFrameReady = false;
    cameraPreviewSwapPending = false;
    return false;
  }
  memset(cameraPreviewFrame, 0, alignedNeeded);
  memset(cameraPreviewFrameBack, 0, alignedNeeded);
  cameraPreviewFrameSize = alignedNeeded;
  cameraPreviewFrameW = w;
  cameraPreviewFrameH = h;
  cameraPreviewFrameReady = false;
  cameraPreviewSwapPending = false;
  return true;
}

bool initCameraJpeg() {
  if (cameraJpegHandle) {
    return true;
  }
  jpeg_encode_engine_cfg_t enc_cfg = {};
  enc_cfg.timeout_ms = 5000;
  if (jpeg_new_encoder_engine(&enc_cfg, &cameraJpegHandle) != ESP_OK) {
    cameraJpegHandle = nullptr;
    return false;
  }
  jpeg_encode_memory_alloc_cfg_t mem_cfg = {};
  mem_cfg.buffer_direction = JPEG_ENC_ALLOC_OUTPUT_BUFFER;
  cameraJpegBuf = reinterpret_cast<uint8_t *>(
      jpeg_alloc_encoder_mem(cameraFrameSize, &mem_cfg, &cameraJpegBufSize));
  if (!cameraJpegBuf) {
    jpeg_del_encoder_engine(cameraJpegHandle);
    cameraJpegHandle = nullptr;
    return false;
  }
  return true;
}

bool ensureCameraPhotoDir() {
  if (!sdReady) {
    return false;
  }
  if (!SD.exists(kCameraPhotoDir)) {
    return SD.mkdir(kCameraPhotoDir);
  }
  return true;
}

String nextCameraPhotoPath() {
  uint32_t idx = cameraPhotoIndex;
  for (size_t attempt = 0; attempt < 9999; ++attempt) {
    ++idx;
    char name[64];
    snprintf(name, sizeof(name), "%s/IMG_%06lu.jpg", kCameraPhotoDir,
             static_cast<unsigned long>(idx));
    if (!SD.exists(name)) {
      cameraPhotoIndex = idx;
      return String(name);
    }
  }
  return "";
}

void scanCameraPhotos() {
  cameraPhotoCount = 0;
  if (!sdReady) {
    return;
  }
  if (!lockSd(2000)) {
    return;
  }
  if (!ensureCameraPhotoDir()) {
    unlockSd();
    return;
  }
  FsFile dir = SD.open(kCameraPhotoDir, FILE_READ);
  if (!dir || !dir.isDirectory()) {
    if (dir) {
      dir.close();
    }
    unlockSd();
    return;
  }
  FsFile file = dir.openNextFile();
  while (file && cameraPhotoCount < kCameraMaxPhotos) {
    if (!file.isDirectory()) {
      char nameBuf[128];
      if (file.getName(nameBuf, sizeof(nameBuf)) == 0) {
        file.close();
        file = dir.openNextFile();
        continue;
      }
      String name = nameBuf;
      name.toLowerCase();
      if (name.endsWith(".jpg")) {
        String fullPath = String(kCameraPhotoDir) + "/" + name;
        cameraPhotoFiles[cameraPhotoCount++] = fullPath;
      }
    }
    file.close();
    file = dir.openNextFile();
  }
  dir.close();
  unlockSd();
  fileManagerStatus = "";
  fileManagerStatusMs = 0;
  for (size_t i = 0; i + 1 < cameraPhotoCount; ++i) {
    for (size_t j = i + 1; j < cameraPhotoCount; ++j) {
      if (cameraPhotoFiles[j] > cameraPhotoFiles[i]) {
        String tmp = cameraPhotoFiles[i];
        cameraPhotoFiles[i] = cameraPhotoFiles[j];
        cameraPhotoFiles[j] = tmp;
      }
    }
  }
  if (cameraGalleryPage * kCameraThumbsPerPage >= cameraPhotoCount) {
    cameraGalleryPage = 0;
  }
}

bool deleteCameraPhotoAtIndex(size_t index) {
  if (!sdReady || index >= cameraPhotoCount) {
    return false;
  }
  String path = cameraPhotoFiles[index];
  bool found = false;
  bool removed = false;
  if (lockSd(2000)) {
    found = SD.exists(path.c_str());
    if (found) {
      removed = SD.remove(path.c_str());
    }
    unlockSd();
  }
  if (removed || !found) {
    scanCameraPhotos();
  }
  return removed;
}

void cameraCaptureTask(void *param) {
  (void)param;
  v4l2_buffer buf = {};
  while (!cameraTaskStop) {
    buf = {};
    buf.type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    buf.memory = V4L2_MEMORY_MMAP;
    if (ioctl(cameraDevice.fd, VIDIOC_DQBUF, &buf) != 0) {
      vTaskDelay(pdMS_TO_TICKS(20));
      continue;
    }
    if (cameraTaskStop) {
      break;
    }
    size_t inputSize = cameraInputSize ? cameraInputSize : cameraFrameSize;
    if (inputSize > cameraDevice.buffer_length[buf.index]) {
      debugPrint("CAM: input size %u exceeds buffer %u", static_cast<unsigned>(inputSize),
                 static_cast<unsigned>(cameraDevice.buffer_length[buf.index]));
      setCameraError("FORMAT");
      if (!cameraTaskStop && cameraDevice.fd >= 0) {
        ioctl(cameraDevice.fd, VIDIOC_QBUF, &buf);
      }
      vTaskDelay(pdMS_TO_TICKS(20));
      continue;
    }

    bool frameOk = false;
    const uint32_t captureW = cameraCaptureWidth();
    const uint32_t captureH = cameraCaptureHeight();
    const size_t packedStride = static_cast<size_t>(captureW) * 2;
    const size_t srcStride =
        cameraDevice.bytes_per_line ? static_cast<size_t>(cameraDevice.bytes_per_line) : packedStride;
    uint32_t now = millis();
    bool previewQueued = false;
    const bool previewPossible = kCameraPreviewUsePpa && cameraPpaHandle &&
                                 ensureCameraPreviewBuffer() && cameraPreviewFrame &&
                                 cameraPreviewFrameBack;
    const bool previewAccepting = !cameraPreviewSwapPending && !cameraPreviewDirty;
    if (previewPossible && previewAccepting) {
      ppa_srm_oper_config_t preview = {};
      preview.in.buffer = cameraDevice.buffer[buf.index];
      uint32_t previewCaptureW = cameraCaptureWidth();
      uint32_t previewCaptureH = cameraCaptureHeight();
      uint32_t cropW = previewCaptureW;
      uint32_t cropH = previewCaptureH;
      uint32_t cropX = 0;
      uint32_t cropY = 0;
      if (kCameraPreviewFill && !kCameraPreviewForceFit && cameraPreviewFrameW > 0 &&
          cameraPreviewFrameH > 0) {
        uint32_t outW = static_cast<uint32_t>(cameraPreviewFrameW);
        uint32_t outH = static_cast<uint32_t>(cameraPreviewFrameH);
        uint64_t inAspect = static_cast<uint64_t>(previewCaptureW) * outH;
        uint64_t outAspect = static_cast<uint64_t>(previewCaptureH) * outW;
        if (inAspect > outAspect) {
          cropW = static_cast<uint32_t>(
              (static_cast<uint64_t>(previewCaptureH) * outW) / outH);
          cropW = min(cropW, previewCaptureW);
          cropX = (previewCaptureW - cropW) / 2;
        } else if (inAspect < outAspect) {
          cropH = static_cast<uint32_t>(
              (static_cast<uint64_t>(previewCaptureW) * outH) / outW);
          cropH = min(cropH, previewCaptureH);
          cropY = (previewCaptureH - cropH) / 2;
        }
      }
      preview.in.pic_w = previewCaptureW;
      preview.in.pic_h = previewCaptureH;
      preview.in.block_w = cropW;
      preview.in.block_h = cropH;
      preview.in.block_offset_x = cropX;
      preview.in.block_offset_y = cropY;
      preview.in.srm_cm = cameraInputColorMode;
      preview.out.buffer = cameraPreviewFrameBack;
      preview.out.buffer_size = cameraPreviewFrameSize;
      preview.out.pic_w = static_cast<uint32_t>(cameraPreviewFrameW);
      preview.out.pic_h = static_cast<uint32_t>(cameraPreviewFrameH);
      preview.out.block_offset_x = 0;
      preview.out.block_offset_y = 0;
      preview.out.srm_cm = PPA_SRM_COLOR_MODE_RGB565;
      preview.rotation_angle = kCameraRotation;
      preview.scale_x =
          static_cast<float>(cameraPreviewFrameW) / static_cast<float>(cropW);
      preview.scale_y =
          static_cast<float>(cameraPreviewFrameH) / static_cast<float>(cropH);
      preview.mirror_x = kCameraMirrorX;
      preview.mirror_y = kCameraMirrorY;
      preview.rgb_swap = kCameraRgbSwap;
      preview.byte_swap = kCameraByteSwap;
      preview.mode = PPA_TRANS_MODE_BLOCKING;
      if (ppa_do_scale_rotate_mirror(cameraPpaHandle, &preview) == ESP_OK) {
        cameraPreviewSwapPending = true;
        previewQueued = true;
      }
    }
    const bool needFullFrame =
        cameraCaptureRequest || !previewPossible || (!previewQueued && !cameraPreviewFrameReady);
    if (needFullFrame && cameraFrame && cameraFrameMutex &&
        xSemaphoreTake(cameraFrameMutex, pdMS_TO_TICKS(20)) == pdTRUE) {
      if (needFullFrame) {
        const bool usePpa = cameraPpaHandle &&
                            (cameraInputColorMode != PPA_SRM_COLOR_MODE_RGB565 ||
                             srcStride == packedStride);
        if (usePpa) {
          ppa_srm_oper_config_t srm = {};
          srm.in.buffer = cameraDevice.buffer[buf.index];
          srm.in.pic_w = captureW;
          srm.in.pic_h = captureH;
          srm.in.block_w = captureW;
          srm.in.block_h = captureH;
          srm.in.block_offset_x = 0;
          srm.in.block_offset_y = 0;
          srm.in.srm_cm = cameraInputColorMode;
          srm.out.buffer = cameraFrame;
          srm.out.buffer_size = cameraFrameSize;
          srm.out.pic_w = captureW;
          srm.out.pic_h = captureH;
          srm.out.block_offset_x = 0;
          srm.out.block_offset_y = 0;
          srm.out.srm_cm = PPA_SRM_COLOR_MODE_RGB565;
          srm.rotation_angle = kCameraRotation;
          srm.scale_x = 1;
          srm.scale_y = 1;
          srm.mirror_x = kCameraMirrorX;
          srm.mirror_y = kCameraMirrorY;
          srm.rgb_swap = kCameraRgbSwap;
          srm.byte_swap = kCameraByteSwap;
          srm.mode = PPA_TRANS_MODE_BLOCKING;
          if (ppa_do_scale_rotate_mirror(cameraPpaHandle, &srm) == ESP_OK) {
            frameOk = true;
          }
        }
        if (!frameOk) {
          if (cameraInputColorMode != PPA_SRM_COLOR_MODE_RGB565) {
            debugPrint("CAM: input format not supported without PPA");
            setCameraError("FORMAT");
          } else {
            if (srcStride != packedStride && !cameraStrideWarned) {
              debugPrint("CAM: repacking stride %u -> %u", static_cast<unsigned>(srcStride),
                         static_cast<unsigned>(packedStride));
              cameraStrideWarned = true;
            }
            const uint8_t *src = cameraDevice.buffer[buf.index];
            uint8_t *dst = cameraFrame;
            if (srcStride == packedStride) {
              if (kCameraByteSwap || kCameraRgbSwap) {
                size_t pixels = static_cast<size_t>(captureW) * static_cast<size_t>(captureH);
                const uint16_t *src16 = reinterpret_cast<const uint16_t *>(src);
                uint16_t *dst16 = reinterpret_cast<uint16_t *>(dst);
                for (size_t i = 0; i < pixels; ++i) {
                  uint16_t px = src16[i];
                  if (kCameraByteSwap) {
                    px = static_cast<uint16_t>((px << 8) | (px >> 8));
                  }
                  if (kCameraRgbSwap) {
                    px = static_cast<uint16_t>((px & 0x07E0) | ((px & 0xF800) >> 11) |
                                               ((px & 0x001F) << 11));
                  }
                  dst16[i] = px;
                }
              } else {
                memcpy(dst, src, cameraFrameSize);
              }
            } else {
              for (uint32_t y = 0; y < captureH; ++y) {
                const uint8_t *row = src + static_cast<size_t>(y) * srcStride;
                uint8_t *out = dst + static_cast<size_t>(y) * packedStride;
                if (kCameraByteSwap || kCameraRgbSwap) {
                  const uint16_t *row16 = reinterpret_cast<const uint16_t *>(row);
                  uint16_t *out16 = reinterpret_cast<uint16_t *>(out);
                  for (uint32_t x = 0; x < captureW; ++x) {
                    uint16_t px = row16[x];
                    if (kCameraByteSwap) {
                      px = static_cast<uint16_t>((px << 8) | (px >> 8));
                    }
                    if (kCameraRgbSwap) {
                      px = static_cast<uint16_t>((px & 0x07E0) | ((px & 0xF800) >> 11) |
                                                 ((px & 0x001F) << 11));
                    }
                    out16[x] = px;
                  }
                } else {
                  memcpy(out, row, packedStride);
                }
              }
            }
            frameOk = true;
          }
        }
        if (frameOk) {
          cameraFrameReady = true;
          cameraFrameMs = now;
          if (cameraCaptureRequest) {
            cameraCaptureRequest = false;
          }
        } else {
          cameraFrameReady = false;
        }
      }
      xSemaphoreGive(cameraFrameMutex);
    }
    if (previewQueued) {
      // Redraw when a new preview frame is queued.
      cameraPreviewDirty = true;
    } else if (!previewPossible && previewAccepting && !cameraPreviewFrameReady) {
      // No preview available yet; draw raw once to avoid a black frame.
      cameraPreviewFrameReady = false;
      cameraPreviewDirty = true;
    } else if (!previewPossible && previewAccepting &&
               now - cameraPreviewFallbackMs >= kCameraPreviewFallbackIntervalMs) {
      // PPA preview not available; fall back to raw preview at a lower rate.
      cameraPreviewFrameReady = false;
      cameraPreviewFallbackMs = now;
      cameraPreviewDirty = true;
    } else if (previewPossible && previewAccepting &&
               now - cameraPreviewFallbackMs >= kCameraPreviewFallbackIntervalMs) {
      // PPA preview failed; allow a raw refresh occasionally.
      cameraPreviewFrameReady = false;
      cameraPreviewFallbackMs = now;
      cameraPreviewDirty = true;
    }
    if (!cameraTaskStop && cameraDevice.fd >= 0) {
      ioctl(cameraDevice.fd, VIDIOC_QBUF, &buf);
    }
    vTaskDelay(pdMS_TO_TICKS(kCameraPreviewCaptureIntervalMs));
  }

  stopCameraDevice();
  deinitCameraPpa();
  cameraTaskStop = false;
  cameraStopping = false;
  cameraTaskHandle = nullptr;
  vTaskDelete(nullptr);
}

void startCameraPreview() {
  if (cameraTaskHandle || cameraStopping) {
    return;
  }
  if (kCameraPreviewDisabled) {
    setCameraError("DISABLED");
    return;
  }
  debugPrint("CAM: preview start");
  if (!initCameraPipeline()) {
    setCameraError("PIPELINE");
    return;
  }
  if (!startCameraDevice()) {
    setCameraError("DEVICE");
    return;
  }
  if (kCameraPreviewUsePpa && !initCameraPpa()) {
    stopCameraDevice();
    setCameraError("PPA");
    return;
  }
  if (!ensureCameraFrameBuffer()) {
    deinitCameraPpa();
    stopCameraDevice();
    setCameraError("BUFFER");
    return;
  }
  cameraError = false;
  cameraErrorDetail = nullptr;
  cameraNextRetryMs = 0;
  cameraTaskStop = false;
  cameraPreviewDirty = true;
  cameraUiDirty = true;
  cameraPreviewLastDrawMs = 0;
  BaseType_t taskOk = xTaskCreatePinnedToCore(cameraCaptureTask, "cam", 8192, nullptr, 2,
                                             &cameraTaskHandle, 1);
  if (taskOk != pdPASS) {
    cameraTaskHandle = nullptr;
    cameraTaskStop = false;
    deinitCameraPpa();
    stopCameraDevice();
    setCameraError("TASK");
    debugPrint("CAM: task create failed");
  }
}

void requestCameraPreviewStop() {
  if (!cameraTaskHandle || cameraStopping) {
    return;
  }
  cameraTaskStop = true;
  cameraStopping = true;
  if (cameraDevice.fd >= 0) {
    int type = V4L2_BUF_TYPE_VIDEO_CAPTURE;
    ioctl(cameraDevice.fd, VIDIOC_STREAMOFF, &type);
  }
}

void prepareForCameraApp() {
#if ENABLE_WIFI
  wifiRestoreAfterCameraMs = 0;
  bool hadWifi = wifiScanInProgress || mapDownload.active;
  if (hadWifi) {
    debugPrint("CAM: pausing WiFi work before preview");
  }
  abortTileDownload();
  if (mapDownload.active) {
    stopMapDownload();
  }
  if (wifiScanInProgress) {
    stopWifiScan();
  }
  wifiScanInProgress = false;
  wifiNetworkCount = 0;
  wifiTransition = false;
  lastWifiToggleMs = 0;
  wifiDirty = true;
  // The hosted Wi-Fi driver leaks its SDIO mempool when repeatedly stopped and restarted.
  // Pause network work for camera bandwidth, but keep the driver initialized across app exits.
  wifiDisabledForCamera = false;
#endif
#if HAS_USB_HOST
  bool hadSdr = rfScanRunning || ghostScanRunning || rtlSdrAutoStartStreamRequested ||
                rtlSdrStreaming;
  if (hadSdr) {
    debugPrint("CAM: stopping SDR stream before preview");
  }
  rfScanRunning = false;
  ghostScanRunning = false;
  rtlSdrAutoStartStreamRequested = false;
  rtlSdrAutoStartRequestedMs = 0;
  rtlSdrAutoRecoveries = 0;
  stopRfSdrStream();
#endif
  closeAudioPlayback();
}

void restoreWifiAfterCameraApp() {
#if ENABLE_WIFI
  wifiDisabledForCamera = false;
#endif
}

void prepareForDeployCamApp() {
#if ENABLE_WIFI
  requestTileDownloadTaskStop();
  if (mapDownload.active) {
    stopMapDownload();
  }
  if (wifiScanInProgress) {
    stopWifiScan();
  }
  wifiScanInProgress = false;
#endif
  if (recorderRunning || recorderTaskHandle) {
    stopAudioRecorder();
  }
  closeAudioPlayback();
  if (audioPlayBuf) {
    heap_caps_free(audioPlayBuf);
    audioPlayBuf = nullptr;
    audioPlayBufIndex = 0;
  }
  if (arrowBackBuffer) {
    heap_caps_free(arrowBackBuffer);
    arrowBackBuffer = nullptr;
    arrowBackValid = false;
  }
  debugPrint("IPCAM: performance prep internal=%u dma=%u",
             static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)),
             static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_DMA)));
}

void stopCameraPreview() {
  requestCameraPreviewStop();
}

void updateCameraState(uint32_t now) {
  bool cameraAppSelected = screen == SCREEN_WAYPOINTS && appSelected == kAppCameraIndex;
  bool wantsPreview = cameraAppSelected && cameraView == CAMERA_VIEW_PREVIEW && !screenDimmed;
  if (wantsPreview) {
#if ENABLE_WIFI
    if (wifiDisabledForCamera && (wifiEnabled || wifiTransition)) {
      if (wifiEnabled) {
        setWifiEnabled(false);
      }
      return;
    }
#endif
    if (!cameraError || now >= cameraNextRetryMs) {
      startCameraPreview();
    }
  } else {
    requestCameraPreviewStop();
    if (!cameraAppSelected && wifiDisabledForCamera && !cameraTaskHandle && !cameraStopping) {
      if (wifiRestoreAfterCameraMs == 0) {
        wifiRestoreAfterCameraMs = now + 300;
      } else if (now >= wifiRestoreAfterCameraMs) {
        wifiRestoreAfterCameraMs = 0;
        restoreWifiAfterCameraApp();
      }
    }
  }
}

bool captureCameraPhoto() {
  if (cameraSaving) {
    return false;
  }
  if (!sdReady || !cameraFrameReady) {
    return false;
  }
  uint32_t now = millis();
  if (now - lastCameraCaptureMs < kCameraCaptureCooldownMs) {
    return false;
  }
  if (!initCameraJpeg()) {
    return false;
  }
  if (!lockSd(2000)) {
    return false;
  }
  if (!ensureCameraPhotoDir()) {
    unlockSd();
    return false;
  }
  String path = nextCameraPhotoPath();
  if (path.length() == 0) {
    unlockSd();
    return false;
  }
  FsFile f = SD.open(path.c_str(), FILE_WRITE);
  if (!f) {
    unlockSd();
    return false;
  }

  cameraSaving = true;
  cameraUiDirty = true;
  cameraCaptureRequest = true;
  cameraFrameReady = false;
  uint32_t waitStart = millis();
  while (!cameraFrameReady && millis() - waitStart < kCameraCaptureWaitMs) {
    vTaskDelay(pdMS_TO_TICKS(5));
  }
  if (!cameraFrameReady) {
    cameraCaptureRequest = false;
    f.close();
    unlockSd();
    cameraSaving = false;
    cameraUiDirty = true;
    return false;
  }
  uint32_t jpegSize = 0;
  if (cameraFrameMutex && xSemaphoreTake(cameraFrameMutex, pdMS_TO_TICKS(200)) == pdTRUE) {
    jpeg_encode_cfg_t enc_cfg = {};
    enc_cfg.width = cameraCaptureWidth();
    enc_cfg.height = cameraCaptureHeight();
    enc_cfg.src_type = JPEG_ENCODE_IN_FORMAT_RGB565;
    enc_cfg.sub_sample = JPEG_DOWN_SAMPLING_YUV420;
    enc_cfg.image_quality = kCameraPreviewQuality;
    esp_err_t res = jpeg_encoder_process(cameraJpegHandle, &enc_cfg, cameraFrame,
                                         static_cast<uint32_t>(cameraFrameSize), cameraJpegBuf,
                                         static_cast<uint32_t>(cameraJpegBufSize), &jpegSize);
    xSemaphoreGive(cameraFrameMutex);
    if (res != ESP_OK || jpegSize == 0) {
      f.close();
      unlockSd();
      cameraSaving = false;
      cameraUiDirty = true;
      return false;
    }
  } else {
    f.close();
    unlockSd();
    cameraSaving = false;
    cameraUiDirty = true;
    return false;
  }
  f.write(cameraJpegBuf, jpegSize);
  f.close();
  unlockSd();
  prefs.begin("responder", false);
  prefs.putUInt("photo_idx", cameraPhotoIndex);
  prefs.end();
  lastCameraCaptureMs = now;
  cameraCaptureNoticeMs = now;
  cameraSaving = false;
  scanCameraPhotos();
  cameraGalleryDirty = true;
  cameraUiDirty = true;
  return true;
}

bool drawCameraPreviewFrame() {
  bool drew = false;
  if (!cameraFrameReady || !cameraFrame || !cameraFrameMutex) {
    M5.Display.fillRect(cameraPreviewRect.x, cameraPreviewRect.y, cameraPreviewRect.w,
                        cameraPreviewRect.h, colors.black);
    cameraPreviewLastDrawMs = millis();
    return true;
  }
  if (cameraPreviewClearNeeded) {
    M5.Display.fillRect(cameraPreviewRect.x, cameraPreviewRect.y, cameraPreviewRect.w,
                        cameraPreviewRect.h, colors.black);
    cameraPreviewClearNeeded = false;
  }
  if (M5.Display.dmaBusy()) {
    return false;
  }
  if (xSemaphoreTake(cameraFrameMutex, pdMS_TO_TICKS(20)) == pdTRUE) {
    if (cameraPreviewSwapPending && cameraPreviewFrame && cameraPreviewFrameBack) {
      uint8_t *swap = cameraPreviewFrame;
      cameraPreviewFrame = cameraPreviewFrameBack;
      cameraPreviewFrameBack = swap;
      cameraPreviewSwapPending = false;
      cameraPreviewFrameReady = true;
    }

    bool usePreview = cameraPreviewFrameReady && cameraPreviewFrame && cameraPreviewFrameW > 0 &&
                      cameraPreviewFrameH > 0;
    uint8_t *previewPtr = cameraPreviewFrame;
    int16_t previewW = cameraPreviewFrameW;
    int16_t previewH = cameraPreviewFrameH;

    if (usePreview) {
      xSemaphoreGive(cameraFrameMutex);
      bool prevSwap = M5.Display.getSwapBytes();
      bool swapChanged = prevSwap != kCameraPreviewSwapBytes;
      if (swapChanged) {
        M5.Display.setSwapBytes(kCameraPreviewSwapBytes);
      }
      M5.Display.pushImageDMA(cameraPreviewDrawRect.x, cameraPreviewDrawRect.y, previewW,
                              previewH, reinterpret_cast<uint16_t *>(previewPtr));
      if (swapChanged) {
        M5.Display.waitDMA();
        M5.Display.setSwapBytes(prevSwap);
      }
      drew = true;
    } else {
      bool prevSwap = M5.Display.getSwapBytes();
      bool swapChanged = prevSwap != kCameraPreviewSwapBytes;
      if (swapChanged) {
        M5.Display.setSwapBytes(kCameraPreviewSwapBytes);
      }
      uint32_t captureW = cameraCaptureWidth();
      uint32_t captureH = cameraCaptureHeight();
      int16_t drawX =
          static_cast<int16_t>(cameraPreviewRect.x + (cameraPreviewRect.w - captureW) / 2);
      int16_t drawY =
          static_cast<int16_t>(cameraPreviewRect.y + (cameraPreviewRect.h - captureH) / 2);
      M5.Display.setClipRect(cameraPreviewRect.x, cameraPreviewRect.y, cameraPreviewRect.w,
                             cameraPreviewRect.h);
      M5.Display.pushImage(drawX, drawY, captureW, captureH,
                           reinterpret_cast<uint16_t *>(cameraFrame));
      M5.Display.waitDMA();
      M5.Display.clearClipRect();
      if (swapChanged) {
        M5.Display.setSwapBytes(prevSwap);
      }
      xSemaphoreGive(cameraFrameMutex);
      drew = true;
    }
  }
  if (drew) {
    cameraPreviewLastDrawMs = millis();
    if (cameraPreviewFpsWindowMs == 0) {
      cameraPreviewFpsWindowMs = cameraPreviewLastDrawMs;
      cameraPreviewFpsFrames = 0;
    }
    ++cameraPreviewFpsFrames;
    if (cameraPreviewLastDrawMs - cameraPreviewFpsWindowMs >= 1000) {
      debugPrint("CAM: preview fps=%lu",
                 static_cast<unsigned long>(cameraPreviewFpsFrames));
      cameraPreviewFpsWindowMs = cameraPreviewLastDrawMs;
      cameraPreviewFpsFrames = 0;
    }
  }
  return drew;
}

void drawCameraButtons() {
  uint16_t shutterFg = cameraSaving ? colors.red : colors.amber;
  drawTerminalButton(cameraShutterButton, cameraSaving ? "SAVING..." : "SHUTTER",
                     shutterFg);
}

void drawCameraGallery() {
  if (!sdReady) {
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString("SD NOT READY", screenW / 2,
                          static_cast<int16_t>(cameraGalleryGridRect.y + 20));
  } else {
    if (cameraGalleryDirty || cameraPhotoCount == 0) {
      scanCameraPhotos();
    }
    if (cameraPhotoCount == 0) {
      M5.Display.setTextDatum(MC_DATUM);
      M5.Display.setTextColor(colors.amberDim, colors.black);
      M5.Display.setTextSize(kSmallTextSize);
      M5.Display.drawString("NO PHOTOS", screenW / 2,
                            static_cast<int16_t>(cameraGalleryGridRect.y + 20));
    } else {
      int16_t cellW =
          static_cast<int16_t>(cameraGalleryGridRect.w / kCameraGalleryCols);
      int16_t cellH =
          static_cast<int16_t>(cameraGalleryGridRect.h / kCameraGalleryRows);
      int16_t pad = 6;
      size_t start = cameraGalleryPage * kCameraThumbsPerPage;
      for (uint8_t row = 0; row < kCameraGalleryRows; ++row) {
        for (uint8_t col = 0; col < kCameraGalleryCols; ++col) {
          size_t idx = start + row * kCameraGalleryCols + col;
          int16_t x = static_cast<int16_t>(cameraGalleryGridRect.x + col * cellW);
          int16_t y = static_cast<int16_t>(cameraGalleryGridRect.y + row * cellH);
          Rect cell = {x, y, cellW, cellH};
          drawTerminalPanel(cell, idx < cameraPhotoCount ? colors.amberDim : colors.black);
          if (idx < cameraPhotoCount) {
            const String &path = cameraPhotoFiles[idx];
            String name = path.substring(path.lastIndexOf('/') + 1);
            M5.Display.fillRect(static_cast<int16_t>(x + pad), static_cast<int16_t>(y + pad),
                                static_cast<int16_t>(cellW - pad * 2),
                                static_cast<int16_t>(cellH - pad * 2), colors.black);
            M5.Display.setTextDatum(MC_DATUM);
            M5.Display.setTextColor(colors.amber, colors.black);
            M5.Display.setTextSize(kSmallTextSize);
            M5.Display.drawString("JPG", static_cast<int16_t>(x + cellW / 2),
                                  static_cast<int16_t>(y + cellH / 2 - 12));
            M5.Display.setTextColor(colors.amberDim, colors.black);
            M5.Display.drawString(name, static_cast<int16_t>(x + cellW / 2),
                                  static_cast<int16_t>(y + cellH / 2 + 12));
          }
        }
      }
    }
  }

  uint16_t btnFg = colors.amber;
  bool hasPrev = cameraGalleryPage > 0;
  bool hasNext = (cameraGalleryPage + 1) * kCameraThumbsPerPage < cameraPhotoCount;
  uint16_t prevFg = hasPrev ? btnFg : colors.amberDim;
  uint16_t nextFg = hasNext ? btnFg : colors.amberDim;
  drawTerminalButton(cameraGalleryPrevButton, "PREV", prevFg);
  drawTerminalButton(cameraGalleryNextButton, "NEXT", nextFg);
}

void drawCameraViewerDeleteButton() {
  bool enabled =
      sdReady && cameraViewerIndex >= 0 && cameraViewerIndex < static_cast<int>(cameraPhotoCount);
  uint16_t btnFg = enabled ? colors.red : colors.amberDim;
  drawTerminalButton(cameraViewerDeleteButton, "DELETE", btnFg);
}

void drawCameraViewer() {
  M5.Display.fillRect(cameraViewerRect.x, cameraViewerRect.y, cameraViewerRect.w,
                      cameraViewerRect.h, colors.black);
  M5.Display.drawRect(cameraViewerRect.x, cameraViewerRect.y, cameraViewerRect.w,
                      cameraViewerRect.h, colors.amberDim);
  if (!sdReady || cameraViewerIndex < 0 || cameraViewerIndex >= static_cast<int>(cameraPhotoCount)) {
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString("NO PHOTO", screenW / 2,
                          static_cast<int16_t>(cameraViewerRect.y + 20));
    drawCameraViewerDeleteButton();
    return;
  }
  const String &path = cameraPhotoFiles[cameraViewerIndex];
  String name = path.substring(path.lastIndexOf('/') + 1);
  bool drew = drawJpgFromSd(path.c_str(), cameraViewerRect.x, cameraViewerRect.y,
                            cameraViewerRect.w, cameraViewerRect.h);
  if (!drew) {
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(colors.red, colors.black);
    M5.Display.setTextSize(kButtonTextSize);
    M5.Display.drawString("IMAGE LOAD FAILED",
                          static_cast<int16_t>(cameraViewerRect.x + cameraViewerRect.w / 2),
                          static_cast<int16_t>(cameraViewerRect.y + cameraViewerRect.h / 2 - 18));
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString(name, static_cast<int16_t>(cameraViewerRect.x + cameraViewerRect.w / 2),
                          static_cast<int16_t>(cameraViewerRect.y + cameraViewerRect.h / 2 + 12));
  }
  drawCameraViewerDeleteButton();
}

void drawCameraUiOverlay() {
  drawAppTopBar("CAMERA");
  M5.Display.drawRect(cameraPreviewRect.x, cameraPreviewRect.y, cameraPreviewRect.w,
                      cameraPreviewRect.h, cameraError ? colors.red : colors.amberDim);
  drawCameraButtons();
  if (cameraError) {
    int16_t msgY = static_cast<int16_t>(cameraShutterButton.y - 24);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(colors.red, colors.black);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString("CAMERA ERROR", screenW / 2,
                          msgY);
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.drawString("TAP TO RETRY", screenW / 2,
                          static_cast<int16_t>(msgY + 16));
  }
  if (cameraCaptureNoticeMs > 0 && millis() - cameraCaptureNoticeMs <= kCameraCaptureNoticeMs) {
    int16_t msgY = static_cast<int16_t>(max<int16_t>(appTopBarRect.h + 24,
                                                     cameraPreviewRect.y + 24));
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(colors.amber, colors.black);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString("CLICK", screenW / 2, msgY);
  }
  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
}

void drawCameraApp() {
  bool fullRedraw = cameraNeedsFullRedraw;
  if (fullRedraw || cameraPreviewDirty) {
    if (cameraError) {
      M5.Display.fillScreen(colors.black);
    } else {
      if (fullRedraw) {
        cameraPreviewClearNeeded = true;
      }
      bool previewDrew = drawCameraPreviewFrame();
      if (previewDrew) {
        cameraPreviewDirty = false;
      }
    }
    if (cameraError) {
      cameraPreviewDirty = false;
    }
  }
  if (fullRedraw || cameraUiDirty) {
    drawCameraUiOverlay();
  }
  cameraNeedsFullRedraw = false;
  cameraUiDirty = false;
  waypointsDirty = false;
}

void drawGalleryApp() {
  if (cameraView == CAMERA_VIEW_PREVIEW) {
    cameraView = CAMERA_VIEW_GALLERY;
    cameraGalleryDirty = true;
    cameraNeedsFullRedraw = true;
  }
  bool fullRedraw = cameraNeedsFullRedraw;
  bool showGallery = (cameraView == CAMERA_VIEW_GALLERY);
  bool contentDirty = fullRedraw || (showGallery ? cameraGalleryDirty : cameraViewerDirty);
  drawAppTopBar(showGallery ? "GALLERY" : "GALLERY VIEWER");
  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
  if (contentDirty) {
    M5.Display.fillRect(0, appTopBarRect.h, screenW,
                        static_cast<int16_t>(screenH - navH - appTopBarRect.h), colors.black);
  }
  if (showGallery) {
    if (fullRedraw || cameraGalleryDirty) {
      drawCameraGallery();
    }
    cameraGalleryDirty = false;
    cameraViewerDirty = false;
  } else {
    if (fullRedraw || cameraViewerDirty) {
      drawCameraViewer();
    }
    cameraViewerDirty = false;
    cameraGalleryDirty = false;
  }
  cameraNeedsFullRedraw = false;
  cameraUiDirty = false;
  waypointsDirty = false;
}

void handleCameraTouch(int16_t x, int16_t y) {
  if (cameraView == CAMERA_VIEW_PREVIEW) {
    if (cameraError) {
      cameraError = false;
      cameraErrorDetail = nullptr;
      cameraNextRetryMs = 0;
      cameraPreviewDirty = true;
      cameraUiDirty = true;
      cameraNeedsFullRedraw = true;
      startCameraPreview();
      waypointsDirty = true;
      return;
    }
    if (inRect(cameraShutterButton, x, y)) {
      if (captureCameraPhoto()) {
        cameraUiDirty = true;
        waypointsDirty = true;
      }
      return;
    }
  }
}

void handleGalleryTouch(int16_t x, int16_t y) {
  if (cameraView == CAMERA_VIEW_VIEWER) {
    if (inRect(cameraViewerDeleteButton, x, y)) {
      if (cameraViewerIndex >= 0 &&
          deleteCameraPhotoAtIndex(static_cast<size_t>(cameraViewerIndex))) {
        cameraViewerIndex = -1;
        cameraView = CAMERA_VIEW_GALLERY;
        cameraGalleryDirty = true;
        cameraViewerDirty = true;
        cameraNeedsFullRedraw = true;
        cameraUiDirty = true;
        waypointsDirty = true;
      }
    }
    return;
  }
  if (cameraView != CAMERA_VIEW_GALLERY) {
    cameraView = CAMERA_VIEW_GALLERY;
    cameraGalleryDirty = true;
    cameraNeedsFullRedraw = true;
    waypointsDirty = true;
    return;
  }
  if (inRect(cameraGalleryPrevButton, x, y)) {
    if (cameraGalleryPage > 0) {
      cameraGalleryPage--;
      cameraGalleryDirty = true;
      waypointsDirty = true;
    }
    return;
  }
  if (inRect(cameraGalleryNextButton, x, y)) {
    if ((cameraGalleryPage + 1) * kCameraThumbsPerPage < cameraPhotoCount) {
      cameraGalleryPage++;
      cameraGalleryDirty = true;
      waypointsDirty = true;
    }
    return;
  }
  if (inRect(cameraGalleryGridRect, x, y) && cameraPhotoCount > 0) {
    int16_t cellW =
        static_cast<int16_t>(cameraGalleryGridRect.w / kCameraGalleryCols);
    int16_t cellH =
        static_cast<int16_t>(cameraGalleryGridRect.h / kCameraGalleryRows);
    int col = (x - cameraGalleryGridRect.x) / max<int16_t>(1, cellW);
    int row = (y - cameraGalleryGridRect.y) / max<int16_t>(1, cellH);
    if (col >= 0 && col < kCameraGalleryCols && row >= 0 && row < kCameraGalleryRows) {
      size_t idx = cameraGalleryPage * kCameraThumbsPerPage +
                   static_cast<size_t>(row * kCameraGalleryCols + col);
      if (idx < cameraPhotoCount) {
        cameraViewerIndex = static_cast<int>(idx);
        cameraView = CAMERA_VIEW_VIEWER;
        cameraViewerDirty = true;
        cameraNeedsFullRedraw = true;
        waypointsDirty = true;
      }
    }
  }
}

void geoToWorldPixels(double lat, double lon, uint8_t zoom, double &x, double &y) {
  double sinLat = sin(lat * M_PI / 180.0);
  double world = 256.0 * (1 << zoom);
  x = (lon + 180.0) / 360.0 * world;
  y = (0.5 - log((1 + sinLat) / (1 - sinLat)) / (4 * M_PI)) * world;
}

void debugPrint(const char *fmt, ...) {
#if ENABLE_SERIAL_LOG
  char buf[256];
  va_list ap;
  va_start(ap, fmt);
  vsnprintf(buf, sizeof(buf), fmt, ap);
  va_end(ap);
#if HAS_USB_JTAG_CMDS
  if (usbJtagCommandDriverInstalled) {
    usb_serial_jtag_write_bytes(buf, strlen(buf), 0);
    usb_serial_jtag_write_bytes("\n", 1, 0);
  } else {
    esp_rom_printf("%s\n", buf);
  }
#else
  Serial.println(buf);
  Serial.flush();
#endif
  pushBootSerialLine(buf);
  captureCrashBreadcrumb(buf);
#else
  (void)fmt;
#endif
}

const char *resetReasonName(esp_reset_reason_t reason) {
  switch (reason) {
    case ESP_RST_POWERON: return "power-on";
    case ESP_RST_EXT: return "external";
    case ESP_RST_SW: return "software";
    case ESP_RST_PANIC: return "panic";
    case ESP_RST_INT_WDT: return "interrupt-watchdog";
    case ESP_RST_TASK_WDT: return "task-watchdog";
    case ESP_RST_WDT: return "watchdog";
    case ESP_RST_DEEPSLEEP: return "deep-sleep";
    case ESP_RST_BROWNOUT: return "brownout";
    case ESP_RST_SDIO: return "sdio";
    default: return "unknown";
  }
}

static bool isCrashResetReason(esp_reset_reason_t reason) {
  return reason == ESP_RST_PANIC || reason == ESP_RST_INT_WDT ||
         reason == ESP_RST_TASK_WDT || reason == ESP_RST_WDT ||
         reason == ESP_RST_BROWNOUT;
}

void prepareCrashCapture() {
  bootResetReason = esp_reset_reason();
  bool retainedValid = crashRetained.magic == kCrashRetainedMagic &&
                       crashRetained.version == kCrashRetainedVersion;
  currentBootSequence = retainedValid ? crashRetained.bootSequence + 1 : 1;
  previousCrashPending = retainedValid && crashRetained.armed &&
                         isCrashResetReason(bootResetReason);
  wifiCrashSafeMode = previousCrashPending && crashRetained.freeDma > 0 &&
                      crashRetained.freeDma < 4096;
  if (esp_core_dump_image_check() == ESP_OK) previousCrashPending = true;
  crashCaptureEnabled = false;
}

void beginCrashCapture() {
  portENTER_CRITICAL(&crashRetainedMux);
  memset(&crashRetained, 0, sizeof(crashRetained));
  crashRetained.magic = kCrashRetainedMagic;
  crashRetained.version = kCrashRetainedVersion;
  crashRetained.armed = 1;
  crashRetained.bootSequence = currentBootSequence;
  portEXIT_CRITICAL(&crashRetainedMux);
  crashCaptureEnabled = true;
  captureCrashBreadcrumb("CRASHLOG: capture armed");
}

void captureCrashBreadcrumb(const char *line) {
  if (!crashCaptureEnabled || !line || !line[0]) return;
  portENTER_CRITICAL(&crashRetainedMux);
  size_t slot = crashRetained.breadcrumbHead % kCrashBreadcrumbCount;
  strlcpy(crashRetained.breadcrumbs[slot], line, kCrashBreadcrumbLength);
  crashRetained.breadcrumbHead =
      static_cast<uint16_t>((crashRetained.breadcrumbHead + 1) % kCrashBreadcrumbCount);
  if (crashRetained.breadcrumbCount < kCrashBreadcrumbCount) {
    ++crashRetained.breadcrumbCount;
  }
  bool problem = strstr(line, "FAIL") || strstr(line, "fail") ||
                 strstr(line, "ERROR") || strstr(line, "Error") ||
                 strstr(line, "watchdog") || strstr(line, "assert");
  if (problem) {
    strlcpy(pendingProblemLine, line, sizeof(pendingProblemLine));
    problemLogPending = true;
  }
  portEXIT_CRITICAL(&crashRetainedMux);
}

void updateCrashSnapshot(uint32_t now) {
  if (!crashCaptureEnabled || now - lastCrashSnapshotMs < 1000) return;
  lastCrashSnapshotMs = now;
  uint32_t freeInternal = heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
  uint32_t minimumInternal =
      heap_caps_get_minimum_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
  uint32_t largestInternal =
      heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
  uint32_t freeDma = heap_caps_get_free_size(MALLOC_CAP_DMA);
  portENTER_CRITICAL(&crashRetainedMux);
  crashRetained.uptimeMs = now;
  crashRetained.freeInternal = freeInternal;
  crashRetained.minimumInternal = minimumInternal;
  crashRetained.largestInternal = largestInternal;
  crashRetained.freeDma = freeDma;
  crashRetained.screenId = static_cast<int16_t>(screen);
  crashRetained.appId = static_cast<int16_t>(appSelected);
  portEXIT_CRITICAL(&crashRetainedMux);
}

static bool exportCoreDump(FsFile &report, uint32_t sequence) {
  size_t imageAddress = 0;
  size_t imageSize = 0;
  if (esp_core_dump_image_get(&imageAddress, &imageSize) != ESP_OK || imageSize == 0) {
    report.println("Native coredump: unavailable");
    if (esp_core_dump_image_check() != ESP_ERR_NOT_FOUND) {
      report.println("Native coredump: invalid image erased for next capture");
      esp_core_dump_image_erase();
    }
    return false;
  }
  char reason[192] = {};
  esp_core_dump_get_panic_reason(reason, sizeof(reason));
  esp_core_dump_summary_t summary = {};
  esp_err_t summaryResult = esp_core_dump_get_summary(&summary);
  report.printf("Native coredump: address=0x%08x size=%u\n",
                static_cast<unsigned>(imageAddress), static_cast<unsigned>(imageSize));
  report.printf("Panic reason: %s\n", reason[0] ? reason : "unavailable");
  if (summaryResult == ESP_OK) {
    report.printf("Fault task: %s\nFault PC: 0x%08x\nMCAUSE: 0x%08x\nMTVAL: 0x%08x\n",
                  summary.exc_task, static_cast<unsigned>(summary.exc_pc),
                  static_cast<unsigned>(summary.ex_info.mcause),
                  static_cast<unsigned>(summary.ex_info.mtval));
    report.printf("ELF SHA256: %s\n", summary.app_elf_sha256);
  }

  const esp_partition_t *partition = esp_partition_find_first(
      ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_COREDUMP, nullptr);
  if (!partition || imageAddress < partition->address ||
      imageAddress + imageSize > partition->address + partition->size) {
    report.println("Native coredump export: partition bounds invalid");
    return false;
  }
  char path[64];
  snprintf(path, sizeof(path), "%s/crash_%06lu.core", kCrashLogDirectory,
           static_cast<unsigned long>(sequence));
  FsFile output = SD.open(path, FILE_WRITE);
  if (!output) {
    report.println("Native coredump export: file open failed");
    return false;
  }
  uint8_t buffer[512];
  size_t offset = imageAddress - partition->address;
  size_t remaining = imageSize;
  bool ok = true;
  while (remaining > 0) {
    size_t count = min(remaining, sizeof(buffer));
    if (esp_partition_read(partition, offset, buffer, count) != ESP_OK ||
        output.write(buffer, count) != count) {
      ok = false;
      break;
    }
    offset += count;
    remaining -= count;
  }
  output.close();
  report.printf("Native coredump export: %s (%s)\n", path, ok ? "complete" : "failed");
  if (ok) esp_core_dump_image_erase();
  return ok;
}

bool persistCrashReport(bool manual, const char *note) {
  if (!sdReady || usbMscActive || !lockSd(1500)) return false;
  if (!SD.exists(kCrashLogDirectory)) SD.mkdir(kCrashLogDirectory);
  uint32_t sequence = manual ? currentBootSequence : crashRetained.bootSequence;
  char path[64];
  snprintf(path, sizeof(path), "%s/%s_%06lu.txt", kCrashLogDirectory,
           manual ? "diagnostic" : "crash", static_cast<unsigned long>(sequence));
  FsFile report = SD.open(path, FILE_WRITE);
  if (!report) {
    unlockSd();
    return false;
  }
  report.println("Tab5 Responder Nav crash report");
  report.printf("Report type: %s\n", manual ? "manual diagnostic" : "automatic post-crash");
  report.printf("Boot reset reason: %s (%d)\n", resetReasonName(bootResetReason),
                static_cast<int>(bootResetReason));
  report.printf("Captured boot sequence: %lu\n", static_cast<unsigned long>(sequence));
  report.printf("Last uptime: %lu ms\n", static_cast<unsigned long>(crashRetained.uptimeMs));
  report.printf("Screen/app: %d/%d\n", crashRetained.screenId, crashRetained.appId);
  report.printf("Memory internal/min/largest/DMA: %lu/%lu/%lu/%lu bytes\n",
                static_cast<unsigned long>(crashRetained.freeInternal),
                static_cast<unsigned long>(crashRetained.minimumInternal),
                static_cast<unsigned long>(crashRetained.largestInternal),
                static_cast<unsigned long>(crashRetained.freeDma));
  if (note && note[0]) report.printf("Note: %s\n", note);
  report.println("\nRecent firmware breadcrumbs (oldest first):");
  size_t count = min<size_t>(crashRetained.breadcrumbCount, kCrashBreadcrumbCount);
  size_t first = (crashRetained.breadcrumbHead + kCrashBreadcrumbCount - count) %
                 kCrashBreadcrumbCount;
  for (size_t i = 0; i < count; ++i) {
    report.printf("%02u: %s\n", static_cast<unsigned>(i),
                  crashRetained.breadcrumbs[(first + i) % kCrashBreadcrumbCount]);
  }
  report.println();
  exportCoreDump(report, sequence);
  report.close();
  unlockSd();
  return true;
}

void flushProblemLog(uint32_t now) {
  if (!problemLogPending || now - lastProblemFlushMs < 1000 || !sdReady ||
      usbMscActive || !lockSd(50)) return;
  lastProblemFlushMs = now;
  char line[kCrashBreadcrumbLength];
  portENTER_CRITICAL(&crashRetainedMux);
  strlcpy(line, pendingProblemLine, sizeof(line));
  problemLogPending = false;
  portEXIT_CRITICAL(&crashRetainedMux);
  if (!SD.exists(kCrashLogDirectory)) SD.mkdir(kCrashLogDirectory);
  if (SD.exists(kProblemLogPath)) {
    FsFile existing = SD.open(kProblemLogPath, FILE_READ);
    uint32_t size = existing ? existing.size() : 0;
    if (existing) existing.close();
    if (size >= kProblemLogMaxBytes) {
      SD.remove("/crash_logs/problems.old.log");
      SD.rename(kProblemLogPath, "/crash_logs/problems.old.log");
    }
  }
  FsFile output = SD.open(kProblemLogPath, FILE_APPEND);
  if (output) {
    output.printf("%lu ms | %s\n", static_cast<unsigned long>(now), line);
    output.close();
  }
  unlockSd();
}

static bool updateHostedFromEmbeddedFirmware() {
#if ENABLE_WIFI
  if (!hostedIsInitialized()) {
    debugPrint("HOSTEDOTA: hosted transport is not initialized");
    return false;
  }
  constexpr size_t total = 1209600;
  const esp_partition_t *staging = esp_partition_find_first(
      ESP_PARTITION_TYPE_DATA, ESP_PARTITION_SUBTYPE_DATA_SPIFFS, nullptr);
  uint8_t imageHeader = 0;
  if (!staging || staging->size < total ||
      esp_partition_read(staging, 0, &imageHeader, 1) != ESP_OK || imageHeader != 0xE9) {
    debugPrint("HOSTEDOTA: staged image unavailable partition=%u header=0x%02x",
               staging ? static_cast<unsigned>(staging->size) : 0U, imageHeader);
    return false;
  }
  debugPrint("HOSTEDOTA: offline update begin bytes=%u", static_cast<unsigned>(total));
  WiFi.setAutoReconnect(false);
  WiFi.disconnect(false, false);
  delay(250);
  if (!hostedBeginUpdate()) {
    debugPrint("HOSTEDOTA: begin failed");
    return false;
  }
  constexpr size_t kChunk = 2048;
  uint8_t buffer[kChunk];
  size_t offset = 0;
  size_t nextProgress = 128 * 1024;
  while (offset < total) {
    size_t count = min(kChunk, total - offset);
    if (esp_partition_read(staging, offset, buffer, count) != ESP_OK) {
      debugPrint("HOSTEDOTA: staged read failed offset=%u", static_cast<unsigned>(offset));
      return false;
    }
    if (!hostedWriteUpdate(buffer, static_cast<uint32_t>(count))) {
      debugPrint("HOSTEDOTA: write failed offset=%u", static_cast<unsigned>(offset));
      return false;
    }
    offset += count;
    if (offset >= nextProgress || offset == total) {
      debugPrint("HOSTEDOTA: progress %u/%u", static_cast<unsigned>(offset),
                 static_cast<unsigned>(total));
      nextProgress += 128 * 1024;
    }
    delay(1);
  }
  if (!hostedEndUpdate()) {
    debugPrint("HOSTEDOTA: finalize failed");
    return false;
  }
  if (!hostedActivateUpdate()) {
    debugPrint("HOSTEDOTA: activate failed");
    return false;
  }
  debugPrint("HOSTEDOTA: offline update complete");
  return true;
#else
  return false;
#endif
}

static bool tab5KeyboardReadReg(uint8_t reg, uint8_t *out, size_t len) {
  if (!out || len == 0) {
    return false;
  }
  tab5KeyboardWire.beginTransmission(kTab5KeyboardAddr);
  tab5KeyboardWire.write(reg);
  if (tab5KeyboardWire.endTransmission(false) != 0) {
    return false;
  }
  int got = tab5KeyboardWire.requestFrom(static_cast<int>(kTab5KeyboardAddr),
                                         static_cast<int>(len));
  if (got != static_cast<int>(len)) {
    while (tab5KeyboardWire.available() > 0) {
      tab5KeyboardWire.read();
    }
    return false;
  }
  for (size_t i = 0; i < len; ++i) {
    out[i] = static_cast<uint8_t>(tab5KeyboardWire.read());
  }
  return true;
}

static bool tab5KeyboardWriteReg(uint8_t reg, uint8_t value) {
  tab5KeyboardWire.beginTransmission(kTab5KeyboardAddr);
  tab5KeyboardWire.write(reg);
  tab5KeyboardWire.write(value);
  return tab5KeyboardWire.endTransmission(true) == 0;
}

static bool tab5KeyboardWriteBlock(uint8_t reg, const uint8_t *data, size_t len) {
  if (!data || len == 0) {
    return false;
  }
  tab5KeyboardWire.beginTransmission(kTab5KeyboardAddr);
  tab5KeyboardWire.write(reg);
  for (size_t i = 0; i < len; ++i) {
    tab5KeyboardWire.write(data[i]);
  }
  return tab5KeyboardWire.endTransmission(true) == 0;
}

static bool tab5KeyboardSetLedState(bool busyLedOn) {
  if (!tab5KeyboardBusStarted) {
    return false;
  }
  // The keyboard registers are B/G/R with an unused gap at 0x63.
  const uint8_t leftAmber[] = {0x00, 0x78, 0xFF};
  const uint8_t rightRed[] = {
      0x00, 0x00, static_cast<uint8_t>(busyLedOn ? 0xFF : 0x00)};
  bool ok = tab5KeyboardWriteBlock(kTab5KeyboardRegRgb1Base, leftAmber,
                                    sizeof(leftAmber));
  return tab5KeyboardWriteBlock(kTab5KeyboardRegRgb2Base, rightRed,
                                 sizeof(rightRed)) && ok;
}

void updateTab5KeyboardBusyLed(bool busy, uint32_t now) {
  if (!tab5KeyboardReady) {
    return;
  }
  bool flashOn = busy && ((now / 450U) % 2U == 0U);
  if (busy == tab5KeyboardBusyLedLastBusy && flashOn == tab5KeyboardBusyLedOn &&
      now - tab5KeyboardBusyLedLastMs < 4000) {
    return;
  }
  tab5KeyboardBusyLedLastBusy = busy;
  tab5KeyboardBusyLedOn = flashOn;
  tab5KeyboardBusyLedLastMs = now;
  if (!tab5KeyboardSetLedState(flashOn)) {
    tab5KeyboardReady = false;
    debugPrint("KBD: led update lost");
  }
}

static void handleTab5KeyboardText(const char *text, uint8_t modifier) {
  if (!text || text[0] == '\0') {
    return;
  }
  debugPrint("KBD: text mod=0x%02X data=%s", modifier, text);
  if (screen == SCREEN_API_KEYS && publicMapApiKeyEditing) {
    bool submit = false;
    for (const char *p = text; *p; ++p) {
      char c = *p;
      if (c == '\b' || c == 0x7f) {
        if (publicMapApiKeyDraft.length()) publicMapApiKeyDraft.remove(publicMapApiKeyDraft.length() - 1);
      } else if (c == '\r' || c == '\n') {
        submit = true;
      } else if (c >= 33 && c < 127 && publicMapApiKeyDraft.length() < 192) {
        publicMapApiKeyDraft += c;
      }
    }
    publicApiKeysStatus = "EDITING - INPUT HIDDEN";
    publicApiKeysDirty = true;
    if (submit) savePublicMapApiKey();
    return;
  }
  if (screen == SCREEN_MAIN && waypointNameEntryActive && !waypointNameEntrySaving &&
      !waypointNameEntrySaved && !waypointNameEntryFailed) {
    bool submit = false;
    for (const char *p = text; *p; ++p) {
      char c = *p;
      if (c == '\b' || c == 0x7f) {
        if (waypointNameInput.length() > 0) waypointNameInput.remove(waypointNameInput.length() - 1);
      } else if (c == '\r' || c == '\n') {
        submit = true;
      } else if (c >= 32 && c < 127 && c != ',' && waypointNameInput.length() < 15) {
        waypointNameInput += c;
      }
    }
    if (submit) {
      if (waypointNameInput.length() > 0) {
        commitWaypointNameEntry();
      } else if (waypointEmptyEnterArmed && millis() - waypointEmptyEnterMs <= 1500UL) {
        commitWaypointNameEntry();
      } else {
        waypointEmptyEnterArmed = true;
        waypointEmptyEnterMs = millis();
        drawWaypointNameModal();
      }
    } else {
      waypointEmptyEnterArmed = false;
      drawWaypointNameModal();
    }
    return;
  }
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex) {
    if (loraView != LORA_VIEW_MESSAGES && loraView != LORA_VIEW_IDENTITY &&
        loraView != LORA_VIEW_RADIO_EDIT && loraView != LORA_VIEW_CONTACTS &&
        loraView != LORA_VIEW_DISCOVER) {
      return;
    }
    bool identityTextField = loraView == LORA_VIEW_IDENTITY && meshIdentityField < 3;
    if (loraView == LORA_VIEW_IDENTITY && !identityTextField) {
      return;
    }
    bool networkTextField = loraView == LORA_VIEW_RADIO_EDIT;
    bool submit = false;
    for (const char *p = text; *p; ++p) {
      char c = *p;
      if (c == '\b' || c == 0x7f) {
        if (loraInput.length() > 0) {
          loraInput.remove(loraInput.length() - 1);
        }
      } else if (c == '\r' || c == '\n') {
        submit = true;
      } else if (c >= 32 && c < 127 && loraInput.length() < 96) {
        if ((loraView == LORA_VIEW_IDENTITY || loraView == LORA_VIEW_RADIO_EDIT ||
             loraView == LORA_VIEW_CONTACTS || loraView == LORA_VIEW_DISCOVER) &&
            c == '_' && text[1] == '\0' && loraInput.length() == 0) {
          continue;
        }
        loraInput += c;
      }
    }
    waypointsDirty = true;
    if (submit) {
      if (loraView == LORA_VIEW_MESSAGES) {
        sendLoraTextMessage();
      } else if (loraView == LORA_VIEW_IDENTITY) {
        applyMeshIdentitySelection();
      } else if (networkTextField) {
        applyMeshNetworkEditField();
      } else if (loraView == LORA_VIEW_CONTACTS) {
        renameSelectedMeshContact();
      } else if (loraView == LORA_VIEW_DISCOVER) {
        addManualMeshContact();
      }
    }
    return;
  }
  if (screen != SCREEN_WIFI_PASS) {
    return;
  }
  bool submit = false;
  for (const char *p = text; *p; ++p) {
    char c = *p;
    if (c == '\b' || c == 0x7f) {
      if (wifiEnteringSsid && selectedSsid.length() > 0) {
        selectedSsid.remove(selectedSsid.length() - 1);
      } else if (!wifiEnteringSsid && passwordInput.length() > 0) {
        passwordInput.remove(passwordInput.length() - 1);
      }
    } else if (c == '\r' || c == '\n') {
      submit = true;
    } else if (c >= 32 && c < 127 && wifiEnteringSsid && selectedSsid.length() < 32) {
      selectedSsid += c;
    } else if (c >= 32 && c < 127 && !wifiEnteringSsid) {
      passwordInput += c;
    }
  }
  wifiPassDirty = true;
  if (submit) {
    if (wifiEnteringSsid) {
      selectedSsid.trim();
      if (selectedSsid.length() > 0) {
        wifiEnteringSsid = false;
        passwordInput = "";
        wifiPassNeedsFullRedraw = true;
      }
    } else {
      saveWifiNetworkAndRebootClean(selectedSsid, passwordInput);
    }
  }
}

static char tab5KeyboardHidToAscii(uint8_t keycode, bool shift) {
  if (keycode >= 0x04 && keycode <= 0x1D) {
    bool upper = shift ^ tab5KeyboardCapsLock;
    return static_cast<char>((upper ? 'A' : 'a') + keycode - 0x04);
  }
  if (keycode >= 0x1E && keycode <= 0x27) {
    static const char normal[] = "1234567890";
    static const char shifted[] = "!@#$%^&*()";
    size_t index = keycode - 0x1E;
    return shift ? shifted[index] : normal[index];
  }
  switch (keycode) {
    case 0x2C: return ' ';
    case 0x2D: return shift ? '_' : '-';
    case 0x2E: return shift ? '+' : '=';
    case 0x2F: return shift ? '{' : '[';
    case 0x30: return shift ? '}' : ']';
    case 0x31: return shift ? '|' : '\\';
    case 0x33: return shift ? ':' : ';';
    case 0x34: return shift ? '"' : '\'';
    case 0x35: return shift ? '~' : '`';
    case 0x36: return shift ? '<' : ',';
    case 0x37: return shift ? '>' : '.';
    case 0x38: return shift ? '?' : '/';
    default: return 0;
  }
}

static void notesInsertText(const String &text) {
  if (text.length() == 0 || notesText.length() + text.length() > 8192) return;
  notesCursor = min(notesCursor, notesText.length());
  notesText = notesText.substring(0, notesCursor) + text + notesText.substring(notesCursor);
  notesCursor += text.length();
  notesDirty = true;
}

static void moveNotesCursorVertical(int direction) {
  notesCursor = min(notesCursor, notesText.length());
  size_t lineStart = notesCursor;
  while (lineStart > 0 && notesText[lineStart - 1] != '\n') --lineStart;
  size_t column = notesCursor - lineStart;
  if (direction < 0) {
    if (lineStart == 0) return;
    size_t previousEnd = lineStart - 1;
    size_t previousStart = previousEnd;
    while (previousStart > 0 && notesText[previousStart - 1] != '\n') --previousStart;
    notesCursor = min(previousStart + column, previousEnd);
  } else {
    size_t lineEnd = notesCursor;
    while (lineEnd < notesText.length() && notesText[lineEnd] != '\n') ++lineEnd;
    if (lineEnd >= notesText.length()) return;
    size_t nextStart = lineEnd + 1;
    size_t nextEnd = nextStart;
    while (nextEnd < notesText.length() && notesText[nextEnd] != '\n') ++nextEnd;
    notesCursor = min(nextStart + column, nextEnd);
  }
}

static const char *emulatorControlSystemName(EmulatorControlSystem system) {
  static const char *names[] = {"GB REMOVED", "GBC REMOVED", "GAME BOY ADVANCE",
                                "NES", "SNES"};
  return names[min<int>(system, CONTROL_SYSTEM_COUNT - 1)];
}

static const char *emulatorControlActionName(int action) {
  static const char *names[] = {"UP", "DOWN", "LEFT", "RIGHT", "A", "B", "START",
                                "SELECT", "LEFT SHOULDER", "RIGHT SHOULDER"};
  return names[constrain(action, 0, CONTROL_ACTION_COUNT - 1)];
}

static String emulatorKeyName(const EmulatorKeyBinding &binding) {
  if (binding.keycode == 0 && (binding.modifier & 0x22)) return "SHIFT";
  String prefix;
  if (binding.modifier & 0x11) prefix += "CTRL+";
  if (binding.modifier & 0x44) prefix += "ALT+";
  if (binding.modifier & 0x88) prefix += "GUI+";
  if (binding.modifier & 0x22) prefix += "SHIFT+";
  uint8_t key = binding.keycode;
  if (key >= 0x04 && key <= 0x1D) return prefix + char('A' + key - 0x04);
  if (key >= 0x1E && key <= 0x26) return prefix + char('1' + key - 0x1E);
  if (key == 0x27) return prefix + "0";
  switch (key) {
    case 0x28: return prefix + "ENTER";
    case 0x29: return prefix + "ESC";
    case 0x2A: return prefix + "BACKSPACE";
    case 0x2B: return prefix + "TAB";
    case 0x2C: return prefix + "SPACE";
    case 0x2D: return prefix + "-";
    case 0x2E: return prefix + "=";
    case 0x2F: return prefix + "[";
    case 0x30: return prefix + "]";
    case 0x31: return prefix + "\\";
    case 0x33: return prefix + ";";
    case 0x34: return prefix + "'";
    case 0x35: return prefix + "`";
    case 0x36: return prefix + ",";
    case 0x37: return prefix + ".";
    case 0x38: return prefix + "/";
    case 0x4F: return prefix + "RIGHT ARROW";
    case 0x50: return prefix + "LEFT ARROW";
    case 0x51: return prefix + "DOWN ARROW";
    case 0x52: return prefix + "UP ARROW";
    default: break;
  }
  char value[12];
  snprintf(value, sizeof(value), "KEY %02X", key);
  return prefix + value;
}

void resetEmulatorControlProfile(EmulatorControlSystem system) {
  EmulatorControlProfile &profile = emulatorControlProfiles[system];
  memset(&profile, 0, sizeof(profile));
  profile.magic = kEmulatorControlMagic;
  profile.bindings[CONTROL_UP] = {0, 0x08};       // E
  profile.bindings[CONTROL_DOWN] = {0, 0x16};     // S
  profile.bindings[CONTROL_LEFT] = {0, 0x04};     // A
  profile.bindings[CONTROL_RIGHT] = {0, 0x07};    // D
  profile.bindings[CONTROL_A] = {0, 0x4F};        // Right arrow
  profile.bindings[CONTROL_B] = {0, 0x2C};        // Space
  profile.bindings[CONTROL_START] = {0, 0x28};    // Enter
  profile.bindings[CONTROL_SELECT] = {0x22, 0};   // Either shift
  profile.bindings[CONTROL_L] = {0, 0x35};        // Backtick
  profile.bindings[CONTROL_R] = {0, 0x31};        // Backslash
}

void saveEmulatorControlProfile(EmulatorControlSystem system) {
  char profileKey[12];
  char acceptedKey[12];
  snprintf(profileKey, sizeof(profileKey), "ctrlp%u", static_cast<unsigned>(system));
  snprintf(acceptedKey, sizeof(acceptedKey), "ctrla%u", static_cast<unsigned>(system));
  prefs.begin("responder", false);
  prefs.putBytes(profileKey, &emulatorControlProfiles[system],
                 sizeof(EmulatorControlProfile));
  prefs.putBool(acceptedKey, emulatorControlAccepted[system]);
  prefs.end();
}

void loadEmulatorControlProfiles() {
  prefs.begin("responder", true);
  for (uint8_t i = 0; i < CONTROL_SYSTEM_COUNT; ++i) {
    char profileKey[12];
    char acceptedKey[12];
    snprintf(profileKey, sizeof(profileKey), "ctrlp%u", i);
    snprintf(acceptedKey, sizeof(acceptedKey), "ctrla%u", i);
    size_t read = prefs.isKey(profileKey)
                      ? prefs.getBytes(profileKey, &emulatorControlProfiles[i],
                                       sizeof(EmulatorControlProfile))
                      : 0;
    if (read != sizeof(EmulatorControlProfile) ||
        emulatorControlProfiles[i].magic != kEmulatorControlMagic) {
      resetEmulatorControlProfile(static_cast<EmulatorControlSystem>(i));
    }
    emulatorControlAccepted[i] = prefs.getBool(acceptedKey, false);
  }
  prefs.end();
}

static bool emulatorBindingMatches(const EmulatorKeyBinding &binding, uint8_t modifier,
                                   uint8_t keycode) {
  if (binding.keycode == 0)
    return binding.modifier != 0 && keycode == 0 && (modifier & binding.modifier) != 0;
  if (binding.keycode != keycode) return false;
  return binding.modifier == 0 || (modifier & binding.modifier) == binding.modifier;
}

static uint16_t emulatorMappedButtons(EmulatorControlSystem system, uint8_t modifier,
                                      uint8_t keycode) {
  uint16_t result = 0;
  const EmulatorControlProfile &profile = emulatorControlProfiles[system];
  for (int action = 0; action < CONTROL_ACTION_COUNT; ++action) {
    if (emulatorBindingMatches(profile.bindings[action], modifier, keycode))
      result |= static_cast<uint16_t>(1U << action);
  }
  return result;
}

static void applyPendingEmulatorBinding(bool replaceDuplicate) {
  EmulatorControlProfile &profile = emulatorControlProfiles[emulatorControlSystem];
  if (replaceDuplicate && emulatorControlDuplicateAction >= 0)
    profile.bindings[emulatorControlDuplicateAction] = {0, 0};
  profile.bindings[emulatorControlSelectedAction] = emulatorPendingBinding;
  saveEmulatorControlProfile(emulatorControlSystem);
  emulatorControlDuplicateAction = -1;
  gamesView = GAMES_VIEW_EDIT_CONTROLS;
  waypointsDirty = true;
}

static void handleTab5KeyboardHid(uint8_t modifier, uint8_t keycode) {
  if (screen == SCREEN_API_KEYS) {
    if (keycode == 0) return;
    if (keycode == 0x29) {
      publicMapApiKeyEditing = false;
      screen = SCREEN_DOWNLOAD;
      downloadMenuDirty = true;
      downloadMenuNeedsFullRedraw = true;
      return;
    }
    if (!publicMapApiKeyEditing) return;
    if (keycode == 0x2A || keycode == 0x4C) {
      if (publicMapApiKeyDraft.length()) publicMapApiKeyDraft.remove(publicMapApiKeyDraft.length() - 1);
    } else if (keycode == 0x28) {
      savePublicMapApiKey();
      return;
    } else {
      bool shift = (modifier & 0x22) != 0;
      char c = tab5KeyboardHidToAscii(keycode, shift);
      if (c >= 33 && c < 127 && publicMapApiKeyDraft.length() < 192) publicMapApiKeyDraft += c;
    }
    publicApiKeysStatus = "EDITING - INPUT HIDDEN";
    publicApiKeysDirty = true;
    return;
  }
  if (screen == SCREEN_MAIN && waypointNameEntryActive) {
    if (keycode == 0) return;
    if (waypointNameEntrySaving || waypointNameEntrySaved || waypointNameEntryFailed) return;
    bool shift = (modifier & 0x22) != 0;
    if (keycode == 0x29) {
      waypointNameEntryActive = false;
      waypointEmptyEnterArmed = false;
      mapDirty = true;
      return;
    }
    if (keycode == 0x2A) {
      if (waypointNameInput.length() > 0) waypointNameInput.remove(waypointNameInput.length() - 1);
      waypointEmptyEnterArmed = false;
      drawWaypointNameModal();
      return;
    }
    if (keycode == 0x28) {
      if (waypointNameInput.length() > 0) {
        commitWaypointNameEntry();
      } else if (waypointEmptyEnterArmed && millis() - waypointEmptyEnterMs <= 1500UL) {
        commitWaypointNameEntry();
      } else {
        waypointEmptyEnterArmed = true;
        waypointEmptyEnterMs = millis();
        drawWaypointNameModal();
      }
      return;
    }
    char c = tab5KeyboardHidToAscii(keycode, shift);
    if (c >= 32 && c < 127 && c != ',' && waypointNameInput.length() < 15) {
      waypointNameInput += c;
      waypointEmptyEnterArmed = false;
      drawWaypointNameModal();
    }
    return;
  }
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppRfScanIndex) {
    if (keycode == 0) return;
    if (keycode == 0x29) {
      if (rfFrequencyEntryActive) {
        rfFrequencyEntryActive = false;
        rfFrequencyInput = "";
        waypointsDirty = true;
      } else {
        leaveCurrentAppToMenu();
      }
      return;
    }
    if (keycode == 0x2A) {
      if (rfFrequencyInput.length() > 0) rfFrequencyInput.remove(rfFrequencyInput.length() - 1);
      rfFrequencyEntryActive = rfFrequencyInput.length() > 0;
      waypointsDirty = true;
      return;
    }
    if (keycode == 0x28) {
      if (!applyRfFrequencyInput()) setAppToast("TYPE FREQUENCY IN MHz");
      waypointsDirty = true;
      return;
    }
    bool shift = (modifier & 0x22) != 0;
    char c = tab5KeyboardHidToAscii(keycode, shift);
    if (((c >= '0' && c <= '9') || c == '.') && rfFrequencyInput.length() < 9) {
      if (c != '.' || rfFrequencyInput.indexOf('.') < 0) rfFrequencyInput += c;
      rfFrequencyEntryActive = true;
      waypointsDirty = true;
    }
    return;
  }
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppGamesIndex) {
    handleTetrisKeyboard(keycode);
    return;
    if (gamesView == GAMES_VIEW_REMAP_PROMPT) {
      if (keycode == 0 && modifier == 0) return;
      emulatorPendingBinding = {modifier, keycode};
      emulatorControlDuplicateAction = -1;
      EmulatorControlProfile &profile = emulatorControlProfiles[emulatorControlSystem];
      for (int action = 0; action < CONTROL_ACTION_COUNT; ++action) {
        if (action == emulatorControlSelectedAction) continue;
        const EmulatorKeyBinding &existing = profile.bindings[action];
        if (existing.modifier == modifier && existing.keycode == keycode) {
          emulatorControlDuplicateAction = action;
          break;
        }
      }
      if (emulatorControlDuplicateAction >= 0)
        gamesView = GAMES_VIEW_DUPLICATE_CONFIRM;
      else
        applyPendingEmulatorBinding(false);
      waypointsDirty = true;
      return;
    }
    if (gamesView == GAMES_VIEW_TEST_CONTROLS) {
      emulatorTestModifier = modifier;
      emulatorTestKeycode = keycode;
      emulatorTestButtons = emulatorMappedButtons(emulatorControlSystem, modifier, keycode);
      if (keycode == 0x29) gamesView = GAMES_VIEW_CONTROLS;
      waypointsDirty = true;
      return;
    }
    if (gamesView == GAMES_VIEW_RUNNING) {
      if (keycode == 0x29) {
        gbaButtons = 0;
        gbaPaused = activeGameSystem == GAME_SYSTEM_GBA;
        gameBoyPaused = false;
        gamesView = GAMES_VIEW_OPTIONS;
        waypointsDirty = true;
        return;
      }
      if (keycode == 0 && modifier == 0) {
        gbaButtons &= static_cast<uint16_t>(~emulatorHeldGbaButtons);
        emulatorHeldModifier = 0;
        emulatorHeldKeycode = 0;
        emulatorHeldGbaButtons = 0;
        emulatorHeldGameBoyButtons = 0;
        gbaInputReleaseMs = 0;
        debugPrint("GAME: input up");
        return;
      }
      if (activeGameSystem != GAME_SYSTEM_GBA) return;
      EmulatorControlSystem system = CONTROL_SYSTEM_GBA;
      uint16_t mapped = emulatorMappedButtons(system, modifier, keycode);
      uint16_t button = 0;
      if (mapped & (1U << CONTROL_UP)) button |= 1U << 6;
      if (mapped & (1U << CONTROL_DOWN)) button |= 1U << 7;
      if (mapped & (1U << CONTROL_LEFT)) button |= 1U << 5;
      if (mapped & (1U << CONTROL_RIGHT)) button |= 1U << 4;
      if (mapped & (1U << CONTROL_A)) button |= 1U << 0;
      if (mapped & (1U << CONTROL_B)) button |= 1U << 1;
      if (mapped & (1U << CONTROL_START)) button |= 1U << 3;
      if (mapped & (1U << CONTROL_SELECT)) button |= 1U << 2;
      if (mapped & (1U << CONTROL_L)) button |= 1U << 9;
      if (mapped & (1U << CONTROL_R)) button |= 1U << 8;
      if (button) {
        gbaButtons &= static_cast<uint16_t>(~emulatorHeldGbaButtons);
        gbaButtons |= button;
        emulatorHeldModifier = modifier;
        emulatorHeldKeycode = keycode;
        emulatorHeldGbaButtons = button;
        emulatorHeldGameBoyButtons = 0;
        gbaInputReleaseMs = 0;
        debugPrint("GAME: input down gba=0x%03X", button);
      }
      return;
    }
    if (gamesView != GAMES_VIEW_ROMS && gamesView != GAMES_VIEW_ERROR) {
      if (keycode == 0x29) {
        if (gamesView == GAMES_VIEW_TRANSFER) {
          stopUsbGameStorage();
          gbaPaused = false;
          gamesView = gbaRunning ? GAMES_VIEW_OPTIONS : GAMES_VIEW_ROMS;
        } else if (gamesView == GAMES_VIEW_CONTROLS || gamesView == GAMES_VIEW_FIRST_RUN) {
          gamesView = gameControlsReturnView;
        } else if (gamesView == GAMES_VIEW_PROFILES || gamesView == GAMES_VIEW_EDIT_CONTROLS ||
                   gamesView == GAMES_VIEW_DUPLICATE_CONFIRM) {
          gamesView = GAMES_VIEW_CONTROLS;
        } else {
          gbaPaused = false;
          gameBoyPaused = false;
          gamesView = GAMES_VIEW_RUNNING;
        }
        waypointsDirty = true;
      }
      return;
    }
    if (keycode == 0x51 && gameRomSelected + 1 < static_cast<int>(gameRomCount)) {
      ++gameRomSelected;
    } else if (keycode == 0x52 && gameRomSelected > 0) {
      --gameRomSelected;
    } else if (keycode == 0x28) {
      startSelectedGameBoyRom();
    } else if (keycode == 0x29) {
      leaveCurrentAppToMenu();
      return;
    }
    M5.Display.setTextSize(kSmallTextSize);
    int16_t rowH = static_cast<int16_t>(M5.Display.fontHeight() + 10);
    int visible = max<int>(1, gameRomListRect.h / max<int16_t>(1, rowH));
    if (gameRomSelected < gameRomScroll) gameRomScroll = gameRomSelected;
    if (gameRomSelected >= gameRomScroll + visible) gameRomScroll = gameRomSelected - visible + 1;
    waypointsDirty = true;
    return;
  }
#if HAS_HOSTED_BLE
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppBleKeyboardIndex) {
    if (keycode == 0x29) {
      leaveCurrentAppToMenu();
      return;
    }
    if (keycode != 0) {
      sendBleKeyboardKey(modifier, keycode);
      waypointsDirty = true;
    }
    return;
  }
#endif
  if (handleMainMapKeyboard(keycode)) {
    return;
  }
  if (keycode == 0) {
    return;
  }
  bool shift = (modifier & 0x22) != 0;
  bool control = (modifier & 0x11) != 0;
  if (keycode == 0x39) {
    tab5KeyboardCapsLock = !tab5KeyboardCapsLock;
    return;
  }

  if (screen == SCREEN_FILE_MGR) {
    int previousSelection = fileSelectedIndex;
    if (keycode == 0x51 && fileSelectedIndex + 1 < static_cast<int>(fileEntryCount)) {
      ++fileSelectedIndex;
    } else if (keycode == 0x52 && fileSelectedIndex > 0) {
      --fileSelectedIndex;
    } else if (keycode == 0x4C) {
      handleFileManagerTouch(fileMgrDeleteButton.x + fileMgrDeleteButton.w / 2,
                             fileMgrDeleteButton.y + fileMgrDeleteButton.h / 2);
      return;
    } else if (keycode == 0x28 && fileSelectedIndex >= 0 &&
               fileSelectedIndex < static_cast<int>(fileEntryCount)) {
      const FileEntry &entry = fileEntries[fileSelectedIndex];
      if (entry.specialUsb) {
        setFileManagerStatus("USB STORAGE DISABLED - USE WEB TRANSFER");
        return;
      } else if (entry.isDir) {
        fileManagerPath = joinFileManagerPath(fileManagerPath, entry.name);
        fileScrollIndex = 0;
        fileSelectedIndex = -1;
        fileManagerListDirty = true;
      }
    } else if (keycode == 0x29) {
      beginMenuTransition(false);
      screen = SCREEN_DOWNLOAD;
      downloadMenuDirty = true;
      downloadMenuNeedsFullRedraw = true;
      return;
    }
    if (fileSelectedIndex >= 0) {
      M5.Display.setTextSize(kFileManagerTextSize);
      int16_t rowH = static_cast<int16_t>(M5.Display.fontHeight() + 4);
      constexpr int16_t listHeaderH = 28;
      int visible = max<int>(
          1, (fileMgrListRect.h - listHeaderH) / max<int16_t>(1, rowH));
      if (fileSelectedIndex < fileScrollIndex) fileScrollIndex = fileSelectedIndex;
      if (fileSelectedIndex >= fileScrollIndex + visible) {
        fileScrollIndex = fileSelectedIndex - visible + 1;
      }
    }
    bool selectionArrow = keycode == 0x51 || keycode == 0x52;
    fileManagerNavigationRedraw = selectionArrow && fileSelectedIndex != previousSelection;
    fileManagerDirty = true;
    return;
  }

  if (screen == SCREEN_WAYPOINTS && appSelected == kAppMenuIndex) {
    if (appMenuVisibleDirty) rebuildAppMenuVisibleList();
    if (keycode == 0) return;
    int previousSelection = appMenuKeyboardSelection;
    uint8_t previousPage = appMenuPage;
    int pageStart = appMenuPage * kAppsPerPage;
    int pageEnd = min<int>(appMenuVisibleCount, pageStart + kAppsPerPage);
    int selectedPos = appMenuVisiblePositionForIndex(appMenuKeyboardSelection);
    if (selectedPos < pageStart || selectedPos >= pageEnd) {
      selectAppMenuVisiblePosition(pageStart);
      selectedPos = appMenuVisiblePositionForIndex(appMenuKeyboardSelection);
    }
    if (keycode == 0x4F) {
      appMenuPage = static_cast<uint8_t>((appMenuPage + 1) % appMenuVisiblePageCount);
      selectAppMenuVisiblePosition(appMenuPage * kAppsPerPage);
    } else if (keycode == 0x50) {
      appMenuPage =
          static_cast<uint8_t>((appMenuPage + appMenuVisiblePageCount - 1) % appMenuVisiblePageCount);
      selectAppMenuVisiblePosition(appMenuPage * kAppsPerPage);
    } else if (keycode == 0x51 && selectedPos + 1 < pageEnd) {
      selectAppMenuVisiblePosition(selectedPos + 1);
    } else if (keycode == 0x52 && selectedPos > pageStart) {
      selectAppMenuVisiblePosition(selectedPos - 1);
    } else if (keycode == 0x28) {
      openApp(static_cast<uint8_t>(appMenuKeyboardSelection));
      return;
    } else if (keycode == 0x29) {
      mapViewMode = MapViewMode::NAV;
      enterMapScreen();
      return;
    }
    appMenuNavigationRedraw = previousPage == appMenuPage &&
                              previousSelection != appMenuKeyboardSelection;
    appMenuPageRedraw = previousPage != appMenuPage;
    appMenuPreviousKeyboardSelection = appMenuNavigationRedraw ? previousSelection : -1;
    waypointsDirty = true;
    return;
  }

  if (screen == SCREEN_WAYPOINTS && appSelected != kAppMenuIndex &&
      responderAppRegistry.appByLegacyIndex(appSelected)) {
    responder::InputEvent event;
    event.type = keycode == 0 ? responder::InputEventType::KeyUp
                              : responder::InputEventType::KeyDown;
    event.modifier = modifier;
    event.keycode = keycode;
    event.timestampMs = millis();
    if (responderAppRegistry.inputByLegacyIndex(appSelected, event)) {
      waypointsDirty = true;
      return;
    }
  }

  if (screen == SCREEN_WAYPOINTS && appSelected == kAppNotesIndex) {
    if (keycode == 0x29) {
      leaveCurrentAppToMenu();
      return;
    }
    if (notesView == NOTES_VIEW_FILES) {
      if (keycode == 0x51 && noteSelectedIndex + 1 < static_cast<int>(noteFileCount)) {
        ++noteSelectedIndex;
      } else if (keycode == 0x52 && noteSelectedIndex > 0) {
        --noteSelectedIndex;
      } else if (keycode == 0x28) {
        openSelectedNote();
      } else if (keycode == 0x11) {
        createNewNote();
      } else if (keycode == 0x4C) {
        deleteSelectedNote();
      }
      waypointsDirty = true;
      return;
    }
    if (control && keycode == 0x16) {
      saveNotes();
      waypointsDirty = true;
      return;
    }
    if (keycode == 0x2A) {
      if (notesCursor > 0 && notesText.length() > 0) {
        notesText.remove(notesCursor - 1, 1);
        --notesCursor;
        notesDirty = true;
      }
    } else if (keycode == 0x4C) {
      if (notesCursor < notesText.length()) {
        notesText.remove(notesCursor, 1);
        notesDirty = true;
      }
    } else if (keycode == 0x50) {
      if (notesCursor > 0) --notesCursor;
    } else if (keycode == 0x4F) {
      if (notesCursor < notesText.length()) ++notesCursor;
    } else if (keycode == 0x52) {
      moveNotesCursorVertical(-1);
    } else if (keycode == 0x51) {
      moveNotesCursorVertical(1);
    } else if (keycode == 0x4A) {
      while (notesCursor > 0 && notesText[notesCursor - 1] != '\n') --notesCursor;
    } else if (keycode == 0x4D) {
      while (notesCursor < notesText.length() && notesText[notesCursor] != '\n') ++notesCursor;
    } else if (keycode == 0x28) {
      notesInsertText("\n");
    } else if (keycode == 0x2B) {
      notesInsertText("    ");
    } else {
      char c = tab5KeyboardHidToAscii(keycode, shift);
      if (c) notesInsertText(String(c));
    }
    notesStatus = notesDirty ? "UNSAVED" : "SAVED";
    waypointsDirty = true;
    return;
  }

  if (screen == SCREEN_WAYPOINTS && appSelected == kAppAudioIndex) {
    if (keycode == 0x29) {
      leaveCurrentAppToMenu();
      return;
    }
    if (keycode == 0x51 && audioFileSelected + 1 < static_cast<int>(audioFileCount)) {
      closeAudioPlayback();
      ++audioFileSelected;
    } else if (keycode == 0x52 && audioFileSelected > 0) {
      closeAudioPlayback();
      --audioFileSelected;
    } else if (keycode == 0x4C) {
      handleSdrAppTouch(appSecondaryButton.x + appSecondaryButton.w / 2,
                        appSecondaryButton.y + appSecondaryButton.h / 2);
      return;
    } else if (keycode == 0x28) {
      handleSdrAppTouch(appPrimaryButton.x + appPrimaryButton.w / 2,
                        appPrimaryButton.y + appPrimaryButton.h / 2);
      return;
    }
    if (audioFileSelected >= 0 && audioFileSelected < static_cast<int>(audioFileCount)) {
      audioSelectedPath = String("/recordings/") + String(audioFiles[audioFileSelected]);
      int visible = max<int>(1, audioFileListRect.h / max<int>(1, 18 * kFileManagerTextSize));
      if (audioFileSelected < audioFileScroll) audioFileScroll = audioFileSelected;
      if (audioFileSelected >= audioFileScroll + visible) {
        audioFileScroll = audioFileSelected - visible + 1;
      }
    }
    waypointsDirty = true;
    return;
  }

  if (screen == SCREEN_WAYPOINTS && appSelected == kAppCalendarIndex && calendarEventEditor) {
    if (keycode == 0x29) {
      calendarEventInput = "";
      calendarEventEditor = false;
    } else if (keycode == 0x2A || keycode == 0x4C) {
      if (calendarEventInput.length() > 0) calendarEventInput.remove(calendarEventInput.length() - 1);
    } else if (keycode == 0x28) {
      if (calendarEventInput.length() > 0 && calendarEventCount < kMaxCalendarEvents) {
        CalendarEvent &event = calendarEvents[calendarEventCount++];
        event.year = calendarSelectedYear;
        event.month = calendarSelectedMonth;
        event.day = calendarSelectedDay;
        event.title = calendarEventInput;
        saveCalendarEvents();
        calendarEventInput = "";
        calendarEventEditor = false;
      }
    } else {
      char c = tab5KeyboardHidToAscii(keycode, shift);
      if (c && calendarEventInput.length() < 96) calendarEventInput += c;
    }
    waypointsDirty = true;
    return;
  }

  if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex) {
    const LoraView meshOldView = loraView;
    const int meshOldSelection = meshSelectionForView(loraView);
    const bool meshOldPeerFocus = meshDiscoverPeerFocus;
    if (keycode == 0x2D && shift && loraInput.length() == 0 &&
        loraView != LORA_VIEW_MESSAGES &&
        !(loraView == LORA_VIEW_IDENTITY && meshIdentityField < 3) &&
        loraView != LORA_VIEW_RADIO_EDIT) {
      waypointsDirty = true;
      return;
    }
    if (keycode == 0x29) {
      if (loraView == LORA_VIEW_MESSAGES) {
        leaveCurrentAppToMenu();
      } else if (loraView == LORA_VIEW_MENU) {
        loraView = LORA_VIEW_MESSAGES;
        loraInput = "";
        waypointsDirty = true;
      } else if (loraView == LORA_VIEW_CONTACT_INFO) {
        loraView = LORA_VIEW_CONTACTS;
        loraInput = "";
        waypointsDirty = true;
      } else {
        if (loraView == LORA_VIEW_IDENTITY || loraView == LORA_VIEW_RADIO_EDIT) saveMeshSettings();
        loraView = LORA_VIEW_MENU;
        loraInput = "";
        waypointsDirty = true;
      }
      return;
    }
    if (keycode == 0x51 && loraView == LORA_VIEW_MESSAGES) {
      if (meshChatSelected + 1 < static_cast<int>(meshContactCount)) ++meshChatSelected;
    } else if (keycode == 0x52 && loraView == LORA_VIEW_MESSAGES) {
      if (meshChatSelected > -1) --meshChatSelected;
    } else if (keycode == 0x51 && loraView == LORA_VIEW_MENU) {
      if (meshMenuSelected < 4) ++meshMenuSelected;
    } else if (keycode == 0x52 && loraView == LORA_VIEW_MENU) {
      if (meshMenuSelected > 0) --meshMenuSelected;
    } else if (keycode == 0x4F && loraView == LORA_VIEW_MENU) {
      activateMeshMenuItem();
      return;
    } else if (keycode == 0x51 && loraView == LORA_VIEW_DISCOVER) {
      if (meshDiscoverPeerFocus) {
        if (meshContactSelected + 1 < static_cast<int>(meshDiscoveredCount)) ++meshContactSelected;
      } else if (meshDiscoverSelected < 4) {
        ++meshDiscoverSelected;
      }
    } else if (keycode == 0x52 && loraView == LORA_VIEW_DISCOVER) {
      if (meshDiscoverPeerFocus) {
        if (meshContactSelected > 0) --meshContactSelected;
      } else if (meshDiscoverSelected > 0) {
        --meshDiscoverSelected;
      }
    } else if (keycode == 0x4F && loraView == LORA_VIEW_DISCOVER) {
      if (meshDiscoverPeerFocus) addDiscoveredMeshContact(meshContactSelected);
      else activateMeshDiscoverItem();
      return;
    } else if (keycode == 0x50 && loraView == LORA_VIEW_DISCOVER) {
      meshDiscoverPeerFocus = true;
    } else if (keycode == 0x51 && loraView == LORA_VIEW_RADIO) {
      if (meshNetworkSelected + 1 <= static_cast<int>(kMeshNetworkPresetCount)) ++meshNetworkSelected;
    } else if (keycode == 0x52 && loraView == LORA_VIEW_RADIO) {
      if (meshNetworkSelected > 0) --meshNetworkSelected;
    } else if (keycode == 0x4F && loraView == LORA_VIEW_RADIO) {
      if (isMeshCustomNetworkSelected()) {
        loraView = LORA_VIEW_RADIO_EDIT;
        loraInput = "";
      } else {
        saveMeshSettings();
        beginLoraP2pConfiguration();
      }
      return;
    } else if (keycode == 0x51 && loraView == LORA_VIEW_RADIO_EDIT) {
      meshNetworkEditField = static_cast<uint8_t>(min<int>(4, meshNetworkEditField + 1));
      loraInput = "";
    } else if (keycode == 0x52 && loraView == LORA_VIEW_RADIO_EDIT) {
      if (meshNetworkEditField > 0) --meshNetworkEditField;
      loraInput = "";
    } else if (keycode == 0x4F && loraView == LORA_VIEW_RADIO_EDIT) {
      applyMeshNetworkEditField();
      return;
    } else if (keycode == 0x51 && (loraView == LORA_VIEW_CONTACTS || loraView == LORA_VIEW_TELEMETRY)) {
      if (meshContactSelected + 1 < static_cast<int>(meshContactCount)) ++meshContactSelected;
    } else if (keycode == 0x52 && (loraView == LORA_VIEW_CONTACTS || loraView == LORA_VIEW_TELEMETRY)) {
      if (meshContactSelected > 0) --meshContactSelected;
    } else if (keycode == 0x4F && loraView == LORA_VIEW_CONTACTS) {
      if (loraInput.length() > 0) renameSelectedMeshContact();
      else if (meshContactSelected >= 0 && meshContactSelected < static_cast<int>(meshContactCount)) {
        loraView = LORA_VIEW_CONTACT_INFO;
      }
      return;
    } else if (keycode == 0x4C && loraView == LORA_VIEW_CONTACT_INFO) {
      deleteSelectedMeshContact();
      loraView = LORA_VIEW_CONTACTS;
      loraInput = "";
      return;
    } else if (keycode == 0x51 && loraView == LORA_VIEW_IDENTITY) {
      meshIdentityField = static_cast<uint8_t>((meshIdentityField + 1) % 5);
      loraInput = "";
    } else if (keycode == 0x52 && loraView == LORA_VIEW_IDENTITY) {
      meshIdentityField = meshIdentityField == 0 ? 4 : static_cast<uint8_t>(meshIdentityField - 1);
      loraInput = "";
    } else if (keycode == 0x4F && loraView == LORA_VIEW_IDENTITY) {
      applyMeshIdentitySelection();
      return;
    } else if (keycode == 0x50 && loraView == LORA_VIEW_IDENTITY) {
      meshIdentityField = meshIdentityField == 0 ? 4 : static_cast<uint8_t>(meshIdentityField - 1);
      loraInput = "";
    } else if (keycode == 0x4C && loraView == LORA_VIEW_CONTACTS && loraInput.length() == 0) {
      deleteSelectedMeshContact();
    } else if (keycode == 0x2A || keycode == 0x4C) {
      if (loraInput.length() > 0) {
        loraInput.remove(loraInput.length() - 1);
      }
    } else if (keycode == 0x28) {
      if (loraView == LORA_VIEW_MESSAGES) sendLoraTextMessage();
      else if (loraView == LORA_VIEW_MENU) activateMeshMenuItem();
      else if (loraView == LORA_VIEW_IDENTITY) {
        applyMeshIdentitySelection();
      } else if (loraView == LORA_VIEW_RADIO) {
        if (isMeshCustomNetworkSelected()) {
          loraView = LORA_VIEW_RADIO_EDIT;
          loraInput = "";
          waypointsDirty = true;
        } else {
          saveMeshSettings();
          beginLoraP2pConfiguration();
        }
      } else if (loraView == LORA_VIEW_RADIO_EDIT) {
        applyMeshNetworkEditField();
      } else if (loraView == LORA_VIEW_CONTACTS) {
        if (loraInput.length() > 0) renameSelectedMeshContact();
        else if (meshContactSelected >= 0 && meshContactSelected < static_cast<int>(meshContactCount)) {
          meshChatSelected = meshContactSelected;
          loraView = LORA_VIEW_MESSAGES;
        }
      } else if (loraView == LORA_VIEW_DISCOVER) {
        if (meshDiscoverPeerFocus) addDiscoveredMeshContact(meshContactSelected);
        else activateMeshDiscoverItem();
      }
      return;
    } else {
      char c = tab5KeyboardHidToAscii(keycode, shift);
      bool acceptsText = loraView == LORA_VIEW_MESSAGES ||
                         loraView == LORA_VIEW_CONTACTS ||
                         loraView == LORA_VIEW_DISCOVER ||
                         loraView == LORA_VIEW_RADIO_EDIT ||
                         (loraView == LORA_VIEW_IDENTITY && meshIdentityField < 3);
      if (acceptsText && c && loraInput.length() < 96) {
        loraInput += c;
      }
    }
    const bool selectionKey = keycode == 0x50 || keycode == 0x51 || keycode == 0x52;
    const int meshNewSelection = meshSelectionForView(loraView);
    if (selectionKey && loraView == meshOldView &&
        (meshOldSelection != meshNewSelection || meshOldPeerFocus != meshDiscoverPeerFocus)) {
      if (!drawMeshSelectionDelta(loraView, meshOldSelection, meshNewSelection,
                                  meshOldPeerFocus, meshDiscoverPeerFocus)) {
        meshContentOnlyRedraw = true;
        waypointsDirty = true;
        debugPrint("MESHCORE: selection content redraw view=%u old=%d new=%d",
                   static_cast<unsigned>(loraView), meshOldSelection, meshNewSelection);
      } else {
        debugPrint("MESHCORE: selection delta view=%u old=%d new=%d",
                   static_cast<unsigned>(loraView), meshOldSelection, meshNewSelection);
      }
    } else if (!selectionKey) {
      waypointsDirty = true;
    }
    return;
  }

  if (screen == SCREEN_WIFI_PASS) {
    if (keycode == 0x29) {
      screen = SCREEN_WIFI;
      wifiDirty = true;
      wifiNeedsFullRedraw = true;
      return;
    }
    if (keycode == 0x2A || keycode == 0x4C) {
      if (passwordInput.length() > 0) {
        passwordInput.remove(passwordInput.length() - 1);
      }
    } else if (keycode == 0x28) {
      saveWifiNetworkAndRebootClean(selectedSsid, passwordInput);
      return;
    } else {
      char c = tab5KeyboardHidToAscii(keycode, shift);
      if (c) {
        passwordInput += c;
      }
    }
    wifiPassDirty = true;
    return;
  }

  if (screen == SCREEN_WAYPOINTS && appSelected != kAppMenuIndex) {
    Rect target = {0, 0, 0, 0};
    if (keycode == 0x28) {
      target = appPrimaryButton;
    } else if (keycode == 0x4F || keycode == 0x51) {
      target = appSecondaryButton;
    } else if (keycode == 0x50 || keycode == 0x52) {
      target = appTertiaryButton;
    } else if (keycode == 0x29) {
      leaveCurrentAppToMenu();
      return;
    }
    if (target.w > 0 && target.h > 0) {
      int16_t x = static_cast<int16_t>(target.x + target.w / 2);
      int16_t y = static_cast<int16_t>(target.y + target.h / 2);
      if (responderAppRegistry.appByLegacyIndex(appSelected)) {
        responder::InputEvent event;
        event.type = responder::InputEventType::TouchDown;
        event.x = x;
        event.y = y;
        event.timestampMs = millis();
        if (responderAppRegistry.inputByLegacyIndex(appSelected, event)) {
          waypointsDirty = true;
          return;
        }
      }
      if (appSelected == kAppCalendarIndex) handleCalendarAppTouch(x, y);
      else if (appSelected == kAppCameraIndex) handleCameraTouch(x, y);
      else if (appSelected == kAppGalleryIndex) handleGalleryTouch(x, y);
      else if (appSelected == kAppLoraIndex) handleLoraAppTouch(x, y);
      else if (appSelected == kAppNotesIndex) handleNotesAppTouch(x, y);
      else if (appSelected == kAppCarIndex) handleCarScannerTouch(x, y);
      else if (appSelected == kAppRfWatchIndex) handleRfWatchTouch(x, y);
      else if (appSelected == kAppWifiMotionIndex) handleWifiMotionTouch(x, y);
      else if (appSelected == kAppBleKeyboardIndex) handleBleKeyboardTouch(x, y);
      else if (appSelected == kAppGamesIndex) handleGamesTouch(x, y);
      else if (appSelected == kAppIpCamsIndex) handleIpCamsTouch(x, y);
      else if (appSelected == kAppAirplanesIndex) handleAircraftTouch(x, y);
      else if (appSelected == kAppGhostIndex ||
               appSelected == kAppRfScanIndex || appSelected == kAppDroneIndex ||
               appSelected == kAppRecorderIndex ||
               appSelected == kAppAudioIndex) {
        handleSdrAppTouch(x, y);
      }
      return;
    }
  }
}

void initTab5Keyboard(bool force) {
  uint32_t now = millis();
  if (!force && tab5KeyboardReady) {
    return;
  }
  if (!force && tab5KeyboardLastProbeMs != 0 && now - tab5KeyboardLastProbeMs < 2000) {
    return;
  }
  tab5KeyboardLastProbeMs = now;
  if (!tab5KeyboardBusStarted || force) {
    bool busOk = tab5KeyboardWire.begin(kTab5KeyboardSdaPin, kTab5KeyboardSclPin,
                                        kTab5KeyboardI2cHz);
    tab5KeyboardWire.setTimeOut(20);
    pinMode(kTab5KeyboardIntPin, INPUT_PULLUP);
    tab5KeyboardBusStarted = busOk;
    debugPrint("KBD: i2c begin port=%d ok=%u sda=%d scl=%d", kTab5KeyboardI2cPort,
               busOk ? 1 : 0, kTab5KeyboardSdaPin, kTab5KeyboardSclPin);
    if (!busOk) {
      tab5KeyboardReady = false;
      return;
    }
  }
  uint8_t intCfg = 0;
  if (!tab5KeyboardReadReg(kTab5KeyboardRegIntCfg, &intCfg, 1)) {
    if (tab5KeyboardReady || force) {
      debugPrint("KBD: not found addr=0x%02X port=%d sda=%d scl=%d int=%d",
                 kTab5KeyboardAddr, kTab5KeyboardI2cPort, kTab5KeyboardSdaPin,
                 kTab5KeyboardSclPin, kTab5KeyboardIntPin);
    }
    tab5KeyboardReady = false;
    return;
  }
  uint8_t version = 0;
  tab5KeyboardReadReg(kTab5KeyboardRegVersion, &version, 1);
  tab5KeyboardWriteReg(kTab5KeyboardRegMode, kTab5KeyboardModeHid);
  bool ledOk = tab5KeyboardWriteReg(kTab5KeyboardRegBrightness, tab5KeyboardBrightness);
  ledOk = tab5KeyboardWriteReg(kTab5KeyboardRegRgbMode, kTab5KeyboardRgbModeStatic) && ledOk;
  ledOk = tab5KeyboardSetLedState(false) && ledOk;
  tab5KeyboardWriteReg(kTab5KeyboardRegEventNum, 0);
  tab5KeyboardWriteReg(kTab5KeyboardRegIntSta, 0);
  tab5KeyboardReady = true;
  debugPrint("KBD: found addr=0x%02X port=%d sda=%d scl=%d int=%d intcfg=0x%02X ver=0x%02X led=%u",
             kTab5KeyboardAddr, kTab5KeyboardI2cPort, kTab5KeyboardSdaPin, kTab5KeyboardSclPin,
             kTab5KeyboardIntPin, intCfg, version, ledOk ? 1 : 0);
}

void pollTab5Keyboard(uint32_t now) {
#if HAS_HOSTED_BLE
  serviceBleKeyboardRelease(now);
  if (isWaypointAppVisible(kAppBleKeyboardIndex) && !bleKeyboardReady &&
      now - bleKeyboardInitAttemptMs >= 1500) {
    bleKeyboardInitAttemptMs = now;
    initBleKeyboard();
  }
#endif
  if (!tab5KeyboardReady) {
    initTab5Keyboard(false);
    return;
  }
  if (now - tab5KeyboardLastPollMs < 50) {
    return;
  }
  tab5KeyboardLastPollMs = now;
  uint8_t status = 0;
  if (!tab5KeyboardReadReg(kTab5KeyboardRegIntSta, &status, 1)) {
    tab5KeyboardReady = false;
    debugPrint("KBD: read lost");
    return;
  }
  if (status == 0 && digitalRead(kTab5KeyboardIntPin) != LOW) {
    return;
  }
  uint8_t eventCount = 0;
  tab5KeyboardReadReg(kTab5KeyboardRegEventNum, &eventCount, 1);
  if (status & 0x02) {
    uint8_t events = eventCount == 0 ? 1 : min<uint8_t>(eventCount, 12);
    for (uint8_t event = 0; event < events; ++event) {
      uint8_t hid[2] = {};
      if (!tab5KeyboardReadReg(kTab5KeyboardRegHidEvent, hid, sizeof(hid))) {
        break;
      }
      debugPrint("KBD: hid mod=0x%02X key=0x%02X", hid[0], hid[1]);
      handleTab5KeyboardHid(hid[0], hid[1]);
    }
  } else if (status & 0x04) {
    uint8_t events = eventCount == 0 ? 1 : min<uint8_t>(eventCount, 8);
    for (uint8_t event = 0; event < events; ++event) {
      uint8_t len = 0;
      if (!tab5KeyboardReadReg(kTab5KeyboardRegCharLen, &len, 1)) {
        break;
      }
      if (len == 0 || len > 15) {
        continue;
      }
      uint8_t buf[17] = {};
      if (!tab5KeyboardReadReg(kTab5KeyboardRegCharBase, buf, static_cast<size_t>(len) + 1)) {
        break;
      }
      char text[16] = {};
      memcpy(text, buf + 1, len);
      handleTab5KeyboardText(text, buf[0]);
    }
  } else if (status & 0x01) {
    uint8_t eventByte = 0;
    if (tab5KeyboardReadReg(kTab5KeyboardRegKeyEvent, &eventByte, 1)) {
      debugPrint("KBD: key raw=0x%02X pressed=%u row=%u col=%u", eventByte,
                 (eventByte & 0x80) ? 1 : 0, (eventByte >> 4) & 0x07,
                 eventByte & 0x0F);
    }
  }
  tab5KeyboardWriteReg(kTab5KeyboardRegEventNum, 0);
  tab5KeyboardWriteReg(kTab5KeyboardRegIntSta, 0);
}

static void clearLoraMessages() {
  for (size_t i = 0; i < kLoraMessageCount; ++i) {
    loraMessages[i] = "";
  }
  loraMessageCount = 0;
  for (size_t i = 0; i < kMeshPacketHistoryCount; ++i) {
    meshPackets[i] = MeshPacketRecord();
  }
  meshPacketCount = 0;
  prefs.begin("responder", false);
  prefs.putUChar("mesh_hc", 0);
  prefs.putUChar("mesh_lc", 0);
  prefs.end();
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex) {
    waypointsDirty = true;
  }
}

static void addLoraMessage(const String &message) {
  if (message.length() == 0) {
    return;
  }
  if (loraMessageCount < kLoraMessageCount) {
    loraMessages[loraMessageCount++] = message;
  } else {
    for (size_t i = 1; i < kLoraMessageCount; ++i) {
      loraMessages[i - 1] = loraMessages[i];
    }
    loraMessages[kLoraMessageCount - 1] = message;
  }
  prefs.begin("responder", false);
  prefs.putUChar("mesh_lc", static_cast<uint8_t>(loraMessageCount));
  for (size_t i = 0; i < kLoraMessageCount; ++i) {
    char key[12];
    snprintf(key, sizeof(key), "mesh_l%u", static_cast<unsigned>(i));
    String stored = i < loraMessageCount ? loraMessages[i] : String();
    if (stored.length() > 192) stored.remove(192);
    prefs.putString(key, stored);
  }
  prefs.putUChar("mesh_hc", static_cast<uint8_t>(meshPacketCount));
  for (size_t i = 0; i < kLoraMessageCount; ++i) {
    const MeshPacketRecord empty;
    const MeshPacketRecord &record = i < meshPacketCount ? meshPackets[meshPacketCount - min(meshPacketCount, kLoraMessageCount) + i] : empty;
    char key[12];
    snprintf(key, sizeof(key), "mesh_p%us", static_cast<unsigned>(i)); prefs.putString(key, record.sender);
    snprintf(key, sizeof(key), "mesh_p%ut", static_cast<unsigned>(i)); prefs.putString(key, record.timestamp);
    snprintf(key, sizeof(key), "mesh_p%ux", static_cast<unsigned>(i)); prefs.putString(key, record.text.substring(0, 192));
    snprintf(key, sizeof(key), "mesh_p%uy", static_cast<unsigned>(i)); prefs.putString(key, record.type);
    snprintf(key, sizeof(key), "mesh_p%ud", static_cast<unsigned>(i)); prefs.putString(key, record.detail.substring(0, 96));
    snprintf(key, sizeof(key), "mesh_p%ur", static_cast<unsigned>(i)); prefs.putString(key, record.rssi);
    snprintf(key, sizeof(key), "mesh_p%un", static_cast<unsigned>(i)); prefs.putString(key, record.snr);
  }
  prefs.end();
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex) {
    waypointsDirty = true;
  }
}

static void loadLoraMessageHistory() {
  prefs.begin("responder", true);
  loraMessageCount = min<size_t>(prefs.getUChar("mesh_lc", 0), kLoraMessageCount);
  for (size_t i = 0; i < kLoraMessageCount; ++i) {
    char key[12];
    snprintf(key, sizeof(key), "mesh_l%u", static_cast<unsigned>(i));
    loraMessages[i] = i < loraMessageCount ? prefs.getString(key, "") : String();
  }
  meshPacketCount = min<size_t>(prefs.getUChar("mesh_hc", 0), kLoraMessageCount);
  for (size_t i = 0; i < meshPacketCount; ++i) {
    char key[12];
    snprintf(key, sizeof(key), "mesh_p%us", static_cast<unsigned>(i)); meshPackets[i].sender = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mesh_p%ut", static_cast<unsigned>(i)); meshPackets[i].timestamp = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mesh_p%ux", static_cast<unsigned>(i)); meshPackets[i].text = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mesh_p%uy", static_cast<unsigned>(i)); meshPackets[i].type = prefs.getString(key, "MESSAGE");
    snprintf(key, sizeof(key), "mesh_p%ud", static_cast<unsigned>(i)); meshPackets[i].detail = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mesh_p%ur", static_cast<unsigned>(i)); meshPackets[i].rssi = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mesh_p%un", static_cast<unsigned>(i)); meshPackets[i].snr = prefs.getString(key, "");
  }
  prefs.end();
  debugPrint("MESHCORE: restored messages=%u packets=%u", static_cast<unsigned>(loraMessageCount),
             static_cast<unsigned>(meshPacketCount));
}

static int loraHexNibble(char c) {
  if (c >= '0' && c <= '9') return c - '0';
  if (c >= 'a' && c <= 'f') return c - 'a' + 10;
  if (c >= 'A' && c <= 'F') return c - 'A' + 10;
  return -1;
}

static String bytesToHex(const uint8_t *data, size_t len) {
  static const char hex[] = "0123456789ABCDEF";
  String encoded;
  encoded.reserve(len * 2);
  for (size_t i = 0; i < len; ++i) {
    encoded += hex[data[i] >> 4];
    encoded += hex[data[i] & 0x0F];
  }
  return encoded;
}

static size_t hexToBytes(const String &hex, uint8_t *dest, size_t destSize) {
  if ((hex.length() & 1U) != 0 || hex.length() / 2 > destSize) {
    return 0;
  }
  size_t len = hex.length() / 2;
  for (size_t i = 0; i < len; ++i) {
    int hi = loraHexNibble(hex[i * 2]);
    int lo = loraHexNibble(hex[i * 2 + 1]);
    if (hi < 0 || lo < 0) {
      return 0;
    }
    dest[i] = static_cast<uint8_t>((hi << 4) | lo);
  }
  return len;
}

static void meshCoreExpandedChannelKey(uint8_t key[32]) {
  memset(key, 0, 32);
  memcpy(key, kMeshCorePublicChannelKey, sizeof(kMeshCorePublicChannelKey));
}

static bool meshCoreCryptBlocks(bool encrypt, const uint8_t *src, uint8_t *dest,
                                size_t len) {
  if ((len % kMeshCoreBlockBytes) != 0) {
    return false;
  }
  mbedtls_aes_context aes;
  mbedtls_aes_init(&aes);
  int rc = encrypt ? mbedtls_aes_setkey_enc(&aes, kMeshCorePublicChannelKey, 128)
                   : mbedtls_aes_setkey_dec(&aes, kMeshCorePublicChannelKey, 128);
  for (size_t offset = 0; rc == 0 && offset < len; offset += kMeshCoreBlockBytes) {
    rc = mbedtls_aes_crypt_ecb(&aes, encrypt ? MBEDTLS_AES_ENCRYPT : MBEDTLS_AES_DECRYPT,
                               src + offset, dest + offset);
  }
  mbedtls_aes_free(&aes);
  return rc == 0;
}

static bool meshCoreMac(const uint8_t *ciphertext, size_t len, uint8_t mac[32]) {
  uint8_t key[32];
  meshCoreExpandedChannelKey(key);
  const mbedtls_md_info_t *md = mbedtls_md_info_from_type(MBEDTLS_MD_SHA256);
  return md && mbedtls_md_hmac(md, key, sizeof(key), ciphertext, len, mac) == 0;
}

static uint32_t meshCoreTimestamp() {
  time_t now = time(nullptr);
  if (now >= 1577836800LL && now < 2524608000LL) {
    return static_cast<uint32_t>(now);
  }
  return cachedEpochValid ? cachedEpochSeconds + (millis() - cachedEpochSetMs) / 1000U
                          : millis() / 1000U;
}

static String meshCoreTimeString(uint32_t nowMs = millis()) {
  tm localTm;
  if (getLocalTimeTm(localTm)) {
    char buf[24];
    strftime(buf, sizeof(buf), "%H:%M:%S", &localTm);
    return String(buf);
  }
  return String(nowMs / 1000U) + "s";
}

static String meshCorePacketId(const String &payloadHex) {
  String id = payloadHex;
  id.trim();
  if (id.length() > 8) id.remove(8);
  if (id.length() == 0) id = "UNKNOWN";
  return id;
}

static String meshCorePayloadTypeName(uint8_t type) {
  switch (type) {
    case 0x00: return "REQ";
    case 0x01: return "RESPONSE";
    case 0x02: return "TEXT";
    case 0x03: return "ACK";
    case 0x04: return "ADVERT";
    case 0x05: return "GROUP TEXT";
    case 0x06: return "GROUP DATA";
    case 0x07: return "ANON REQ";
    case 0x08: return "PATH";
    case 0x09: return "TRACE";
    case 0x0A: return "MULTIPART";
    case 0x0B: return "CONTROL";
    case 0x0F: return "RAW CUSTOM";
    default: return String("TYPE ") + String(type);
  }
}

static String meshCoreRouteTypeName(uint8_t route) {
  switch (route) {
    case 0x00: return "TRANSPORT FLOOD";
    case 0x01: return "FLOOD";
    case 0x02: return "DIRECT";
    case 0x03: return "TRANSPORT DIRECT";
    default: return "UNKNOWN ROUTE";
  }
}

static String classifyMeshCorePacketHeader(const String &hex) {
  uint8_t packet[kMeshCoreMaxPacketBytes];
  size_t packetLen = hexToBytes(hex, packet, sizeof(packet));
  if (packetLen == 0) return "INVALID PACKET";
  if (packetLen < 2) return String("TRUNCATED / ") + String(packetLen) + "B";
  uint8_t route = packet[0] & 0x03;
  uint8_t type = (packet[0] >> 2) & 0x0F;
  uint8_t ver = (packet[0] >> 6) & 0x03;
  String detail = meshCorePayloadTypeName(type) + " / " + meshCoreRouteTypeName(route) +
                  " / V" + String(ver + 1) + " / " + String(packetLen) + "B";
  uint8_t pathLen = packet[1];
  bool validPath = mesh::Packet::isValidPathLen(pathLen);
  uint8_t pathBytes = validPath ? (((pathLen >> 6) + 1) * (pathLen & 63)) : 0;
  detail += " / PATH " + String(pathLen & 63);
  if (!validPath || 2U + pathBytes >= packetLen) {
    detail += " / MALFORMED OR TRUNCATED";
    return detail;
  }
  size_t bodyLen = packetLen - 2U - pathBytes;
  detail += " / BODY " + String(bodyLen) + "B";
  if (type == 0x02) {
    detail += " / ENCRYPTED DIRECT TEXT - IMPORT OR DISCOVER SENDER CONTACT";
  } else if (type == 0x04) {
    detail += " / CONTACT ADVERT";
  } else if (type == 0x05) {
    detail += " / PUBLIC GROUP TEXT";
  } else if (type == 0x06) {
    detail += " / GROUP DATA MAY CONTAIN TELEMETRY";
  } else if (type == 0x0B) {
    detail += " / DISCOVERY CONTROL";
  }
  return detail;
}

static int findMeshContactById(const String &deviceId) {
  for (size_t i = 0; i < meshContactCount; ++i) {
    if (meshContacts[i].deviceId == deviceId) return static_cast<int>(i);
  }
  return -1;
}

static int ensureMeshContact(const String &deviceId, const String &fallbackName) {
  int idx = findMeshContactById(deviceId);
  if (idx >= 0) return idx;
  if (meshContactCount >= kMeshContactCount) return -1;
  MeshContact &contact = meshContacts[meshContactCount];
  contact.deviceId = deviceId;
  contact.name = fallbackName.length() ? fallbackName : deviceId;
  contact.shortName = contact.name.substring(0, min<size_t>(4, contact.name.length()));
  contact.notes = "";
  contact.lastSeen = "";
  contact.lastRssi = "";
  contact.lastSnr = "";
  contact.hasGps = false;
  contact.battery = -1;
  contact.lastSeenMs = 0;
  contact.lastGpsMs = 0;
  return static_cast<int>(meshContactCount++);
}

static void updateMeshContactSeen(const String &deviceId, const String &sender,
                                  const String &rssi, const String &snr) {
  int idx = findMeshContactById(deviceId);
  if (idx < 0 && sender.length()) {
    for (size_t i = 0; i < meshContactCount; ++i) {
      if (meshContacts[i].name == sender || meshContacts[i].shortName == sender) {
        idx = static_cast<int>(i);
        break;
      }
    }
  }
  if (idx < 0) return;
  MeshContact &contact = meshContacts[idx];
  contact.lastSeen = meshCoreTimeString();
  contact.lastRssi = rssi;
  contact.lastSnr = snr;
  contact.lastSeenMs = millis();
}

static int findMeshContactByIdOrName(const String &idOrName) {
  int idx = findMeshContactById(idOrName);
  if (idx >= 0) return idx;
  for (size_t i = 0; i < meshContactCount; ++i) {
    if (meshContacts[i].name == idOrName || meshContacts[i].shortName == idOrName) {
      return static_cast<int>(i);
    }
  }
  return -1;
}

static int findMeshDiscoveredById(const String &deviceId) {
  for (size_t i = 0; i < meshDiscoveredCount; ++i) {
    if (meshDiscovered[i].deviceId == deviceId) return static_cast<int>(i);
  }
  return -1;
}

static void rememberMeshDiscoveredContact(const String &deviceId, const String &name,
                                          bool hasGps, double lat, double lon,
                                          const String &rssi, const String &snr) {
  if (deviceId.length() == 0) return;
  int idx = findMeshDiscoveredById(deviceId);
  if (idx < 0) {
    if (meshDiscoveredCount >= kMeshDiscoveredCount) {
      for (size_t i = 1; i < kMeshDiscoveredCount; ++i) meshDiscovered[i - 1] = meshDiscovered[i];
      idx = static_cast<int>(kMeshDiscoveredCount - 1);
    } else {
      idx = static_cast<int>(meshDiscoveredCount++);
    }
  }
  MeshDiscoveredContact &peer = meshDiscovered[idx];
  peer.deviceId = deviceId;
  peer.name = name.length() ? name : deviceId.substring(0, 8);
  peer.shortName = peer.name.substring(0, min<size_t>(4, peer.name.length()));
  peer.lastSeenMs = millis();
  peer.lastRssi = rssi;
  peer.lastSnr = snr;
  peer.hasGps = hasGps;
  if (hasGps) {
    peer.lat = lat;
    peer.lon = lon;
    mapOverlayDirty = true;
    responderDirty = true;
  }
  if (meshContactSelected >= static_cast<int>(meshDiscoveredCount)) {
    meshContactSelected = meshDiscoveredCount == 0 ? 0 : static_cast<int>(meshDiscoveredCount) - 1;
  }
  waypointsDirty = true;
}

static bool addDiscoveredMeshContact(int index) {
  if (index < 0 || index >= static_cast<int>(meshDiscoveredCount)) {
    loraStatus = "NO DISCOVERED CONTACT";
    return false;
  }
  const MeshDiscoveredContact &peer = meshDiscovered[index];
  int idx = ensureMeshContact(peer.deviceId, peer.name);
  if (idx < 0) {
    loraStatus = "CONTACT LIST FULL";
    return false;
  }
  MeshContact &contact = meshContacts[idx];
  contact.name = peer.name;
  contact.shortName = peer.shortName;
  contact.deviceId = peer.deviceId;
  contact.lastRssi = peer.lastRssi;
  contact.lastSnr = peer.lastSnr;
  contact.lastSeen = meshCoreTimeString();
  contact.lastSeenMs = peer.lastSeenMs ? peer.lastSeenMs : millis();
  if (peer.hasGps) {
    contact.hasGps = true;
    contact.lat = peer.lat;
    contact.lon = peer.lon;
    contact.lastGpsMs = contact.lastSeenMs;
  }
  meshContactSelected = idx;
  meshChatSelected = idx;
  saveMeshSettings();
  loraStatus = "CONTACT ADDED";
  return true;
}

static void updateMeshContactTelemetry(int idx, double lat, double lon, bool hasGps, int battery,
                                       const String &rssi, const String &snr) {
  if (idx < 0 || idx >= static_cast<int>(meshContactCount)) return;
  MeshContact &contact = meshContacts[idx];
  bool shouldPersist = false;
  contact.lastSeen = meshCoreTimeString();
  contact.lastSeenMs = millis();
  if (rssi.length()) contact.lastRssi = rssi;
  if (snr.length()) contact.lastSnr = snr;
  if (hasGps) {
    double oldLat = contact.lat;
    double oldLon = contact.lon;
    bool hadGps = contact.hasGps;
    contact.lat = lat;
    contact.lon = lon;
    contact.hasGps = true;
    contact.lastGpsMs = millis();
    if (!hadGps || fabs(oldLat - lat) > 0.00001 || fabs(oldLon - lon) > 0.00001) {
      shouldPersist = true;
    }
    mapDirty = true;
    mapOverlayDirty = true;
    responderDirty = true;
  }
  if (battery >= 0 && contact.battery != battery) {
    contact.battery = battery;
    shouldPersist = true;
  }
  static uint32_t lastTelemetrySaveMs = 0;
  uint32_t now = millis();
  if (shouldPersist && (lastTelemetrySaveMs == 0 || now - lastTelemetrySaveMs > 30000U)) {
    saveMeshSettings();
    lastTelemetrySaveMs = now;
  }
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex) {
    waypointsDirty = true;
  }
}

static String formatMeshAge(uint32_t sinceMs) {
  if (sinceMs == 0) return "never";
  uint32_t age = (millis() - sinceMs) / 1000U;
  if (age < 60) return String(age) + "s";
  if (age < 3600) return String(age / 60U) + "m";
  return String(age / 3600U) + "h";
}

static bool parseMeshTelemetryText(const String &text, double &lat, double &lon,
                                   bool &hasGps, int &battery) {
  String upper = text;
  upper.toUpperCase();
  hasGps = false;
  battery = -1;
  int latPos = upper.indexOf("LAT");
  int lonPos = upper.indexOf("LON");
  if (lonPos < 0) lonPos = upper.indexOf("LNG");
  if (latPos >= 0 && lonPos >= 0) {
    int latStart = text.indexOf(':', latPos);
    if (latStart < 0) latStart = text.indexOf('=', latPos);
    int lonStart = text.indexOf(':', lonPos);
    if (lonStart < 0) lonStart = text.indexOf('=', lonPos);
    if (latStart >= 0 && lonStart >= 0) {
      lat = text.substring(latStart + 1).toDouble();
      lon = text.substring(lonStart + 1).toDouble();
      hasGps = lat >= -90.0 && lat <= 90.0 && lon >= -180.0 && lon <= 180.0 &&
               (fabs(lat) > 0.000001 || fabs(lon) > 0.000001);
    }
  }
  int battPos = upper.indexOf("BATT");
  if (battPos < 0) battPos = upper.indexOf("BAT=");
  if (battPos >= 0) {
    int sep = text.indexOf(':', battPos);
    if (sep < 0) sep = text.indexOf('=', battPos);
    if (sep >= 0) battery = max<int>(0, min<int>(100, text.substring(sep + 1).toInt()));
  }
  return hasGps || battery >= 0 || upper.indexOf("TELEM") >= 0 || upper.indexOf("GPS") >= 0;
}

static void addMeshPacketRecord(const MeshPacketRecord &record) {
  if (meshPacketCount < kMeshPacketHistoryCount) {
    meshPackets[meshPacketCount++] = record;
  } else {
    for (size_t i = 1; i < kMeshPacketHistoryCount; ++i) meshPackets[i - 1] = meshPackets[i];
    meshPackets[kMeshPacketHistoryCount - 1] = record;
  }
  String line = record.timestamp + " " + record.sender + " ";
  if (record.type == "MESSAGE") line += record.text;
  else if (record.type == "TELEMETRY") line += "TELEMETRY " + record.detail;
  else if (record.type == "CONTACT") line += "CONTACT " + record.detail;
  else {
    line += "Packet detected - unsupported/unknown payload";
    if (record.detail.length()) line += " (" + record.detail + ")";
  }
  addLoraMessage(line);
}

static void refreshMeshExportText() {
  MeshNetworkPreset preset = activeMeshNetworkPreset();
  meshExportText = "MESHCONTACT|NAME=" + meshDeviceName + "|SHORT=" + meshShortName +
                   "|ID=" + meshDeviceId + "|NET=" + preset.name +
                   "|FREQ=" + String(preset.frequencyHz / 1000000.0, 3) +
                   "|SF=" + String(preset.spreadingFactor) +
                   "|CR=" + String(preset.displayCodingRate) +
                   "|BW=" + String(preset.bandwidthKhz);
}

static void loadMeshSettings() {
  prefs.begin("responder", true);
  meshDeviceName = prefs.getString("mesh_name", meshDeviceName);
  meshShortName = prefs.getString("mesh_short", meshShortName);
  meshDeviceId = prefs.getString("mesh_id", meshDeviceId);
  meshAutoAdvert = prefs.getBool("mesh_adv", meshAutoAdvert);
  bool meshLocMigrated = prefs.getBool("mesh_loc_v2", false);
  meshIncludeLocation = meshLocMigrated ? prefs.getBool("mesh_loc", meshIncludeLocation) : true;
  if (!meshLocMigrated) {
    prefs.putBool("mesh_loc", meshIncludeLocation);
    prefs.putBool("mesh_loc_v2", true);
  }
  meshCustomNetworkEnabled = prefs.getBool("mesh_cust_en", meshCustomNetworkEnabled);
  meshCustomNetwork.frequencyHz = prefs.getUInt("mesh_cfreq", meshCustomNetwork.frequencyHz);
  meshCustomNetwork.bandwidthKhz = prefs.getUShort("mesh_cbw", meshCustomNetwork.bandwidthKhz);
  meshCustomNetwork.spreadingFactor = prefs.getUChar("mesh_csf", meshCustomNetwork.spreadingFactor);
  meshCustomNetwork.displayCodingRate = prefs.getUChar("mesh_ccr", meshCustomNetwork.displayCodingRate);
  meshCustomNetwork.moduleCodingRate = 0;
  meshCustomNetwork.powerDbm = prefs.getUChar("mesh_cpwr", meshCustomNetwork.powerDbm);
  meshNetworkSelected = prefs.getInt("mesh_net", meshNetworkSelected);
  int maxNetworkIndex = static_cast<int>(kMeshNetworkPresetCount);
  if (meshNetworkSelected < 0 || meshNetworkSelected > maxNetworkIndex ||
      (meshNetworkSelected == maxNetworkIndex && !meshCustomNetworkEnabled)) {
    meshNetworkSelected = 0;
  }
  meshContactCount = prefs.getUChar("mesh_cc", 0);
  if (meshContactCount > kMeshContactCount) meshContactCount = kMeshContactCount;
  for (size_t i = 0; i < meshContactCount; ++i) {
    char key[16];
    snprintf(key, sizeof(key), "mc%un", static_cast<unsigned>(i));
    meshContacts[i].name = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mc%us", static_cast<unsigned>(i));
    meshContacts[i].shortName = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mc%ui", static_cast<unsigned>(i));
    meshContacts[i].deviceId = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mc%uo", static_cast<unsigned>(i));
    meshContacts[i].notes = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mc%ug", static_cast<unsigned>(i));
    meshContacts[i].hasGps = prefs.getBool(key, false);
    if (meshContacts[i].hasGps) {
      snprintf(key, sizeof(key), "mc%ula", static_cast<unsigned>(i));
      meshContacts[i].lat = static_cast<double>(prefs.getInt(key, 0)) / 1000000.0;
      snprintf(key, sizeof(key), "mc%ulo", static_cast<unsigned>(i));
      meshContacts[i].lon = static_cast<double>(prefs.getInt(key, 0)) / 1000000.0;
      meshContacts[i].lastSeen = "stored";
      meshContacts[i].lastSeenMs = millis();
      meshContacts[i].lastGpsMs = millis();
    }
    snprintf(key, sizeof(key), "mc%ub", static_cast<unsigned>(i));
    meshContacts[i].battery = prefs.getInt(key, -1);
    snprintf(key, sizeof(key), "mc%ur", static_cast<unsigned>(i));
    meshContacts[i].lastRssi = prefs.getString(key, "");
    snprintf(key, sizeof(key), "mc%uq", static_cast<unsigned>(i));
    meshContacts[i].lastSnr = prefs.getString(key, "");
  }
  prefs.end();
  if (meshDeviceName.length() == 0) meshDeviceName = "Tab5 Responder";
  if (meshShortName.length() == 0) meshShortName = "TAB5";
  if (meshDeviceId.length() == 0) meshDeviceId = "TAB5";
  refreshMeshExportText();
}

static void saveMeshSettings() {
  prefs.begin("responder", false);
  prefs.putString("mesh_name", meshDeviceName);
  prefs.putString("mesh_short", meshShortName);
  prefs.putString("mesh_id", meshDeviceId);
  prefs.putBool("mesh_adv", meshAutoAdvert);
  prefs.putBool("mesh_loc", meshIncludeLocation);
  prefs.putBool("mesh_loc_v2", true);
  prefs.putInt("mesh_net", meshNetworkSelected);
  prefs.putBool("mesh_cust_en", meshCustomNetworkEnabled);
  prefs.putUInt("mesh_cfreq", meshCustomNetwork.frequencyHz);
  prefs.putUShort("mesh_cbw", meshCustomNetwork.bandwidthKhz);
  prefs.putUChar("mesh_csf", meshCustomNetwork.spreadingFactor);
  prefs.putUChar("mesh_ccr", meshCustomNetwork.displayCodingRate);
  prefs.putUChar("mesh_cpwr", meshCustomNetwork.powerDbm);
  prefs.putUChar("mesh_cc", static_cast<uint8_t>(meshContactCount));
  for (size_t i = 0; i < kMeshContactCount; ++i) {
    char key[16];
    snprintf(key, sizeof(key), "mc%un", static_cast<unsigned>(i));
    prefs.putString(key, i < meshContactCount ? meshContacts[i].name : "");
    snprintf(key, sizeof(key), "mc%us", static_cast<unsigned>(i));
    prefs.putString(key, i < meshContactCount ? meshContacts[i].shortName : "");
    snprintf(key, sizeof(key), "mc%ui", static_cast<unsigned>(i));
    prefs.putString(key, i < meshContactCount ? meshContacts[i].deviceId : "");
    snprintf(key, sizeof(key), "mc%uo", static_cast<unsigned>(i));
    prefs.putString(key, i < meshContactCount ? meshContacts[i].notes : "");
    snprintf(key, sizeof(key), "mc%ug", static_cast<unsigned>(i));
    prefs.putBool(key, i < meshContactCount ? meshContacts[i].hasGps : false);
    snprintf(key, sizeof(key), "mc%ula", static_cast<unsigned>(i));
    prefs.putInt(key, (i < meshContactCount && meshContacts[i].hasGps)
                          ? static_cast<int32_t>(meshContacts[i].lat * 1000000.0)
                          : 0);
    snprintf(key, sizeof(key), "mc%ulo", static_cast<unsigned>(i));
    prefs.putInt(key, (i < meshContactCount && meshContacts[i].hasGps)
                          ? static_cast<int32_t>(meshContacts[i].lon * 1000000.0)
                          : 0);
    snprintf(key, sizeof(key), "mc%ub", static_cast<unsigned>(i));
    prefs.putInt(key, i < meshContactCount ? meshContacts[i].battery : -1);
    snprintf(key, sizeof(key), "mc%ur", static_cast<unsigned>(i));
    prefs.putString(key, i < meshContactCount ? meshContacts[i].lastRssi : "");
    snprintf(key, sizeof(key), "mc%uq", static_cast<unsigned>(i));
    prefs.putString(key, i < meshContactCount ? meshContacts[i].lastSnr : "");
  }
  prefs.end();
  refreshMeshExportText();
}

static void applyMeshIdentitySelection() {
  if (meshIdentityField == 0 && loraInput.length() > 0) {
    meshDeviceName = loraInput;
  } else if (meshIdentityField == 1 && loraInput.length() > 0) {
    meshShortName = loraInput;
  } else if (meshIdentityField == 2 && loraInput.length() > 0) {
    meshDeviceId = loraInput;
  } else if (meshIdentityField == 3) {
    meshAutoAdvert = !meshAutoAdvert;
  } else if (meshIdentityField == 4) {
    meshIncludeLocation = !meshIncludeLocation;
  }
  loraInput = "";
  saveMeshSettings();
  loraStatus = "IDENTITY SAVED";
  tab5MeshCoreAdvert(false);
}

static void applyMeshNetworkEditField() {
  if (loraInput.length() > 0) {
    if (meshNetworkEditField == 0) {
      double mhz = loraInput.toDouble();
      if (mhz > 100.0 && mhz < 1000.0) meshCustomNetwork.frequencyHz = static_cast<uint32_t>(mhz * 1000000.0);
      else {
        uint32_t hz = static_cast<uint32_t>(loraInput.toInt());
        if (hz > 100000000UL) meshCustomNetwork.frequencyHz = hz;
      }
    } else if (meshNetworkEditField == 1) {
      meshCustomNetwork.spreadingFactor = static_cast<uint8_t>(max<int>(5, min<int>(12, loraInput.toInt())));
    } else if (meshNetworkEditField == 2) {
      meshCustomNetwork.displayCodingRate = static_cast<uint8_t>(max<int>(5, min<int>(8, loraInput.toInt())));
    } else if (meshNetworkEditField == 3) {
      meshCustomNetwork.bandwidthKhz = static_cast<uint16_t>(max<int>(7, min<int>(500, loraInput.toInt())));
    } else if (meshNetworkEditField == 4) {
      meshCustomNetwork.powerDbm = static_cast<uint8_t>(max<int>(0, min<int>(22, loraInput.toInt())));
    }
  }
  meshCustomNetwork.moduleCodingRate = 0;
  meshCustomNetworkEnabled = true;
  meshNetworkSelected = static_cast<int>(kMeshNetworkPresetCount);
  loraInput = "";
  saveMeshSettings();
  beginLoraP2pConfiguration();
  loraStatus = "CUSTOM NETWORK SAVED";
}

static bool importMeshContactText(const String &raw) {
  String text = raw;
  text.trim();
  if (text.startsWith("ID ")) text.remove(0, 3);
  if (!text.startsWith("MESHCONTACT|")) {
    return false;
  }
  String name;
  String shortName;
  String id;
  int start = 0;
  while (start < static_cast<int>(text.length())) {
    int end = text.indexOf('|', start);
    if (end < 0) end = text.length();
    String part = text.substring(start, end);
    int eq = part.indexOf('=');
    if (eq > 0) {
      String key = part.substring(0, eq);
      String value = part.substring(eq + 1);
      key.toUpperCase();
      if (key == "NAME") name = value;
      else if (key == "SHORT") shortName = value;
      else if (key == "ID") id = value;
    }
    start = end + 1;
  }
  if (id.length() == 0) {
    loraStatus = "CONTACT IMPORT NEEDS ID";
    return false;
  }
  int idx = ensureMeshContact(id, name.length() ? name : id);
  if (idx < 0) {
    loraStatus = "CONTACT LIST FULL";
    return false;
  }
  MeshContact &contact = meshContacts[idx];
  if (name.length()) contact.name = name;
  if (shortName.length()) contact.shortName = shortName;
  contact.notes = "IMPORTED";
  saveMeshSettings();
  loraStatus = "CONTACT IMPORTED";
  return true;
}

static void addManualMeshContact() {
  if (meshContactCount >= kMeshContactCount) {
    loraStatus = "CONTACT LIST FULL";
    return;
  }
  String id = loraInput;
  id.trim();
  if (importMeshContactText(id)) {
    loraInput = "";
    return;
  }
  if (id.length() == 0) id = String("TDECK") + String(meshContactCount + 1);
  int idx = ensureMeshContact(id, id);
  if (idx >= 0) {
    loraInput = "";
    saveMeshSettings();
    loraStatus = "CONTACT ADDED";
  }
}

static void renameSelectedMeshContact() {
  if (meshContactSelected < 0 || meshContactSelected >= static_cast<int>(meshContactCount)) {
    loraStatus = "SELECT CONTACT";
    return;
  }
  String name = loraInput;
  name.trim();
  if (name.length() == 0) {
    loraStatus = "TYPE NEW NAME";
    return;
  }
  MeshContact &contact = meshContacts[meshContactSelected];
  contact.name = name;
  contact.notes = name;
  if (contact.shortName.length() == 0 || contact.shortName == contact.deviceId.substring(0, 4)) {
    contact.shortName = name.substring(0, min(static_cast<size_t>(4), name.length()));
  }
  loraInput = "";
  saveMeshSettings();
  loraStatus = "CONTACT RENAMED";
}

static void deleteSelectedMeshContact() {
  if (meshContactSelected < 0 || meshContactSelected >= static_cast<int>(meshContactCount)) {
    loraStatus = "SELECT CONTACT";
    return;
  }
  for (size_t i = static_cast<size_t>(meshContactSelected) + 1; i < meshContactCount; ++i) {
    meshContacts[i - 1] = meshContacts[i];
  }
  if (meshContactCount > 0) {
    --meshContactCount;
    meshContacts[meshContactCount] = MeshContact();
  }
  if (meshContactCount == 0) meshContactSelected = 0;
  else if (meshContactSelected >= static_cast<int>(meshContactCount)) {
    meshContactSelected = static_cast<int>(meshContactCount) - 1;
  }
  if (meshChatSelected >= static_cast<int>(meshContactCount)) {
    meshChatSelected = -1;
  }
  if (meshMapFocusIndex == meshContactSelected || meshMapFocusIndex >= static_cast<int>(meshContactCount)) {
    meshMapFocusIndex = -1;
  }
  if (meshNavTargetIndex == meshContactSelected || meshNavTargetIndex >= static_cast<int>(meshContactCount)) {
    meshNavTargetIndex = -1;
  }
  saveMeshSettings();
  loraStatus = "CONTACT DELETED";
}

static bool focusSelectedMeshContactOnMap(bool navigate) {
  if (meshContactSelected < 0 || meshContactSelected >= static_cast<int>(meshContactCount)) {
    loraStatus = "NO CONTACT SELECTED";
    return false;
  }
  const MeshContact &contact = meshContacts[meshContactSelected];
  if (!contact.hasGps) {
    loraStatus = "CONTACT HAS NO TELEMETRY";
    return false;
  }
  meshMapFocusIndex = meshContactSelected;
  meshNavTargetIndex = navigate ? meshContactSelected : -1;
  mapNavTargetIndex = -1;
  mapCenterLat = contact.lat;
  mapCenterLon = contact.lon;
  mapCenterValid = true;
  mapFollowPaused = true;
  mapViewMode = MapViewMode::NAV;
  mapLookAheadDx = 0;
  mapLookAheadDy = 0;
  lastLookAheadMs = 0;
  lastMapHasFix = false;
  mapDirty = true;
  mapOverlayDirty = true;
  statusDirty = true;
  statusNeedsFullRedraw = true;
  mainNavDirty = true;
  enterMapScreen();
  mapTilesDrawn = false;
  lastMapTileViewValid = false;
  lastUiDraw = 0;
  return true;
}

static void sendMeshIdentityMessage(const char *scope) {
  String saved = loraInput;
  refreshMeshExportText();
  loraInput = String("ID ") + meshExportText;
  sendLoraTextMessage();
  loraStatus = String("ID SENT ") + scope;
  loraInput = saved;
}

static void purgeOldMeshContacts() {
  uint32_t now = millis();
  size_t write = 0;
  size_t removed = 0;
  for (size_t read = 0; read < meshContactCount; ++read) {
    bool old = meshContacts[read].lastSeenMs != 0 &&
               now - meshContacts[read].lastSeenMs >= 7UL * 24UL * 60UL * 60UL * 1000UL;
    bool keep = !old;
    if (keep) {
      if (write != read) meshContacts[write] = meshContacts[read];
      ++write;
    } else {
      ++removed;
    }
  }
  while (meshContactCount > write) {
    --meshContactCount;
    meshContacts[meshContactCount] = MeshContact();
  }
  if (meshContactSelected >= static_cast<int>(meshContactCount)) {
    meshContactSelected = meshContactCount == 0 ? 0 : static_cast<int>(meshContactCount) - 1;
  }
  if (meshChatSelected >= static_cast<int>(meshContactCount)) {
    meshChatSelected = -1;
  }
  saveMeshSettings();
  loraStatus = removed ? String("OLD CONTACTS DELETED ") + String(removed) : "NO OLD CONTACTS";
}

class Tab5MeshMillis : public mesh::MillisecondClock {
public:
  unsigned long getMillis() override { return millis(); }
};

class Tab5MeshRtc : public mesh::RTCClock {
public:
  uint32_t getCurrentTime() override { return meshCoreTimestamp(); }
  void setCurrentTime(uint32_t time) override {
    if (time >= 1577836800UL && time < 2524608000UL) {
      cachedEpochSeconds = time;
      cachedEpochValid = true;
      cachedEpochSetMs = millis();
      applyValidatedSystemEpoch(time);
      debugPrint("CLOCK: accepted MeshCore RTC sync epoch=%lu", static_cast<unsigned long>(time));
    } else {
      debugPrint("CLOCK: rejected MeshCore RTC epoch=%lu", static_cast<unsigned long>(time));
    }
  }
};

class Tab5MeshRng : public mesh::RNG {
public:
  void random(uint8_t *dest, size_t sz) override {
    for (size_t i = 0; i < sz; i += 4) {
      uint32_t r = esp_random();
      size_t n = min<size_t>(4, sz - i);
      memcpy(dest + i, &r, n);
    }
  }
};

class Tab5AtMeshRadio : public mesh::Radio {
  struct RxPacket {
    uint8_t bytes[MAX_TRANS_UNIT];
    uint8_t len = 0;
    float rssi = 0;
    float snr = 0;
  };
  RxPacket rxQueue[4];
  uint8_t rxHead = 0;
  uint8_t rxTail = 0;
  uint8_t rxCount = 0;
  bool txPending = false;
  bool txDone = false;
  uint32_t txStartedMs = 0;
  float lastRssi = 0;
  float lastSnr = 0;

public:
  void begin() override {
    if (wifiBootProfileMode) {
      debugPrint("MESHCORE: begin skipped in Wi-Fi profile");
      return;
    }
    initLoraPortA(false);
    if (!loraP2pConfigured && loraConfigStep == 0) beginLoraP2pConfiguration();
  }

  bool enqueueHex(const String &hex, const String &rssi, const String &snr) {
    if (rxCount >= 4) return false;
    RxPacket &slot = rxQueue[rxTail];
    size_t len = hexToBytes(hex, slot.bytes, sizeof(slot.bytes));
    if (len == 0 || len > MAX_TRANS_UNIT) return false;
    slot.len = static_cast<uint8_t>(len);
    slot.rssi = rssi.toFloat();
    slot.snr = snr.toFloat();
    rxTail = static_cast<uint8_t>((rxTail + 1) % 4);
    ++rxCount;
    return true;
  }

  int recvRaw(uint8_t *bytes, int sz) override {
    if (rxCount == 0) return 0;
    RxPacket &slot = rxQueue[rxHead];
    int n = min<int>(sz, slot.len);
    memcpy(bytes, slot.bytes, n);
    lastRssi = slot.rssi;
    lastSnr = slot.snr;
    rxHead = static_cast<uint8_t>((rxHead + 1) % 4);
    --rxCount;
    return n;
  }

  uint32_t getEstAirtimeFor(int lenBytes) override {
    MeshNetworkPreset preset = activeMeshNetworkPreset();
    uint32_t perByte = preset.spreadingFactor >= 12 ? 24 : preset.spreadingFactor >= 10 ? 14 : 8;
    return max<uint32_t>(250, 160 + static_cast<uint32_t>(max(1, lenBytes)) * perByte);
  }

  float packetScore(float snr, int packetLen) override {
    float sizePenalty = min<float>(20.0f, packetLen / 12.0f);
    return max<float>(0.1f, snr + 20.0f - sizePenalty);
  }

  bool startSendRaw(const uint8_t *bytes, int len) override {
    if (!loraP2pConfigured || loraCommandPending || txPending || len <= 0 || len > MAX_TRANS_UNIT) {
      return false;
    }
    String hex = bytesToHex(bytes, static_cast<size_t>(len));
    loraSerial.print("AT+PSEND=");
    loraSerial.print(hex);
    loraSerial.print("\r\n");
    txPending = true;
    txDone = false;
    txStartedMs = millis();
    loraStatus = "MESH TX";
    debugPrint("MESHCORE: tx raw len=%d", len);
    return true;
  }

  bool isSendComplete() override {
    if (!txPending) return true;
    if (txDone) return true;
    if (millis() - txStartedMs > 7000) {
      txDone = true;
      loraStatus = "MESH TX TIMEOUT";
    }
    return txDone;
  }

  void onSendFinished() override {
    txPending = false;
    txDone = false;
    loraStatus = "LISTENING";
  }

  void notifyTxDone(bool ok) {
    if (!txPending) return;
    txDone = true;
    loraStatus = ok ? "MESH TX DONE" : "MESH TX ERROR";
  }

  bool isInRecvMode() const override { return !txPending; }
  bool isReceiving() override { return false; }
  float getLastRSSI() const override { return lastRssi; }
  float getLastSNR() const override { return lastSnr; }
};

class Tab5MeshCoreNode : public BaseChatMesh {
public:
  Tab5MeshCoreNode(mesh::Radio &radio, mesh::MillisecondClock &ms, mesh::RNG &rng,
                   mesh::RTCClock &rtc, mesh::PacketManager &mgr, mesh::MeshTables &tables)
      : BaseChatMesh(radio, ms, rng, rtc, mgr, tables) {}

protected:
  bool isAutoAddEnabled() const override { return false; }
  bool shouldOverwriteWhenFull() const override { return true; }

  void onDiscoveredContact(ContactInfo &contact, bool isNew, uint8_t pathLen,
                           const uint8_t *path) override {
    char pubHex[PUB_KEY_SIZE * 2 + 1] = {};
    mesh::Utils::toHex(pubHex, contact.id.pub_key, PUB_KEY_SIZE);
    const String displayName = contact.name[0] ? String(contact.name) : String(pubHex).substring(0, 8);
    const bool hasGps = contact.gps_lat || contact.gps_lon;
    const double lat = hasGps ? contact.gps_lat / 1000000.0 : 0.0;
    const double lon = hasGps ? contact.gps_lon / 1000000.0 : 0.0;
    rememberMeshDiscoveredContact(pubHex, displayName, hasGps, lat, lon,
                                  meshCurrentRxRssi, meshCurrentRxSnr);
    int idx = findMeshContactById(pubHex);
    if (idx >= 0) {
      MeshContact &uiContact = meshContacts[idx];
      uiContact.name = displayName;
      uiContact.shortName = uiContact.name.substring(0, min<size_t>(4, uiContact.name.length()));
      uiContact.deviceId = pubHex;
      if (hasGps) {
        updateMeshContactTelemetry(idx, lat, lon, true, -1,
                                   meshCurrentRxRssi, meshCurrentRxSnr);
      } else {
        updateMeshContactTelemetry(idx, 0.0, 0.0, false, -1,
                                   meshCurrentRxRssi, meshCurrentRxSnr);
      }
      saveMeshSettings();
    }
    MeshPacketRecord record;
    record.timestamp = meshCoreTimeString();
    record.sender = displayName;
    record.rssi = meshCurrentRxRssi;
    record.snr = meshCurrentRxSnr;
    record.type = "CONTACT";
    record.detail = String(isNew ? "ADVERT NEW" : "ADVERT") + " hops=" + String(pathLen);
    record.text = pubHex;
    addMeshPacketRecord(record);
    loraStatus = "ADVERT RECEIVED";
  }

  ContactInfo *processAck(const uint8_t *data) override { return nullptr; }
  void onContactPathUpdated(const ContactInfo &contact) override {
    loraStatus = "PATH UPDATED";
  }

  void onMessageRecv(const ContactInfo &contact, mesh::Packet *pkt,
                     uint32_t senderTimestamp, const char *text) override {
    addIncomingText(contact.name, text, "MESSAGE", "DIRECT");
  }

  void onCommandDataRecv(const ContactInfo &contact, mesh::Packet *pkt,
                         uint32_t senderTimestamp, const char *text) override {
    addIncomingText(contact.name, text, "MESSAGE", "COMMAND");
  }

  void onSignedMessageRecv(const ContactInfo &contact, mesh::Packet *pkt,
                           uint32_t senderTimestamp, const uint8_t *senderPrefix,
                           const char *text) override {
    addIncomingText(contact.name, text, "MESSAGE", "SIGNED");
  }

  uint32_t calcFloodTimeoutMillisFor(uint32_t pktAirtimeMillis) const override {
    return max<uint32_t>(2000, pktAirtimeMillis * 6);
  }

  uint32_t calcDirectTimeoutMillisFor(uint32_t pktAirtimeMillis, uint8_t pathLen) const override {
    return max<uint32_t>(2500, pktAirtimeMillis * (4 + pathLen));
  }

  void onSendTimeout() override { loraStatus = "MESH SEND TIMEOUT"; }

  void onChannelMessageRecv(const mesh::GroupChannel &channel, mesh::Packet *pkt,
                            uint32_t timestamp, const char *text) override {
    MeshPacketRecord record;
    record.timestamp = meshCoreTimeString();
    record.sender = "PUBLIC";
    record.rssi = String(pkt ? pkt->getSNR() : 0, 1);
    record.snr = "";
    record.type = "MESSAGE";
    record.detail = "CHANNEL";
    record.text = text ? String(text) : "";
    addMeshPacketRecord(record);
    loraStatus = "CHANNEL MESSAGE";
  }

  void onChannelDataRecv(const mesh::GroupChannel &channel, mesh::Packet *pkt,
                         uint16_t dataType, const uint8_t *data, size_t dataLen) override {
    MeshPacketRecord record;
    record.timestamp = meshCoreTimeString();
    record.sender = "PUBLIC";
    record.type = dataType == DATA_TYPE_DEV ? "TELEMETRY" : "UNSUPPORTED";
    record.detail = String("GROUP DATA ") + String(dataType) + " " + String(dataLen) + "B";
    record.text = "Packet detected - unsupported/unknown payload";
    if (data && dataLen > 0 && dataLen < 120) {
      String text;
      bool printable = true;
      for (size_t i = 0; i < dataLen; ++i) {
        if (data[i] == 0) break;
        if (data[i] < 9 || (data[i] > 13 && data[i] < 32) || data[i] > 126) {
          printable = false;
          break;
        }
        text += static_cast<char>(data[i]);
      }
      double lat = 0.0;
      double lon = 0.0;
      bool hasGps = false;
      int battery = -1;
      if (printable && parseMeshTelemetryText(text, lat, lon, hasGps, battery)) {
        record.text = text;
        record.detail = text;
        int idx = meshChatSelected >= 0 ? meshChatSelected : -1;
        if (idx >= 0 && idx < static_cast<int>(meshContactCount)) {
          updateMeshContactTelemetry(idx, lat, lon, hasGps, battery,
                                     meshCurrentRxRssi, meshCurrentRxSnr);
        }
      }
    }
    addMeshPacketRecord(record);
  }

  uint8_t onContactRequest(const ContactInfo &contact, uint32_t senderTimestamp,
                           const uint8_t *data, uint8_t len, uint8_t *reply) override {
    return 0;
  }

  void onContactResponse(const ContactInfo &contact, const uint8_t *data, uint8_t len) override {}

private:
  void addIncomingText(const char *sender, const char *text, const char *type, const char *detail) {
    MeshPacketRecord record;
    record.timestamp = meshCoreTimeString();
    record.sender = sender && sender[0] ? String(sender) : "UNKNOWN";
    record.rssi = "";
    record.snr = "";
    record.type = type;
    record.detail = detail;
    record.text = text ? String(text) : "";
    addMeshPacketRecord(record);
    updateMeshContactSeen(record.sender, record.sender, record.rssi, record.snr);
    loraStatus = "MESSAGE RECEIVED";
  }
};

static Tab5MeshMillis tab5MeshMillis;
static Tab5MeshRtc tab5MeshRtc;
static Tab5MeshRng tab5MeshRng;
static Tab5AtMeshRadio tab5MeshRadio;
static SimpleMeshTables tab5MeshTables;
static StaticPoolPacketManager tab5MeshPackets(24);
static Tab5MeshCoreNode tab5MeshNode(tab5MeshRadio, tab5MeshMillis, tab5MeshRng, tab5MeshRtc,
                                     tab5MeshPackets, tab5MeshTables);
static ChannelDetails *tab5PublicChannel = nullptr;
static bool tab5MeshStarted = false;
static uint32_t tab5LastAdvertMs = 0;
static double tab5LastAdvertLat = 0.0;
static double tab5LastAdvertLon = 0.0;
static bool tab5LastAdvertHadGps = false;

static bool meshContactToContactInfo(const MeshContact &src, ContactInfo &dest) {
  if (src.deviceId.length() != PUB_KEY_SIZE * 2) return false;
  memset(&dest, 0, sizeof(dest));
  if (!mesh::Utils::fromHex(dest.id.pub_key, PUB_KEY_SIZE, src.deviceId.c_str())) return false;
  StrHelper::strncpy(dest.name, src.name.c_str(), sizeof(dest.name));
  dest.type = ADV_TYPE_CHAT;
  dest.out_path_len = OUT_PATH_UNKNOWN;
  if (src.hasGps) {
    dest.gps_lat = static_cast<int32_t>(src.lat * 1000000.0);
    dest.gps_lon = static_cast<int32_t>(src.lon * 1000000.0);
  }
  return true;
}

static void tab5MeshLoadIdentity() {
  prefs.begin("responder", false);
  String keyHex = prefs.getString("mesh_key", "");
  prefs.end();
  uint8_t raw[PRV_KEY_SIZE + PUB_KEY_SIZE] = {};
  if (keyHex.length() == (PRV_KEY_SIZE + PUB_KEY_SIZE) * 2 &&
      hexToBytes(keyHex, raw, sizeof(raw)) == sizeof(raw)) {
    tab5MeshNode.self_id.readFrom(raw, sizeof(raw));
  } else {
    mesh::LocalIdentity generated(&tab5MeshRng);
    tab5MeshNode.self_id = generated;
    size_t len = tab5MeshNode.self_id.writeTo(raw, sizeof(raw));
    prefs.begin("responder", false);
    prefs.putString("mesh_key", bytesToHex(raw, len));
    prefs.end();
  }
  char pubHex[PUB_KEY_SIZE * 2 + 1] = {};
  mesh::Utils::toHex(pubHex, tab5MeshNode.self_id.pub_key, PUB_KEY_SIZE);
  meshDeviceId = pubHex;
  refreshMeshExportText();
  saveMeshSettings();
}

void tab5MeshCoreBegin() {
  if (tab5MeshStarted) return;
  tab5MeshLoadIdentity();
  tab5PublicChannel = tab5MeshNode.addChannel("Public", "izOH6cXN6mrJ5e26oRXNcg==");
  for (size_t i = 0; i < meshContactCount; ++i) {
    ContactInfo contact;
    if (meshContactToContactInfo(meshContacts[i], contact)) {
      tab5MeshNode.addContact(contact);
    }
  }
  tab5MeshNode.begin();
  tab5MeshStarted = true;
  loraStatus = tab5PublicChannel ? "MESHCORE READY" : "MESHCORE NO CHANNEL";
}

static void tab5MeshCoreAdvert(bool flood) {
  if (!tab5MeshStarted) return;
  mesh::Packet *packet = nullptr;
  double lat = 0.0;
  double lon = 0.0;
  if (meshIncludeLocation && getMeshAdvertLocation(lat, lon)) {
    packet = tab5MeshNode.createSelfAdvert(meshDeviceName.c_str(), lat, lon);
  }
  else packet = tab5MeshNode.createSelfAdvert(meshDeviceName.c_str());
  if (!packet) return;
  if (flood) tab5MeshNode.sendFlood(packet);
  else tab5MeshNode.sendZeroHop(packet);
  loraStatus = flood ? "ADVERT FLOOD QUEUED" : "ADVERT LOCAL QUEUED";
}

void tab5MeshCoreLoop(uint32_t now) {
  if (!tab5MeshStarted) return;
  tab5MeshNode.loop();
  double lat = 0.0;
  double lon = 0.0;
  bool hasGps = meshIncludeLocation && getMeshAdvertLocation(lat, lon);
  bool gpsMoved = hasGps && (!tab5LastAdvertHadGps ||
                             fabs(lat - tab5LastAdvertLat) > 0.00005 ||
                             fabs(lon - tab5LastAdvertLon) > 0.00005);
  uint32_t intervalMs = gpsMoved ? 15000UL : 60000UL;
  if (meshAutoAdvert && loraP2pConfigured &&
      (tab5LastAdvertMs == 0 || now - tab5LastAdvertMs > intervalMs)) {
    tab5LastAdvertMs = now;
    tab5LastAdvertHadGps = hasGps;
    if (hasGps) {
      tab5LastAdvertLat = lat;
      tab5LastAdvertLon = lon;
    }
    tab5MeshCoreAdvert(false);
  }
}

bool tab5MeshCoreHandleRx(const String &payloadHex, const String &rssi, const String &snr) {
  if (!tab5MeshStarted) return false;
  size_t before = meshPacketCount;
  if (!tab5MeshRadio.enqueueHex(payloadHex, rssi, snr)) return false;
  meshCurrentRxRssi = rssi;
  meshCurrentRxSnr = snr;
  tab5MeshNode.loop();
  return meshPacketCount != before;
}

void tab5MeshCoreNotifyTxDone(bool ok) {
  tab5MeshRadio.notifyTxDone(ok);
}

static void activateMeshMenuItem() {
  switch (meshMenuSelected) {
    case 0: loraView = LORA_VIEW_MESSAGES; break;
    case 1: loraView = LORA_VIEW_DISCOVER; break;
    case 2: loraView = LORA_VIEW_IDENTITY; break;
    case 3: loraView = LORA_VIEW_RADIO; break;
    case 4: loraView = LORA_VIEW_CONTACTS; break;
    default: loraView = LORA_VIEW_MESSAGES; break;
  }
  loraInput = "";
}

static void activateMeshDiscoverItem() {
  switch (meshDiscoverSelected) {
    case 0:
      beginLoraP2pConfiguration();
      tab5MeshCoreBegin();
      tab5MeshCoreAdvert(false);
      loraStatus = "DISCOVER ID SENT";
      break;
    case 1:
      tab5MeshCoreBegin();
      tab5MeshCoreAdvert(false);
      break;
    case 2:
      tab5MeshCoreBegin();
      tab5MeshCoreAdvert(true);
      break;
    case 3:
      addDiscoveredMeshContact(meshContactSelected);
      break;
    case 4:
      purgeOldMeshContacts();
      break;
    default:
      break;
  }
}

static String encodeMeshCorePublicMessage(const String &message) {
  String sender = meshShortName.length() ? meshShortName : String(kMeshCoreNodeName);
  String body = sender + ": " + message;
  if (body.length() > 128) {
    body.remove(128);
  }
  uint8_t plaintext[160] = {};
  uint32_t timestamp = meshCoreTimestamp();
  memcpy(plaintext, &timestamp, sizeof(timestamp));
  plaintext[4] = 0;  // plain group text, first attempt
  memcpy(plaintext + 5, body.c_str(), body.length());
  size_t plaintextLen = 5 + body.length();
  size_t cipherLen = (plaintextLen + kMeshCoreBlockBytes - 1) & ~(kMeshCoreBlockBytes - 1);
  uint8_t ciphertext[160] = {};
  if (!meshCoreCryptBlocks(true, plaintext, ciphertext, cipherLen)) {
    return String();
  }
  uint8_t mac[32];
  if (!meshCoreMac(ciphertext, cipherLen, mac)) {
    return String();
  }
  uint8_t packet[kMeshCoreMaxPacketBytes] = {};
  size_t pos = 0;
  packet[pos++] = kMeshCoreGroupTextHeader;
  packet[pos++] = 0;  // flood route with no hops yet
  packet[pos++] = kMeshCorePublicChannelHash;
  packet[pos++] = mac[0];
  packet[pos++] = mac[1];
  memcpy(packet + pos, ciphertext, cipherLen);
  pos += cipherLen;
  return bytesToHex(packet, pos);
}

static bool decodeMeshCorePublicMessageDetailed(const String &hex, MeshPacketRecord &record) {
  // TODO: Wire this to MeshCore's upstream packet/companion structures for signed
  // adverts, direct messages, queued channel messages, and telemetry responses.
  // This decoder only handles the local public-channel encrypted text format used
  // by this firmware and returns false for unsupported packets.
  uint8_t packet[kMeshCoreMaxPacketBytes];
  size_t packetLen = hexToBytes(hex, packet, sizeof(packet));
  if (packetLen < 7 || ((packet[0] >> 2) & 0x0F) != 0x05) {
    return false;
  }
  size_t pos = 1;
  uint8_t route = packet[0] & 0x03;
  if (route == 0x00 || route == 0x03) {
    if (packetLen < pos + 4) return false;
    pos += 4;
  }
  if (packetLen <= pos) return false;
  uint8_t pathMeta = packet[pos++];
  uint8_t hashSize = static_cast<uint8_t>((pathMeta >> 6) + 1);
  uint8_t hopCount = pathMeta & 0x3F;
  size_t pathBytes = static_cast<size_t>(hashSize) * hopCount;
  if (hashSize > 3 || packetLen < pos + pathBytes + 3) return false;
  pos += pathBytes;
  if (packet[pos++] != kMeshCorePublicChannelHash) return false;
  uint8_t receivedMac[2] = {packet[pos], packet[pos + 1]};
  pos += 2;
  size_t cipherLen = packetLen - pos;
  if (cipherLen == 0 || (cipherLen % kMeshCoreBlockBytes) != 0 || cipherLen > 160) {
    return false;
  }
  uint8_t mac[32];
  if (!meshCoreMac(packet + pos, cipherLen, mac) || receivedMac[0] != mac[0] ||
      receivedMac[1] != mac[1]) {
    return false;
  }
  uint8_t plaintext[161] = {};
  if (!meshCoreCryptBlocks(false, packet + pos, plaintext, cipherLen)) {
    return false;
  }
  if (cipherLen <= 5) return false;
  size_t textLen = cipherLen - 5;
  while (textLen > 0 && plaintext[5 + textLen - 1] == 0) {
    --textLen;
  }
  for (size_t i = 0; i < textLen; ++i) {
    if (plaintext[5 + i] < 32 || plaintext[5 + i] >= 127) {
      return false;
    }
  }
  String text = String(reinterpret_cast<const char *>(plaintext + 5)).substring(0, textLen);
  text.trim();
  if (text.length() == 0) return false;
  record.text = text;
  String sender = "UNKNOWN";
  int colon = text.indexOf(':');
  if (colon > 0 && colon <= 24) {
    sender = text.substring(0, colon);
    sender.trim();
  }
  record.sender = sender.length() ? sender : "UNKNOWN";
  double lat = 0.0;
  double lon = 0.0;
  bool hasGps = false;
  int battery = -1;
  int contactTextPos = text.indexOf("MESHCONTACT|");
  if (contactTextPos >= 0) {
    // TODO: Replace this local text-card import with true MeshCore advert parsing
    // when the signed advert packet fields are wired into this firmware.
    record.type = "CONTACT";
    record.detail = "CONTACT CARD";
    importMeshContactText(text.substring(contactTextPos));
  } else if (parseMeshTelemetryText(text, lat, lon, hasGps, battery)) {
    record.type = "TELEMETRY";
    record.detail = "";
    if (hasGps) record.detail += String(lat, 5) + "," + String(lon, 5);
    if (battery >= 0) {
      if (record.detail.length()) record.detail += " ";
      record.detail += "BATT " + String(battery) + "%";
    }
    if (record.sender != "UNKNOWN") {
      int idx = findMeshContactByIdOrName(record.sender);
      updateMeshContactTelemetry(idx, lat, lon, hasGps, battery, record.rssi, record.snr);
    }
  } else {
    record.type = "MESSAGE";
    record.detail = "TEXT";
  }
  return true;
}

static bool decodeMeshCorePublicMessage(const String &hex, String &message) {
  MeshPacketRecord record;
  if (!decodeMeshCorePublicMessageDetailed(hex, record) || record.text.length() == 0) return false;
  message = record.text;
  return true;
}

static void sendLoraCommand(const String &command) {
  if (!loraPortReady) {
    initLoraPortA(false);
  }
  loraSerial.print(command);
  loraSerial.print("\r\n");
  loraCommandPending = true;
  loraCommandMs = millis();
  debugPrint("LORA: tx %s", command.c_str());
}

static void sendLoraConfigStep() {
  switch (loraConfigStep) {
    case 1:
      sendLoraCommand("AT+PRECV=0");
      loraStatus = "STOP RX";
      break;
    case 2:
      sendLoraCommand("AT+NWM=0");
      loraStatus = "P2P MODE";
      break;
    case 3:
      {
        MeshNetworkPreset preset = activeMeshNetworkPreset();
        String moduleBandwidth = preset.bandwidthKhz == 62 ? "62.5" : String(preset.bandwidthKhz);
        sendLoraCommand(String("AT+P2P=") + String(preset.frequencyHz) + ":" +
                        String(preset.spreadingFactor) + ":" +
                        moduleBandwidth + ":" + String(preset.moduleCodingRate) + ":" +
                        String(kLoraP2pPreamble) + ":" + String(preset.powerDbm));
      }
      loraStatus = "RADIO CONFIG";
      break;
    case 4:
      sendLoraCommand("AT+PRECV=65533");
      loraStatus = "RX START";
      break;
    default:
      break;
  }
}

void beginLoraP2pConfiguration() {
  loraProbePending = false;
  loraP2pConfigured = false;
  loraConfigStep = 1;
  loraConfigRetries = 0;
  sendLoraConfigStep();
  waypointsDirty = true;
}

void ensureLoraP2pConfigured() {
  if (loraP2pConfigured) {
    loraStatus = "LISTENING";
    waypointsDirty = true;
    return;
  }
  if (loraConfigStep == 0) {
    beginLoraP2pConfiguration();
  }
}

void sendLoraTextMessage() {
  loraInput.trim();
  if (loraInput.length() == 0) {
    return;
  }
  tab5MeshCoreBegin();
  if (!loraP2pConfigured) {
    loraStatus = "CONFIGURE FIRST";
    beginLoraP2pConfiguration();
    return;
  }
  String message = loraInput.substring(0, 96);
  auto recordSentMessage = [&](const String &detail) {
    MeshPacketRecord record;
    record.sender = "YOU";
    record.timestamp = meshCoreTimeString();
    record.rssi = "--";
    record.snr = "--";
    record.text = message;
    record.type = "MESSAGE";
    record.detail = detail;
    addMeshPacketRecord(record);
  };
  if (tab5MeshStarted) {
    if (meshChatSelected >= 0 && meshChatSelected < static_cast<int>(meshContactCount)) {
      ContactInfo contact;
      if (!meshContactToContactInfo(meshContacts[meshChatSelected], contact)) {
        loraStatus = "CONTACT NEEDS PUBLIC KEY";
        return;
      }
      tab5MeshNode.addContact(contact);
      uint32_t expectedAck = 0;
      uint32_t estTimeout = 0;
      int rc = tab5MeshNode.sendMessage(contact, meshCoreTimestamp(), 0, message.c_str(),
                                        expectedAck, estTimeout);
      loraStatus = rc == MSG_SEND_FAILED ? "DIRECT SEND FAILED" : "DIRECT QUEUED";
      if (rc != MSG_SEND_FAILED) recordSentMessage("DIRECT TX");
      loraInput = "";
      waypointsDirty = true;
      return;
    }
    if (tab5PublicChannel &&
        tab5MeshNode.sendGroupMessage(meshCoreTimestamp(), tab5PublicChannel->channel,
                                      meshShortName.c_str(), message.c_str(), message.length())) {
      loraStatus = "PUBLIC QUEUED";
      recordSentMessage("PUBLIC TX");
      loraInput = "";
      waypointsDirty = true;
      return;
    }
  }
  String packet = encodeMeshCorePublicMessage(message);
  if (packet.length() == 0) {
    loraStatus = "ENCODE ERROR";
    addLoraMessage("MESHCORE ENCODE ERROR");
    return;
  }
  sendLoraCommand(String("AT+PSEND=") + packet);
  recordSentMessage("PUBLIC TX");
  loraInput = "";
  loraStatus = "TRANSMITTING";
  waypointsDirty = true;
}

void initLoraPortA(bool force) {
  if (wifiBootProfileMode && !force) {
    return;
  }
  if (loraPortReady && !force) {
    return;
  }
  if (force && loraPortReady) {
    loraSerial.end();
    delay(20);
  }
  loraSerial.begin(kLoraBaud, SERIAL_8N1, kLoraPortARxPin, kLoraPortATxPin);
  loraSerial.setTimeout(5);
  loraPortReady = true;
  loraProbePending = true;
  loraLastProbeMs = 0;
  loraRxLine = "";
  loraConfigStep = 0;
  loraConfigRetries = 0;
  loraCommandPending = false;
  loraP2pConfigured = false;
  loraStatus = "PROBING";
  debugPrint("LORA: PortA UART begin rx=%d tx=%d baud=%lu", kLoraPortARxPin,
             kLoraPortATxPin, static_cast<unsigned long>(kLoraBaud));
}

static void sendLoraAtProbe() {
  if (wifiBootProfileMode) {
    return;
  }
  if (!loraPortReady) {
    initLoraPortA(false);
  }
  loraSerial.print("AT\r\n");
  loraLastProbeMs = millis();
  loraProbePending = true;
  debugPrint("LORA: tx AT PortA");
}

void pollLoraPortA(uint32_t now) {
  if (wifiBootProfileMode) {
    return;
  }
  if (!loraPortReady) {
    initLoraPortA(false);
  }
  if (loraConfigStep != 0 && loraCommandPending && now - loraCommandMs >= 7000) {
    loraCommandPending = false;
    if (++loraConfigRetries <= 2) {
      sendLoraConfigStep();
    } else {
      loraStatus = "CONFIG TIMEOUT";
      loraConfigStep = 0;
      addLoraMessage("RADIO CONFIG TIMEOUT");
    }
  }
  if (loraConfigStep == 0 && loraProbePending &&
      (loraLastProbeMs == 0 || now - loraLastProbeMs >= 5000)) {
    sendLoraAtProbe();
  }
  while (loraSerial.available() > 0) {
    char c = static_cast<char>(loraSerial.read());
    if (c == '\r') {
      continue;
    }
    if (c == '\n') {
      if (loraRxLine.length() > 0) {
        debugPrint("LORA: rx %s", loraRxLine.c_str());
        String line = loraRxLine;
        loraRxLine = "";
        loraLastRxMs = now;
        if (line == "OK") {
          loraProbePending = false;
          loraCommandPending = false;
          loraConfigRetries = 0;
          if (loraConfigStep > 0 && loraConfigStep < 4) {
            ++loraConfigStep;
            sendLoraConfigStep();
          } else if (loraConfigStep == 4) {
            loraConfigStep = 0;
            loraP2pConfigured = true;
            loraStatus = "LISTENING";
            addLoraMessage("RADIO READY 915.000");
          } else if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex &&
                     !loraP2pConfigured) {
            beginLoraP2pConfiguration();
          } else {
            loraStatus = "MODULE READY";
          }
        } else if (line.startsWith("+EVT:RXP2P:")) {
          int first = line.indexOf(':', 11);
          int second = first >= 0 ? line.indexOf(':', first + 1) : -1;
          if (first > 0 && second > first) {
            String rssi = line.substring(11, first);
            String snr = line.substring(first + 1, second);
            String payloadHex = line.substring(second + 1);
            bool decodedByRealMesh = tab5MeshCoreHandleRx(payloadHex, rssi, snr);
            MeshPacketRecord record;
            record.timestamp = meshCoreTimeString(now);
            record.rssi = rssi;
            record.snr = snr;
            if (decodedByRealMesh) {
              loraStatus = "MESH PACKET DECODED";
              continue;
            } else if (decodeMeshCorePublicMessageDetailed(payloadHex, record)) {
              if (record.sender.length() == 0) record.sender = "UNKNOWN";
            } else {
              record.sender = meshCorePacketId(payloadHex);
              record.type = "UNSUPPORTED";
              record.text = "Packet detected - unsupported/unknown payload";
              record.detail = classifyMeshCorePacketHeader(payloadHex);
            }
            if ((record.type == "MESSAGE" || record.type == "TELEMETRY" || record.type == "CONTACT") &&
                record.sender.length() > 0 && record.sender != "UNKNOWN") {
              updateMeshContactSeen(record.sender, record.sender, rssi, snr);
            }
            addMeshPacketRecord(record);
          }
          loraStatus = "PACKET RECEIVED";
        } else if (line.startsWith("+EVT:TXP2P")) {
          loraCommandPending = false;
          tab5MeshCoreNotifyTxDone(line.indexOf("DONE") >= 0);
          loraStatus = line.indexOf("DONE") >= 0 ? "LISTENING" : "TX ERROR";
        } else if (line.indexOf("ERROR") >= 0) {
          loraCommandPending = false;
          if (loraConfigStep != 0 && ++loraConfigRetries <= 2) {
            loraStatus = String("RETRY STEP ") + String(loraConfigStep);
            sendLoraConfigStep();
          } else if (loraP2pConfigured) {
            loraStatus = "LISTENING";
          } else {
            loraStatus = String("RADIO ERROR S") + String(loraConfigStep);
            loraConfigStep = 0;
          }
          addLoraMessage(line);
        }
        if (screen == SCREEN_WAYPOINTS && appSelected == kAppLoraIndex) {
          waypointsDirty = true;
        }
      }
      continue;
    }
    if (c >= 32 && c < 127 && loraRxLine.length() < 1100) {
      loraRxLine += c;
    }
  }
}

void resetRfFmTuningDefaults() {
  rfFmTuneParam = RF_FM_TUNE_GAIN;
  rfFmBassCut = 4;
  rfFmPreClean = 2;
  rfFmPostClean = 2;
  rfFmDemodGain = 6;
  rfFmTunerGainIndex = 0;
  rfFmBandwidthIndex = 1;
  logRfFmTune();
  resetRfAudioDemod();
  setAppToast("FM TUNE RESET");
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppRfScanIndex) {
    waypointsDirty = true;
  }
}

void pushBootSerialLine(const char *line) {
  if (!line) {
    return;
  }
  size_t idx = bootSerialIndex % kBootSerialLines;
  memset(bootSerialLines[idx], 0, kBootSerialLineLen);
  strncpy(bootSerialLines[idx], line, kBootSerialLineLen - 1);
  bootSerialIndex = (bootSerialIndex + 1) % kBootSerialLines;
  if (bootSerialCount < kBootSerialLines) {
    bootSerialCount++;
  }
  bootSerialDirty = true;
  if (displayReady && screen == SCREEN_BOOT) {
    drawBootSerialCube();
    bootSerialDirty = false;
  }
}

void drawBootSerialCube() {
  int16_t cubeX = 12;
  int16_t cubeY = 12;
  int16_t boxW = 180;
  int16_t boxH = 52;
  M5.Display.fillRect(cubeX, cubeY, boxW, boxH, colors.black);
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(1);
  M5.Display.setTextColor(colors.amber, colors.black);
  int16_t textX = static_cast<int16_t>(cubeX + 4);
  int16_t textY = static_cast<int16_t>(cubeY + 4);
  size_t count = min(bootSerialCount, kBootSerialLines);
  size_t start = (bootSerialIndex + kBootSerialLines - count) % kBootSerialLines;
  for (size_t i = 0; i < count; ++i) {
    size_t idx = (start + i) % kBootSerialLines;
    M5.Display.drawString(bootSerialLines[idx], textX, textY);
    textY = static_cast<int16_t>(textY + M5.Display.fontHeight());
    if (textY > cubeY + boxH - M5.Display.fontHeight()) {
      break;
    }
  }
}

void drawHeadingArrow(int16_t cx, int16_t cy, int16_t size) {
  int16_t baseR = max<int16_t>(4, size / 4);
  M5.Display.fillCircle(cx, cy, baseR, colors.red);
  for (int8_t i = 0; i < kMarkerOutlineThickness; ++i) {
    M5.Display.drawCircle(cx, cy, static_cast<int16_t>(baseR + i), colors.amber);
  }
}

bool drawMapTilesClipped(double centerLat, double centerLon, uint8_t zoom, const Rect &clip,
                         bool queueMissing) {
  if (!sdReady) {
    M5.Display.fillRect(clip.x, clip.y, clip.w, clip.h, colors.black);
    return true;
  }
  if (!lockSd(5)) {
    return false;
  }
  if (!SD.exists(tileRoot.c_str())) {
    unlockSd();
    M5.Display.fillRect(clip.x, clip.y, clip.w, clip.h, colors.black);
    return true;
  }
  if (mapViewMode == MapViewMode::NAV && !mapCenterValid &&
      !gps.location.isValid() && !lastGpsFixValid &&
      !isWifiGeoUsable()) {
    unlockSd();
    M5.Display.fillRect(clip.x, clip.y, clip.w, clip.h, colors.black);
    return true;
  }

  double centerPx = 0.0;
  double centerPy = 0.0;
  geoToWorldPixels(centerLat, centerLon, zoom, centerPx, centerPy);
  centerPx += mapLookAheadDx;
  centerPy += mapLookAheadDy;
  int tileCount = 1 << zoom;

  double left = centerPx - mapW / 2.0;
  double top = centerPy - mapH / 2.0;
  double world = 256.0 * tileCount;
  if (mapW > world) {
    left = (world - mapW) / 2.0;
  }
  if (mapH > world) {
    top = (world - mapH) / 2.0;
  }
  int startTileX = static_cast<int>(floor(left / 256.0));
  int startTileY = static_cast<int>(floor(top / 256.0));
  int tilesX = mapW / 256 + 2;
  int tilesY = mapH / 256 + 2;

  int offsetX = static_cast<int>(-fmod(left, 256.0));
  int offsetY = static_cast<int>(-fmod(top, 256.0));

  char pathBuf[160] = {0};
  for (int ty = 0; ty < tilesY; ++ty) {
    for (int tx = 0; tx < tilesX; ++tx) {
      int tileX = startTileX + tx;
      int tileY = startTileY + ty;
      if (tileY < 0 || tileY >= tileCount) {
        continue;
      }
      int wrappedX = tileX % tileCount;
      if (wrappedX < 0) {
        wrappedX += tileCount;
      }
      int drawX = mapX + offsetX + tx * 256;
      int drawY = mapY + offsetY + ty * 256;
      int tileRight = drawX + 256;
      int tileBottom = drawY + 256;
      if (drawX >= clip.x + clip.w || tileRight <= clip.x || drawY >= clip.y + clip.h ||
          tileBottom <= clip.y) {
        continue;
      }

      bool hasPath = buildTilePath(pathBuf, sizeof(pathBuf), zoom, wrappedX, tileY);
      bool drewTile = hasPath && drawPngFromSd(pathBuf, drawX, drawY);
      if (!drewTile) {
        M5.Display.fillRect(drawX, drawY, 256, 256, colors.black);
        M5.Display.drawRect(drawX, drawY, 256, 256, colors.amberDim);
        if (queueMissing && !mapDownload.active) {
          if (hasPath && SD.exists(pathBuf)) SD.remove(pathBuf);
          queueTileDownload(zoom, wrappedX, tileY, false);
        }
      }
    }
  }

  unlockSd();
  if (kReleaseMapPngDecoderAfterDraw) {
    M5.Display.releasePngMemory();
  }
  return true;
}

bool getGpsLocation(double &lat, double &lon) {
  if (gps.location.isValid()) {
    lat = gps.location.lat();
    lon = gps.location.lng();
    return true;
  }
  // Prefer a fresh network estimate over an arbitrarily old GPS hold.  Aircraft
  // and maps can therefore start immediately indoors, then switch to GPS on fix.
  if (isWifiGeoUsable()) {
    lat = wifiGeoLat;
    lon = wifiGeoLon;
    return true;
  }
  if (lastGpsFixValid) {
    lat = lastGpsFixLat;
    lon = lastGpsFixLon;
    return true;
  }
  return false;
}

bool getMeshAdvertLocation(double &lat, double &lon) {
  if (getGpsLocation(lat, lon)) {
    return true;
  }
  if (isWifiGeoUsable()) {
    lat = wifiGeoLat;
    lon = wifiGeoLon;
    return true;
  }
  return false;
}

bool getMapCenter(double &lat, double &lon) {
  if (mapCenterValid) {
    lat = mapCenterLat;
    lon = mapCenterLon;
    return true;
  }
  if (getGpsLocation(lat, lon)) {
    return true;
  }
  if (isWifiGeoUsable()) {
    lat = wifiGeoLat;
    lon = wifiGeoLon;
    return true;
  }
  return false;
}

static bool isMapArrowKey(uint8_t keycode) {
  return keycode == 0x4F || keycode == 0x50 || keycode == 0x51 || keycode == 0x52;
}

static void worldPixelsToGeo(double x, double y, uint8_t zoom, double &lat, double &lon) {
  double world = 256.0 * (1 << zoom);
  while (x < 0.0) x += world;
  while (x >= world) x -= world;
  y = max<double>(0.0, min<double>(world, y));
  lon = x / world * 360.0 - 180.0;
  double n = M_PI - 2.0 * M_PI * y / world;
  lat = atan(sinh(n)) * 180.0 / M_PI;
  lat = max<double>(-85.05112878, min<double>(85.05112878, lat));
}

static void recenterMapFollow() {
  mapPanHeldKey = 0;
  mapPanPendingKey = 0;
  mapPanLastStepMs = 0;
  mapPanLastHidMs = 0;
  mapPanReleaseGraceUntilMs = 0;
  mapPanCleanFrameReady = false;
  mapFollowPaused = false;
  mapCenterValid = false;
  lastMapHasFix = false;
  mapLookAheadDx = 0;
  mapLookAheadDy = 0;
  lastLookAheadMs = 0;
  arrowBackValid = false;
  mapDirty = true;
  mapOverlayDirty = false;
  statusDirty = true;
  debugPrint("MAP: recenter follow=1");
}

static Rect mapPanViewportRect() {
  Rect r = {mapX, mapY, mapW, mapH};
  int16_t controlX = screenW;
  if (isRectValid(zoomInButton)) controlX = min<int16_t>(controlX, zoomInButton.x);
  if (isRectValid(zoomOutButton)) controlX = min<int16_t>(controlX, zoomOutButton.x);
  if (isRectValid(zoomIndicatorRect)) controlX = min<int16_t>(controlX, zoomIndicatorRect.x);
  if (isRectValid(recordTripButton)) controlX = min<int16_t>(controlX, recordTripButton.x);
  if (isRectValid(recenterMapButton)) controlX = min<int16_t>(controlX, recenterMapButton.x);
  if (controlX > mapX + 64 && controlX < screenW) {
    r.w = static_cast<int16_t>(max<int>(64, controlX - mapX - 10));
  }
  return r;
}

static void redrawMapRightControlColumn() {
  int16_t controlX = screenW;
  if (isRectValid(zoomInButton)) controlX = min<int16_t>(controlX, zoomInButton.x);
  if (isRectValid(zoomOutButton)) controlX = min<int16_t>(controlX, zoomOutButton.x);
  if (isRectValid(zoomIndicatorRect)) controlX = min<int16_t>(controlX, zoomIndicatorRect.x);
  if (isRectValid(recordTripButton)) controlX = min<int16_t>(controlX, recordTripButton.x);
  if (isRectValid(recenterMapButton)) controlX = min<int16_t>(controlX, recenterMapButton.x);
  if (controlX >= screenW) return;
  controlX = max<int16_t>(mapX, static_cast<int16_t>(controlX - 10));
  M5.Display.fillRect(controlX, mapY, static_cast<int16_t>(screenW - controlX), mapH,
                      colors.black);
  M5.Display.drawRect(controlX, mapY, static_cast<int16_t>(screenW - controlX), mapH,
                      colors.amberDim);
  M5.Display.drawRect(static_cast<int16_t>(controlX + 3), static_cast<int16_t>(mapY + 3),
                      static_cast<int16_t>(screenW - controlX - 6),
                      static_cast<int16_t>(mapH - 6), colors.amberDim);
  drawZoomControls();
  drawRecordTripButton();
  drawRecenterMapButton();
}

static void invalidateMapTileCache() {
  for (auto &entry : mapTileCache) {
    entry.valid = false;
    entry.zoom = -1;
    entry.tileX = -1;
    entry.tileY = -1;
    entry.lastUse = 0;
  }
  mapTileCacheUseCounter = 0;
}

static void releaseMapRenderCanvas() {
  if (mapRenderCanvas) {
    mapRenderCanvas->deleteSprite();
    delete mapRenderCanvas;
    mapRenderCanvas = nullptr;
  }
  mapRenderCanvasW = 0;
  mapRenderCanvasH = 0;
  mapRenderCanvasValid = false;
}

static bool ensureMapRenderCanvas(const Rect &view) {
  if (!isRectValid(view)) return false;
  if (mapRenderCanvas && mapRenderCanvasW == view.w && mapRenderCanvasH == view.h) {
    return true;
  }
  releaseMapRenderCanvas();
  mapRenderCanvas = new (std::nothrow) M5Canvas(&M5.Display);
  if (!mapRenderCanvas) return false;
  mapRenderCanvas->setColorDepth(16);
  mapRenderCanvas->setPsram(true);
  if (!mapRenderCanvas->createSprite(view.w, view.h)) {
    releaseMapRenderCanvas();
    debugPrint("MAP: framebuffer alloc failed %dx%d", view.w, view.h);
    return false;
  }
  mapRenderCanvasW = view.w;
  mapRenderCanvasH = view.h;
  mapRenderCanvas->fillSprite(colors.black);
  mapRenderCanvas->setScrollRect(0, 0, view.w, view.h, colors.black);
  mapRenderCanvasValid = false;
  debugPrint("MAP: framebuffer ready %dx%d psram=%lu", view.w, view.h,
             static_cast<unsigned long>(heap_caps_get_free_size(MALLOC_CAP_SPIRAM)));
  return true;
}

static MapTileCacheEntry *selectMapTileCacheEntry(int zoom, int tileX, int tileY) {
  if (mapTileCacheRoot != tileRoot) {
    mapTileCacheRoot = tileRoot;
    invalidateMapTileCache();
  }
  for (auto &entry : mapTileCache) {
    if (entry.valid && entry.zoom == zoom && entry.tileX == tileX && entry.tileY == tileY) {
      entry.lastUse = ++mapTileCacheUseCounter;
      return &entry;
    }
  }
  MapTileCacheEntry *slot = nullptr;
  for (auto &entry : mapTileCache) {
    if (!entry.valid) {
      slot = &entry;
      break;
    }
    if (!slot || entry.lastUse < slot->lastUse) slot = &entry;
  }
  return slot;
}

static bool loadMapTileCacheEntry(MapTileCacheEntry &entry, const char *path,
                                  int zoom, int tileX, int tileY) {
  if (!entry.canvas) {
    entry.canvas = new (std::nothrow) M5Canvas(&M5.Display);
    if (!entry.canvas) return false;
    entry.canvas->setColorDepth(16);
    entry.canvas->setPsram(true);
    if (!entry.canvas->createSprite(256, 256)) {
      delete entry.canvas;
      entry.canvas = nullptr;
      return false;
    }
  }
  entry.valid = false;
  entry.canvas->fillSprite(colors.black);
  FsFile file = SD.open(path, FILE_READ);
  if (!file) return false;
  lgfx::DataWrapperT<FsFile> data(&file);
  bool ok = entry.canvas->drawPng(&data, 0, 0);
  file.close();
  if (kReleaseMapPngDecoderAfterDraw) entry.canvas->releasePngMemory();
  if (!ok) return false;
  entry.zoom = zoom;
  entry.tileX = tileX;
  entry.tileY = tileY;
  entry.lastUse = ++mapTileCacheUseCounter;
  entry.valid = true;
  return true;
}

static bool drawCachedMapTile(M5Canvas &target, const char *path,
                              int zoom, int tileX, int tileY,
                              int32_t drawX, int32_t drawY) {
  MapTileCacheEntry *entry = selectMapTileCacheEntry(zoom, tileX, tileY);
  if (!entry) return false;
  if (!(entry->valid && entry->zoom == zoom && entry->tileX == tileX &&
        entry->tileY == tileY)) {
    if (!loadMapTileCacheEntry(*entry, path, zoom, tileX, tileY)) return false;
  }
  entry->canvas->pushSprite(&target, drawX, drawY);
  return true;
}

static bool renderMapCanvasRegion(double centerLat, double centerLon, uint8_t zoom,
                                  const Rect &localClip, bool queueMissing,
                                  bool updateViewState) {
  Rect view = mapPanViewportRect();
  if (!ensureMapRenderCanvas(view)) return false;
  Rect canvasBounds = {0, 0, view.w, view.h};
  Rect clip = intersectRect(localClip, canvasBounds);
  if (!isRectValid(clip)) return true;

  mapRenderCanvas->setClipRect(clip.x, clip.y, clip.w, clip.h);
  mapRenderCanvas->fillRect(clip.x, clip.y, clip.w, clip.h, colors.black);
  if (!sdReady || !lockSd(50)) {
    mapRenderCanvas->clearClipRect();
    return false;
  }
  if (!SD.exists(tileRoot.c_str())) {
    unlockSd();
    mapRenderCanvas->clearClipRect();
    return true;
  }

  double centerPx = 0.0;
  double centerPy = 0.0;
  geoToWorldPixels(centerLat, centerLon, zoom, centerPx, centerPy);
  centerPx += mapLookAheadDx;
  centerPy += mapLookAheadDy;
  int tileCount = 1 << zoom;
  double left = centerPx - mapW / 2.0;
  double top = centerPy - mapH / 2.0;
  double world = 256.0 * tileCount;
  if (mapW > world) left = (world - mapW) / 2.0;
  if (mapH > world) top = (world - mapH) / 2.0;
  int startTileX = static_cast<int>(floor(left / 256.0));
  int startTileY = static_cast<int>(floor(top / 256.0));
  int tilesX = mapW / 256 + 2;
  int tilesY = mapH / 256 + 2;
  int offsetX = static_cast<int>(-fmod(left, 256.0));
  int offsetY = static_cast<int>(-fmod(top, 256.0));

  char pathBuf[160] = {0};
  for (int ty = 0; ty < tilesY; ++ty) {
    for (int tx = 0; tx < tilesX; ++tx) {
      int tileX = startTileX + tx;
      int tileY = startTileY + ty;
      if (tileY < 0 || tileY >= tileCount) continue;
      int wrappedX = tileX % tileCount;
      if (wrappedX < 0) wrappedX += tileCount;
      int32_t drawX = mapX + offsetX + tx * 256 - view.x;
      int32_t drawY = mapY + offsetY + ty * 256 - view.y;
      if (drawX >= clip.x + clip.w || drawX + 256 <= clip.x ||
          drawY >= clip.y + clip.h || drawY + 256 <= clip.y) {
        continue;
      }
      bool hasPath = buildTilePath(pathBuf, sizeof(pathBuf), zoom, wrappedX, tileY);
      bool drewTile = hasPath &&
                      drawCachedMapTile(*mapRenderCanvas, pathBuf, zoom, wrappedX,
                                        tileY, drawX, drawY);
      if (!drewTile) {
        mapRenderCanvas->fillRect(drawX, drawY, 256, 256, colors.black);
        mapRenderCanvas->drawRect(drawX, drawY, 256, 256, colors.amberDim);
        if (queueMissing && !mapDownload.active) {
          if (hasPath && SD.exists(pathBuf)) SD.remove(pathBuf);
          queueTileDownload(zoom, wrappedX, tileY, false);
        }
      }
    }
  }

  // Decode the immediately adjacent tile border while the map loading screen
  // is still visible. Without this, crossing a 256 px boundary synchronously
  // decodes an entire row/column and briefly stalls keyboard panning.
  if (updateViewState) {
    uint32_t prefetchStartMs = millis();
    uint16_t prefetched = 0;
    // Border tiles are only an optimization. Never let them monopolize the UI
    // thread, and skip them at road speed where the next frame may already
    // require a different border.
    bool skipPrefetch = vehicleMotionActive(prefetchStartMs);
    constexpr uint16_t kMaxBorderPrefetchTiles = 3;
    constexpr uint32_t kBorderPrefetchBudgetMs = 14;
    bool prefetchBudgetExhausted = skipPrefetch;
    for (int ty = -1; ty <= tilesY; ++ty) {
      for (int tx = -1; tx <= tilesX; ++tx) {
        if (prefetchBudgetExhausted) break;
        if (tx >= 0 && tx < tilesX && ty >= 0 && ty < tilesY) continue;
        int tileX = startTileX + tx;
        int tileY = startTileY + ty;
        if (tileY < 0 || tileY >= tileCount) continue;
        int wrappedX = tileX % tileCount;
        if (wrappedX < 0) wrappedX += tileCount;
        if (!buildTilePath(pathBuf, sizeof(pathBuf), zoom, wrappedX, tileY) ||
            !SD.exists(pathBuf)) {
          continue;
        }
        MapTileCacheEntry *entry = selectMapTileCacheEntry(zoom, wrappedX, tileY);
        if (!entry) continue;
        if (entry->valid && entry->zoom == zoom && entry->tileX == wrappedX &&
            entry->tileY == tileY) {
          continue;
        }
        if (loadMapTileCacheEntry(*entry, pathBuf, zoom, wrappedX, tileY)) {
          ++prefetched;
        }
        if (prefetched >= kMaxBorderPrefetchTiles ||
            millis() - prefetchStartMs >= kBorderPrefetchBudgetMs) {
          prefetchBudgetExhausted = true;
        }
      }
      if (prefetchBudgetExhausted) break;
    }
    if (prefetched != 0) {
      debugPrint("MAP: prefetched border tiles=%u ms=%lu", prefetched,
                 static_cast<unsigned long>(millis() - prefetchStartMs));
    }
  }
  unlockSd();
  mapRenderCanvas->clearClipRect();

  if (updateViewState) {
    lastMapTileView.zoom = zoom;
    lastMapTileView.startTileX = startTileX;
    lastMapTileView.startTileY = startTileY;
    lastMapTileView.tilesX = tilesX;
    lastMapTileView.tilesY = tilesY;
    lastMapTileView.offsetX = offsetX;
    lastMapTileView.offsetY = offsetY;
    lastMapTileView.valid = true;
    lastMapTileViewValid = true;
    mapTilesDrawn = true;
    mapRenderCanvasValid = true;
    mapModeBadgeBackingValid = false;
  }
  return true;
}

static void presentMapCanvas(const Rect *globalClip = nullptr) {
  if (!mapRenderCanvas || !mapRenderCanvasValid) return;
  Rect view = mapPanViewportRect();
  if (globalClip) {
    Rect clip = intersectRect(*globalClip, view);
    if (!isRectValid(clip)) return;
    M5.Display.setClipRect(clip.x, clip.y, clip.w, clip.h);
  }
  M5.Display.startWrite();
  mapRenderCanvas->pushSprite(view.x, view.y);
  M5.Display.endWrite();
  if (globalClip) M5.Display.clearClipRect();
}

static Rect mapModeBadgeRect() {
  Rect view = mapPanViewportRect();
  if (!isRectValid(view)) return {0, 0, 0, 0};
  int16_t badgeW = min<int16_t>(410, static_cast<int16_t>(view.w - 24));
  if (badgeW < 180) return {0, 0, 0, 0};
  return {static_cast<int16_t>(view.x + 12), static_cast<int16_t>(view.y + 12), badgeW, 38};
}

static String mapModeBadgeLabel() {
  const char *source = gps.location.isValid()
                           ? "GPS"
                           : (isWifiGeoUsable() ? "WI-FI" :
                              (lastGpsFixValid ? "GPS HOLD" : "NO FIX"));
  return String(source) + "  |  " + (mapFollowPaused ? "MANUAL PAN" : "FOLLOWING") +
         "  |  Z" + String(mapZoom);
}

static void drawMapModeBadge() {
  if (mapViewMode != MapViewMode::NAV) return;
  Rect badge = mapModeBadgeRect();
  if (!isRectValid(badge)) return;
  String label = mapModeBadgeLabel();
  uint16_t fg = mapFollowPaused ? colors.red : colors.amber;
  M5.Display.fillRect(badge.x, badge.y, badge.w, badge.h, colors.black);
  M5.Display.drawRect(badge.x, badge.y, badge.w, badge.h, fg);
  M5.Display.drawRect(static_cast<int16_t>(badge.x + 2), static_cast<int16_t>(badge.y + 2),
                      static_cast<int16_t>(badge.w - 4), static_cast<int16_t>(badge.h - 4),
                      colors.amberDim);
  M5.Display.setTextDatum(ML_DATUM);
  M5.Display.setTextColor(fg, colors.black);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.drawString(label, static_cast<int16_t>(badge.x + 12),
                        static_cast<int16_t>(badge.y + badge.h / 2));
  M5.Display.setTextDatum(TL_DATUM);
}

static void drawMapModeBadgeOnCanvas() {
  if (!mapRenderCanvas || mapViewMode != MapViewMode::NAV) return;
  Rect view = mapPanViewportRect();
  Rect badge = mapModeBadgeRect();
  if (!isRectValid(view) || !isRectValid(badge)) return;
  badge.x = static_cast<int16_t>(badge.x - view.x);
  badge.y = static_cast<int16_t>(badge.y - view.y);
  String label = mapModeBadgeLabel();
  uint16_t fg = mapFollowPaused ? colors.red : colors.amber;
  mapRenderCanvas->fillRect(badge.x, badge.y, badge.w, badge.h, colors.black);
  mapRenderCanvas->drawRect(badge.x, badge.y, badge.w, badge.h, fg);
  mapRenderCanvas->drawRect(static_cast<int16_t>(badge.x + 2),
                            static_cast<int16_t>(badge.y + 2),
                            static_cast<int16_t>(badge.w - 4),
                            static_cast<int16_t>(badge.h - 4), colors.amberDim);
  mapRenderCanvas->setTextDatum(ML_DATUM);
  mapRenderCanvas->setTextColor(fg, colors.black);
  mapRenderCanvas->setTextSize(kSmallTextSize);
  mapRenderCanvas->drawString(label, static_cast<int16_t>(badge.x + 12),
                              static_cast<int16_t>(badge.y + badge.h / 2));
  mapRenderCanvas->setTextDatum(TL_DATUM);
}

static bool ensureMapModeBadgeBacking(const Rect &localBadge) {
  if (!isRectValid(localBadge)) return false;
  if (mapModeBadgeBacking && mapModeBadgeBackingW == localBadge.w &&
      mapModeBadgeBackingH == localBadge.h) {
    return true;
  }
  if (mapModeBadgeBacking) {
    heap_caps_free(mapModeBadgeBacking);
    mapModeBadgeBacking = nullptr;
  }
  size_t bytes = static_cast<size_t>(localBadge.w) * localBadge.h * sizeof(uint16_t);
  mapModeBadgeBacking = static_cast<uint16_t *>(
      heap_caps_malloc(bytes, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
  mapModeBadgeBackingW = mapModeBadgeBacking ? localBadge.w : 0;
  mapModeBadgeBackingH = mapModeBadgeBacking ? localBadge.h : 0;
  mapModeBadgeBackingValid = false;
  return mapModeBadgeBacking != nullptr;
}

static void drawMapDynamicOverlays(double centerLat, double centerLon, uint8_t zoom) {
  if (mapNavTargetIndex >= 0 || meshNavTargetIndex >= 0) {
    drawNavTargetLine(centerLat, centerLon, zoom);
  }
  drawMeshContactsOnMap(centerLat, centerLon, zoom);
  drawAircraftOnMap(centerLat, centerLon, zoom);
}

static bool drawMapExposedStrip(double centerLat, double centerLon, const Rect &strip) {
  Rect view = mapPanViewportRect();
  Rect clip = intersectRect(strip, view);
  if (!isRectValid(clip)) return true;
  Rect localClip = {static_cast<int16_t>(clip.x - view.x),
                    static_cast<int16_t>(clip.y - view.y), clip.w, clip.h};
  return renderMapCanvasRegion(centerLat, centerLon, mapZoom, localClip, false, false);
}

static void drawCurrentMapMarkerAfterPan(double centerLat, double centerLon) {
  if (mapViewMode != MapViewMode::NAV) return;
  int32_t markerX = mapX + mapW / 2;
  int32_t markerY = mapY + mapH / 2;
  if (mapTargetValid) {
    mapGeoToScreen(mapTargetLat, mapTargetLon, centerLat, centerLon, mapZoom, markerX, markerY);
  }
  if (mapFollowPaused) {
    int16_t margin = static_cast<int16_t>(mapMarkerSize + 8);
    if (markerX < mapX + margin || markerX > mapX + mapW - margin ||
        markerY < mapY + margin || markerY > mapY + mapH - margin) {
      arrowBackValid = false;
      return;
    }
  }
  int16_t cx = static_cast<int16_t>(markerX);
  int16_t cy = static_cast<int16_t>(markerY);
  if (!mapFollowPaused) {
    cx = max<int16_t>(mapX + 8, min<int16_t>(mapX + mapW - 8, cx));
    cy = max<int16_t>(mapY + 8, min<int16_t>(mapY + mapH - 8, cy));
  }
  Rect backRect = arrowBackgroundRect(cx, cy);
  if (kMapOverlayUseReadback) {
    captureArrowBackground(backRect);
  } else {
    arrowBackValid = false;
  }
  drawHeadingArrow(cx, cy, mapMarkerSize);
  lastArrowHeadingDrawn = lastGpsHeadingDeg;
  lastArrowHeadingDrawnValid = lastGpsHeadingValid;
  lastArrowCx = cx;
  lastArrowCy = cy;
  lastOverlayDrawMs = millis();
  arrowBackRect = backRect;
}

static bool tryAcceleratedMapPan(int16_t scrollDx, int16_t scrollDy,
                                 double centerLat, double centerLon) {
  if (!mapTilesDrawn || !lastMapTileViewValid || !mapRenderCanvasValid) return false;
  Rect view = mapPanViewportRect();
  if (!isRectValid(view) || !ensureMapRenderCanvas(view)) return false;
  if (abs(scrollDx) >= view.w || abs(scrollDy) >= view.h) return false;

  arrowBackValid = false;
  // Restore the raw map pixels under the previous badge from PSRAM before the
  // framebuffer scroll. This avoids both LCD flashing and an SD/tile read on
  // every keyboard-repeat frame.
  Rect badge = mapModeBadgeRect();
  Rect localBadge = {static_cast<int16_t>(badge.x - view.x),
                     static_cast<int16_t>(badge.y - view.y), badge.w, badge.h};
  bool haveBadgeBacking = ensureMapModeBadgeBacking(localBadge);
  if (haveBadgeBacking && mapModeBadgeBackingValid) {
    mapRenderCanvas->pushImage(localBadge.x, localBadge.y, localBadge.w, localBadge.h,
                               mapModeBadgeBacking);
  }
  mapRenderCanvas->setScrollRect(0, 0, view.w, view.h, colors.black);
  mapRenderCanvas->scroll(scrollDx, scrollDy);

  bool ok = true;
  if (scrollDx > 0) {
    Rect strip = {view.x, view.y, scrollDx, view.h};
    ok = drawMapExposedStrip(centerLat, centerLon, strip) && ok;
  } else if (scrollDx < 0) {
    Rect strip = {static_cast<int16_t>(view.x + view.w + scrollDx), view.y,
                  static_cast<int16_t>(-scrollDx), view.h};
    ok = drawMapExposedStrip(centerLat, centerLon, strip) && ok;
  }
  if (scrollDy > 0) {
    Rect strip = {view.x, view.y, view.w, scrollDy};
    ok = drawMapExposedStrip(centerLat, centerLon, strip) && ok;
  } else if (scrollDy < 0) {
    Rect strip = {view.x, static_cast<int16_t>(view.y + view.h + scrollDy),
                  view.w, static_cast<int16_t>(-scrollDy)};
    ok = drawMapExposedStrip(centerLat, centerLon, strip) && ok;
  }

  if (!ok) return false;
  if (haveBadgeBacking) {
    mapRenderCanvas->readRect(localBadge.x, localBadge.y, localBadge.w, localBadge.h,
                              mapModeBadgeBacking);
    mapModeBadgeBackingValid = true;
  }
  drawMapModeBadgeOnCanvas();
  presentMapCanvas();
  M5.Display.setClipRect(view.x, view.y, view.w, view.h);
  drawMapDynamicOverlays(centerLat, centerLon, mapZoom);
  drawCurrentMapMarkerAfterPan(centerLat, centerLon);
  M5.Display.clearClipRect();
  mapPanCleanFrameReady = false;
  mapDirty = false;
  mapOverlayDirty = false;
  return true;
}

static void panMapByKey(uint8_t keycode, bool allowAcceleratedDraw) {
  if (!isMapArrowKey(keycode)) return;
  bool wasFollowPaused = mapFollowPaused;
  double lat = 0.0;
  double lon = 0.0;
  if (!getMapCenter(lat, lon)) {
    lat = kDefaultLat;
    lon = kDefaultLon;
  }
  double x = 0.0;
  double y = 0.0;
  geoToWorldPixels(lat, lon, mapZoom, x, y);
  Rect panView = mapPanViewportRect();
  int16_t stepPx = static_cast<int16_t>(
      max<long>(22L, min<long>(28L, lround(static_cast<double>(panView.w) / 36.0))));
  int16_t scrollDx = 0;
  int16_t scrollDy = 0;
  if (keycode == 0x4F) {       // Right arrow: pan east.
    x += stepPx;
    scrollDx = static_cast<int16_t>(-stepPx);
  } else if (keycode == 0x50) {  // Left arrow: pan west.
    x -= stepPx;
    scrollDx = stepPx;
  } else if (keycode == 0x51) {  // Down arrow: pan south.
    y += stepPx;
    scrollDy = static_cast<int16_t>(-stepPx);
  } else if (keycode == 0x52) {  // Up arrow: pan north.
    y -= stepPx;
    scrollDy = stepPx;
  }
  worldPixelsToGeo(x, y, mapZoom, mapCenterLat, mapCenterLon);
  mapCenterValid = true;
  mapFollowPaused = true;
  mapLookAheadDx = 0;
  mapLookAheadDy = 0;
  lastLookAheadMs = 0;
  lastMapHasFix = false;
  uint32_t panRenderStartUs = micros();
  bool accelerated = allowAcceleratedDraw &&
                     tryAcceleratedMapPan(scrollDx, scrollDy, mapCenterLat, mapCenterLon);
  uint32_t panRenderUs = micros() - panRenderStartUs;
  if (!accelerated) {
    arrowBackValid = false;
    mapDirty = true;
    mapOverlayDirty = false;
  }
  if (!wasFollowPaused) {
    statusDirty = true;
  }
  static uint32_t lastMapPanLogMs = 0;
  uint32_t now = millis();
  if (now - lastMapPanLogMs >= 750) {
    lastMapPanLogMs = now;
    debugPrint("MAP: pan key=0x%02X zoom=%u follow=0 accel=%u frame_us=%lu",
               keycode, mapZoom, accelerated ? 1U : 0U,
               static_cast<unsigned long>(panRenderUs));
  }
}

bool handleMainMapKeyboard(uint8_t keycode) {
  if (screen != SCREEN_MAIN || mapViewMode != MapViewMode::NAV) {
    mapPanHeldKey = 0;
    mapPanPendingKey = 0;
    mapPanReleaseGraceUntilMs = 0;
    return false;
  }
  if (keycode == 0) {
    mapPanLastHidMs = millis();
    // A HID key-up is authoritative. Do not synthesize extra frames after it;
    // the keyboard supplies repeat key-down events while a key is held.
    mapPanHeldKey = 0;
    mapPanReleaseGraceUntilMs = 0;
    mapOverlayDirty = true;
    return true;
  }
  if (isMapArrowKey(keycode)) {
    mapPanHeldKey = keycode;
    mapPanPendingKey = keycode;
    mapPanLastHidMs = millis();
    mapPanReleaseGraceUntilMs = 0;
    return true;
  }
  if (keycode == 0x28) {  // Enter: recenter and resume GPS follow.
    recenterMapFollow();
    return true;
  }
  mapPanHeldKey = 0;
  mapPanReleaseGraceUntilMs = 0;
  return false;
}

void updateMapKeyboardPan(uint32_t now) {
  // pollTab5Keyboard() may spend time presenting a pan frame, so the loop's
  // original timestamp can be older than mapPanLastStepMs. Refresh it here to
  // prevent unsigned wraparound from creating an unintended extra step.
  now = millis();
  if (screen != SCREEN_MAIN || mapViewMode != MapViewMode::NAV) {
    mapPanHeldKey = 0;
    mapPanPendingKey = 0;
    mapPanReleaseGraceUntilMs = 0;
    return;
  }
  // Never render from inside the keyboard I2C event-drain loop. A burst of
  // queued HID events could otherwise perform several synchronous SD tile
  // decodes before input was polled again and appear to cancel a long hold.
  // Retain one pending step so a quick press/release still moves exactly once.
  if (mapPanPendingKey != 0) {
    uint8_t pendingKey = mapPanPendingKey;
    mapPanPendingKey = 0;
    mapPanLastStepMs = now;
    panMapByKey(pendingKey, true);
    return;
  }
  if (mapPanHeldKey == 0) {
    mapPanReleaseGraceUntilMs = 0;
    return;
  }
  if (mapPanReleaseGraceUntilMs != 0 && static_cast<int32_t>(now - mapPanReleaseGraceUntilMs) >= 0) {
    mapPanHeldKey = 0;
    mapPanReleaseGraceUntilMs = 0;
    mapOverlayDirty = true;
    return;
  }
  if (now - mapPanLastStepMs < 33) {
    return;
  }
  mapPanLastStepMs = now;
  panMapByKey(mapPanHeldKey, true);
}

void updateMapFollow(uint32_t now) {
  mapLookAheadDx = 0;
  mapLookAheadDy = 0;

  if (mapFollowPaused) {
    return;
  }

  if (!mapTargetValid) {
    if (lastMapHasFix) {
      lastMapHasFix = false;
      mapCenterValid = false;
      mapDirty = true;
    }
    lastMapTargetSource = mapTargetSource;
    return;
  }

  auto isGpsLike = [](MapTargetSource source) {
    return source == MapTargetSource::GPS || source == MapTargetSource::GPS_HOLD;
  };
  bool sourceChanged = mapTargetSource != lastMapTargetSource;
  if (sourceChanged && isGpsLike(mapTargetSource) && isGpsLike(lastMapTargetSource)) {
    sourceChanged = false;
  }
  if (mapCenterValid && sourceChanged) {
    mapCenterLat = mapTargetLat;
    mapCenterLon = mapTargetLon;
    mapCenterValid = true;
    lastMapFollowMs = now;
    lastMapHasFix = false;
    mapDirty = true;
  }

  if (!mapCenterValid) {
    mapCenterLat = mapTargetLat;
    mapCenterLon = mapTargetLon;
    mapCenterValid = true;
    lastMapFollowMs = now;
    mapDirty = true;
  }

  double oldCenterX = 0.0;
  double oldCenterY = 0.0;
  double targetX = 0.0;
  double targetY = 0.0;
  geoToWorldPixels(mapCenterLat, mapCenterLon, mapZoom, oldCenterX, oldCenterY);
  geoToWorldPixels(mapTargetLat, mapTargetLon, mapZoom, targetX, targetY);
  long scrollDxLong = lround(oldCenterX - targetX);
  long scrollDyLong = lround(oldCenterY - targetY);
  bool centerMovedAtLeastPixel = scrollDxLong != 0 || scrollDyLong != 0;

  if (centerMovedAtLeastPixel) {
    Rect view = mapPanViewportRect();
    bool deltaFits = abs(scrollDxLong) < view.w && abs(scrollDyLong) < view.h &&
                     scrollDxLong >= INT16_MIN && scrollDxLong <= INT16_MAX &&
                     scrollDyLong >= INT16_MIN && scrollDyLong <= INT16_MAX;
    double newCenterLat = mapTargetLat;
    double newCenterLon = mapTargetLon;
    uint32_t renderStartUs = micros();
    bool accelerated = screen == SCREEN_MAIN && deltaFits &&
                       tryAcceleratedMapPan(static_cast<int16_t>(scrollDxLong),
                                            static_cast<int16_t>(scrollDyLong),
                                            newCenterLat, newCenterLon);
    mapCenterLat = newCenterLat;
    mapCenterLon = newCenterLon;
    mapCenterValid = true;
    lastMapFollowMs = now;
    if (!accelerated) {
      arrowBackValid = false;
      mapDirty = true;
      mapOverlayDirty = false;
    }
    uint32_t renderUs = micros() - renderStartUs;
    if (renderUs >= 100000) {
      debugPrint("MAP: slow follow shift dx=%ld dy=%ld accelerated=%u us=%lu",
                 scrollDxLong, scrollDyLong, accelerated ? 1U : 0U,
                 static_cast<unsigned long>(renderUs));
    }
    lastMapHasFix = true;
  } else {
    int32_t markerX = mapX + mapW / 2;
    int32_t markerY = mapY + mapH / 2;
    mapGeoToScreen(mapTargetLat, mapTargetLon, mapCenterLat, mapCenterLon,
                   mapZoom, markerX, markerY);
    if (!lastMapHasFix || abs(markerX - lastArrowCx) >= 2 ||
        abs(markerY - lastArrowCy) >= 2) {
      mapOverlayDirty = true;
      lastMapHasFix = true;
    }
  }
  lastMapTargetSource = mapTargetSource;
}

void initImu() {
  if (!kCompassFeatureEnabled) {
    imuAvailable = false;
    imuHeadingValid = false;
    return;
  }
  imuAvailable = M5.Imu.isEnabled();
  if (!imuAvailable) {
    imuAvailable = M5.Imu.begin();
  }
  if (imuAvailable) {
    imuHeadingValid = false;
    lastImuMs = 0;
    accelMagAvg = 1.0f;
  }
}

static float wrapDegrees(float deg) {
  while (deg >= 360.0f) {
    deg -= 360.0f;
  }
  while (deg < 0.0f) {
    deg += 360.0f;
  }
  return deg;
}

void updateImu(uint32_t now) {
  if (!kCompassFeatureEnabled) {
    return;
  }
  if (!imuAvailable) {
    return;
  }

  float ax = 0.0f;
  float ay = 0.0f;
  float az = 0.0f;
  if (M5.Imu.getAccel(&ax, &ay, &az)) {
    float roll = atan2f(ay, az);
    float pitch = atan2f(-ax, sqrtf(ay * ay + az * az));
    deviceRollDeg = roll * 180.0f / static_cast<float>(M_PI);
    devicePitchDeg = pitch * 180.0f / static_cast<float>(M_PI);

    float mag = sqrtf(ax * ax + ay * ay + az * az);
    accelMagAvg = accelMagAvg * 0.9f + mag * 0.1f;
    if (tripActive) {
      float delta = mag - accelMagAvg;
      if (delta > kStepThresholdG && now - lastStepMs >= kStepMinIntervalMs) {
        lastStepMs = now;
        tripSteps++;
        tripDistanceMeters += kStepLengthMeters;
      }
    }
  }

  float gx = 0.0f;
  float gy = 0.0f;
  float gz = 0.0f;
  if (M5.Imu.getGyro(&gx, &gy, &gz)) {
    if (lastImuMs != 0) {
      float dt = (now - lastImuMs) / 1000.0f;
      if (dt > 0.5f) {
        dt = 0.5f;
      }
      deviceYawDeg = wrapDegrees(deviceYawDeg + gz * dt);
      imuHeadingValid = true;
    }
    lastImuMs = now;
  }
  if (tripActive && now - lastTripLogMs >= kTripLogIntervalMs) {
    lastTripLogMs = now;
    logTripEvent("SAMPLE");
  }
}

void logTripEvent(const char *tag) {
  if (!sdReady) {
    return;
  }
  if (!lockSd(200)) {
    return;
  }
  FsFile f = SD.open(kTripLogPath, FILE_APPEND);
  if (!f) {
    unlockSd();
    return;
  }
  if (f.size() == 0) {
    f.println("ts_ms,event,steps,dist_m,lat,lon,spd_kmh,imu_yaw,imu_pitch,imu_roll");
  }
  f.print(millis());
  f.print(',');
  f.print(tag);
  f.print(',');
  f.print(tripSteps);
  f.print(',');
  f.print(tripDistanceMeters, 1);
  f.print(',');
  if (gps.location.isValid()) {
    f.print(gps.location.lat(), 6);
  }
  f.print(',');
  if (gps.location.isValid()) {
    f.print(gps.location.lng(), 6);
  }
  f.print(',');
  if (gps.speed.isValid()) {
    f.print(gps.speed.kmph(), 1);
  }
  f.print(',');
  if (imuHeadingValid) {
    f.print(deviceYawDeg, 1);
  }
  f.print(',');
  if (imuHeadingValid) {
    f.print(devicePitchDeg, 1);
  }
  f.print(',');
  if (imuHeadingValid) {
    f.print(deviceRollDeg, 1);
  }
  f.println();
  f.close();
  unlockSd();
}

void startTrip() {
  tripActive = true;
  tripStartMs = millis();
  tripSteps = 0;
  tripDistanceMeters = 0.0f;
  lastTripLogMs = tripStartMs;
  logTripEvent("START");
}

void stopTrip() {
  if (!tripActive) {
    return;
  }
  logTripEvent("STOP");
  tripActive = false;
}

void toggleTripRecording() {
  if (tripActive) {
    stopTrip();
  } else {
    startTrip();
  }
  statusDirty = true;
  mapDirty = true;
  mapOverlayDirty = true;
  mainNavDirty = true;
}

void applyTileStyle(bool persist) {
  if (tileServerRoot.length() == 0 || tileServerStyle.length() == 0) {
    return;
  }
  tileServerBase = tileServerRoot + "/" + tileServerStyle;
  if (!persist || !sdReady) {
    return;
  }
  FsFile f = SD.open(kTileStylePath, FILE_WRITE);
  if (!f) {
    return;
  }
  f.println(tileServerStyle);
  f.close();
}

bool refreshTileZoomRange(bool preserveZoom) {
  if (!sdReady) {
    debugPrint("ZOOM: refresh skipped (sd not ready)");
    return false;
  }
  String roots[3] = {tileRoot, String(kTileRoot), String(kTileRoot) + "/tiles"};
  int bestZoom = mapZoom;
  int minZoom = mapMinZoom;
  int maxZoom = mapMaxZoom;
  bool found = false;
  String bestRoot = tileRoot;
  for (size_t i = 0; i < 3; ++i) {
    if (!lockSd(200)) {
      continue;
    }
    int rootBest = mapZoom;
    int rootMin = mapMinZoom;
    int rootMax = mapMaxZoom;
    bool rootFound = scanZoomDirs(roots[i], mapZoom, rootBest, rootMin, rootMax);
    unlockSd();
    debugPrint("ZOOM: scan root=%s found=%d best=%d min=%d max=%d",
               roots[i].c_str(), rootFound ? 1 : 0, rootBest, rootMin, rootMax);
    if (!rootFound) {
      continue;
    }
    if (!found || rootMax > maxZoom) {
      found = true;
      bestRoot = roots[i];
      bestZoom = rootBest;
      minZoom = rootMin;
      maxZoom = rootMax;
    }
  }
  if (!found) {
    debugPrint("ZOOM: refresh failed (no roots)");
    return false;
  }
  tileRoot = bestRoot;
  if (minZoom < kUserMinZoom) {
    minZoom = kUserMinZoom;
  }
  if (maxZoom < minZoom) {
    maxZoom = minZoom;
  }
  if (maxZoom < mapZoom && tileZoomDirExists(mapZoom)) {
    maxZoom = mapZoom;
  }
  if (minZoom > mapZoom && tileZoomDirExists(mapZoom)) {
    minZoom = mapZoom;
  }
  mapMinZoom = static_cast<uint8_t>(minZoom);
  mapMaxZoom = static_cast<uint8_t>(maxZoom);
  debugPrint("ZOOM: refresh root=%s zoom=%u range=%u..%u",
             tileRoot.c_str(), mapZoom, mapMinZoom, mapMaxZoom);
  if (preserveZoom) {
    if (mapZoom < mapMinZoom) {
      mapZoom = mapMinZoom;
    }
    if (mapZoom > mapMaxZoom) {
      mapZoom = mapMaxZoom;
    }
  } else {
    mapZoom = static_cast<uint8_t>(bestZoom);
  }
  return true;
}

bool tileZoomDirExists(uint8_t zoom) {
  if (!sdReady) {
    return false;
  }
  String roots[3] = {tileRoot, String(kTileRoot), String(kTileRoot) + "/tiles"};
  for (size_t i = 0; i < 3; ++i) {
    String dir = roots[i] + "/" + String(zoom);
    bool ok = false;
    if (lockSd(50)) {
      ok = SD.exists(dir.c_str());
      unlockSd();
    } else {
      ok = SD.exists(dir.c_str());
    }
    debugPrint("ZOOM: dir check %s -> %d", dir.c_str(), ok ? 1 : 0);
    if (ok) {
      return true;
    }
  }
  return false;
}

double haversineMeters(const GeoPoint &a, const GeoPoint &b) {
  constexpr double r = 6371000.0;
  double lat1 = a.lat * M_PI / 180.0;
  double lat2 = b.lat * M_PI / 180.0;
  double dLat = (b.lat - a.lat) * M_PI / 180.0;
  double dLon = (b.lon - a.lon) * M_PI / 180.0;
  double h = sin(dLat / 2) * sin(dLat / 2) +
             cos(lat1) * cos(lat2) * sin(dLon / 2) * sin(dLon / 2);
  return 2 * r * atan2(sqrt(h), sqrt(1 - h));
}

double bearingDegrees(const GeoPoint &from, const GeoPoint &to) {
  double lat1 = from.lat * M_PI / 180.0;
  double lat2 = to.lat * M_PI / 180.0;
  double dLon = (to.lon - from.lon) * M_PI / 180.0;
  double y = sin(dLon) * cos(lat2);
  double x = cos(lat1) * sin(lat2) - sin(lat1) * cos(lat2) * cos(dLon);
  double bearing = atan2(y, x) * 180.0 / M_PI;
  while (bearing < 0.0) bearing += 360.0;
  while (bearing >= 360.0) bearing -= 360.0;
  return bearing;
}

void updateFilteredGpsPosition(double lat, double lon, uint32_t now) {
  if (!gpsFilteredValid) {
    gpsFilteredLat = lat;
    gpsFilteredLon = lon;
    gpsFilteredValid = true;
    gpsFilteredMs = now;
  } else {
    GeoPoint filtered = {gpsFilteredLat, gpsFilteredLon};
    GeoPoint incoming = {lat, lon};
    double distance = haversineMeters(filtered, incoming);
    uint32_t elapsedMs = max<uint32_t>(1, now - gpsFilteredMs);
    float speedKmh = gps.speed.isValid() ? gps.speed.kmph() : 0.0f;
    int satellites = gps.satellites.isValid() ? gps.satellites.value() : 0;
    int hdop = gps.hdop.isValid() ? gps.hdop.value() : 9999;

    if (elapsedMs < 5000 && distance > 150.0 && speedKmh < 20.0f) {
      debugPrint("GPS: rejected jump %.1fm speed=%.1f sats=%d hdop=%d", distance,
                 speedKmh, satellites, hdop);
      return;
    }
    if (speedKmh < 1.5f && distance < 8.0) {
      gpsFilteredMs = now;
    } else {
      // At road speed, heavy smoothing makes the marker visibly trail the car.
      // Preserve the stopped jitter filter, but track valid moving fixes quickly.
      float alpha = speedKmh < 1.5f ? 0.14f
                    : speedKmh < 12.0f ? 0.34f
                    : speedKmh < 50.0f ? 0.72f
                                       : 0.86f;
      if (speedKmh < 12.0f && satellites > 0 && satellites <= 6) {
        alpha *= 0.65f;
      }
      if (speedKmh < 12.0f && hdop > 250) {
        alpha *= 0.65f;
      }
      if (elapsedMs > 10000 || distance > 60.0) {
        alpha = max(alpha, 0.65f);
      }
      gpsFilteredLat += (lat - gpsFilteredLat) * alpha;
      gpsFilteredLon += (lon - gpsFilteredLon) * alpha;
      gpsFilteredMs = now;
    }
  }
  lastGpsFixLat = gpsFilteredLat;
  lastGpsFixLon = gpsFilteredLon;
  lastGpsFixValid = true;
  mapTargetLat = gpsFilteredLat;
  mapTargetLon = gpsFilteredLon;
  mapTargetValid = true;
  mapTargetSource = MapTargetSource::GPS;
}

void drawBootScreen() {
  M5.Display.fillScreen(colors.black);
  if (kEnableBootPng && sdReady && SD.exists(kBootImagePath)) {
    drawPngFromSd(kBootImagePath, 0, 0, screenW, screenH);
  }
  drawBootSerialCube();
  uint8_t titleSize = 8;
  uint8_t subSize = 4;
  int16_t maxTextW = static_cast<int16_t>(screenW - 24);
  auto fitText = [&](uint8_t &size, const char *label) {
    while (size > 1) {
      M5.Display.setTextSize(size);
      if (M5.Display.textWidth(label) <= maxTextW) {
        break;
      }
      size--;
    }
  };
  fitText(titleSize, "RESPONDER NAV");
  fitText(subSize, "by ACH Industries");

  M5.Display.setTextSize(titleSize);
  int16_t titleH = M5.Display.fontHeight();
  M5.Display.setTextSize(subSize);
  int16_t subH = M5.Display.fontHeight();
  int16_t textBlockH = static_cast<int16_t>(titleH + subH + 8);
  int16_t gap = 12;
  int16_t maxArtArea = max<int16_t>(0, screenH - textBlockH - gap - 16);

  auto measureArt = [&](uint8_t size, int16_t &outW, int16_t &outH) {
    M5.Display.setTextSize(size);
    outH = static_cast<int16_t>(kBootArtLines * M5.Display.fontHeight());
    outW = 0;
    for (size_t i = 0; i < kBootArtLines; ++i) {
      int16_t w = static_cast<int16_t>(M5.Display.textWidth(kBootArt[i]));
      if (w > outW) {
        outW = w;
      }
    }
  };

  uint8_t artSize = 2;
  int16_t artW = 0;
  int16_t artH = 0;
  measureArt(artSize, artW, artH);
  if (artW > screenW - 24 || artH > maxArtArea) {
    artSize = 1;
    measureArt(artSize, artW, artH);
  }

  int16_t artX = static_cast<int16_t>((screenW - artW) / 2);
  int16_t totalH = static_cast<int16_t>(artH + gap + textBlockH);
  int16_t artY = max<int16_t>(8, static_cast<int16_t>((screenH - totalH) / 2));
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(artSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  for (size_t i = 0; i < kBootArtLines; ++i) {
    M5.Display.drawString(kBootArt[i], artX, static_cast<int16_t>(artY + i * M5.Display.fontHeight()));
  }

  int16_t textTop = static_cast<int16_t>(artY + artH + gap);
  if (textTop + textBlockH > screenH - 8) {
    textTop = static_cast<int16_t>(screenH - textBlockH - 8);
  }

  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.setTextSize(titleSize);
  M5.Display.drawString("RESPONDER NAV", screenW / 2,
                        static_cast<int16_t>(textTop + titleH / 2));
  M5.Display.setTextColor(colors.red, colors.black);
  M5.Display.setTextSize(subSize);
  M5.Display.drawString("by ACH Industries", screenW / 2,
                        static_cast<int16_t>(textTop + titleH + 8 + subH / 2));
}

