void drawBootArtBackdrop(int16_t top, int16_t bottom) {
  int16_t availH = static_cast<int16_t>(bottom - top);
  if (availH <= 0) {
    return;
  }
  int16_t maxW = static_cast<int16_t>(screenW - 24);

  auto measureArt = [&](uint8_t size, int16_t &outW, int16_t &outH) {
    M5.Display.setTextSize(size);
    outH = static_cast<int16_t>(kBootArtLines * M5.Display.fontHeight());
    outW = 0;
    for (size_t i = 0; i < kBootArtLines; ++i) {
      int16_t w = static_cast<int16_t>(M5.Display.textWidth(kBootArt[i]));
      if (w > outW) {
        outW = w;
      }
    }
  };

  uint8_t artSize = 2;
  int16_t artW = 0;
  int16_t artH = 0;
  measureArt(artSize, artW, artH);
  if (artW > maxW || artH > availH - 8) {
    artSize = 1;
    measureArt(artSize, artW, artH);
  }

  int16_t artX = static_cast<int16_t>((screenW - artW) / 2);
  int16_t artY = static_cast<int16_t>(top + (availH - artH) / 2);
  int16_t minY = static_cast<int16_t>(top + 4);
  int16_t maxY = static_cast<int16_t>(bottom - artH - 4);
  if (artY < minY) {
    artY = minY;
  }
  if (artY > maxY) {
    artY = maxY;
  }

  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(artSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  for (size_t i = 0; i < kBootArtLines; ++i) {
    M5.Display.drawString(kBootArt[i], artX,
                          static_cast<int16_t>(artY + i * M5.Display.fontHeight()));
  }
}

void drawNavBar() {
  const char *labels[4] = {"MAP", "APPS", "UTILITIES", "LOCK"};
  for (int i = 0; i < 4; ++i) {
    bool active = false;
    if (i == 0 && screen == SCREEN_MAIN) active = true;
    if (i == 1 && screen == SCREEN_WAYPOINTS) active = true;
    if (i == 2 && (screen == SCREEN_DOWNLOAD || screen == SCREEN_SETTINGS || screen == SCREEN_WIFI ||
                   screen == SCREEN_WIFI_PASS || screen == SCREEN_MAP_DL ||
                   screen == SCREEN_FILE_MGR || screen == SCREEN_USB || screen == SCREEN_ABOUT ||
                   screen == SCREEN_API_KEYS)) {
      active = true;
    }
    if (i == 3 && screenDimmed) active = true;
    uint16_t bg = active ? colors.redDim : colors.black;
    uint16_t fg = active ? colors.red : colors.amber;
    M5.Display.fillRect(navButtons[i].x, navButtons[i].y, navButtons[i].w, navButtons[i].h, bg);
    M5.Display.drawRect(navButtons[i].x, navButtons[i].y, navButtons[i].w, navButtons[i].h, fg);
    M5.Display.setTextColor(fg, bg);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextSize(kNavTextSize);
    M5.Display.drawString(labels[i], navButtons[i].x + navButtons[i].w / 2,
                          navButtons[i].y + navButtons[i].h / 2);
    if (i == 1 && calendarHasReminder()) {
      M5.Display.setTextDatum(TR_DATUM);
      M5.Display.setTextColor(colors.red, bg);
      M5.Display.drawString("*", navButtons[i].x + navButtons[i].w - 8, navButtons[i].y + 4);
    }
  }
}

