void drawLockBatteryIndicator() {
  int batteryLevel = M5.Power.getBatteryLevel();
  if (batteryLevel < 0 || batteryLevel > 100) {
    batteryLevel = -1;
  }
  auto chargeState = M5.Power.isCharging();
  bool charging = chargeState == m5::Power_Class::is_charging_t::is_charging;
  bool externalPower = chargeState != m5::Power_Class::is_charging_t::is_discharging;
  int16_t batteryMv = M5.Power.getBatteryVoltage();
  bool batteryPresent = batteryLevel >= 0;
  if (batteryMv > 0) {
    batteryPresent = batteryMv > 2000;
  }
  bool pluggedNoBattery = !batteryPresent && externalPower;
  uint16_t battColor = colors.amber;
  if (batteryLevel >= 0 && batteryLevel <= 20) {
    battColor = colors.red;
  }
  char label[16] = {0};
  if (batteryLevel >= 0) {
    snprintf(label, sizeof(label), "BAT %d%%", batteryLevel);
  } else {
    snprintf(label, sizeof(label), "BAT --");
  }

  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kWifiTextSize);
  int16_t lineH = static_cast<int16_t>(M5.Display.fontHeight());
  int16_t iconW = 32;
  int16_t iconH = max<int16_t>(14, static_cast<int16_t>(lineH - 4));
  int16_t gap = 9;
  int16_t textW = static_cast<int16_t>(M5.Display.textWidth(label));
  int16_t boxW = static_cast<int16_t>(textW + gap + iconW + 6);
  int16_t boxH = static_cast<int16_t>(max<int16_t>(lineH, iconH) + 4);
  int16_t boxX = static_cast<int16_t>(screenW - 12 - boxW);
  if (boxX < 12) {
    boxX = 12;
  }
  int16_t boxY = 8;
  M5.Display.fillRect(boxX, boxY, boxW, boxH, colors.black);

  int16_t iconX = static_cast<int16_t>(boxX + 2);
  int16_t iconY = static_cast<int16_t>(boxY + (boxH - iconH) / 2);
  int16_t nubW = 4;
  int16_t nubH = static_cast<int16_t>(iconH / 2);
  int16_t nubX = static_cast<int16_t>(iconX + iconW);
  int16_t nubY = static_cast<int16_t>(iconY + (iconH - nubH) / 2);
  M5.Display.drawRect(iconX, iconY, iconW, iconH, battColor);
  M5.Display.drawRect(nubX, nubY, nubW, nubH, battColor);
  if (batteryLevel >= 0) {
    int16_t fillW = static_cast<int16_t>((iconW - 4) * batteryLevel / 100);
    if (fillW > 0) {
      M5.Display.fillRect(iconX + 2, iconY + 2, fillW, iconH - 4, battColor);
    }
  }
  int16_t iconInnerX = static_cast<int16_t>(iconX + 3);
  int16_t iconInnerY = static_cast<int16_t>(iconY + 3);
  int16_t iconInnerW = static_cast<int16_t>(iconW - 6);
  int16_t iconInnerH = static_cast<int16_t>(iconH - 6);
  if (charging && batteryPresent) {
    int16_t cx = static_cast<int16_t>(iconInnerX + iconInnerW / 2);
    int16_t topY = iconInnerY;
    int16_t midY = static_cast<int16_t>(iconInnerY + iconInnerH / 2);
    int16_t botY = static_cast<int16_t>(iconInnerY + iconInnerH);
    M5.Display.drawLine(cx - 2, topY, cx + 1, midY, battColor);
    M5.Display.drawLine(cx + 1, midY, cx - 1, midY, battColor);
    M5.Display.drawLine(cx - 1, midY, cx + 2, botY, battColor);
  } else if (pluggedNoBattery) {
    int16_t plugW = max<int16_t>(4, iconInnerW / 2);
    int16_t plugH = max<int16_t>(6, iconInnerH);
    int16_t plugX = static_cast<int16_t>(iconInnerX + (iconInnerW - plugW) / 2);
    int16_t plugY = iconInnerY;
    int16_t prongH = max<int16_t>(2, plugH / 4);
    M5.Display.drawRect(plugX, static_cast<int16_t>(plugY + prongH), plugW,
                        static_cast<int16_t>(plugH - prongH), battColor);
    M5.Display.drawLine(static_cast<int16_t>(plugX + 2), plugY,
                        static_cast<int16_t>(plugX + 2),
                        static_cast<int16_t>(plugY + prongH), battColor);
    M5.Display.drawLine(static_cast<int16_t>(plugX + plugW - 3), plugY,
                        static_cast<int16_t>(plugX + plugW - 3),
                        static_cast<int16_t>(plugY + prongH), battColor);
  }

  int16_t textX = static_cast<int16_t>(iconX + iconW + gap);
  int16_t textY = static_cast<int16_t>(boxY + (boxH - lineH) / 2);
  M5.Display.setTextColor(battColor, colors.black);
  M5.Display.drawString(label, textX, textY);
  M5.Display.setTextDatum(TL_DATUM);
}

void drawCompass(int16_t cx, int16_t cy, int16_t radius) {
  M5.Display.drawCircle(cx, cy, radius, colors.amber);
  M5.Display.drawCircle(cx, cy, radius - 2, colors.amberDim);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.setTextSize(kCompassTextSize);
  M5.Display.setTextDatum(MC_DATUM);
  int16_t labelInset = max<int16_t>(8, static_cast<int16_t>(M5.Display.fontHeight() / 2));
  M5.Display.drawString("N", cx, cy - radius + labelInset);
  M5.Display.drawString("S", cx, cy + radius - labelInset);
  M5.Display.drawString("W", cx - radius + labelInset, cy);
  M5.Display.drawString("E", cx + radius - labelInset, cy);

  float heading = 0.0f;
  if (lastGpsHeadingValid) {
    heading = lastGpsHeadingDeg;
  }
  float angle = (heading - 90.0f) * M_PI / 180.0f;
  int16_t dx = static_cast<int16_t>(cos(angle) * (radius - 6));
  int16_t dy = static_cast<int16_t>(sin(angle) * (radius - 6));
  M5.Display.drawLine(cx, cy, cx + dx, cy + dy, colors.red);
}

void trimLeadingSpaces(char *buf) {
  if (!buf) {
    return;
  }
  char *p = buf;
  while (*p == ' ') {
    ++p;
  }
  if (p != buf) {
    size_t len = strlen(p);
    memmove(buf, p, len + 1);
  }
}

void formatFloatValue(float value, uint8_t decimals, char *out, size_t outLen) {
  if (!out || outLen == 0) {
    return;
  }
  dtostrf(value, 0, decimals, out);
  trimLeadingSpaces(out);
}

void drawStatusPanel() {
  bool fullRedraw = statusNeedsFullRedraw;
  if (statusNeedsFullRedraw) {
    M5.Display.fillRect(0, 0, statusW, mapH, colors.black);
    M5.Display.drawRect(0, 0, statusW, mapH, colors.amberDim);
    statusNeedsFullRedraw = false;
    statusCacheValid = false;
  }
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kStatusTextSize);
  int16_t y = 8;
  int16_t lineH = M5.Display.fontHeight() + 4;
  int16_t innerX = 1;
  int16_t innerW = max<int16_t>(0, statusW - 2);

  auto clearLine = [&](int16_t lineY) {
    M5.Display.fillRect(innerX, lineY, innerW, lineH, colors.black);
  };

  auto updateLine = [&](int index, const char *text, uint16_t color) {
    if (!text) {
      return;
    }
    if (!statusCacheValid || strcmp(statusLineCache[index].text, text) != 0 ||
        statusLineCache[index].color != color) {
      clearLine(y);
      M5.Display.setTextColor(color, colors.black);
      M5.Display.drawString(text, 8, y);
      strncpy(statusLineCache[index].text, text, kStatusLineMax - 1);
      statusLineCache[index].text[kStatusLineMax - 1] = '\0';
      statusLineCache[index].color = color;
    }
  };

  auto sectionHeader = [&](const char *label) {
    if (fullRedraw) {
      Rect section = {4, y, static_cast<int16_t>(statusW - 8),
                      static_cast<int16_t>(lineH - 2)};
      M5.Display.fillRect(section.x, section.y, section.w, section.h, colors.amberDim);
      M5.Display.setTextDatum(ML_DATUM);
      M5.Display.setTextColor(colors.amber, colors.amberDim);
      M5.Display.setTextSize(kStatusTextSize);
      M5.Display.drawString(label, static_cast<int16_t>(section.x + 7),
                            static_cast<int16_t>(section.y + section.h / 2));
      M5.Display.setTextDatum(TL_DATUM);
    }
    y = static_cast<int16_t>(y + lineH + 2);
  };

  updateLine(0, "RESPONDER NAV", colors.amber);
  y += lineH;
  sectionHeader("POSITION");

  bool lock = gps.location.isValid();
  uint16_t lockColor = lock ? colors.amber : colors.red;
  const char *lockText = lock ? "SAT LOCK" : "NO LOCK";
  const char *tripText = tripActive ? "TRIP ON" : "TRIP OFF";
  uint16_t tripColor = tripActive ? colors.amber : colors.red;
  bool line1Changed =
      !statusCacheValid || strcmp(statusLineCache[1].text, lockText) != 0 ||
      statusLineCache[1].color != lockColor ||
      strcmp(statusTripCache.text, tripText) != 0 ||
      statusTripCache.color != tripColor;
  if (line1Changed) {
    clearLine(y);
    M5.Display.setTextColor(lockColor, colors.black);
    M5.Display.drawString(lockText, 8, y);
    M5.Display.setTextDatum(TR_DATUM);
    M5.Display.setTextColor(tripColor, colors.black);
    M5.Display.drawString(tripText, statusW - 8, y);
    M5.Display.setTextDatum(TL_DATUM);
    strncpy(statusLineCache[1].text, lockText, kStatusLineMax - 1);
    statusLineCache[1].text[kStatusLineMax - 1] = '\0';
    statusLineCache[1].color = lockColor;
    strncpy(statusTripCache.text, tripText, kStatusLineMax - 1);
    statusTripCache.text[kStatusLineMax - 1] = '\0';
    statusTripCache.color = tripColor;
  }
  y += lineH;

  char lineBuf[kStatusLineMax] = {0};
  char numBuf[16] = {0};
  if (gps.satellites.isValid()) {
    snprintf(numBuf, sizeof(numBuf), "%d", gps.satellites.value());
  } else {
    strncpy(numBuf, "--", sizeof(numBuf) - 1);
  }
  snprintf(lineBuf, sizeof(lineBuf), "SAT: %s", numBuf);
  updateLine(2, lineBuf, colors.amber);
  y += lineH;

  if (gps.hdop.isValid()) {
    float hdopVal = gps.hdop.value() / 100.0f;
    formatFloatValue(hdopVal, 1, numBuf, sizeof(numBuf));
  } else {
    strncpy(numBuf, "--", sizeof(numBuf) - 1);
  }
  snprintf(lineBuf, sizeof(lineBuf), "HDOP: %s", numBuf);
  updateLine(3, lineBuf, colors.amber);
  y += lineH;

  bool wifiUsable = isWifiGeoUsable();
  bool hasLoc = gps.location.isValid() || wifiUsable || lastGpsFixValid;
  double locLat = gps.location.isValid()
                      ? gps.location.lat()
                      : (wifiUsable ? wifiGeoLat : lastGpsFixLat);
  double locLon = gps.location.isValid()
                      ? gps.location.lng()
                      : (wifiUsable ? wifiGeoLon : lastGpsFixLon);
  if (hasLoc) {
    formatFloatValue(static_cast<float>(locLat), 5, numBuf, sizeof(numBuf));
  } else {
    strncpy(numBuf, "--", sizeof(numBuf) - 1);
  }
  snprintf(lineBuf, sizeof(lineBuf), "LAT %s", numBuf);
  updateLine(4, lineBuf, colors.amber);
  y += lineH;
  if (hasLoc) {
    formatFloatValue(static_cast<float>(locLon), 5, numBuf, sizeof(numBuf));
  } else {
    strncpy(numBuf, "--", sizeof(numBuf) - 1);
  }
  snprintf(lineBuf, sizeof(lineBuf), "LON %s", numBuf);
  updateLine(5, lineBuf, colors.amber);
  y += lineH;

  sectionHeader("MOTION");

  if (gps.speed.isValid()) {
    formatFloatValue(gps.speed.kmph(), 1, numBuf, sizeof(numBuf));
    snprintf(lineBuf, sizeof(lineBuf), "SPD %skmh", numBuf);
  } else {
    snprintf(lineBuf, sizeof(lineBuf), "SPD --");
  }
  updateLine(6, lineBuf, colors.amber);
  y += lineH;

  if (lastGpsHeadingValid) {
    formatFloatValue(lastGpsHeadingDeg, 0, numBuf, sizeof(numBuf));
  } else {
    strncpy(numBuf, "--", sizeof(numBuf) - 1);
  }
  snprintf(lineBuf, sizeof(lineBuf), "HDG %s", numBuf);
  updateLine(7, lineBuf, colors.amber);
  y += lineH;

  sectionHeader("SYSTEM");

  uint16_t locColor = colors.red;
  const char *locText = "LOC NONE";
  if (gps.location.isValid()) {
    locColor = colors.amber;
    locText = "LOC GPS";
  } else if (wifiUsable) {
    locColor = colors.amberDim;
    locText = "LOC WIFI";
  } else if (lastGpsFixValid) {
    locColor = colors.amberDim;
    locText = "LOC GPS HOLD";
  }
  updateLine(8, locText, locColor);
  y += lineH;

  uint32_t nowMs = millis();
  if (gps.time.isValid()) {
    clockBaseSeconds = static_cast<uint32_t>(gps.time.hour()) * 3600UL +
                       static_cast<uint32_t>(gps.time.minute()) * 60UL +
                       static_cast<uint32_t>(gps.time.second());
    clockBaseMs = nowMs;
    clockHasGps = true;
  }
  char timeBuf[16] = {0};
  int32_t offsetSeconds = clockOffsetValid ? clockOffsetHours * 3600 : 0;
  if (clockHasGps) {
    uint32_t elapsed = (nowMs - clockBaseMs) / 1000UL;
    int64_t seconds = static_cast<int64_t>(clockBaseSeconds) + static_cast<int64_t>(elapsed) +
                      static_cast<int64_t>(offsetSeconds);
    seconds %= 86400;
    if (seconds < 0) {
      seconds += 86400;
    }
    formatHm12(seconds, timeBuf, sizeof(timeBuf));
    snprintf(lineBuf, sizeof(lineBuf), "TIME %s", timeBuf);
  } else if (clockHasNtp) {
    time_t epoch = time(nullptr);
    epoch += offsetSeconds;
    if (formatEpochHm12(epoch, timeBuf, sizeof(timeBuf))) {
      snprintf(lineBuf, sizeof(lineBuf), "TIME %s", timeBuf);
    } else {
      formatHms(nowMs / 1000UL, false, timeBuf, sizeof(timeBuf));
      snprintf(lineBuf, sizeof(lineBuf), "UP %s", timeBuf);
    }
  } else {
    formatHms(nowMs / 1000UL, false, timeBuf, sizeof(timeBuf));
    snprintf(lineBuf, sizeof(lineBuf), "UP %s", timeBuf);
  }
  updateLine(9, lineBuf, colors.amber);
  y += lineH;

  updateLine(10, sdReady ? "SD OK" : "SD FAIL", sdReady ? colors.amber : colors.red);
  y += lineH;

  int batteryLevel = M5.Power.getBatteryLevel();
  if (batteryLevel < 0 || batteryLevel > 100) {
    batteryLevel = -1;
  }
  auto chargeState = M5.Power.isCharging();
  bool charging = chargeState == m5::Power_Class::is_charging_t::is_charging;
  bool externalPower = chargeState != m5::Power_Class::is_charging_t::is_discharging;
  int16_t batteryMv = M5.Power.getBatteryVoltage();
  bool batteryPresent = batteryLevel >= 0;
  if (batteryMv > 0) {
    batteryPresent = batteryMv > 2000;
  }
  bool pluggedNoBattery = !batteryPresent && externalPower;
  uint16_t battColor = colors.amber;
  if (batteryLevel >= 0 && batteryLevel <= 20) {
    battColor = colors.red;
  }
  if (batteryLevel >= 0) {
    snprintf(lineBuf, sizeof(lineBuf), "BAT %d%%", batteryLevel);
  } else {
    snprintf(lineBuf, sizeof(lineBuf), "BAT --");
  }
  bool batteryChanged = !statusCacheValid ||
                        strcmp(statusLineCache[11].text, lineBuf) != 0 ||
                        statusLineCache[11].color != battColor ||
                        batteryLevel != lastStatusBatteryLevel ||
                        charging != lastStatusCharging ||
                        pluggedNoBattery != lastStatusPluggedNoBattery;
  if (batteryChanged) {
    clearLine(y);
    M5.Display.setTextColor(battColor, colors.black);
    M5.Display.drawString(lineBuf, 8, y);
    strncpy(statusLineCache[11].text, lineBuf, kStatusLineMax - 1);
    statusLineCache[11].text[kStatusLineMax - 1] = '\0';
    statusLineCache[11].color = battColor;
    lastStatusBatteryLevel = batteryLevel;
    lastStatusCharging = charging;
    lastStatusPluggedNoBattery = pluggedNoBattery;
  }
  int16_t iconW = 26;
  int16_t iconH = max<int16_t>(12, lineH - 6);
  int16_t iconX = static_cast<int16_t>(innerX + innerW - iconW - 6);
  int16_t iconY = static_cast<int16_t>(y + (lineH - iconH) / 2);
  int16_t nubW = 4;
  int16_t nubH = static_cast<int16_t>(iconH / 2);
  int16_t nubX = static_cast<int16_t>(iconX + iconW);
  int16_t nubY = static_cast<int16_t>(iconY + (iconH - nubH) / 2);
  if (batteryChanged) {
    M5.Display.drawRect(iconX, iconY, iconW, iconH, battColor);
    M5.Display.drawRect(nubX, nubY, nubW, nubH, battColor);
    if (batteryLevel >= 0) {
      int16_t fillW = static_cast<int16_t>((iconW - 4) * batteryLevel / 100);
      if (fillW > 0) {
        M5.Display.fillRect(iconX + 2, iconY + 2, fillW, iconH - 4, battColor);
      }
    }
    int16_t iconInnerX = static_cast<int16_t>(iconX + 3);
    int16_t iconInnerY = static_cast<int16_t>(iconY + 3);
    int16_t iconInnerW = static_cast<int16_t>(iconW - 6);
    int16_t iconInnerH = static_cast<int16_t>(iconH - 6);
    if (charging && batteryPresent) {
      int16_t cx = static_cast<int16_t>(iconInnerX + iconInnerW / 2);
      int16_t topY = iconInnerY;
      int16_t midY = static_cast<int16_t>(iconInnerY + iconInnerH / 2);
      int16_t botY = static_cast<int16_t>(iconInnerY + iconInnerH);
      M5.Display.drawLine(cx - 2, topY, cx + 1, midY, battColor);
      M5.Display.drawLine(cx + 1, midY, cx - 1, midY, battColor);
      M5.Display.drawLine(cx - 1, midY, cx + 2, botY, battColor);
    } else if (pluggedNoBattery) {
      int16_t plugW = max<int16_t>(4, iconInnerW / 2);
      int16_t plugH = max<int16_t>(6, iconInnerH);
      int16_t plugX = static_cast<int16_t>(iconInnerX + (iconInnerW - plugW) / 2);
      int16_t plugY = iconInnerY;
      int16_t prongH = max<int16_t>(2, plugH / 4);
      M5.Display.drawRect(plugX, static_cast<int16_t>(plugY + prongH), plugW,
                          static_cast<int16_t>(plugH - prongH), battColor);
      M5.Display.drawLine(static_cast<int16_t>(plugX + 2), plugY,
                          static_cast<int16_t>(plugX + 2), static_cast<int16_t>(plugY + prongH),
                          battColor);
      M5.Display.drawLine(static_cast<int16_t>(plugX + plugW - 3), plugY,
                          static_cast<int16_t>(plugX + plugW - 3),
                          static_cast<int16_t>(plugY + prongH), battColor);
    }
  }
  y += lineH;

  int16_t compassCx = statusW / 2;
  int16_t compassTop = y + 6;
  int16_t compassBottom = mapModeButton.y - 6;
  int16_t availableH = compassBottom - compassTop;
  int16_t compassRadius = min<int16_t>(statusW / 2 - kCompassInset, kCompassMaxRadius);
  if (availableH < compassRadius * 2) {
    compassRadius = max<int16_t>(16, availableH / 2);
  }
  if (kCompassFeatureEnabled && compassBottom > compassTop + compassRadius * 2) {
    bool compassNeedsRedraw =
        !statusCacheValid || !lastCompassDrawn || lastGpsHeadingValid != lastCompassHeadingValid;
    if (lastGpsHeadingValid) {
      float delta = fabsf(lastGpsHeadingDeg - lastCompassHeadingDrawn);
      if (delta > 180.0f) {
        delta = 360.0f - delta;
      }
      if (delta >= kArrowHeadingThresholdDeg) {
        compassNeedsRedraw = true;
      }
    }
    if (compassNeedsRedraw) {
    int16_t compassCy = compassTop + availableH / 2;
    if (compassCy - compassRadius < compassTop) {
      compassCy = compassTop + compassRadius;
    }
    if (compassCy + compassRadius > compassBottom) {
      compassCy = compassBottom - compassRadius;
    }
    int16_t compassLeft = max<int16_t>(innerX, compassCx - compassRadius - 2);
    int16_t compassRight = min<int16_t>(statusW - 2, compassCx + compassRadius + 2);
    int16_t compassTopY = max<int16_t>(0, compassCy - compassRadius - 2);
    int16_t compassBottomY = min<int16_t>(mapH - 1, compassCy + compassRadius + 2);
    if (compassRight > compassLeft && compassBottomY > compassTopY) {
      M5.Display.fillRect(compassLeft, compassTopY, compassRight - compassLeft + 1,
                          compassBottomY - compassTopY + 1, colors.black);
    }
    int16_t texStep = 8;
    int16_t texDot = 2;
    int32_t radiusSq = static_cast<int32_t>(compassRadius - 2);
    radiusSq *= radiusSq;
    M5.Display.setTextColor(colors.amberDim, colors.black);
    for (int16_t ty = static_cast<int16_t>(compassTopY + 2); ty <= compassBottomY - 2; ty += texStep) {
      for (int16_t tx = static_cast<int16_t>(compassLeft + 2); tx <= compassRight - 2; tx += texStep) {
        int32_t dx = static_cast<int32_t>(tx - compassCx);
        int32_t dy = static_cast<int32_t>(ty - compassCy);
        if (dx * dx + dy * dy <= radiusSq) {
          continue;
        }
        M5.Display.fillRect(tx, ty, texDot, texDot, colors.amberDim);
      }
    }
      drawCompass(compassCx, compassCy, compassRadius);
      lastCompassHeadingDrawn = lastGpsHeadingDeg;
      lastCompassHeadingValid = lastGpsHeadingValid;
      lastCompassDrawn = true;
    }
  } else {
    lastCompassDrawn = false;
  }

  uint16_t btnBg = colors.black;
  uint16_t modeFg = colors.amber;
  const char *modeLabel = mapViewMode == MapViewMode::NAV ? "LOC SELE" : "NAV MODE";
  M5.Display.fillRect(mapModeButton.x, mapModeButton.y, mapModeButton.w, mapModeButton.h, btnBg);
  M5.Display.drawRect(mapModeButton.x, mapModeButton.y, mapModeButton.w, mapModeButton.h, modeFg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(modeFg, btnBg);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString(modeLabel, mapModeButton.x + mapModeButton.w / 2,
                        mapModeButton.y + mapModeButton.h / 2);

  uint16_t addFg = colors.amber;
  if (!gps.location.isValid()) {
    addFg = colors.amberDim;
  }
  M5.Display.fillRect(addWpButton.x, addWpButton.y, addWpButton.w, addWpButton.h, btnBg);
  M5.Display.drawRect(addWpButton.x, addWpButton.y, addWpButton.w, addWpButton.h, addFg);
  M5.Display.setTextColor(addFg, btnBg);
  M5.Display.drawString("ADD LOC", addWpButton.x + addWpButton.w / 2,
                        addWpButton.y + addWpButton.h / 2);
  statusCacheValid = true;
}

String tilePath(uint8_t z, int x, int y) {
  String path = tileRoot + "/" + String(z) + "/" + String(x) + "/" + String(y) + ".png";
  return path;
}

bool buildTilePath(char *out, size_t outLen, uint8_t z, int x, int y) {
  if (!out || outLen == 0) {
    return false;
  }
  int written = snprintf(out, outLen, "%s/%u/%d/%d.png", tileRoot.c_str(), z, x, y);
  return written > 0 && static_cast<size_t>(written) < outLen;
}

constexpr size_t kTileFailureHistoryCount = 6;
constexpr uint32_t kTileFailureSuppressMs = 15000;
struct TileFailureRecord {
  uint8_t zoom = 0;
  int16_t x = 0;
  int16_t y = 0;
  uint32_t untilMs = 0;
};
static TileFailureRecord tileFailureHistory[kTileFailureHistoryCount];
static size_t tileFailureHistoryIndex = 0;

bool isTileDownloadSuppressed(uint8_t zoom, int x, int y) {
  uint32_t now = millis();
  for (size_t i = 0; i < kTileFailureHistoryCount; ++i) {
    const TileFailureRecord &entry = tileFailureHistory[i];
    if (entry.zoom == zoom && entry.x == x && entry.y == y && entry.untilMs > now) {
      return true;
    }
  }
  return false;
}

void noteTileDownloadFailure(uint8_t zoom, int x, int y) {
  tileFailureHistory[tileFailureHistoryIndex] = {
      zoom, static_cast<int16_t>(x), static_cast<int16_t>(y),
      static_cast<uint32_t>(millis() + kTileFailureSuppressMs)};
  tileFailureHistoryIndex = (tileFailureHistoryIndex + 1) % kTileFailureHistoryCount;
}

void queueTileDownload(uint8_t z, int x, int y, bool fromMapDownload) {
  static uint32_t lastQueueSkipLogMs = 0;
  auto logSkip = [&](const char *reason) {
    uint32_t now = millis();
    if (fromMapDownload && now - lastQueueSkipLogMs >= 1000) {
      debugPrint("DLQ: skip %s z=%u x=%d y=%d", reason, static_cast<unsigned>(z), x, y);
      lastQueueSkipLogMs = now;
    }
  };
  if (isTileDownloadSuppressed(z, x, y)) {
    logSkip("suppressed");
    return;
  }
  if (tileDownloadQueued || tileDownloadActive || tileServerBase.length() == 0) {
    if (tileServerBase.length() == 0) {
      logSkip("no-server");
    } else if (tileDownloadQueued) {
      logSkip("already-queued");
    } else {
      logSkip("active");
    }
    return;
  }
#if ENABLE_WIFI
  if (!wifiEnabled || !wifiAvailable || WiFi.status() != WL_CONNECTED) {
    logSkip("wifi-not-ready");
    return;
  }
#endif
  tileDownloadQueued = true;
  queuedFromMapDownload = fromMapDownload;
  queuedZ = z;
  queuedX = x;
  queuedY = y;
}

bool ensureDir(const String &path) {
  if (!sdReady) {
    return false;
  }
  if (!lockSd(2000)) {
    return false;
  }
  bool ok = SD.exists(path.c_str());
  if (!ok) {
    ok = SD.mkdir(path);
  }
  unlockSd();
  return ok;
}

void finishTileDownload(bool ok) {
#if ENABLE_WIFI
  bool wasFromMapDownload = queuedFromMapDownload;
  int doneZ = queuedZ;
  int doneX = queuedX;
  int doneY = queuedY;
  bool success = ok;
  bool verifiedOk = false;
  if (tileDownloadFile) {
    tileDownloadFile.close();
  }
  tileDownloadHttp.end();
  if (success && tileDownloadFinalPath.length() > 0 && tileDownloadPath.length() > 0) {
    if (lockSd(2000)) {
      if (SD.exists(tileDownloadFinalPath.c_str())) {
        SD.remove(tileDownloadFinalPath.c_str());
      }
      if (!SD.rename(tileDownloadPath.c_str(), tileDownloadFinalPath.c_str())) {
        success = false;
      } else {
        verifiedOk = SD.exists(tileDownloadFinalPath.c_str());
        if (!verifiedOk) {
          success = false;
        }
      }
      unlockSd();
    } else {
      success = false;
    }
  }
  if (success && !verifiedOk) {
    verifiedOk = true;
  }
  if (success && verifiedOk && tileDownloadFinalPath.length() > 0) {
    if (lockSd(200)) {
      FsFile verifyFile = SD.open(tileDownloadFinalPath.c_str(), FILE_READ);
      if (verifyFile) {
        uint32_t size = static_cast<uint32_t>(verifyFile.fileSize());
        verifyFile.close();
        if (size < 64) {
          success = false;
        }
      } else {
        success = false;
      }
      unlockSd();
    } else {
      success = false;
    }
  }
  if (!success && tileDownloadPath.length() > 0) {
    if (lockSd(2000)) {
      SD.remove(tileDownloadPath.c_str());
      if (tileDownloadFinalPath.length() > 0) {
        SD.remove(tileDownloadFinalPath.c_str());
      }
      unlockSd();
    }
  }
  tileDownloadActive = false;
  tileDownloadQueued = false;
  if (wasFromMapDownload) {
    uint32_t now = millis();
    bool wasActive = mapDownload.active;
    mapDownload.doneTiles++;
    if (!success) {
      mapDownload.failedTiles++;
    } else if (verifiedOk) {
      mapDownload.verifiedTiles++;
    }
    if (mapDownload.doneTiles > mapDownload.totalTiles) {
      mapDownload.doneTiles = mapDownload.totalTiles;
    }
    if (mapDownload.active && mapDownload.totalTiles > 0 &&
        mapDownload.doneTiles >= mapDownload.totalTiles) {
      mapDownload.active = false;
    }
    bool ended = wasActive && !mapDownload.active;
    if (ended) {
      refreshTileZoomRange(true);
      mapTilesDrawn = false;
      lastMapTileViewValid = false;
      mapDirty = true;
      mapDownloadDirty = true;
    } else if (now - lastMapDownloadUiMs >= kMapDownloadUiIntervalMs) {
      mapDownloadProgressDirty = true;
      lastMapDownloadUiMs = now;
    }
  }
  if (!success) {
    if (lastTileDownloadStatus.length() == 0) {
      lastTileDownloadStatus = "DOWNLOAD FAILED";
      lastTileDownloadStatusMs = millis();
    }
    noteTileDownloadFailure(doneZ, doneX, doneY);
  } else {
    lastTileDownloadHttpCode = 0;
    lastTileDownloadStatus = "";
    lastTileDownloadStatusMs = 0;
    mapTilesDrawn = false;
    if (doneZ > static_cast<int>(mapMaxZoom)) {
      mapMaxZoom = static_cast<uint8_t>(doneZ);
    }
  }
  queuedFromMapDownload = false;
  lastTileDownloadMs = millis();
  if (!wasFromMapDownload && screen == SCREEN_MAIN) {
    mapDirty = true;
  }
  debugPrint("DL: done z=%d x=%d y=%d ok=%d", doneZ, doneX, doneY, success ? 1 : 0);
  tileDownloadPath = "";
  tileDownloadFinalPath = "";
#else
  (void)ok;
#endif
}

bool beginTileDownload() {
#if ENABLE_WIFI
  if (!tileDownloadQueued) {
    return false;
  }
  tileDownloadPath = "";
  tileDownloadFinalPath = "";
  if (!sdReady || tileServerBase.length() == 0 || !wifiEnabled || !wifiAvailable) {
    finishTileDownload(false);
    return false;
  }
  if (WiFi.status() != WL_CONNECTED) {
    finishTileDownload(false);
    return false;
  }
  String zDir = tileRoot + "/" + String(queuedZ);
  String xDir = zDir + "/" + String(queuedX);
  if (!ensureDir(tileRoot) || !ensureDir(zDir) || !ensureDir(xDir)) {
    finishTileDownload(false);
    return false;
  }

  String url = tileServerBase + "/" + String(queuedZ) + "/" + String(queuedX) + "/" +
               String(queuedY) + ".png";
  if (tileServerKey.length() > 0 && url.indexOf("apikey=") < 0) {
    url += (url.indexOf('?') >= 0) ? "&apikey=" : "?apikey=";
    url += tileServerKey;
  }
  lastTileDownloadStatus = "";
  lastTileDownloadStatusMs = 0;
  lastTileDownloadHttpCode = 0;
  debugPrint("DL: start z=%d x=%d y=%d", queuedZ, queuedX, queuedY);
  tileDownloadFinalPath = tilePath(queuedZ, queuedX, queuedY);
  tileDownloadPath = tileDownloadFinalPath + ".tmp";

  if (url.startsWith("https://")) {
    tileDownloadSecureClient.setInsecure();
    tileDownloadSecureClient.setTimeout(kTileDownloadTimeoutMs);
    tileDownloadSecureClient.setHandshakeTimeout(5);
    tileDownloadHttp.begin(tileDownloadSecureClient, url);
  } else {
    tileDownloadPlainClient.setTimeout(kTileDownloadTimeoutMs);
    tileDownloadHttp.begin(tileDownloadPlainClient, url);
  }
  tileDownloadHttp.setReuse(true);
  tileDownloadHttp.useHTTP10(false);
  tileDownloadHttp.setUserAgent("Tab5ResponderNav/1.0");
  tileDownloadHttp.setFollowRedirects(HTTPC_STRICT_FOLLOW_REDIRECTS);
  tileDownloadHttp.setConnectTimeout(kTileDownloadTimeoutMs);
  tileDownloadHttp.setTimeout(kTileDownloadTimeoutMs);
  int code = tileDownloadHttp.GET();
  if (code != HTTP_CODE_OK) {
    lastTileDownloadHttpCode = code;
    if (code > 0) {
      lastTileDownloadStatus = "HTTP " + String(code);
    } else {
      lastTileDownloadStatus = HTTPClient::errorToString(code);
    }
    lastTileDownloadStatusMs = millis();
    debugPrint("DL: HTTP code=%d msg=%s", code, lastTileDownloadStatus.c_str());
    tileDownloadHttp.end();
    finishTileDownload(false);
    return false;
  }

  if (!lockSd(2000)) {
    tileDownloadHttp.end();
    finishTileDownload(false);
    return false;
  }
  if (SD.exists(tileDownloadPath.c_str())) {
    SD.remove(tileDownloadPath.c_str());
  }
  tileDownloadFile = SD.open(tileDownloadPath.c_str(), FILE_WRITE);
  unlockSd();
  if (!tileDownloadFile) {
    tileDownloadHttp.end();
    finishTileDownload(false);
    return false;
  }

  WiFiClient *stream = tileDownloadHttp.getStreamPtr();
  if (!stream) {
    tileDownloadHttp.end();
    finishTileDownload(false);
    return false;
  }
  tileDownloadContentLen = tileDownloadHttp.getSize();
  tileDownloadActive = true;
  return true;
#else
  return false;
#endif
}

void processTileDownloadChunk() {
#if ENABLE_WIFI
  if (!tileDownloadActive) {
    return;
  }
  if (!wifiEnabled || WiFi.status() != WL_CONNECTED) {
    finishTileDownload(false);
    return;
  }
  WiFiClient *stream = tileDownloadHttp.getStreamPtr();
  if (!stream) {
    finishTileDownload(false);
    return;
  }
  uint32_t startMs = millis();
  bool foregroundDownloadScreen =
      (screen == SCREEN_MAIN || screen == SCREEN_DOWNLOAD || screen == SCREEN_MAP_DL);
  size_t chunkByteLimit = foregroundDownloadScreen ? kTileDownloadChunkBytes :
                          (focusedDownloadThrottleEnabled ? kTileDownloadChunkBytesFocused :
                                                           kTileDownloadChunkBytesBg);
  uint32_t chunkTimeLimit = foregroundDownloadScreen ? kTileDownloadChunkMs :
                            (focusedDownloadThrottleEnabled ? kTileDownloadChunkMsFocused :
                                                             kTileDownloadChunkMsBg);
  size_t totalRead = 0;
  while (tileDownloadHttp.connected() &&
         (tileDownloadContentLen > 0 || tileDownloadContentLen == -1)) {
    size_t available = stream->available();
    if (available == 0) {
      break;
    }
    size_t toRead = min(static_cast<size_t>(available),
                        static_cast<size_t>(sizeof(tileDownloadBuffer)));
    if (totalRead + toRead > chunkByteLimit) {
      toRead = chunkByteLimit - totalRead;
    }
    int read = stream->read(tileDownloadBuffer, static_cast<int>(toRead));
    if (read <= 0) {
      break;
    }
    if (!lockSd(2000)) {
      finishTileDownload(false);
      return;
    }
    tileDownloadFile.write(tileDownloadBuffer, read);
    unlockSd();
    totalRead += static_cast<size_t>(read);
    if (tileDownloadContentLen > 0) {
      tileDownloadContentLen -= read;
    }
    if (totalRead >= chunkByteLimit || millis() - startMs >= chunkTimeLimit) {
      break;
    }
  }

  bool done = false;
  if (tileDownloadContentLen == 0) {
    done = true;
  } else if (tileDownloadContentLen < 0 && !tileDownloadHttp.connected() &&
             stream->available() == 0) {
    done = true;
  } else if (!tileDownloadHttp.connected() && tileDownloadContentLen > 0) {
    finishTileDownload(false);
    return;
  }

  if (done) {
    finishTileDownload(tileDownloadContentLen <= 0);
  }
#endif
}

void processTileDownload() {
#if ENABLE_WIFI
  static uint32_t lastFocusedChunkMs = 0;
  if (!wifiEnabled || !wifiAvailable) {
    return;
  }
  if (tileDownloadActive) {
    if (focusedDownloadThrottleEnabled) {
      uint32_t now = millis();
      uint32_t interval = isAudioPlaybackSensitive() ? kTileDownloadChunkIntervalAudioMs :
                                                       kTileDownloadChunkIntervalFocusedMs;
      if (now - lastFocusedChunkMs < interval) {
        return;
      }
      lastFocusedChunkMs = now;
    }
    processTileDownloadChunk();
    return;
  }
  if (!tileDownloadQueued) {
    return;
  }
  if (isAudioPlaybackSensitive()) {
    return;
  }
  if (millis() - lastUserInputMs < kDownloadInputQuietMs) {
    return;
  }
  if (millis() - lastTileDownloadMs < kTileDownloadCooldownMs) {
    return;
  }
  if (beginTileDownload()) {
    processTileDownloadChunk();
  }
#else
  tileDownloadQueued = false;
#endif
}

void tileDownloadTask(void *param) {
  (void)param;
  for (;;) {
    if (tileDownloadTaskStop) {
      abortTileDownload();
      tileDownloadTaskStop = false;
      tileDownloadTaskHandle = nullptr;
      vTaskDelete(nullptr);
      return;
    }
    if (!tileDownloadProcessingEnabled && !tileDownloadActive) {
      vTaskDelay(pdMS_TO_TICKS(kTileDownloadTaskIdleMs));
      continue;
    }
    if (tileDownloadActive) {
      processTileDownloadChunk();
      vTaskDelay(pdMS_TO_TICKS(1));
      continue;
    }
    if (!tileDownloadQueued) {
      vTaskDelay(pdMS_TO_TICKS(kTileDownloadTaskIdleMs));
      continue;
    }
    if (millis() - lastUserInputMs < kDownloadInputQuietMs ||
        millis() - lastTileDownloadMs < kTileDownloadCooldownMs) {
      vTaskDelay(pdMS_TO_TICKS(kTileDownloadTaskIdleMs));
      continue;
    }
    if (beginTileDownload()) {
      processTileDownloadChunk();
      vTaskDelay(pdMS_TO_TICKS(1));
      continue;
    }
    vTaskDelay(pdMS_TO_TICKS(kTileDownloadTaskIdleMs));
  }
}

double clampLat(double lat) {
  if (lat > 85.0511) {
    return 85.0511;
  }
  if (lat < -85.0511) {
    return -85.0511;
  }
  return lat;
}

double clampLon(double lon) {
  if (lon > 180.0) {
    return 180.0;
  }
  if (lon < -180.0) {
    return -180.0;
  }
  return lon;
}

void formatHms(uint32_t seconds, bool wrap24, char *buffer, size_t bufferLen) {
  if (wrap24) {
    seconds %= 86400;
  }
  uint32_t hours = seconds / 3600;
  uint32_t minutes = (seconds / 60) % 60;
  uint32_t secs = seconds % 60;
  snprintf(buffer, bufferLen, "%02lu:%02lu:%02lu", static_cast<unsigned long>(hours),
           static_cast<unsigned long>(minutes), static_cast<unsigned long>(secs));
}

void formatHm12(uint32_t seconds, char *buffer, size_t bufferLen) {
  seconds %= 86400;
  uint32_t hours = seconds / 3600;
  uint32_t minutes = (seconds / 60) % 60;
  bool pm = hours >= 12;
  uint32_t hour12 = hours % 12;
  if (hour12 == 0) {
    hour12 = 12;
  }
  snprintf(buffer, bufferLen, "%02lu:%02lu %s", static_cast<unsigned long>(hour12),
           static_cast<unsigned long>(minutes), pm ? "PM" : "AM");
}

bool formatUtcFromEpoch(time_t epoch, char *buffer, size_t bufferLen) {
  if (epoch <= 0 || bufferLen < 9) {
    return false;
  }
  struct tm timeinfo;
  if (gmtime_r(&epoch, &timeinfo) == nullptr) {
    return false;
  }
  snprintf(buffer, bufferLen, "%02u:%02u:%02u", static_cast<unsigned>(timeinfo.tm_hour),
           static_cast<unsigned>(timeinfo.tm_min), static_cast<unsigned>(timeinfo.tm_sec));
  return true;
}

bool formatEpochHm12(time_t epoch, char *buffer, size_t bufferLen) {
  if (epoch <= 0 || bufferLen < 7) {
    return false;
  }
  struct tm timeinfo;
  if (gmtime_r(&epoch, &timeinfo) == nullptr) {
    return false;
  }
  int hour = timeinfo.tm_hour;
  bool pm = hour >= 12;
  int hour12 = hour % 12;
  if (hour12 == 0) {
    hour12 = 12;
  }
  snprintf(buffer, bufferLen, "%02d:%02d %s", hour12, timeinfo.tm_min, pm ? "PM" : "AM");
  return true;
}

int computeTimeZoneOffset(double lon) {
  int offset = static_cast<int>(lround(lon / 15.0));
  if (offset < kTimeZoneMinOffset) {
    offset = kTimeZoneMinOffset;
  }
  if (offset > kTimeZoneMaxOffset) {
    offset = kTimeZoneMaxOffset;
  }
  return offset;
}

bool tileExistsAtZoom(double lat, double lon, uint8_t zoom, int &tileX, int &tileY) {
  if (!sdReady) {
    return false;
  }
  double worldX = 0.0;
  double worldY = 0.0;
  geoToWorldPixels(lat, lon, zoom, worldX, worldY);
  int tileCount = 1 << zoom;
  int tx = static_cast<int>(floor(worldX / 256.0));
  int ty = static_cast<int>(floor(worldY / 256.0));
  if (ty < 0 || ty >= tileCount) {
    return false;
  }
  int wrappedX = tx % tileCount;
  if (wrappedX < 0) {
    wrappedX += tileCount;
  }
  tileX = wrappedX;
  tileY = ty;
  String path = tilePath(zoom, wrappedX, ty);
  if (!lockSd(5)) {
    return false;
  }
  bool exists = SD.exists(path.c_str());
  unlockSd();
  return exists;
}

bool findNearestAvailableZoom(double lat, double lon, uint8_t desiredZoom, uint8_t &outZoom) {
  int minZoom = static_cast<int>(mapMinZoom);
  int maxZoom = static_cast<int>(mapMaxZoom);
  if (minZoom > maxZoom) {
    return false;
  }
  int range = maxZoom - minZoom;
  for (int delta = 0; delta <= range; ++delta) {
    int z1 = static_cast<int>(desiredZoom) - delta;
    int z2 = static_cast<int>(desiredZoom) + delta;
    int tx = 0;
    int ty = 0;
    if (z1 >= minZoom && z1 <= maxZoom) {
      if (tileExistsAtZoom(lat, lon, static_cast<uint8_t>(z1), tx, ty)) {
        outZoom = static_cast<uint8_t>(z1);
        return true;
      }
    }
    if (delta == 0) {
      continue;
    }
    if (z2 >= minZoom && z2 <= maxZoom) {
      if (tileExistsAtZoom(lat, lon, static_cast<uint8_t>(z2), tx, ty)) {
        outZoom = static_cast<uint8_t>(z2);
        return true;
      }
    }
  }
  return false;
}

bool maybeAdjustZoomForLocation(double lat, double lon) {
  (void)lat;
  (void)lon;
  return false;
  if (!sdReady) {
    return false;
  }
  uint32_t now = millis();
  if (now - lastManualZoomMs < kAutoZoomHoldMs) {
    debugPrint("ZOOM: auto adjust skipped (manual hold)");
    return false;
  }
  int tx = 0;
  int ty = 0;
  if (tileExistsAtZoom(lat, lon, mapZoom, tx, ty)) {
    return false;
  }
  if (tx == lastAutoZoomTileX && ty == lastAutoZoomTileY && mapZoom == lastAutoZoomZoom &&
      now - lastAutoZoomMs < kAutoZoomCheckMs) {
    return false;
  }
  lastAutoZoomTileX = tx;
  lastAutoZoomTileY = ty;
  lastAutoZoomZoom = mapZoom;
  lastAutoZoomMs = now;

  uint8_t newZoom = mapZoom;
  if (!findNearestAvailableZoom(lat, lon, mapZoom, newZoom)) {
    return false;
  }
  if (newZoom == mapZoom) {
    return false;
  }
  mapZoom = newZoom;
  if (mapZoom < mapMinZoom) {
    mapMinZoom = mapZoom;
  }
  if (mapZoom > mapMaxZoom) {
    mapMaxZoom = mapZoom;
  }
  lastAutoZoomAppliedMs = millis();
  lastMapHasFix = false;
  mapDirty = true;
  statusDirty = true;
  return true;
}

bool fetchWifiGeoLocation(double &lat, double &lon, String &city, String &region, String &country) {
#if ENABLE_WIFI
  if (!wifiEnabled || !wifiAvailable || WiFi.status() != WL_CONNECTED) {
    return false;
  }
  WiFiClient client;
  HTTPClient http;
  http.setTimeout(6000);
  if (!http.begin(client,
                  "http://ip-api.com/json?fields=status,lat,lon,city,regionName,country")) {
    return false;
  }
  int code = http.GET();
  if (code != HTTP_CODE_OK) {
    http.end();
    return false;
  }
  String payload = http.getString();
  http.end();
  String status;
  if (!extractJsonStringField(payload, "status", status) || status != "success") {
    return false;
  }
  int latPos = payload.indexOf("\"lat\":");
  int lonPos = payload.indexOf("\"lon\":");
  if (latPos < 0 || lonPos < 0) {
    return false;
  }
  int latStart = latPos + 6;
  while (latStart < payload.length() && payload[latStart] == ' ') {
    ++latStart;
  }
  int latEnd = payload.indexOf(',', latStart);
  if (latEnd < 0) {
    latEnd = payload.indexOf('}', latStart);
  }
  int lonStart = lonPos + 6;
  while (lonStart < payload.length() && payload[lonStart] == ' ') {
    ++lonStart;
  }
  int lonEnd = payload.indexOf(',', lonStart);
  if (lonEnd < 0) {
    lonEnd = payload.indexOf('}', lonStart);
  }
  if (latEnd <= latStart || lonEnd <= lonStart) {
    return false;
  }
  lat = payload.substring(latStart, latEnd).toDouble();
  lon = payload.substring(lonStart, lonEnd).toDouble();
  city = "";
  region = "";
  country = "";
  extractJsonStringField(payload, "city", city);
  extractJsonStringField(payload, "regionName", region);
  extractJsonStringField(payload, "country", country);
  return true;
#else
  (void)lat;
  (void)lon;
  (void)city;
  (void)region;
  (void)country;
  return false;
#endif
}

void updateWifiGeoLocation(uint32_t now) {
#if ENABLE_WIFI
  if (gps.location.isValid()) {
    return;
  }
  if (!wifiEnabled || !wifiAvailable || WiFi.status() != WL_CONNECTED) {
    return;
  }
  if (!wifiGeoUseAllowed) {
    return;
  }
  bool refreshDue = wifiGeoValid ? now - lastWifiGeoMs >= kWifiGeoCooldownMs
                                 : lastWifiGeoAttemptMs == 0 ||
                                       now - lastWifiGeoAttemptMs >= kWifiGeoRetryMs;
  if (refreshDue) {
    lastWifiGeoAttemptMs = now;
    double lat = 0.0;
    double lon = 0.0;
    String city;
    String region;
    String country;
    if (fetchWifiGeoLocation(lat, lon, city, region, country)) {
      wifiGeoLat = lat;
      wifiGeoLon = lon;
      wifiGeoCity = city;
      wifiGeoRegion = region;
      wifiGeoCountry = country;
      wifiGeoValid = true;
      lastWifiGeoMs = now;
    }
  }
#else
  (void)now;
#endif
}

bool regionToTileRange(const MapRegion &region, uint8_t zoom, int &xMin, int &xMax, int &yMin, int &yMax) {
  double lat1 = clampLat(region.minLat);
  double lat2 = clampLat(region.maxLat);
  double lon1 = clampLon(region.minLon);
  double lon2 = clampLon(region.maxLon);
  double x1 = 0.0;
  double y1 = 0.0;
  double x2 = 0.0;
  double y2 = 0.0;
  geoToWorldPixels(lat1, lon1, zoom, x1, y1);
  geoToWorldPixels(lat2, lon2, zoom, x2, y2);

  double minX = min(x1, x2);
  double maxX = max(x1, x2);
  double minY = min(y1, y2);
  double maxY = max(y1, y2);
  int tileCount = 1 << zoom;
  xMin = max(0, min(tileCount - 1, static_cast<int>(floor(minX / 256.0))));
  xMax = max(0, min(tileCount - 1, static_cast<int>(floor(maxX / 256.0))));
  yMin = max(0, min(tileCount - 1, static_cast<int>(floor(minY / 256.0))));
  yMax = max(0, min(tileCount - 1, static_cast<int>(floor(maxY / 256.0))));
  return xMin <= xMax && yMin <= yMax;
}

uint32_t countRegionTiles(const MapRegion &region, uint8_t minZoom, uint8_t maxZoom) {
  uint64_t total = 0;
  for (uint8_t z = minZoom; z <= maxZoom; ++z) {
    int xMin = 0;
    int xMax = -1;
    int yMin = 0;
    int yMax = -1;
    if (!regionToTileRange(region, z, xMin, xMax, yMin, yMax)) {
      continue;
    }
    uint64_t dx = static_cast<uint64_t>(xMax - xMin + 1);
    uint64_t dy = static_cast<uint64_t>(yMax - yMin + 1);
    total += dx * dy;
    if (total > 0xFFFFFFFFULL) {
      total = 0xFFFFFFFFULL;
      break;
    }
  }
  return static_cast<uint32_t>(total);
}

bool setupMapDownloadZoom(uint8_t zoom) {
  int xMin = 0;
  int xMax = -1;
  int yMin = 0;
  int yMax = -1;
  if (!regionToTileRange(kMapRegions[mapDownload.regionIndex], zoom, xMin, xMax, yMin, yMax)) {
    return false;
  }
  mapDownload.zoom = zoom;
  mapDownload.xStart = xMin;
  mapDownload.xEnd = xMax;
  mapDownload.yStart = yMin;
  mapDownload.yEnd = yMax;
  mapDownload.x = xMin;
  mapDownload.y = yMin;
  return true;
}

bool advanceMapDownloadZoom() {
  for (uint8_t z = static_cast<uint8_t>(mapDownload.zoom + 1); z <= mapDownload.maxZoom; ++z) {
    if (setupMapDownloadZoom(z)) {
      return true;
    }
  }
  mapDownload.active = false;
  return false;
}

bool nextMapDownloadTile(uint8_t &z, int &x, int &y, int scanBudget, uint32_t scanMs) {
  int scanned = 0;
  uint32_t startMs = millis();
  bool progressChanged = false;
  while (mapDownload.active) {
    if (scanned >= scanBudget || millis() - startMs >= scanMs) {
      break;
    }
    if (mapDownload.x > mapDownload.xEnd) {
      mapDownload.x = mapDownload.xStart;
      mapDownload.y++;
    }
    if (mapDownload.y > mapDownload.yEnd) {
      if (!advanceMapDownloadZoom()) {
        return false;
      }
      continue;
    }
    int curX = mapDownload.x;
    int curY = mapDownload.y;
    mapDownload.x++;
    String path = tilePath(mapDownload.zoom, curX, curY);
    bool exists = false;
    if (sdReady && lockSd(5)) {
      exists = SD.exists(path.c_str());
      unlockSd();
    }
    if (exists) {
      mapDownload.doneTiles++;
      mapDownload.skippedTiles++;
      mapDownload.verifiedTiles++;
      mapDownload.verifiedExistingTiles++;
      progressChanged = true;
      if (mapDownload.doneTiles >= mapDownload.totalTiles && mapDownload.totalTiles > 0) {
        mapDownload.active = false;
        break;
      }
      scanned++;
      continue;
    }
    z = mapDownload.zoom;
    x = curX;
    y = curY;
    return true;
  }
  if (progressChanged) {
    uint32_t now = millis();
    if (!mapDownload.active) {
      mapDownloadDirty = true;
    } else if (now - lastMapDownloadUiMs >= kMapDownloadUiIntervalMs) {
      mapDownloadProgressDirty = true;
      lastMapDownloadUiMs = now;
    }
  }
  return false;
}

void startMapDownload(int regionIndex) {
  mapDownload = MapDownloadJob();
  mapDownload.active = true;
  mapDownload.regionIndex = regionIndex;
  mapDownload.minZoom = mapDownloadMinZoomSel;
  mapDownload.maxZoom = mapDownloadMaxZoomSel;
  if (mapDownload.minZoom < kDownloadMinZoom) {
    mapDownload.minZoom = kDownloadMinZoom;
  }
  if (mapDownload.maxZoom > kDownloadMaxZoom) {
    mapDownload.maxZoom = kDownloadMaxZoom;
  }
  if (mapDownload.minZoom > mapDownload.maxZoom) {
    mapDownload.maxZoom = mapDownload.minZoom;
  }
  mapDownload.totalTiles =
      countRegionTiles(kMapRegions[mapDownload.regionIndex], mapDownload.minZoom, mapDownload.maxZoom);
  if (mapDownload.totalTiles == 0) {
    mapDownload.active = false;
    mapDownloadDirty = true;
    return;
  }
  if (!setupMapDownloadZoom(mapDownload.minZoom)) {
    if (!advanceMapDownloadZoom()) {
      mapDownload.active = false;
    }
  }
  mapDownloadDirty = true;
}

void stopMapDownload() {
  mapDownload.active = false;
  mapDownloadDirty = true;
  if (refreshTileZoomRange(true)) {
    mapTilesDrawn = false;
    lastMapTileViewValid = false;
    mapDirty = true;
  }
}

void processMapDownload() {
#if ENABLE_WIFI
  static bool lastBlocked = false;
  static uint32_t lastBgStepMs = 0;
  static uint8_t lastState = 0xFF;
  static uint32_t lastStateLogMs = 0;
  auto logState = [&](uint8_t state, const char *msg) {
    uint32_t now = millis();
    if (state != lastState || now - lastStateLogMs >= 2000) {
      debugPrint("MAPDL: %s", msg);
      lastState = state;
      lastStateLogMs = now;
    }
  };
  bool blocked = tileDownloadQueued || tileDownloadActive;
  if (!mapDownload.active) {
    if (lastBlocked) {
      debugPrint("MAPDL: idle");
      lastBlocked = false;
    }
    return;
  }
  if (blocked) {
    if (!lastBlocked) {
      debugPrint("MAPDL: wait tile q=%d a=%d done=%lu/%lu", tileDownloadQueued ? 1 : 0,
                 tileDownloadActive ? 1 : 0, static_cast<unsigned long>(mapDownload.doneTiles),
                 static_cast<unsigned long>(mapDownload.totalTiles));
      lastBlocked = true;
    }
    return;
  }
  if (lastBlocked) {
    debugPrint("MAPDL: resume done=%lu/%lu", static_cast<unsigned long>(mapDownload.doneTiles),
               static_cast<unsigned long>(mapDownload.totalTiles));
    lastBlocked = false;
  }
  if (!sdReady || tileServerBase.length() == 0) {
    logState(1, !sdReady ? "blocked sd-not-ready" : "blocked no-server");
    return;
  }
  if (!wifiEnabled || !wifiAvailable || WiFi.status() != WL_CONNECTED) {
    logState(2, "blocked wifi-not-connected");
    return;
  }
  if (millis() - lastTileDownloadMs < kTileDownloadCooldownMs) {
    logState(3, "blocked cooldown");
    return;
  }
  if (millis() - lastUserInputMs < kDownloadInputQuietMs) {
    logState(4, "blocked input-quiet");
    return;
  }
  if (isAudioPlaybackSensitive()) {
    logState(7, "blocked audio-focus");
    return;
  }
  bool foregroundDownloadScreen =
      (screen == SCREEN_MAIN || screen == SCREEN_DOWNLOAD || screen == SCREEN_MAP_DL);
  if (!foregroundDownloadScreen) {
    uint32_t now = millis();
    uint32_t stepInterval =
        focusedDownloadThrottleEnabled ? kMapDownloadStepIntervalFocusedMs : kMapDownloadStepIntervalBgMs;
    if (now - lastBgStepMs < stepInterval) {
      logState(6, "blocked bg-throttle");
      return;
    }
    lastBgStepMs = now;
  }
  logState(5, "scan-next");
  uint8_t z = 0;
  int x = 0;
  int y = 0;
  int scanBudget = foregroundDownloadScreen ? kMapDownloadScanBudget :
                   (focusedDownloadThrottleEnabled ? kMapDownloadScanBudgetFocused : kMapDownloadScanBudgetBg);
  uint32_t scanMs = foregroundDownloadScreen ? kMapDownloadScanMs :
                    (focusedDownloadThrottleEnabled ? kMapDownloadScanMsFocused : kMapDownloadScanMsBg);
  if (!nextMapDownloadTile(z, x, y, scanBudget, scanMs)) {
    if (!mapDownload.active) {
      mapDownloadDirty = true;
    }
    return;
  }
  queueTileDownload(z, x, y, true);
#endif
}

void drawMapDownloadScreen() {
#if ENABLE_WIFI
  uint32_t now = millis();
  if (mapDownloadBusyDirty && !mapDownloadDirty && !mapDownloadNeedsFullRedraw &&
      !mapDownloadProgressDirty && !mapDownloadStatusDirty) {
    drawBusyIndicatorTopCenter(kSmallTextSize);
    mapDownloadBusyDirty = false;
    return;
  }
  uint8_t textSize = kWifiTextSize;
  M5.Display.setTextSize(textSize);
  int16_t titleY = 12;
  int16_t lineH = static_cast<int16_t>(M5.Display.fontHeight() + 4);
  int16_t statusY = static_cast<int16_t>(titleY + lineH);
  uint8_t displayMin = mapDownload.active ? mapDownload.minZoom : mapDownloadMinZoomSel;
  uint8_t displayMax = mapDownload.active ? mapDownload.maxZoom : mapDownloadMaxZoomSel;
  if (displayMin == 0) {
    displayMin = kDownloadMinZoom;
  }
  if (displayMax == 0) {
    displayMax = kDownloadMaxZoom;
  }
  String zoomLabel = "ZOOM " + String(displayMin) + "-" + String(displayMax);
  uint16_t statusColor = colors.red;
  String status = "WIFI OFF";
  if (!wifiAvailable) {
    status = "WIFI N/A";
  } else if (wifiEnabled && WiFi.status() == WL_CONNECTED) {
    status = "WIFI OK";
    statusColor = colors.amber;
  } else if (wifiEnabled) {
    status = "WIFI WAIT";
    statusColor = colors.amberDim;
  }
  if (tileServerBase.length() == 0) {
    status = "NO SERVER";
    statusColor = colors.red;
  }

  int16_t barH = max<int16_t>(8, static_cast<int16_t>(lineH / 2));
  int16_t footerPad = 6;
  int16_t barGap = 6;
  int16_t footerH =
      static_cast<int16_t>(lineH * 2 + barH * 2 + barGap * 2 + footerPad * 2);
  if (mapDownload.failedTiles > 0) {
    footerH = static_cast<int16_t>(footerH + lineH + 2);
  }
  if (lastTileDownloadStatus.length() > 0 && now - lastTileDownloadStatusMs < 120000) {
    footerH = static_cast<int16_t>(footerH + lineH + 2);
  }
  int16_t footerY = static_cast<int16_t>(screenH - navH - footerH - 4);
  if (footerY < mapDlListRect.y) {
    footerY = mapDlListRect.y;
  }
  int16_t listGap = 8;
  int16_t listBottom = static_cast<int16_t>(footerY - listGap);
  int16_t listH = static_cast<int16_t>(listBottom - mapDlListRect.y);
  if (listH < 0) {
    listH = 0;
  }
  if (listH != mapDlListRect.h) {
    mapDlListRect.h = listH;
    int16_t arrowPad = kMapDlArrowPad;
    int16_t arrowH =
        static_cast<int16_t>(max<int16_t>(40, (mapDlListRect.h - arrowPad * 3) / 2));
    mapDlUpButton.y = static_cast<int16_t>(mapDlListRect.y + arrowPad);
    mapDlUpButton.h = arrowH;
    mapDlDownButton.y =
        static_cast<int16_t>(mapDlListRect.y + mapDlListRect.h - arrowPad - arrowH);
    mapDlDownButton.h = arrowH;
    mapDownloadNeedsFullRedraw = true;
  }

  bool canStart = wifiEnabled && wifiAvailable && WiFi.status() == WL_CONNECTED &&
                  tileServerBase.length() > 0 && sdReady;
  const char *actionLabel = mapDownload.active ? "STOP DOWNLOAD" : "START DOWNLOAD";
  uint16_t actionFg = mapDownload.active ? colors.red : (canStart ? colors.amber : colors.amberDim);
  uint16_t actionBg = mapDownload.active ? colors.redDim : colors.black;

  auto drawHeader = [&]() {
    drawMenuSectionHeader("MAP DOWNLOADS", 64);
  };

  auto drawActionButton = [&]() {
    M5.Display.fillRect(mapDlActionButton.x, mapDlActionButton.y, mapDlActionButton.w,
                        mapDlActionButton.h, actionBg);
    M5.Display.drawRect(mapDlActionButton.x, mapDlActionButton.y, mapDlActionButton.w,
                        mapDlActionButton.h, actionFg);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextColor(colors.amberDim, actionBg);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString("TRANSFER CONTROL", static_cast<int16_t>(mapDlActionButton.x + 14),
                          static_cast<int16_t>(mapDlActionButton.y + 10));
    M5.Display.setTextDatum(TR_DATUM);
    M5.Display.setTextColor(statusColor, actionBg);
    M5.Display.drawString(status, static_cast<int16_t>(mapDlActionButton.x +
                                                       mapDlActionButton.w - 14),
                          static_cast<int16_t>(mapDlActionButton.y + 10));
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(actionFg, actionBg);
    M5.Display.setTextSize(kButtonTextSize + 1);
    M5.Display.drawString(actionLabel, mapDlActionButton.x + mapDlActionButton.w / 2,
                          static_cast<int16_t>(mapDlActionButton.y +
                                               mapDlActionButton.h / 2 + 12));
  };

  auto drawFooter = [&]() {
    M5.Display.fillRect(0, footerY, screenW, footerH, colors.black);
    M5.Display.setTextDatum(TL_DATUM);

    uint32_t total = mapDownload.totalTiles;
    uint32_t verified = mapDownload.verifiedTiles;
    uint32_t verifiedExisting = mapDownload.verifiedExistingTiles;
    uint32_t skipped = mapDownload.skippedTiles;
    uint32_t failed = mapDownload.failedTiles;
    uint32_t done = mapDownload.doneTiles;
    uint32_t downloaded = 0;
    if (done > skipped + failed) {
      downloaded = done - skipped - failed;
    }
    uint32_t downloadTotal = (total > verifiedExisting) ? (total - verifiedExisting) : 0;
    uint32_t displayDownloaded = min<uint32_t>(downloaded, downloadTotal);
    uint32_t displayVerified = min<uint32_t>(verified, total);
    uint32_t barDownloadTotal = max<uint32_t>(1, downloadTotal);
    uint32_t barDownloadValue = displayDownloaded;
    if (downloadTotal == 0 && total > 0) {
      barDownloadValue = barDownloadTotal;
    }

    auto drawBar = [&](int16_t x, int16_t y, int16_t w, int16_t h, uint32_t value,
                       uint32_t maxValue, uint16_t fg) {
      M5.Display.drawRect(x, y, w, h, fg);
      if (w <= 2 || h <= 2) {
        return;
      }
      M5.Display.fillRect(x + 1, y + 1, w - 2, h - 2, colors.black);
      if (maxValue == 0) {
        return;
      }
      uint32_t clamped = min<uint32_t>(value, maxValue);
      int16_t fillW = static_cast<int16_t>((w - 2) * clamped / maxValue);
      if (fillW > 0) {
        M5.Display.fillRect(x + 1, y + 1, fillW, h - 2, fg);
      }
    };

    int16_t barX = 12;
    int16_t barW = static_cast<int16_t>(screenW - 24);
    int16_t y = static_cast<int16_t>(footerY + footerPad);
    M5.Display.setTextColor(mapDownload.active ? colors.amber : colors.amberDim, colors.black);
    if (downloadTotal == 0 && total > 0) {
      M5.Display.drawString("DOWNLOAD DONE", 12, y);
    } else if (mapDownload.active || downloaded > 0) {
      int percent = downloadTotal > 0 ? static_cast<int>((displayDownloaded * 100UL) / downloadTotal) : 0;
      percent = min(100, percent);
      String line = "DOWNLOAD " + String(displayDownloaded) + "/" + String(downloadTotal) + " (" +
                    String(percent) + "%)";
      M5.Display.drawString(line, 12, y);
    } else {
      M5.Display.drawString("DOWNLOAD IDLE", 12, y);
    }
    y = static_cast<int16_t>(y + lineH);
    drawBar(barX, y, barW, barH, barDownloadValue, barDownloadTotal, colors.amber);
    y = static_cast<int16_t>(y + barH + barGap);

    M5.Display.setTextColor(colors.amberDim, colors.black);
    if (total > 0 || verified > 0) {
      int percent = total > 0 ? static_cast<int>((displayVerified * 100UL) / total) : 0;
      percent = min(100, percent);
      String line = "VERIFY " + String(displayVerified) + "/" + String(total) + " (" +
                    String(percent) + "%)";
      M5.Display.drawString(line, 12, y);
    } else {
      M5.Display.drawString("VERIFY IDLE", 12, y);
    }
    y = static_cast<int16_t>(y + lineH);
    drawBar(barX, y, barW, barH, displayVerified, max<uint32_t>(1, total), colors.amberDim);
    y = static_cast<int16_t>(y + barH + barGap);

    if (mapDownload.failedTiles > 0) {
      M5.Display.setTextColor(colors.red, colors.black);
      String errors =
          "ERRORS " + String(mapDownload.failedTiles) + " SKIP " + String(mapDownload.skippedTiles);
      M5.Display.drawString(errors, 12, y);
      y = static_cast<int16_t>(y + lineH);
    }
    if (lastTileDownloadStatus.length() > 0 && now - lastTileDownloadStatusMs < 120000) {
      M5.Display.setTextColor(colors.red, colors.black);
      String line = "LAST " + lastTileDownloadStatus;
      M5.Display.drawString(line, 12, y);
    }
  };

  bool fullRedraw = mapDownloadNeedsFullRedraw || mapDownloadDirty;
  if (!fullRedraw && (mapDownloadStatusDirty || mapDownloadProgressDirty)) {
    if (mapDownloadStatusDirty) {
      M5.Display.fillRect(0, titleY - 2, screenW, static_cast<int16_t>(lineH * 2 + 6), colors.black);
      drawHeader();
      drawActionButton();
    }
    if (mapDownloadProgressDirty) {
      drawFooter();
    }
    drawBusyIndicatorTopCenter(kSmallTextSize);
    mapDownloadStatusDirty = false;
    mapDownloadProgressDirty = false;
    mapDownloadBusyDirty = false;
    return;
  }

  if (fullRedraw) {
    M5.Display.fillScreen(colors.black);
    mapDownloadNeedsFullRedraw = false;
  }

  drawHeader();
  drawActionButton();
  bool canAdjust = !mapDownload.active;
  uint16_t ctrlBg = colors.black;
  uint16_t ctrlFg = canAdjust ? colors.amber : colors.amberDim;
  uint16_t ctrlFgDisabled = colors.amberDim;
  auto drawCtrl = [&](const Rect &r, const String &label, uint16_t fg) {
    M5.Display.fillRect(r.x, r.y, r.w, r.h, ctrlBg);
    M5.Display.drawRect(r.x, r.y, r.w, r.h, fg);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(fg, ctrlBg);
    M5.Display.setTextSize(textSize);
    M5.Display.drawString(label, r.x + r.w / 2, r.y + r.h / 2);
  };

  M5.Display.fillRect(mapDlZoomBarRect.x, mapDlZoomBarRect.y, mapDlZoomBarRect.w,
                      mapDlZoomBarRect.h, colors.black);
  M5.Display.drawRect(mapDlZoomBarRect.x, mapDlZoomBarRect.y, mapDlZoomBarRect.w,
                      mapDlZoomBarRect.h, ctrlFg);
  int range = static_cast<int>(kDownloadMaxZoom) - static_cast<int>(kDownloadMinZoom);
  if (range < 1) {
    range = 1;
  }
  auto zoomToX = [&](uint8_t zoom) -> int16_t {
    int z = static_cast<int>(zoom);
    int x = mapDlZoomBarRect.x +
            (z - static_cast<int>(kDownloadMinZoom)) * mapDlZoomBarRect.w / range;
    return static_cast<int16_t>(x);
  };
  uint8_t minSel = displayMin;
  uint8_t maxSel = displayMax;
  int16_t minX = zoomToX(minSel);
  int16_t maxX = zoomToX(maxSel);
  int16_t barY = static_cast<int16_t>(mapDlZoomBarRect.y + mapDlZoomBarRect.h / 2);
  M5.Display.drawLine(mapDlZoomBarRect.x, barY, mapDlZoomBarRect.x + mapDlZoomBarRect.w, barY,
                      colors.amberDim);
  M5.Display.drawLine(minX, barY, maxX, barY, ctrlFg);
  int16_t handleW = 12;
  int16_t handleH = mapDlZoomBarRect.h;
  int16_t minHandleX = static_cast<int16_t>(minX - handleW / 2);
  int16_t maxHandleX = static_cast<int16_t>(maxX - handleW / 2);
  minHandleX = max<int16_t>(mapDlZoomBarRect.x, min<int16_t>(mapDlZoomBarRect.x + mapDlZoomBarRect.w - handleW, minHandleX));
  maxHandleX = max<int16_t>(mapDlZoomBarRect.x, min<int16_t>(mapDlZoomBarRect.x + mapDlZoomBarRect.w - handleW, maxHandleX));
  M5.Display.fillRect(minHandleX, mapDlZoomBarRect.y, handleW, handleH, ctrlFg);
  M5.Display.fillRect(maxHandleX, mapDlZoomBarRect.y, handleW, handleH, ctrlFg);
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextColor(ctrlFg, colors.black);
  M5.Display.setTextSize(kSmallTextSize + 1);
  M5.Display.drawString("MIN " + String(minSel), mapDlZoomBarRect.x + 2,
                        mapDlZoomBarRect.y + 2);
  M5.Display.setTextDatum(TR_DATUM);
  M5.Display.drawString("MAX " + String(maxSel), mapDlZoomBarRect.x + mapDlZoomBarRect.w - 2,
                        mapDlZoomBarRect.y + 2);

  String styleLabel = "STYLE";
  uint16_t styleFg = ctrlFg;
  if (tileServerRoot.length() == 0) {
    styleLabel = "STYLE N/A";
    styleFg = ctrlFgDisabled;
  } else if (tileServerStyle.length() > 0) {
    styleLabel += " ";
    styleLabel += tileServerStyle;
  }
  drawCtrl(mapDlStyleButton, styleLabel, styleFg);

  int16_t rowH = static_cast<int16_t>(20 * textSize);
  int totalRegions = static_cast<int>(sizeof(kMapRegions) / sizeof(kMapRegions[0]));
  int visibleRows = max<int>(1, mapDlListRect.h / rowH);
  int maxScroll = max<int>(0, totalRegions - visibleRows);
  if (mapDownloadSelected < 0) {
    mapDownloadSelected = 0;
  }
  if (mapDownloadSelected >= totalRegions) {
    mapDownloadSelected = max<int>(0, totalRegions - 1);
  }
  mapDownloadScroll = max<int>(0, min<int>(mapDownloadScroll, maxScroll));
  if (mapDownloadSelected != lastMapDownloadSelected) {
    if (mapDownloadSelected < mapDownloadScroll) {
      mapDownloadScroll = mapDownloadSelected;
    } else if (mapDownloadSelected >= mapDownloadScroll + visibleRows) {
      mapDownloadScroll = mapDownloadSelected - visibleRows + 1;
    }
    mapDownloadScroll = max<int>(0, min<int>(mapDownloadScroll, maxScroll));
    lastMapDownloadSelected = mapDownloadSelected;
  }

  int16_t y = mapDlListRect.y;
  M5.Display.drawRect(mapDlListRect.x, mapDlListRect.y, mapDlListRect.w,
                      mapDlListRect.h, colors.amberDim);
  for (int i = 0; i < visibleRows; ++i) {
    int regionIndex = mapDownloadScroll + i;
    if (regionIndex >= totalRegions) {
      break;
    }
    bool selected = regionIndex == mapDownloadSelected;
    bool activeRegion = mapDownload.active && regionIndex == mapDownload.regionIndex;
    uint16_t bg = selected ? colors.redDim : colors.black;
    uint16_t fg = activeRegion ? colors.red : colors.amber;
    M5.Display.fillRect(mapDlListRect.x, y, mapDlListRect.w, rowH, bg);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextColor(fg, bg);
    M5.Display.drawString(kMapRegions[regionIndex].name, mapDlListRect.x + 4, y + 2);
    y += rowH;
  }

  uint16_t upFg = (mapDownloadScroll > 0) ? ctrlFg : ctrlFgDisabled;
  uint16_t downFg = (mapDownloadScroll < maxScroll) ? ctrlFg : ctrlFgDisabled;
  drawCtrl(mapDlUpButton, "UP", upFg);
  drawCtrl(mapDlDownButton, "DN", downFg);

  drawFooter();

  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
  mapDownloadDirty = false;
  mapDownloadProgressDirty = false;
  mapDownloadStatusDirty = false;
  mapDownloadBusyDirty = false;
#else
  M5.Display.fillScreen(colors.black);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("WIFI DISABLED", screenW / 2, screenH / 2);
  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
  mapDownloadDirty = false;
  mapDownloadProgressDirty = false;
  mapDownloadStatusDirty = false;
  mapDownloadBusyDirty = false;
#endif
}

void handleMapDownloadTouch(int16_t x, int16_t y) {
#if ENABLE_WIFI
  if (inRect(mapDlActionButton, x, y)) {
    if (mapDownload.active) {
      debugPrint("MAPDL: stop requested");
      stopMapDownload();
    } else {
      debugPrint(
          "MAPDL: start requested wifiEnabled=%d wifiAvailable=%d wl=%d sdReady=%d server=%d screen=%d",
          wifiEnabled ? 1 : 0, wifiAvailable ? 1 : 0, static_cast<int>(WiFi.status()),
          sdReady ? 1 : 0, tileServerBase.length() > 0 ? 1 : 0, static_cast<int>(screen));
      if (wifiEnabled && wifiAvailable && WiFi.status() == WL_CONNECTED &&
          tileServerBase.length() > 0 && sdReady) {
        debugPrint("MAPDL: start accepted region=%d zoom=%u..%u", mapDownloadSelected,
                   static_cast<unsigned>(mapDownloadMinZoomSel),
                   static_cast<unsigned>(mapDownloadMaxZoomSel));
        startMapDownload(mapDownloadSelected);
      } else {
        debugPrint("MAPDL: start blocked");
        mapDownloadDirty = true;
      }
    }
    return;
  }

  if (mapDownload.active) {
    return;
  }
  if (inRect(mapDlZoomBarRect, x, y)) {
    int range = static_cast<int>(kDownloadMaxZoom) - static_cast<int>(kDownloadMinZoom);
    if (range < 1) {
      return;
    }
    int pos = x - mapDlZoomBarRect.x;
    if (pos < 0) {
      pos = 0;
    }
    if (pos > mapDlZoomBarRect.w) {
      pos = mapDlZoomBarRect.w;
    }
    float t = static_cast<float>(pos) / static_cast<float>(mapDlZoomBarRect.w);
    int zoom = static_cast<int>(kDownloadMinZoom) + static_cast<int>(lroundf(t * range));
    if (zoom < kDownloadMinZoom) {
      zoom = kDownloadMinZoom;
    }
    if (zoom > kDownloadMaxZoom) {
      zoom = kDownloadMaxZoom;
    }
    int distMin = abs(zoom - mapDownloadMinZoomSel);
    int distMax = abs(zoom - mapDownloadMaxZoomSel);
    if (distMin <= distMax) {
      mapDownloadMinZoomSel = static_cast<uint8_t>(zoom);
      if (mapDownloadMinZoomSel > mapDownloadMaxZoomSel) {
        mapDownloadMaxZoomSel = mapDownloadMinZoomSel;
      }
    } else {
      mapDownloadMaxZoomSel = static_cast<uint8_t>(zoom);
      if (mapDownloadMaxZoomSel < mapDownloadMinZoomSel) {
        mapDownloadMinZoomSel = mapDownloadMaxZoomSel;
      }
    }
    storeMapDownloadSettings();
    mapDownloadDirty = true;
    return;
  }
  if (inRect(mapDlStyleButton, x, y)) {
    if (tileServerRoot.length() > 0) {
      tileStyleIndex = (tileStyleIndex + 1) % static_cast<int>(kTileStyleCount);
      tileServerStyle = kTileStyles[tileStyleIndex];
      applyTileStyle();
      mapDownloadDirty = true;
    }
    return;
  }
  int totalRegions = static_cast<int>(sizeof(kMapRegions) / sizeof(kMapRegions[0]));
  int rowH = static_cast<int>(20 * kWifiTextSize);
  int visibleRows = max<int>(1, mapDlListRect.h / rowH);
  int maxScroll = max<int>(0, totalRegions - visibleRows);
  if (inRect(mapDlUpButton, x, y)) {
    if (mapDownloadScroll > 0) {
      mapDownloadScroll--;
      mapDownloadDirty = true;
    }
    return;
  }
  if (inRect(mapDlDownButton, x, y)) {
    if (mapDownloadScroll < maxScroll) {
      mapDownloadScroll++;
      mapDownloadDirty = true;
    }
    return;
  }
  if (inRect(mapDlListRect, x, y)) {
    int index = (y - mapDlListRect.y) / rowH;
    int regionIndex = mapDownloadScroll + index;
    if (regionIndex >= 0 && regionIndex < totalRegions) {
      mapDownloadSelected = regionIndex;
      storeMapDownloadSettings();
      mapDownloadDirty = true;
    }
  }
#else
  (void)x;
  (void)y;
#endif
}

const Waypoint *getWaypointPtr(int index) {
  if (index < 0 || index >= static_cast<int>(waypointCount)) {
    return nullptr;
  }
  return &waypoints[index];
}

bool mapGeoToScreen(double lat, double lon, double centerLat, double centerLon, uint8_t zoom,
                    int32_t &sx, int32_t &sy) {
  double centerX = 0.0;
  double centerY = 0.0;
  geoToWorldPixels(centerLat, centerLon, zoom, centerX, centerY);
  centerX += mapLookAheadDx;
  centerY += mapLookAheadDy;
  double worldX = 0.0;
  double worldY = 0.0;
  geoToWorldPixels(lat, lon, zoom, worldX, worldY);
  double world = 256.0 * (1 << zoom);
  double dx = worldX - centerX;
  if (dx > world / 2.0) dx -= world;
  if (dx < -world / 2.0) dx += world;
  double dy = worldY - centerY;
  sx = static_cast<int32_t>(lround(mapX + mapW / 2.0 + dx));
  sy = static_cast<int32_t>(lround(mapY + mapH / 2.0 + dy));
  return sx >= mapX && sx < (mapX + mapW) && sy >= mapY && sy < (mapY + mapH);
}

void drawTargetMarker(int32_t sx, int32_t sy, int16_t size) {
  int16_t radius = max<int16_t>(6, size / 3);
  M5.Display.fillCircle(static_cast<int16_t>(sx), static_cast<int16_t>(sy), radius, colors.amber);
  M5.Display.drawCircle(static_cast<int16_t>(sx), static_cast<int16_t>(sy),
                        static_cast<int16_t>(radius + 2), colors.amberDim);
  M5.Display.drawCircle(static_cast<int16_t>(sx), static_cast<int16_t>(sy),
                        static_cast<int16_t>(radius + 4), colors.amberDim);
}

Rect getContactNavButtonRect() {
  Rect r = mapStartNavButton;
  int16_t targetW = max<int16_t>(r.w, 150);
  int16_t grow = targetW - r.w;
  r.x = max<int16_t>(mapX + 8, r.x - grow);
  r.w = targetW;
  return r;
}

void drawThickLine(int32_t x0, int32_t y0, int32_t x1, int32_t y1, uint16_t color,
                   int8_t radius) {
  radius = max<int8_t>(1, radius);
  for (int8_t dx = -radius; dx <= radius; ++dx) {
    for (int8_t dy = -radius; dy <= radius; ++dy) {
      if (dx * dx + dy * dy <= radius * radius) {
        M5.Display.drawLine(x0 + dx, y0 + dy, x1 + dx, y1 + dy, color);
      }
    }
  }
}

void drawNavTargetLine(double centerLat, double centerLon, uint8_t zoom) {
  double targetLat = 0.0;
  double targetLon = 0.0;
  bool hasTarget = false;
  if (meshNavTargetIndex >= 0 && meshNavTargetIndex < static_cast<int>(meshContactCount) &&
      meshContacts[meshNavTargetIndex].hasGps) {
    targetLat = meshContacts[meshNavTargetIndex].lat;
    targetLon = meshContacts[meshNavTargetIndex].lon;
    hasTarget = true;
  } else {
    const Waypoint *wp = getWaypointPtr(mapNavTargetIndex);
    if (wp) {
      targetLat = wp->lat;
      targetLon = wp->lon;
      hasTarget = true;
    }
  }
  if (!hasTarget) {
    return;
  }
  int32_t targetX = 0;
  int32_t targetY = 0;
  bool targetVisible = mapGeoToScreen(targetLat, targetLon, centerLat, centerLon, zoom, targetX,
                                      targetY);
  int32_t cx = static_cast<int32_t>(mapX + mapW / 2 - mapLookAheadDx);
  int32_t cy = static_cast<int32_t>(mapY + mapH / 2 - mapLookAheadDy);
  if (mapTargetValid) {
    mapGeoToScreen(mapTargetLat, mapTargetLon, centerLat, centerLon, zoom, cx, cy);
  }
  drawThickLine(cx, cy, targetX, targetY, colors.amberDim, 2);
  M5.Display.drawLine(cx, cy, targetX, targetY, colors.amber);
  if (targetVisible) {
    drawTargetMarker(targetX, targetY, mapMarkerSize);
  }
}

void drawMapLocList() {
  Rect clearRect = mapViewMode == MapViewMode::NAV ? mapPanViewportRect()
                                                   : Rect{mapX, mapY, mapW, mapH};
  M5.Display.fillRect(clearRect.x, clearRect.y, clearRect.w, clearRect.h, colors.black);
  if (mapLocHeaderRect.h > 0) {
    drawTextureRect(mapLocHeaderRect);
  }
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.setTextSize(kSmallTextSize);
  String header = String("LOCATIONS (") + String(waypointCount) + ")";
  M5.Display.drawString(header, mapLocHeaderRect.x + 12, mapLocHeaderRect.y + 8);

  if (mapLocSelectedIndex < 0 && waypointCount > 0) {
    mapLocSelectedIndex = 0;
    mapLocScrollIndex = 0;
  }
  if (mapLocSelectedIndex >= static_cast<int>(waypointCount)) {
    mapLocSelectedIndex = waypointCount > 0 ? static_cast<int>(waypointCount - 1) : -1;
  }
  if (mapNavTargetIndex >= static_cast<int>(waypointCount)) {
    mapNavTargetIndex = -1;
  }
  int16_t rowH = 0;
  bool twoLine = false;
  if (mapLocListRect.h > 0) {
    int16_t lineH = static_cast<int16_t>(M5.Display.fontHeight() + 4);
    twoLine = mapLocListRect.h >= static_cast<int16_t>(lineH * 2);
    rowH = twoLine ? static_cast<int16_t>(lineH * 2) : lineH;
  }
  int visibleRows = rowH > 0 ? static_cast<int>(mapLocListRect.h / rowH) : 0;
  if (visibleRows < 1) {
    visibleRows = 1;
  }
  int maxScroll = max<int>(0, static_cast<int>(waypointCount) - visibleRows);
  mapLocScrollIndex = max<int>(0, min<int>(mapLocScrollIndex, maxScroll));
  if (mapLocSelectedIndex >= 0) {
    if (mapLocSelectedIndex < mapLocScrollIndex) {
      mapLocScrollIndex = mapLocSelectedIndex;
    } else if (mapLocSelectedIndex >= mapLocScrollIndex + visibleRows) {
      mapLocScrollIndex = mapLocSelectedIndex - visibleRows + 1;
    }
    mapLocScrollIndex = max<int>(0, min<int>(mapLocScrollIndex, maxScroll));
  }

  if (waypointCount == 0 || rowH == 0) {
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.drawString("NO LOCATIONS SAVED", mapLocListRect.x, mapLocListRect.y);
    M5.Display.setTextColor(colors.amber, colors.black);
  } else {
    for (int row = 0; row < visibleRows; ++row) {
      int index = mapLocScrollIndex + row;
      if (index >= static_cast<int>(waypointCount)) {
        break;
      }
      int16_t rowY = static_cast<int16_t>(mapLocListRect.y + row * rowH);
      bool selected = index == mapLocSelectedIndex;
      if (selected) {
        M5.Display.drawRect(mapLocListRect.x, rowY, mapLocListRect.w, rowH, colors.amberDim);
      }
      String nameLine = String(index + 1) + ") " + String(waypoints[index].name);
      if (twoLine) {
        M5.Display.setTextColor(colors.amber, colors.black);
        M5.Display.drawString(nameLine, mapLocListRect.x + 6, rowY);
        M5.Display.setTextColor(selected ? colors.amber : colors.amberDim, colors.black);
        String coordLine = "LAT " + String(waypoints[index].lat, 4) + "  LON " +
                           String(waypoints[index].lon, 4);
        M5.Display.drawString(coordLine, mapLocListRect.x + 14,
                              static_cast<int16_t>(rowY + rowH / 2));
      } else {
        String line = nameLine + " " + String(waypoints[index].lat, 4) + "," +
                      String(waypoints[index].lon, 4);
        M5.Display.setTextColor(colors.amber, colors.black);
        M5.Display.drawString(line, mapLocListRect.x + 6, rowY);
      }
    }
  }

  if (isRectValid(mapLocUpButton)) {
    bool canScrollUp = mapLocScrollIndex > 0;
    bool canScrollDown = mapLocScrollIndex < maxScroll;
    uint16_t upFg = canScrollUp ? colors.amber : colors.amberDim;
    uint16_t downFg = canScrollDown ? colors.amber : colors.amberDim;
    M5.Display.fillRect(mapLocUpButton.x, mapLocUpButton.y, mapLocUpButton.w, mapLocUpButton.h,
                        colors.black);
    M5.Display.drawRect(mapLocUpButton.x, mapLocUpButton.y, mapLocUpButton.w, mapLocUpButton.h,
                        upFg);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextColor(upFg, colors.black);
    M5.Display.setTextSize(kButtonTextSize);
    M5.Display.drawString("^", mapLocUpButton.x + mapLocUpButton.w / 2,
                          mapLocUpButton.y + mapLocUpButton.h / 2);

    M5.Display.fillRect(mapLocDownButton.x, mapLocDownButton.y, mapLocDownButton.w,
                        mapLocDownButton.h, colors.black);
    M5.Display.drawRect(mapLocDownButton.x, mapLocDownButton.y, mapLocDownButton.w,
                        mapLocDownButton.h, downFg);
    M5.Display.setTextColor(downFg, colors.black);
    M5.Display.drawString("v", mapLocDownButton.x + mapLocDownButton.w / 2,
                          mapLocDownButton.y + mapLocDownButton.h / 2);
    M5.Display.setTextDatum(TL_DATUM);
  }

  bool canSelect = mapLocSelectedIndex >= 0 &&
                   mapLocSelectedIndex < static_cast<int>(waypointCount);
  uint16_t selFg = canSelect ? colors.amber : colors.amberDim;
  M5.Display.fillRect(mapLocSelectButton.x, mapLocSelectButton.y, mapLocSelectButton.w,
                      mapLocSelectButton.h, colors.black);
  M5.Display.drawRect(mapLocSelectButton.x, mapLocSelectButton.y, mapLocSelectButton.w,
                      mapLocSelectButton.h, selFg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(selFg, colors.black);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("SELECT", mapLocSelectButton.x + mapLocSelectButton.w / 2,
                        mapLocSelectButton.y + mapLocSelectButton.h / 2);
  drawRecordTripButton();
  M5.Display.setTextDatum(TL_DATUM);
}

void drawMapTiles(double centerLat, double centerLon, uint8_t zoom,
                  const BusyIndicatorInfo *busy = nullptr) {
  if (!sdReady) {
    M5.Display.fillRect(mapX, mapY, mapW, mapH, colors.black);
    M5.Display.setTextColor(colors.red, colors.black);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kAlertTextSize);
    M5.Display.drawString("NO SD", mapX + 12, mapY + 12);
    return;
  }
  if (mapViewMode == MapViewMode::NAV && !mapCenterValid &&
      !gps.location.isValid() && !lastGpsFixValid &&
      !isWifiGeoUsable()) {
    M5.Display.fillRect(mapX, mapY, mapW, mapH, colors.black);
    M5.Display.setTextColor(colors.red, colors.black);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kAlertTextSize);
    M5.Display.drawString("NO FIX", mapX + 12, mapY + 12);
    return;
  }

  if (mapViewMode == MapViewMode::NAV) {
    Rect view = mapPanViewportRect();
    Rect fullCanvas = {0, 0, view.w, view.h};
    if (renderMapCanvasRegion(centerLat, centerLon, zoom, fullCanvas, true, true)) {
      presentMapCanvas();
      return;
    }
    mapRenderCanvasValid = false;
    debugPrint("MAP: framebuffer render failed; using direct fallback");
  }

  double centerPx = 0.0;
  double centerPy = 0.0;
  geoToWorldPixels(centerLat, centerLon, zoom, centerPx, centerPy);
  centerPx += mapLookAheadDx;
  centerPy += mapLookAheadDy;
  int tileCount = 1 << zoom;

  double left = centerPx - mapW / 2.0;
  double top = centerPy - mapH / 2.0;
  double world = 256.0 * tileCount;
  if (mapW > world) {
    left = (world - mapW) / 2.0;
  }
  if (mapH > world) {
    top = (world - mapH) / 2.0;
  }
  int startTileX = static_cast<int>(floor(left / 256.0));
  int startTileY = static_cast<int>(floor(top / 256.0));
  int tilesX = mapW / 256 + 2;
  int tilesY = mapH / 256 + 2;

  int offsetX = static_cast<int>(-fmod(left, 256.0));
  int offsetY = static_cast<int>(-fmod(top, 256.0));

  MapTileViewState view;
  view.zoom = zoom;
  view.startTileX = startTileX;
  view.startTileY = startTileY;
  view.tilesX = tilesX;
  view.tilesY = tilesY;
  view.offsetX = offsetX;
  view.offsetY = offsetY;
  view.valid = true;

  if (!lockSd(50)) {
    return;
  }
  if (!SD.exists(tileRoot.c_str())) {
    unlockSd();
    M5.Display.fillRect(mapX, mapY, mapW, mapH, colors.black);
    M5.Display.setTextColor(colors.red, colors.black);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kAlertTextSize);
    M5.Display.drawString("NO TILES", mapX + 12, mapY + 12);
    return;
  }
  M5.Display.fillRect(mapX, mapY, mapW, mapH, colors.black);

  char pathBuf[160] = {0};
  for (int ty = 0; ty < tilesY; ++ty) {
    for (int tx = 0; tx < tilesX; ++tx) {
      int tileX = startTileX + tx;
      int tileY = startTileY + ty;
      if (tileY < 0 || tileY >= tileCount) {
        continue;
      }
      int wrappedX = tileX % tileCount;
      if (wrappedX < 0) {
        wrappedX += tileCount;
      }
      int drawX = mapX + offsetX + tx * 256;
      int drawY = mapY + offsetY + ty * 256;
      bool hasPath = buildTilePath(pathBuf, sizeof(pathBuf), zoom, wrappedX, tileY);
      bool drewTile = hasPath && drawPngFromSd(pathBuf, drawX, drawY);
      if (!drewTile) {
        M5.Display.fillRect(drawX, drawY, 256, 256, colors.black);
        M5.Display.drawRect(drawX, drawY, 256, 256, colors.amberDim);
        if (!mapDownload.active) {
          if (hasPath && SD.exists(pathBuf)) SD.remove(pathBuf);
          queueTileDownload(zoom, wrappedX, tileY, false);
        }
      }
    }
    if (busy != nullptr && ty < tilesY - 1) {
      drawBusyIndicatorInfo(*busy);
    }
  }
  unlockSd();
  if (kReleaseMapPngDecoderAfterDraw) {
    M5.Display.releasePngMemory();
  }
  lastMapTileView = view;
  lastMapTileViewValid = true;
  mapTilesDrawn = true;
}

static void drawMeshContactsOnMap(double centerLat, double centerLon, uint8_t zoom) {
  auto drawMeshMarker = [&](double lat, double lon, const String &labelText,
                            uint32_t ageMs, uint16_t fillColor) {
    int32_t sx = 0;
    int32_t sy = 0;
    if (!mapGeoToScreen(lat, lon, centerLat, centerLon, zoom, sx, sy)) return;
    if (sx < mapX - 16 || sx > mapX + mapW + 16 || sy < mapY - 16 || sy > mapY + mapH + 16) {
      return;
    }
    M5.Display.fillCircle(sx, sy, 6, fillColor);
    M5.Display.drawCircle(sx, sy, 8, colors.amber);
    String label = labelText;
    if (ageMs != 0) {
      label += " ";
      label += formatMeshAge(ageMs);
    }
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(1);
    M5.Display.setTextColor(colors.amber, colors.black);
    M5.Display.drawString(label, sx + 10, sy - 8);
  };
  for (size_t i = 0; i < meshContactCount; ++i) {
    const MeshContact &contact = meshContacts[i];
    if (!contact.hasGps) continue;
    drawMeshMarker(contact.lat, contact.lon,
                   contact.name.length() ? contact.name : contact.deviceId,
                   contact.lastGpsMs, colors.red);
  }
  for (size_t i = 0; i < meshDiscoveredCount; ++i) {
    const MeshDiscoveredContact &peer = meshDiscovered[i];
    if (!peer.hasGps || findMeshContactById(peer.deviceId) >= 0) continue;
    drawMeshMarker(peer.lat, peer.lon,
                   peer.name.length() ? peer.name : peer.deviceId.substring(0, 8),
                   peer.lastSeenMs, colors.amberDim);
  }
}

static bool mapWaitingForLocationServices() {
  return screen == SCREEN_MAIN && mapViewMode == MapViewMode::NAV && !mapCenterValid &&
         !gps.location.isValid() && !lastGpsFixValid && !isWifiGeoUsable();
}

static String clippedSerialLine(const String &line, uint16_t maxWidth) {
  String out = line;
  while (out.length() > 4 && M5.Display.textWidth(out) > maxWidth) {
    out.remove(out.length() - 1);
  }
  if (out.length() < line.length() && out.length() > 3) {
    out.remove(out.length() - 3);
    out += "...";
  }
  return out;
}

static void drawMapWaitingForLocationOverlay() {
  if (mapW <= 0 || mapH <= 0) return;
  int16_t overlayW = min<int16_t>(static_cast<int16_t>(mapW - 28), 560);
  overlayW = max<int16_t>(overlayW, 260);
  int16_t overlayH = min<int16_t>(static_cast<int16_t>(mapH - 28), 214);
  overlayH = max<int16_t>(overlayH, 172);
  int16_t x = mapX + (mapW - overlayW) / 2;
  int16_t y = mapY + (mapH - overlayH) / 2;
  uint32_t now = millis();

  M5.Display.fillRect(x, y, overlayW, overlayH, colors.black);
  M5.Display.drawRect(x, y, overlayW, overlayH, colors.amber);
  M5.Display.drawRect(x + 2, y + 2, overlayW - 4, overlayH - 4, colors.amberDim);

  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("WAITING FOR LOCATION SERVICES", x + overlayW / 2, y + 26);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.drawString("GPS / WIFI GEOLOCATION", x + overlayW / 2, y + 50);

  int16_t logX = x + 14;
  int16_t logY = y + 72;
  int16_t logW = overlayW - 28;
  int16_t lineH = 18;
  M5.Display.fillRect(logX, logY, logW, overlayH - 86, colors.black);
  M5.Display.drawRect(logX, logY, logW, overlayH - 86, colors.amberDim);
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(1);
  M5.Display.setTextColor(colors.amber, colors.black);

  uint32_t gpsAge = lastGpsByteMs ? now - lastGpsByteMs : 0;
  int sats = gps.satellites.isValid() ? gps.satellites.value() : 0;
  String hdopText = gps.hdop.isValid() ? String(gps.hdop.value() / 100.0f, 1) : "N/A";
  String gpsLine = "GPS bytes=" + String(gpsBytesSeen) + " age=" + String(gpsAge) +
                   "ms sats=" + String(sats) + " hdop=" + hdopText;

  String wifiLine = "WIFI ";
#if ENABLE_WIFI
  if (!wifiEnabled) {
    wifiLine += "OFF";
  } else if (!wifiAvailable) {
    wifiLine += "UNAVAILABLE";
  } else if (WiFi.status() == WL_CONNECTED) {
    wifiLine += "CONNECTED ";
    wifiLine += WiFi.SSID();
  } else {
    wifiLine += "SEARCHING";
  }
  wifiLine += wifiGeoValid ? " GEO=READY" : " GEO=PENDING";
#else
  wifiLine += "DISABLED";
#endif

  const char *lastSentence = "";
  if (gpsDiagSentenceCount > 0) {
    size_t idx = (gpsDiagSentenceHead + kGpsDiagSentenceCount - 1) % kGpsDiagSentenceCount;
    lastSentence = gpsDiagSentences[idx];
  }
  String rawLine = String("SERIAL ") + (lastSentence[0] ? lastSentence : "waiting for NMEA data");

  M5.Display.drawString(clippedSerialLine(gpsLine, logW - 12), logX + 6, logY + 8);
  M5.Display.drawString(clippedSerialLine(wifiLine, logW - 12), logX + 6, logY + 8 + lineH);
  M5.Display.drawString(clippedSerialLine(rawLine, logW - 12), logX + 6, logY + 8 + lineH * 2);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.drawString("Map will render when GPS or Wi-Fi location is ready.",
                        logX + 6, logY + 8 + lineH * 3);
}

static bool mapStartupWifiProfileHoldActive(uint32_t now) {
#if ENABLE_WIFI
  if (!mapStartupWifiProfileHold) return false;
  bool timeout = static_cast<int32_t>(now - mapStartupWifiProfileHoldUntilMs) >= 0;
  bool locationReady = !mapWaitingForLocationServices();
  bool releaseHold = locationReady || timeout;
  if (releaseHold) {
    mapStartupWifiProfileHold = false;
    mapStartupWifiProfileHoldDrawn = false;
    mapDirty = true;
    statusDirty = true;
    statusNeedsFullRedraw = true;
    mainNavDirty = true;
    mapTilesDrawn = false;
    lastMapTileViewValid = false;
    debugPrint("MAP: Wi-Fi startup hold released connected=%u geo=%u gps=%u timeout=%u",
               WiFi.status() == WL_CONNECTED ? 1U : 0U,
               isWifiGeoUsable() ? 1U : 0U,
               (gps.location.isValid() || lastGpsFixValid) ? 1U : 0U,
               timeout ? 1U : 0U);
    return false;
  }
  return screen == SCREEN_MAIN && mapViewMode == MapViewMode::NAV;
#else
  (void)now;
  return false;
#endif
}

