class Tab5BleKeyboardServerCallbacks : public BLEServerCallbacks {
public:
  void onConnect(BLEServer *server) override {
    (void)server;
    bleKeyboardConnected = true;
    bleKeyboardAdvertising = false;
    waypointsDirty = true;
    debugPrint("BLEKBD: client connected");
  }
  void onConnect(BLEServer *server, ble_gap_conn_desc *desc) override {
    (void)server;
    if (desc) bleKeyboardConnHandle = desc->conn_handle;
    bleKeyboardConnected = true;
    bleKeyboardAdvertising = false;
    waypointsDirty = true;
    debugPrint("BLEKBD: client connected handle=%u",
               static_cast<unsigned>(bleKeyboardConnHandle));
  }
  void onDisconnect(BLEServer *server) override {
    (void)server;
    bleKeyboardConnected = false;
    bleKeyboardConnHandle = BLE_HS_CONN_HANDLE_NONE;
    bleKeyboardAdvertising = true;
    BLEDevice::startAdvertising();
    waypointsDirty = true;
    debugPrint("BLEKBD: client disconnected; advertising restarted");
  }
};
Tab5BleKeyboardServerCallbacks tab5BleKeyboardServerCallbacks;

class Tab5BleKeyboardSecurityCallbacks : public BLESecurityCallbacks {
public:
  bool onSecurityRequest() override { return true; }
  uint32_t onPassKeyRequest() override { return 0; }
  void onPassKeyNotify(uint32_t) override {}
  bool onConfirmPIN(uint32_t) override { return true; }
  void onAuthenticationComplete(ble_gap_conn_desc *desc) override {
    bool encrypted = desc && desc->sec_state.encrypted;
    bool bonded = desc && desc->sec_state.bonded;
    snprintf(bleLastStatus, sizeof(bleLastStatus),
             encrypted ? (bonded ? "PAIRED + BONDED" : "PAIRED") : "PAIRING FAILED");
    debugPrint("BLEKBD: authentication encrypted=%u bonded=%u",
               encrypted ? 1U : 0U, bonded ? 1U : 0U);
    waypointsDirty = true;
  }
};
