enum BleKeyboardAttribute : uintptr_t {
  BLE_KBD_HID_INFO = 1,
  BLE_KBD_REPORT_MAP,
  BLE_KBD_CONTROL_POINT,
  BLE_KBD_PROTOCOL_MODE,
  BLE_KBD_INPUT_REPORT,
  BLE_KBD_REPORT_REFERENCE,
};

static int bleKeyboardGattAccess(uint16_t connHandle, uint16_t attrHandle,
                                 ble_gatt_access_ctxt *ctxt, void *arg) {
  (void)connHandle;
  (void)attrHandle;
  uintptr_t attribute = reinterpret_cast<uintptr_t>(arg);
  const uint8_t hidInfo[] = {0x11, 0x01, 0x00, 0x01};
  const uint8_t reportReference[] = {0x01, 0x01};
  if (ctxt->op == BLE_GATT_ACCESS_OP_READ_CHR ||
      ctxt->op == BLE_GATT_ACCESS_OP_READ_DSC) {
    const void *data = nullptr;
    uint16_t length = 0;
    switch (attribute) {
      case BLE_KBD_HID_INFO: data = hidInfo; length = sizeof(hidInfo); break;
      case BLE_KBD_REPORT_MAP:
        data = bleKeyboardReportMap; length = sizeof(bleKeyboardReportMap); break;
      case BLE_KBD_PROTOCOL_MODE:
        data = &bleKeyboardProtocolMode; length = 1; break;
      case BLE_KBD_INPUT_REPORT:
        data = bleKeyboardCurrentReport; length = sizeof(bleKeyboardCurrentReport); break;
      case BLE_KBD_REPORT_REFERENCE:
        data = reportReference; length = sizeof(reportReference); break;
      default: return BLE_ATT_ERR_UNLIKELY;
    }
    return os_mbuf_append(ctxt->om, data, length) == 0 ? 0 : BLE_ATT_ERR_INSUFFICIENT_RES;
  }
  if (ctxt->op == BLE_GATT_ACCESS_OP_WRITE_CHR) {
    if (attribute == BLE_KBD_PROTOCOL_MODE && OS_MBUF_PKTLEN(ctxt->om) == 1) {
      uint8_t mode = 1;
      if (ble_hs_mbuf_to_flat(ctxt->om, &mode, 1, nullptr) == 0) {
        bleKeyboardProtocolMode = mode;
        return 0;
      }
    }
    if (attribute == BLE_KBD_CONTROL_POINT) return 0;
  }
  return BLE_ATT_ERR_WRITE_NOT_PERMITTED;
}

static bool registerBleKeyboardGatt() {
  static ble_uuid16_t hidServiceUuid = BLE_UUID16_INIT(0x1812);
  static ble_uuid16_t hidInfoUuid = BLE_UUID16_INIT(0x2A4A);
  static ble_uuid16_t reportMapUuid = BLE_UUID16_INIT(0x2A4B);
  static ble_uuid16_t controlUuid = BLE_UUID16_INIT(0x2A4C);
  static ble_uuid16_t protocolUuid = BLE_UUID16_INIT(0x2A4E);
  static ble_uuid16_t reportUuid = BLE_UUID16_INIT(0x2A4D);
  static ble_uuid16_t reportRefUuid = BLE_UUID16_INIT(0x2908);
  static ble_gatt_dsc_def reportDescriptors[2] = {};
  static ble_gatt_chr_def characteristics[6] = {};
  static ble_gatt_svc_def services[2] = {};
  static bool configured = false;
  if (!configured) {
    reportDescriptors[0].uuid = &reportRefUuid.u;
    reportDescriptors[0].att_flags = BLE_ATT_F_READ;
    reportDescriptors[0].access_cb = bleKeyboardGattAccess;
    reportDescriptors[0].arg = reinterpret_cast<void *>(BLE_KBD_REPORT_REFERENCE);

    characteristics[0] = {&hidInfoUuid.u, bleKeyboardGattAccess,
                          reinterpret_cast<void *>(BLE_KBD_HID_INFO), nullptr,
                          BLE_GATT_CHR_F_READ, 0, nullptr};
    characteristics[1] = {&reportMapUuid.u, bleKeyboardGattAccess,
                          reinterpret_cast<void *>(BLE_KBD_REPORT_MAP), nullptr,
                          BLE_GATT_CHR_F_READ, 0, nullptr};
    characteristics[2] = {&controlUuid.u, bleKeyboardGattAccess,
                          reinterpret_cast<void *>(BLE_KBD_CONTROL_POINT), nullptr,
                          BLE_GATT_CHR_F_WRITE_NO_RSP, 0, nullptr};
    characteristics[3] = {&protocolUuid.u, bleKeyboardGattAccess,
                          reinterpret_cast<void *>(BLE_KBD_PROTOCOL_MODE), nullptr,
                          BLE_GATT_CHR_F_READ | BLE_GATT_CHR_F_WRITE_NO_RSP, 0, nullptr};
    characteristics[4] = {&reportUuid.u, bleKeyboardGattAccess,
                          reinterpret_cast<void *>(BLE_KBD_INPUT_REPORT),
                          reportDescriptors,
                          BLE_GATT_CHR_F_READ | BLE_GATT_CHR_F_READ_ENC |
                              BLE_GATT_CHR_F_NOTIFY, 0,
                          &bleKeyboardInputHandle};
    services[0].type = BLE_GATT_SVC_TYPE_PRIMARY;
    services[0].uuid = &hidServiceUuid.u;
    services[0].characteristics = characteristics;
    configured = true;
  }
  int countResult = ble_gatts_count_cfg(services);
  int addResult = countResult;
  if (countResult == 0) {
#if MYNEWT_VAL(BLE_DYNAMIC_SERVICE)
    addResult = ble_gatts_add_dynamic_svcs(services);
#else
    addResult = ble_gatts_add_svcs(services);
#endif
  }
  debugPrint("BLEKBD: GATT count=%d add=%d handle=%u", countResult, addResult,
             static_cast<unsigned>(bleKeyboardInputHandle));
  return countResult == 0 && addResult == 0;
}

static void bleKeyboardHostTask(void *) {
  nimble_port_run();
  nimble_port_freertos_deinit();
}

static void bleKeyboardHostReset(int reason) {
  debugPrint("BLEKBD: host reset reason=%d", reason);
}

static void bleKeyboardHostSync() {
  int rc = ble_hs_util_ensure_addr(0);
  if (rc == 0) {
    rc = ble_hs_id_set_rnd(bleKeyboardStaticAddress);
    if (rc == 0) bleKeyboardOwnAddrType = BLE_OWN_ADDR_RANDOM;
  }
  bleKeyboardRawSynced = rc == 0;
  debugPrint("BLEKBD: host sync rc=%d addrType=%u", rc,
             static_cast<unsigned>(bleKeyboardOwnAddrType));
}

static int bleKeyboardGapEvent(ble_gap_event *event, void *);

static bool startRawBleKeyboardAdvertising() {
  static ble_uuid16_t hidUuid = BLE_UUID16_INIT(0x1812);
  ble_hs_adv_fields fields = {};
  fields.flags = BLE_HS_ADV_F_DISC_GEN | BLE_HS_ADV_F_BREDR_UNSUP;
  const char *name = "Tab5 Keyboard";
  fields.name = reinterpret_cast<const uint8_t *>(name);
  fields.name_len = strlen(name);
  fields.name_is_complete = 1;
  fields.appearance = 0x03C1;
  fields.appearance_is_present = 1;
  fields.uuids16 = &hidUuid;
  fields.num_uuids16 = 1;
  fields.uuids16_is_complete = 1;
  int rc = ble_gap_adv_set_fields(&fields);
  if (rc != 0) {
    debugPrint("BLEKBD: adv fields failed rc=%d", rc);
    return false;
  }
  ble_gap_adv_params params = {};
  params.conn_mode = BLE_GAP_CONN_MODE_UND;
  params.disc_mode = BLE_GAP_DISC_MODE_GEN;
  rc = ble_gap_adv_start(bleKeyboardOwnAddrType, nullptr, BLE_HS_FOREVER, &params,
                         bleKeyboardGapEvent, nullptr);
  debugPrint("BLEKBD: raw advertising rc=%d reportHandle=%u internal=%u dma=%u", rc,
             static_cast<unsigned>(bleKeyboardInputHandle),
             static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL)),
             static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_DMA)));
  bleKeyboardAdvertising = rc == 0;
  return bleKeyboardAdvertising;
}

static int bleKeyboardGapEvent(ble_gap_event *event, void *) {
  switch (event->type) {
    case BLE_GAP_EVENT_CONNECT:
      if (event->connect.status == 0) {
        bleKeyboardConnHandle = event->connect.conn_handle;
        bleKeyboardConnected = true;
        bleKeyboardAdvertising = false;
        debugPrint("BLEKBD: connected handle=%u", bleKeyboardConnHandle);
      } else {
        startRawBleKeyboardAdvertising();
      }
      waypointsDirty = true;
      return 0;
    case BLE_GAP_EVENT_DISCONNECT:
      bleKeyboardConnHandle = BLE_HS_CONN_HANDLE_NONE;
      bleKeyboardConnected = false;
      debugPrint("BLEKBD: disconnected reason=%d", event->disconnect.reason);
      startRawBleKeyboardAdvertising();
      waypointsDirty = true;
      return 0;
    case BLE_GAP_EVENT_ENC_CHANGE:
      debugPrint("BLEKBD: pairing encryption status=%d", event->enc_change.status);
      snprintf(bleLastStatus, sizeof(bleLastStatus),
               event->enc_change.status == 0 ? "PAIRED + ENCRYPTED" : "PAIRING FAILED %d",
               event->enc_change.status);
      waypointsDirty = true;
      return 0;
    default:
      return 0;
  }
}

static bool initHostedBleKeyboardRaw() {
  snprintf(bleLastStatus, sizeof(bleLastStatus), "HOSTED INIT");
  if (!hostedInitBLE()) {
    snprintf(bleLastStatus, sizeof(bleLastStatus), "HOSTED INIT FAILED");
    bleTransportFaulted = true;
    debugPrint("BLEKBD: hosted transport init failed");
    return false;
  }
  hostedBleBootReady = true;
  snprintf(bleLastStatus, sizeof(bleLastStatus), "NIMBLE INIT");
  int rc = nimble_port_init();
  if (rc != 0) {
    snprintf(bleLastStatus, sizeof(bleLastStatus), "NIMBLE INIT FAILED %d", rc);
    bleTransportFaulted = true;
    hostedDeinitBLE();
    hostedBleBootReady = false;
    debugPrint("BLEKBD: nimble init failed rc=%d", rc);
    return false;
  }
  ble_hs_cfg.reset_cb = bleKeyboardHostReset;
  ble_hs_cfg.sync_cb = bleKeyboardHostSync;
  ble_hs_cfg.sm_io_cap = BLE_HS_IO_NO_INPUT_OUTPUT;
  ble_hs_cfg.sm_bonding = 1;
  ble_hs_cfg.sm_mitm = 0;
  ble_hs_cfg.sm_sc = 1;
  ble_hs_cfg.sm_our_key_dist = BLE_SM_PAIR_KEY_DIST_ENC | BLE_SM_PAIR_KEY_DIST_ID;
  ble_hs_cfg.sm_their_key_dist = BLE_SM_PAIR_KEY_DIST_ENC | BLE_SM_PAIR_KEY_DIST_ID;
  ble_gatts_reset();
  ble_svc_gap_init();
  ble_svc_gatt_init();
  rc = ble_svc_gap_device_name_set("Tab5 Keyboard");
  if (rc != 0 || !registerBleKeyboardGatt()) {
    snprintf(bleLastStatus, sizeof(bleLastStatus), "GATT FAILED %d", rc);
    bleTransportFaulted = true;
    return false;
  }
  ble_store_config_init();
  prefs.begin("responder", false);
  uint8_t bondSchema = prefs.getUChar("ble_schema", 0);
  bool clearLegacyBonds = bondSchema != 3;
  size_t addressLength = prefs.getBytesLength("ble_kbd_addr");
  if (addressLength == sizeof(bleKeyboardStaticAddress)) {
    prefs.getBytes("ble_kbd_addr", bleKeyboardStaticAddress,
                   sizeof(bleKeyboardStaticAddress));
  } else {
    uint64_t chipId = ESP.getEfuseMac();
    for (size_t i = 0; i < sizeof(bleKeyboardStaticAddress); ++i) {
      bleKeyboardStaticAddress[i] = static_cast<uint8_t>(chipId >> (i * 8));
    }
    bleKeyboardStaticAddress[0] ^= 0xA5;
    bleKeyboardStaticAddress[5] =
        static_cast<uint8_t>((bleKeyboardStaticAddress[5] & 0x3F) | 0xC0);
    prefs.putBytes("ble_kbd_addr", bleKeyboardStaticAddress,
                   sizeof(bleKeyboardStaticAddress));
  }
  if (clearLegacyBonds) prefs.putUChar("ble_schema", 3);
  prefs.end();
  debugPrint("BLEKBD: identity %02X:%02X:%02X:%02X:%02X:%02X",
             bleKeyboardStaticAddress[5], bleKeyboardStaticAddress[4],
             bleKeyboardStaticAddress[3], bleKeyboardStaticAddress[2],
             bleKeyboardStaticAddress[1], bleKeyboardStaticAddress[0]);
  if (clearLegacyBonds) {
    int clearResult = ble_store_clear();
    debugPrint("BLEKBD: cleared legacy bonds rc=%d", clearResult);
  }
  bleKeyboardRawSynced = false;
  nimble_port_freertos_init(bleKeyboardHostTask);
  uint32_t deadline = millis() + 5000;
  while (!bleKeyboardRawSynced && static_cast<int32_t>(deadline - millis()) > 0) {
    vTaskDelay(pdMS_TO_TICKS(10));
  }
  if (!bleKeyboardRawSynced || !startRawBleKeyboardAdvertising()) {
    snprintf(bleLastStatus, sizeof(bleLastStatus), "ADVERTISE FAILED");
    bleTransportFaulted = true;
    return false;
  }
  bleKeyboardInitAttempted = true;
  bleKeyboardReady = true;
  bleTransportFaulted = false;
  snprintf(bleLastStatus, sizeof(bleLastStatus), "ADVERTISING");
  return true;
}

void setExclusiveRadioBoot(bool bleMode, uint8_t targetApp) {
  prefs.begin("responder", false);
  prefs.putBool("radio_ble", bleMode);
  prefs.putUChar("radio_app", bleMode ? targetApp : kAppMenuIndex);
  if (bleMode) prefs.putBool("radio_wifi", false);
  prefs.end();
}

static bool isUsbExclusiveTargetApp(uint8_t targetApp) {
  return targetApp == kAppAirplanesIndex || targetApp == kAppGhostIndex ||
         targetApp == kAppCarIndex;
}

void setExclusiveUsbBoot(bool usbMode, uint8_t targetApp) {
  prefs.begin("responder", false);
  prefs.putBool("radio_usb", usbMode);
  prefs.putUChar("usb_app", usbMode ? targetApp : kAppMenuIndex);
  if (usbMode) prefs.putBool("radio_wifi", false);
  prefs.end();
}

static void restartWithBlackScreen(const char *reason) {
  debugPrint("SYSTEM: restart requested reason=%s", reason ? reason : "?");
  if (displayReady) {
    M5.Display.setBrightness(0);
    M5.Display.fillScreen(colors.black);
    M5.Display.display();
  }
  delay(350);
  ESP.restart();
}

void requestExclusiveBleBoot(uint8_t targetApp) {
  if (!kHostedBleRuntimeSafe) {
    (void)targetApp;
    setExclusiveRadioBoot(false, kAppMenuIndex);
    bleExclusiveBootMode = false;
    hostedBleBootReady = false;
    debugPrint("BLE: exclusive boot disabled; hosted transport failed safety test");
    setAppToast("BLE DISABLED - HOSTED RADIO UNSAFE");
    return;
  }
  setExclusiveRadioBoot(true, targetApp);
  debugPrint("BLE: one-shot isolated boot requested app=%u",
             static_cast<unsigned>(targetApp));
  if (displayReady) {
    drawUnifiedLoadingScreen("STARTING BLE KEYBOARD", "PREPARING BLUETOOTH RADIO",
                             "ISOLATED SAFE PROFILE");
  }
  delay(250);
  restartWithBlackScreen("ble exclusive boot");
}

void requestExclusiveUsbBoot(uint8_t targetApp) {
  if (!isUsbExclusiveTargetApp(targetApp)) {
    return;
  }
  setExclusiveRadioBoot(false, kAppMenuIndex);
  setExclusiveUsbBoot(true, targetApp);
#if ENABLE_WIFI
  bool restoreWifiOnExit = isUsbExclusiveTargetApp(targetApp) && wifiEnabled &&
                           wifiAvailable && WiFi.status() == WL_CONNECTED;
  prefs.begin("responder", false);
    prefs.putBool("usb_w_restore", restoreWifiOnExit);
  prefs.end();
  debugPrint("USBHOST: Wi-Fi restore after USB app=%u",
             restoreWifiOnExit ? 1U : 0U);
#endif
  debugPrint("USBHOST: one-shot isolated boot requested app=%u",
             static_cast<unsigned>(targetApp));
  if (displayReady) {
    drawUnifiedLoadingScreen(appLaunchTitle(targetApp), "PREPARING USB HOST",
                             "WI-FI WILL RESUME ON EXIT");
  }
  delay(250);
  restartWithBlackScreen("usb exclusive boot");
}

void requestWifiBoot() {
  requestWifiBoot(false, false);
}

void requestWifiBoot(bool carExitTransition) {
  requestWifiBoot(carExitTransition, false);
}

void requestWifiBoot(bool carExitTransition, bool bleExitTransition) {
  setExclusiveRadioBoot(false, kAppMenuIndex);
  setExclusiveUsbBoot(false, kAppMenuIndex);
  prefs.begin("responder", false);
  prefs.putBool("radio_wifi", true);
  prefs.putBool("wifi_car_exit", carExitTransition);
  prefs.putBool("wifi_ble_exit", bleExitTransition);
  prefs.end();
  debugPrint(bleExitTransition ? "WIFI: restarting into Wi-Fi profile after BLE Keyboard"
             : (carExitTransition ? "WIFI: restarting into Wi-Fi profile after USB app"
                                  : "WIFI: restarting into Wi-Fi profile"));
  if (displayReady) {
    if (bleExitTransition) {
      drawWifiCarExitLoadingScreen("BLE Keyboard closed");
    } else if (carExitTransition) {
      drawWifiCarExitLoadingScreen("USB app closed");
    } else {
      M5.Display.fillScreen(colors.black);
      M5.Display.setTextDatum(MC_DATUM);
      M5.Display.setTextColor(colors.amber, colors.black);
      M5.Display.setTextSize(kButtonTextSize);
      M5.Display.drawString("RESTORING WI-FI", screenW / 2, screenH / 2 - 24);
      M5.Display.setTextSize(kSmallTextSize);
      M5.Display.setTextColor(colors.amberDim, colors.black);
      M5.Display.drawString("PLEASE WAIT", screenW / 2, screenH / 2 + 28);
    }
  }
  delay(250);
  restartWithBlackScreen("wifi profile boot");
}

bool initBleKeyboard() {
  if (!kHostedBleRuntimeSafe) {
    if (!bleKeyboardInitAttempted) {
      debugPrint("BLEKBD: disabled; hosted transport is not crash-safe on this build");
    }
    bleKeyboardInitAttempted = true;
    snprintf(bleLastStatus, sizeof(bleLastStatus), "TRANSPORT SAFETY LOCK");
    return false;
  }
  if (bleKeyboardReady) return true;
  if (bleKeyboardInitAttempted) return false;
  if (bleTransportFaulted) {
    debugPrint("BLEKBD: blocked after transport fault; status=%s", bleLastStatus);
    return false;
  }
  UsbHostSnapshot usb = usbHostManager.snapshot();
  if (rtlSdrHostInstalled || usb.hostInstalled || usb.owner != UsbHostOwner::NONE) {
    stopRtlSdrHost();
    snprintf(bleLastStatus, sizeof(bleLastStatus), "WAITING FOR USB HOST OFF");
    debugPrint("BLEKBD: waiting for USB host shutdown");
    return false;
  }
  if (wifiEnabled) {
    stopWifiForBleRadio("runtime request");
    snprintf(bleLastStatus, sizeof(bleLastStatus), "WAITING FOR WIFI OFF");
    debugPrint("BLEKBD: waiting for Wi-Fi transport shutdown");
    return false;
  }
  size_t internalFree = heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
  size_t largest = heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT);
  size_t dmaFree = heap_caps_get_free_size(MALLOC_CAP_DMA | MALLOC_CAP_INTERNAL);
  if (wifiTransition || wifiStackReady || internalFree < 70000 || largest < 24000 ||
      dmaFree < 12000) {
    snprintf(bleLastStatus, sizeof(bleLastStatus), "LOW MEM I=%u L=%u D=%u",
             static_cast<unsigned>(internalFree), static_cast<unsigned>(largest),
             static_cast<unsigned>(dmaFree));
    debugPrint("BLEKBD: blocked low memory internal=%u largest=%u dma=%u",
               static_cast<unsigned>(internalFree), static_cast<unsigned>(largest),
               static_cast<unsigned>(dmaFree));
    return false;
  }
  if (rfWatchBleScanner && rfWatchBleScanning) rfWatchBleScanner->stop();
  return initHostedBleKeyboardRaw();
}

bool sendBleKeyboardKey(uint8_t modifier, uint8_t keycode) {
  if (!bleKeyboardReady || !bleKeyboardConnected ||
      bleKeyboardConnHandle == BLE_HS_CONN_HANDLE_NONE ||
      bleKeyboardInputHandle == 0 || keycode == 0) return false;
  uint8_t report[8] = {modifier, 0, keycode, 0, 0, 0, 0, 0};
  memcpy(bleKeyboardCurrentReport, report, sizeof(report));
  os_mbuf *packet = ble_hs_mbuf_from_flat(report, sizeof(report));
  if (!packet || ble_gatts_notify_custom(bleKeyboardConnHandle,
                                         bleKeyboardInputHandle, packet) != 0) return false;
  bleKeyboardLastModifier = modifier;
  bleKeyboardLastKeycode = keycode;
  bleKeyboardSentCount++;
  bleKeyboardReleasePending = true;
  bleKeyboardReleaseDueMs = millis() + 15;
  return true;
}

void serviceBleKeyboardRelease(uint32_t now) {
  if (!bleKeyboardReleasePending || static_cast<int32_t>(now - bleKeyboardReleaseDueMs) < 0) return;
  bleKeyboardReleasePending = false;
  if (!bleKeyboardConnected || bleKeyboardConnHandle == BLE_HS_CONN_HANDLE_NONE ||
      bleKeyboardInputHandle == 0) return;
  uint8_t release[8] = {};
  memset(bleKeyboardCurrentReport, 0, sizeof(bleKeyboardCurrentReport));
  os_mbuf *packet = ble_hs_mbuf_from_flat(release, sizeof(release));
  if (packet) ble_gatts_notify_custom(bleKeyboardConnHandle, bleKeyboardInputHandle, packet);
}
#endif

const char *rfWatchModeName(RfWatchMode mode) {
  switch (mode) {
  case RfWatchMode::WIFI:
    return "Wi-Fi Watch";
  case RfWatchMode::CSI_MOTION:
    return "CSI Motion Watch";
  case RfWatchMode::LOGS:
    return "Logs";
  default:
    return "Unknown";
  }
}

void drawRfWatchApp() {
  drawAppTopBar("RF WATCH");
  int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 8);
  int16_t contentBottom = static_cast<int16_t>(screenH - navH);
  M5.Display.fillRect(0, contentTop, screenW, static_cast<int16_t>(contentBottom - contentTop),
                      colors.black);
  const int16_t margin = 12;
  const int16_t gap = 6;
  const int16_t modeW = static_cast<int16_t>(min<int16_t>(210, max<int16_t>(150, screenW / 4)));
  const int16_t modeH = 46;
  int16_t y = contentTop;
  for (uint8_t i = 0; i < static_cast<uint8_t>(RfWatchMode::COUNT); ++i) {
    Rect r = {margin, y, modeW, modeH};
    rfWatchModeRects[i] = r;
    bool selected = static_cast<uint8_t>(rfWatchMode) == i;
    uint16_t bg = selected ? colors.amberDim : colors.black;
    uint16_t fg = selected ? colors.amber : colors.amberDim;
    M5.Display.fillRect(r.x, r.y, r.w, r.h, bg);
    M5.Display.drawRect(r.x, r.y, r.w, r.h, fg);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(fg, bg);
    M5.Display.drawString(rfWatchModeName(static_cast<RfWatchMode>(i)), r.x + r.w / 2,
                          r.y + r.h / 2);
    y = static_cast<int16_t>(y + modeH + gap);
  }

  int16_t infoX = static_cast<int16_t>(margin + modeW + 14);
  int16_t infoW = static_cast<int16_t>(screenW - infoX - margin);
  int16_t lineY = contentTop;
  int16_t lineH = static_cast<int16_t>(M5.Display.fontHeight() + 10);
  auto valueLine = [&](const char *label, const String &value, uint16_t valueColor = 0) {
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.drawString(label, infoX, lineY);
    M5.Display.setTextColor(valueColor ? valueColor : colors.amber, colors.black);
    M5.Display.drawString(value, static_cast<int16_t>(infoX + infoW / 2), lineY);
    lineY = static_cast<int16_t>(lineY + lineH);
  };

  String signature = "Not detected";
  String rssi = "Unavailable";
  String channel = "Unavailable";
  String lastSeen = "Never";
  String confidence = "Unavailable";
  String logCount = String(rfWatchLogCount);
  uint16_t sigColor = colors.amberDim;

  if (rfWatchMode == RfWatchMode::WIFI) {
#if ENABLE_WIFI
    if (wifiScanInProgress) {
      signature = "Scanning...";
      sigColor = colors.amber;
      lastSeen = "Now";
    } else if (wifiNetworkCount > 0) {
      int best = 0;
      for (int i = 1; i < wifiNetworkCount; ++i) {
        if (wifiNetworks[i].rssi > wifiNetworks[best].rssi) best = i;
      }
      signature = wifiNetworks[best].ssid.length() ? wifiNetworks[best].ssid : String("Hidden SSID");
      rssi = String(wifiNetworks[best].rssi) + " dBm";
      confidence = wifiNetworks[best].secure ? "80% secured AP" : "65% open AP";
      lastSeen = rfWatchLastScanMs ? String((millis() - rfWatchLastScanMs) / 1000UL) + "s ago"
                                   : "Recent";
      sigColor = colors.amber;
      logCount = String(wifiNetworkCount) + " AP / " + String(rfWatchLanDeviceCount) + " LAN";
    } else if (!wifiEnabled) {
      signature = "Wi-Fi off";
      confidence = "Feature unavailable";
    } else {
      signature = "No APs logged";
    }
#else
    signature = "Unsupported";
    confidence = "Feature unavailable";
#endif
  } else if (rfWatchMode == RfWatchMode::CSI_MOTION) {
#if ENABLE_WIFI
    if (!wifiEnabled || WiFi.status() != WL_CONNECTED) {
      signature = wifiMotionStartPending ? "Auto-connecting Wi-Fi" : "Wi-Fi not connected";
      confidence = "Dual-band APs use compatible band automatically";
    } else if (!wifiMotionEnabled) {
      signature = wifiMotionAvailable ? "CSI monitor stopped" : "CSI unavailable";
      confidence = "Not running";
    } else if (wifiMotionCalibrationSamples < (wifiMotionUsingRssiFallback ? 100U : 200U)) {
      signature = String("Calibrating ") + String(wifiMotionCalibrationSamples) + "/" +
                  String(wifiMotionUsingRssiFallback ? 100 : 200);
      confidence = "Learning baseline";
      sigColor = colors.amber;
    } else {
      signature = wifiMotionDetected ? "Motion detected" : "Channel stable";
      confidence = String("Score ") + String(wifiMotionScore, 1) + " / " +
                   String(wifiMotionThreshold, 1);
      sigColor = wifiMotionDetected ? colors.red : colors.amber;
    }
    rssi = WiFi.status() == WL_CONNECTED ? String(WiFi.RSSI()) + " dBm" : "Unavailable";
    channel = WiFi.status() == WL_CONNECTED ? String("Wi-Fi ch ") + String(WiFi.channel())
                                            : "Unavailable";
    lastSeen = wifiMotionLastPacketMs ? String((millis() - wifiMotionLastPacketMs) / 1000UL) + "s ago"
                                      : "Never";
    logCount = String(wifiMotionPackets);
#else
    signature = "Unsupported";
    confidence = "Feature unavailable";
#endif
  } else if (rfWatchMode == RfWatchMode::LOGS) {
    signature = "Passive logs";
    rssi = "See mode pages";
    channel = "Mixed";
    lastSeen = rfWatchLastSeenMs ? String((millis() - rfWatchLastSeenMs) / 1000UL) + "s ago"
                                 : "Never";
    confidence = "N/A";
    logCount = String(rfWatchLogCount + static_cast<uint32_t>(wifiNetworkCount));
    sigColor = colors.amber;
  }

  valueLine("Mode", rfWatchModeName(rfWatchMode));
  valueLine("Detected device/signature", signature, sigColor);
  valueLine("RSSI", rssi);
  valueLine("Channel/frequency", channel);
  valueLine("Last seen", lastSeen);
  valueLine("Confidence", confidence);
  valueLine("Log count", logCount);

  if (rfWatchMode == RfWatchMode::WIFI &&
      (rfWatchLanScanning || rfWatchLanDeviceCount > 0)) {
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.drawString(rfWatchLanScanning ? "LAN DEVICES (SCANNING)" : "LAN DEVICES",
                          infoX, lineY);
    lineY = static_cast<int16_t>(lineY + lineH);
    size_t shown = min<size_t>(static_cast<size_t>(rfWatchLanDeviceCount), 5);
    for (size_t i = 0; i < shown; ++i) {
      const RfWatchLanDevice &device = rfWatchLanDevices[i];
      String label = String(device.ip[0]) + "." + String(device.ip[1]) + "." +
                     String(device.ip[2]) + "." + String(device.ip[3]);
      M5.Display.setTextColor(colors.amber, colors.black);
      M5.Display.drawString(label, infoX, lineY);
      lineY = static_cast<int16_t>(lineY + lineH);
    }
  }

  auto drawButton = [&](const Rect &rect, const char *label, uint16_t color) {
    M5.Display.fillRect(rect.x, rect.y, rect.w, rect.h, colors.black);
    M5.Display.drawRect(rect.x, rect.y, rect.w, rect.h, color);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextSize(kButtonTextSize);
    M5.Display.setTextColor(color, colors.black);
    M5.Display.drawString(label, rect.x + rect.w / 2, rect.y + rect.h / 2);
  };
  const char *primaryLabel = "PASSIVE";
  uint16_t primaryColor = colors.amberDim;
  if (rfWatchMode == RfWatchMode::WIFI) {
    primaryLabel = wifiScanInProgress ? "SCANNING" : "SCAN";
    primaryColor = colors.amber;
  } else if (rfWatchMode == RfWatchMode::CSI_MOTION) {
#if ENABLE_WIFI
    primaryLabel = wifiMotionEnabled ? "STOP" : "START";
    primaryColor = colors.amber;
#endif
  }
  drawButton(appPrimaryButton, primaryLabel, primaryColor);
  drawButton(appSecondaryButton, "MODE", colors.amberDim);
  drawButton(appTertiaryButton, "CLEAR", colors.redDim);
  if (appToast.length()) {
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(colors.amber, colors.black);
    M5.Display.drawString(appToast, 12, static_cast<int16_t>(appPrimaryButton.y - 24));
  }
  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
  waypointsDirty = false;
}

void handleRfWatchTouch(int16_t x, int16_t y) {
  for (uint8_t i = 0; i < static_cast<uint8_t>(RfWatchMode::COUNT); ++i) {
    if (inRect(rfWatchModeRects[i], x, y)) {
      rfWatchMode = static_cast<RfWatchMode>(i);
      if (bleExclusiveBootMode) {
        requestWifiBoot();
        return;
      }
      waypointsDirty = true;
      return;
    }
  }
  if (inRect(appPrimaryButton, x, y)) {
    if (rfWatchMode == RfWatchMode::WIFI) {
#if ENABLE_WIFI
      if (bleExclusiveBootMode) {
        requestWifiBoot();
        return;
      }
      if (!prepareWifiForRadioApp()) {
        setAppToast("WI-FI AUTO-CONNECTING");
        waypointsDirty = true;
        return;
      }
      startWifiScan();
      startRfWatchLanScan();
      rfWatchLastScanMs = millis();
      rfWatchLastSeenMs = rfWatchLastScanMs;
      setAppToast("WI-FI WATCH SCAN");
#else
      setAppToast("WI-FI UNSUPPORTED");
#endif
    } else {
      if (rfWatchMode == RfWatchMode::CSI_MOTION) {
#if ENABLE_WIFI
        if (wifiMotionEnabled) {
          stopWifiMotion();
          setAppToast("CSI MONITOR STOPPED");
        } else if (startWifiMotion()) {
          setAppToast("CSI CALIBRATING");
        } else {
          setAppToast("WI-FI AUTO-CONNECTING");
        }
#else
        setAppToast("CSI UNSUPPORTED");
#endif
      } else {
        setAppToast("PASSIVE ONLY");
      }
    }
    waypointsDirty = true;
    return;
  }
  if (inRect(appSecondaryButton, x, y)) {
    rfWatchMode = static_cast<RfWatchMode>((static_cast<uint8_t>(rfWatchMode) + 1) %
                                           static_cast<uint8_t>(RfWatchMode::COUNT));
    if (bleExclusiveBootMode) {
      requestWifiBoot();
      return;
    }
    waypointsDirty = true;
    return;
  }
  if (inRect(appTertiaryButton, x, y)) {
    rfWatchLogCount = 0;
    rfWatchLastSeenMs = 0;
    if (!rfWatchLanScanning) {
      rfWatchLanDeviceCount = 0;
      memset(rfWatchLanDevices, 0, sizeof(rfWatchLanDevices));
    }
#if HAS_HOSTED_BLE
    clearRfWatchBleDevices();
#endif
    setAppToast("RF WATCH LOG CLEARED");
    waypointsDirty = true;
    return;
  }
}

#if ENABLE_WIFI
static String ipCamAddress(const IpCamDevice &device) {
  return String(device.ip[0]) + "." + String(device.ip[1]) + "." +
         String(device.ip[2]) + "." + String(device.ip[3]);
}

static bool ensureIpCamFrameMutex() {
  if (!ipCamFrameMutex) {
    ipCamFrameMutex = xSemaphoreCreateMutex();
  }
  return ipCamFrameMutex != nullptr;
}

static bool ipCamIsDeployCam(const IpCamDevice &device) {
  return strcmp(device.service, "DEPLOY CAM") == 0;
}

static void ipCamFreeSnapshotLocked() {
  if (ipCamSnapshot) {
    heap_caps_free(ipCamSnapshot);
    ipCamSnapshot = nullptr;
  }
  ipCamSnapshotSize = 0;
  ipCamFrameWidth = 0;
  ipCamFrameHeight = 0;
  ipCamShowingSnapshot = false;
  ipCamLiveFrameFileReady = false;
}

static bool ipCamWriteLiveFrameFileLocked(const uint8_t *data, size_t len) {
  if (!sdReady || !data || len == 0) return false;
  if (!lockSd(100)) return false;
  SD.mkdir(kIpCamRecordRoot);
  SD.remove(kIpCamLiveFramePath);
  FsFile f = SD.open(kIpCamLiveFramePath, FILE_WRITE);
  if (!f) {
    unlockSd();
    return false;
  }
  size_t written = f.write(data, len);
  f.close();
  unlockSd();
  return written == len;
}

static bool ipCamProbeDeployCam(const String &host, uint16_t port) {
  if (port != 80 && port != 8080 && port != 8000) return false;
  WiFiClient client;
  IPAddress ip;
  if (!ip.fromString(host)) return false;
  if (!client.connect(ip, port, 220)) return false;
  client.print(String("GET /status HTTP/1.0\r\nHost: ") + host + "\r\nConnection: close\r\n\r\n");
  String body;
  uint32_t deadline = millis() + 650;
  while (static_cast<int32_t>(deadline - millis()) > 0 && body.length() < 900) {
    while (client.available() && body.length() < 900) {
      body += static_cast<char>(client.read());
    }
    if (!client.connected() && !client.available()) break;
    delay(2);
  }
  client.stop();
  body.toLowerCase();
  return body.indexOf("200 ok") >= 0 && body.indexOf("deploy cam") >= 0 &&
         body.indexOf("cameraready") >= 0;
}

static bool ipCamAddDevice(uint8_t a, uint8_t b, uint8_t c, uint8_t d, uint16_t port,
                           const char *service, bool selectDevice) {
  for (size_t i = 0; i < ipCamDeviceCount; ++i) {
    if (ipCamDevices[i].ip[0] == a && ipCamDevices[i].ip[1] == b &&
        ipCamDevices[i].ip[2] == c && ipCamDevices[i].ip[3] == d &&
        ipCamDevices[i].port == port) {
      if (selectDevice) ipCamSelected = static_cast<int>(i);
      return true;
    }
  }
  if (ipCamDeviceCount >= kIpCamMaxDevices) return false;
  size_t index = ipCamDeviceCount++;
  IpCamDevice &device = ipCamDevices[index];
  device.ip[0] = a;
  device.ip[1] = b;
  device.ip[2] = c;
  device.ip[3] = d;
  device.port = port;
  strlcpy(device.service, service ? service : "HTTP", sizeof(device.service));
  if (ipCamSelected < 0 || selectDevice) ipCamSelected = static_cast<int>(index);
  debugPrint("IPCAM: add %u.%u.%u.%u:%u %s selected=%d",
             static_cast<unsigned>(a), static_cast<unsigned>(b), static_cast<unsigned>(c),
             static_cast<unsigned>(d), static_cast<unsigned>(port), device.service,
             static_cast<int>(ipCamSelected));
  waypointsDirty = true;
  return true;
}

static bool ipCamAddIfDeployCam(const IPAddress &target, uint16_t port, bool selectDevice) {
  String hostText = target.toString();
  if (!ipCamProbeDeployCam(hostText, port)) return false;
  return ipCamAddDevice(target[0], target[1], target[2], target[3], port, "DEPLOY CAM",
                        selectDevice);
}

static bool ipCamExtractJpeg(uint8_t *buffer, size_t &received) {
  size_t jpegStart = 0;
  while (jpegStart + 1 < received &&
         !(buffer[jpegStart] == 0xFF && buffer[jpegStart + 1] == 0xD8)) ++jpegStart;
  size_t jpegEnd = jpegStart + 2;
  while (jpegEnd + 1 < received &&
         !(buffer[jpegEnd] == 0xFF && buffer[jpegEnd + 1] == 0xD9)) ++jpegEnd;
  if (jpegStart + 1 >= received || jpegEnd + 1 >= received) return false;
  jpegEnd += 2;
  if (jpegStart > 0) memmove(buffer, buffer + jpegStart, jpegEnd - jpegStart);
  received = jpegEnd - jpegStart;
  return true;
}

static bool ipCamJpegSize(const uint8_t *data, size_t len, uint16_t &width, uint16_t &height) {
  width = 0;
  height = 0;
  if (!data || len < 8 || data[0] != 0xFF || data[1] != 0xD8) return false;
  size_t pos = 2;
  while (pos + 9 < len) {
    if (data[pos] != 0xFF) {
      ++pos;
      continue;
    }
    while (pos < len && data[pos] == 0xFF) ++pos;
    if (pos >= len) break;
    uint8_t marker = data[pos++];
    if (marker == 0xD9 || marker == 0xDA) break;
    if (pos + 1 >= len) break;
    uint16_t segmentLen = (static_cast<uint16_t>(data[pos]) << 8) | data[pos + 1];
    if (segmentLen < 2 || pos + segmentLen > len) break;
    bool sof = (marker >= 0xC0 && marker <= 0xC3) || (marker >= 0xC5 && marker <= 0xC7) ||
               (marker >= 0xC9 && marker <= 0xCB) || (marker >= 0xCD && marker <= 0xCF);
    if (sof && segmentLen >= 7) {
      height = (static_cast<uint16_t>(data[pos + 3]) << 8) | data[pos + 4];
      width = (static_cast<uint16_t>(data[pos + 5]) << 8) | data[pos + 6];
      return width > 0 && height > 0;
    }
    pos += segmentLen;
  }
  return false;
}

static Rect ipCamCenteredFrameRect(const uint8_t *data, size_t len) {
  Rect out = ipCamViewRect;
  if (ipCamViewRect.w <= 0 || ipCamViewRect.h <= 0) {
    return out;
  }
  uint16_t jpegW = ipCamFrameWidth;
  uint16_t jpegH = ipCamFrameHeight;
  if ((!jpegW || !jpegH) && data && len) {
    ipCamJpegSize(data, len, jpegW, jpegH);
  }
  if (!jpegW || !jpegH) {
    jpegW = 640;
    jpegH = 480;
  }
  float fit = min(static_cast<float>(ipCamViewRect.w) / static_cast<float>(jpegW),
                  static_cast<float>(ipCamViewRect.h) / static_cast<float>(jpegH));
  // QVGA is decoded into a PSRAM canvas and enlarged in one block transfer.
  // VGA stays native-size because enlarging it is unnecessarily expensive.
  float maxScale = (jpegW <= 320 && jpegH <= 240) ? 2.0f : 1.0f;
  fit = min(maxScale, fit);
  out.w = static_cast<int16_t>(max<int32_t>(1, lroundf(static_cast<float>(jpegW) * fit)));
  out.h = static_cast<int16_t>(max<int32_t>(1, lroundf(static_cast<float>(jpegH) * fit)));
  out.x = static_cast<int16_t>(ipCamViewRect.x + (ipCamViewRect.w - out.w) / 2);
  out.y = static_cast<int16_t>(ipCamViewRect.y + (ipCamViewRect.h - out.h) / 2);
  return out;
}

static void ipCamClearFrameMargins(const Rect &nextRect) {
  if (ipCamViewRect.w <= 0 || ipCamViewRect.h <= 0) return;
  if (ipCamFrameDrawRect.w == nextRect.w && ipCamFrameDrawRect.h == nextRect.h &&
      ipCamFrameDrawRect.x == nextRect.x && ipCamFrameDrawRect.y == nextRect.y) {
    return;
  }
  M5.Display.fillRect(ipCamViewRect.x, ipCamViewRect.y, ipCamViewRect.w, ipCamViewRect.h,
                      colors.black);
}

static void releaseIpCamRenderCanvas() {
  if (!ipCamRenderCanvas) return;
  ipCamRenderCanvas->deleteSprite();
  delete ipCamRenderCanvas;
  ipCamRenderCanvas = nullptr;
  ipCamRenderCanvasW = 0;
  ipCamRenderCanvasH = 0;
}

static bool ipCamDrawBufferedJpegZoom(const uint8_t *data, size_t len, uint16_t jpegW,
                                     uint16_t jpegH, const Rect &drawRect) {
  if (!data || !len || jpegW == 0 || jpegH == 0 || jpegW > 400 || jpegH > 300 ||
      (drawRect.w == static_cast<int16_t>(jpegW) &&
       drawRect.h == static_cast<int16_t>(jpegH))) {
    return false;
  }
  if (!ipCamRenderCanvas || ipCamRenderCanvasW != static_cast<int16_t>(jpegW) ||
      ipCamRenderCanvasH != static_cast<int16_t>(jpegH)) {
    releaseIpCamRenderCanvas();
    ipCamRenderCanvas = new (std::nothrow) M5Canvas(&M5.Display);
    if (!ipCamRenderCanvas) return false;
    ipCamRenderCanvas->setColorDepth(16);
    ipCamRenderCanvas->setPsram(true);
    if (!ipCamRenderCanvas->createSprite(jpegW, jpegH)) {
      releaseIpCamRenderCanvas();
      return false;
    }
    ipCamRenderCanvasW = static_cast<int16_t>(jpegW);
    ipCamRenderCanvasH = static_cast<int16_t>(jpegH);
    ipCamRenderCanvas->setPivot(jpegW * 0.5f, jpegH * 0.5f);
    debugPrint("IPCAM: render canvas ready %ux%u psram=%u",
               static_cast<unsigned>(jpegW), static_cast<unsigned>(jpegH),
               static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_SPIRAM)));
  }
  if (!ipCamRenderCanvas->drawJpg(data, len, 0, 0)) return false;
  float zoomX = static_cast<float>(drawRect.w) / static_cast<float>(jpegW);
  float zoomY = static_cast<float>(drawRect.h) / static_cast<float>(jpegH);
  ipCamRenderCanvas->pushRotateZoom(&M5.Display,
                                   drawRect.x + drawRect.w * 0.5f,
                                   drawRect.y + drawRect.h * 0.5f,
                                   0.0f, zoomX, zoomY);
  return true;
}

static void ipCamDrawCenteredJpeg(const uint8_t *data, size_t len) {
  Rect drawRect = ipCamCenteredFrameRect(data, len);
  ipCamClearFrameMargins(drawRect);
  uint16_t jpegW = ipCamFrameWidth;
  uint16_t jpegH = ipCamFrameHeight;
  if (data && len && (jpegW || ipCamJpegSize(data, len, jpegW, jpegH)) && jpegW && jpegH) {
    if (ipCamDrawBufferedJpegZoom(data, len, jpegW, jpegH, drawRect)) {
      ipCamFrameDrawRect = drawRect;
      return;
    }
    if (drawRect.w == static_cast<int16_t>(jpegW) &&
        drawRect.h == static_cast<int16_t>(jpegH) &&
        M5.Display.drawJpg(data, len, drawRect.x, drawRect.y)) {
      ipCamFrameDrawRect = drawRect;
      return;
    }
    float scaleX = static_cast<float>(drawRect.w) / static_cast<float>(jpegW);
    float scaleY = static_cast<float>(drawRect.h) / static_cast<float>(jpegH);
    if (M5.Display.drawJpg(data, len, drawRect.x, drawRect.y, drawRect.w, drawRect.h,
                           0, 0, scaleX, scaleY)) {
      ipCamFrameDrawRect = drawRect;
      return;
    }
  }
  if (data && len && M5.Display.drawJpg(data, len, drawRect.x, drawRect.y,
                                        drawRect.w, drawRect.h)) {
    ipCamFrameDrawRect = drawRect;
    return;
  }
  if (ipCamLiveFrameFileReady &&
      drawJpgFromSd(kIpCamLiveFramePath, drawRect.x, drawRect.y, drawRect.w, drawRect.h)) {
    ipCamFrameDrawRect = drawRect;
    return;
  }
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.drawString("FRAME READY - DRAW WAIT", ipCamViewRect.x + ipCamViewRect.w / 2,
                        ipCamViewRect.y + ipCamViewRect.h / 2);
  ipCamFrameDrawRect = drawRect;
}

static int ipCamHexNibble(uint8_t c) {
  if (c >= '0' && c <= '9') return c - '0';
  if (c >= 'A' && c <= 'F') return c - 'A' + 10;
  if (c >= 'a' && c <= 'f') return c - 'a' + 10;
  return -1;
}

static bool ipCamDecodeHexJpeg(uint8_t *buffer, size_t &received) {
  if (!buffer || received < 12) return false;
  size_t marker = received;
  for (size_t i = 0; i + 7 < received; ++i) {
    if (memcmp(buffer + i, "JPGHEX ", 7) == 0) {
      marker = i;
      break;
    }
  }
  if (marker >= received) return false;
  size_t newline = marker;
  while (newline < received && buffer[newline] != '\n') ++newline;
  if (newline >= received) return false;
  size_t read = newline + 1;
  size_t write = 0;
  while (read + 1 < received) {
    while (read < received && (buffer[read] == '\r' || buffer[read] == '\n' || buffer[read] == ' ')) {
      ++read;
    }
    if (read + 1 >= received) break;
    int hi = ipCamHexNibble(buffer[read]);
    int lo = ipCamHexNibble(buffer[read + 1]);
    if (hi < 0 || lo < 0) break;
    buffer[write++] = static_cast<uint8_t>((hi << 4) | lo);
    read += 2;
  }
  received = write;
  return received > 4 && buffer[0] == 0xFF && buffer[1] == 0xD8 &&
         buffer[received - 2] == 0xFF && buffer[received - 1] == 0xD9;
}

static bool ipCamHexPayloadComplete(const uint8_t *buffer, size_t received) {
  if (!buffer || received < 12) return false;
  size_t marker = received;
  for (size_t i = 0; i + 7 < received; ++i) {
    if (memcmp(buffer + i, "JPGHEX ", 7) == 0) {
      marker = i;
      break;
    }
  }
  if (marker >= received) return false;
  size_t cursor = marker + 7;
  size_t jpegBytes = 0;
  while (cursor < received && buffer[cursor] >= '0' && buffer[cursor] <= '9') {
    jpegBytes = jpegBytes * 10 + static_cast<size_t>(buffer[cursor] - '0');
    if (jpegBytes > kIpCamSnapshotMax) return false;
    ++cursor;
  }
  while (cursor < received && buffer[cursor] != '\n') ++cursor;
  if (cursor >= received || jpegBytes == 0) return false;
  return received >= cursor + 1 + jpegBytes * 2U;
}

static bool ipCamFetchJpegFrame(const IpCamDevice &device, uint8_t **out, size_t *outSize) {
  if (!out || !outSize) return false;
  *out = nullptr;
  *outSize = 0;
  if (device.port == 554 || device.port == 8554 || device.port == 443) {
    ipCamStatus = device.port == 443 ? "HTTPS CAMERA - LOGIN REQUIRED" :
                                       "RTSP FOUND - STREAM LOGIN REQUIRED";
    return false;
  }
  // Do not use Deploy Cam /stream on Tab5: continuous multipart MJPEG can exhaust
  // ESP-Hosted SDIO RX buffers on the C6 Wi-Fi bridge and panic in sdio_rx_get_buffer.
  // /capture is still live video behavior from the app point of view, but each frame is
  // fetched as a bounded JPEG response and drawn from memory without SD frame staging.
  static const char *deployPaths[] = {"/capture"};
  static const char *genericPaths[] = {"/video/mjpg.cgi", "/mjpeg", "/stream", "/capture",
                                       "/snapshot.jpg", "/snapshot.jpeg",
                                       "/cgi-bin/snapshot.cgi", "/image.jpg", "/jpg/image.jpg",
                                       "/ISAPI/Streaming/channels/101/picture", "/"};
  const char **paths = ipCamIsDeployCam(device) ? deployPaths : genericPaths;
  size_t pathCount = ipCamIsDeployCam(device) ? (sizeof(deployPaths) / sizeof(deployPaths[0]))
                                              : (sizeof(genericPaths) / sizeof(genericPaths[0]));
  String host = ipCamAddress(device);
  bool deployCam = ipCamIsDeployCam(device);
  if (deployCam) {
    IPAddress ip;
    if (!ip.fromString(host)) return false;
    uint32_t now = millis();
    if (static_cast<int32_t>(ipCamLiveBackoffUntilMs - now) > 0) {
      return false;
    }
    for (size_t i = 0; i < pathCount; ++i) {
      uint32_t dmaBefore = heap_caps_get_free_size(MALLOC_CAP_DMA);
      if (dmaBefore < 3200) {
        ipCamLiveBackoffUntilMs = millis() + 1200;
        if (millis() - ipCamLiveLastStatusMs > 1800) {
          ipCamLiveLastStatusMs = millis();
          ipCamStatus = "LIVE PAUSED - WIFI RECOVERY";
          waypointsDirty = true;
          debugPrint("IPCAM: deploy fetch blocked low dma=%u path=%s",
                     static_cast<unsigned>(dmaBefore), paths[i]);
        }
        return false;
      }
      debugPrint("IPCAM: deploy fetch path=%s", paths[i]);
      WiFiClient client;
      client.setNoDelay(true);
      if (!client.connect(ip, device.port, 650)) continue;
      client.print("GET ");
      client.print(paths[i]);
      client.print(" HTTP/1.0\r\nHost: ");
      client.print(host);
      client.print("\r\nConnection: close\r\n\r\n");
      bool isHex = strcmp(paths[i], "/capture.hex") == 0;
      size_t capacity = min<size_t>(kIpCamSnapshotMax, isHex ? 12 * 1024 : 4 * 1024);
      uint8_t *buffer = static_cast<uint8_t *>(
          heap_caps_malloc(capacity, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
      if (!buffer) {
        client.stop();
        ipCamStatus = "CAM FRAME MEMORY FAILED";
        debugPrint("IPCAM: deploy frame memory failed capacity=%u psram=%u internal=%u",
                   static_cast<unsigned>(capacity),
                   static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT)),
                   static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)));
        return false;
      }
      size_t received = 0;
      bool sawJpegStart = false;
      uint32_t deadline = millis() + 1200;
      while (received < capacity && static_cast<int32_t>(deadline - millis()) > 0) {
        uint32_t loopDma = heap_caps_get_free_size(MALLOC_CAP_DMA);
        if (loopDma < 1400) {
          ipCamLiveBackoffUntilMs = millis() + 1800;
          if (millis() - ipCamLiveLastStatusMs > 1800) {
            ipCamLiveLastStatusMs = millis();
            ipCamStatus = "LIVE PAUSED - WIFI RECOVERY";
            waypointsDirty = true;
            debugPrint("IPCAM: deploy read abort low dma=%u bytes=%u path=%s",
                       static_cast<unsigned>(loopDma),
                       static_cast<unsigned>(received), paths[i]);
          }
          break;
        }
        size_t available = client.available();
        if (available == 0) {
          if (!client.connected()) break;
          vTaskDelay(pdMS_TO_TICKS(3));
          continue;
        }
        size_t amount = min<size_t>(available, capacity - received);
        int got = client.read(buffer + received, static_cast<int>(amount));
        if (got > 0) {
          size_t oldReceived = received;
          received += static_cast<size_t>(got);
          if (!sawJpegStart) {
            for (size_t p = oldReceived > 0 ? oldReceived - 1 : 0; p + 1 < received; ++p) {
              if (buffer[p] == 0xFF && buffer[p + 1] == 0xD8) {
                sawJpegStart = true;
                break;
              }
            }
          }
          if (isHex && ipCamHexPayloadComplete(buffer, received)) break;
          if (sawJpegStart && received > 4 &&
              buffer[received - 2] == 0xFF && buffer[received - 1] == 0xD9) {
            break;
          }
        }
      }
      client.stop();
      bool decoded = isHex ? ipCamDecodeHexJpeg(buffer, received)
                           : ipCamExtractJpeg(buffer, received);
      if (!decoded) {
        if (millis() - ipCamLiveLastStatusMs > 1800) {
          ipCamLiveLastStatusMs = millis();
          debugPrint("IPCAM: deploy decode failed bytes=%u path=%s",
                     static_cast<unsigned>(received), paths[i]);
        }
        heap_caps_free(buffer);
        continue;
      }
      if ((ipCamLiveFrames % 20U) == 0U) {
        debugPrint("IPCAM: frame %s:%u %u bytes path=%s", host.c_str(),
                   static_cast<unsigned>(device.port), static_cast<unsigned>(received), paths[i]);
      }
      *out = buffer;
      *outSize = received;
      return true;
    }
    ipCamStatus = "NO DEPLOY CAM STREAM FRAME";
    return false;
  }

  IPAddress ip;
  if (!ip.fromString(host)) return false;
  for (size_t i = 0; i < pathCount; ++i) {
    WiFiClient client;
    if (!client.connect(ip, device.port, 650)) continue;
    client.print("GET ");
    client.print(paths[i]);
    client.print(" HTTP/1.0\r\nHost: ");
    client.print(host);
    client.print("\r\nConnection: close\r\n\r\n");
    size_t capacity = min<size_t>(kIpCamSnapshotMax, 32 * 1024);
    uint8_t *buffer = static_cast<uint8_t *>(heap_caps_malloc(capacity, MALLOC_CAP_8BIT));
    if (!buffer) {
      client.stop();
      ipCamStatus = "CAM FRAME MEMORY FAILED";
      debugPrint("IPCAM: frame memory failed capacity=%u internal=%u largest=%u",
                 static_cast<unsigned>(capacity),
                 static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)),
                 static_cast<unsigned>(heap_caps_get_largest_free_block(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)));
      return false;
    }
    size_t received = 0;
    bool sawJpegStart = false;
    uint32_t deadline = millis() + 3200;
    while (received < capacity && static_cast<int32_t>(deadline - millis()) > 0) {
      size_t available = client.available();
      if (available == 0) {
        if (!client.connected()) break;
        vTaskDelay(pdMS_TO_TICKS(3));
        continue;
      }
      size_t amount = min<size_t>(available, capacity - received);
      int got = client.read(buffer + received, static_cast<int>(amount));
      if (got > 0) {
        size_t oldReceived = received;
        received += static_cast<size_t>(got);
        if (!sawJpegStart) {
          for (size_t p = oldReceived > 0 ? oldReceived - 1 : 0; p + 1 < received; ++p) {
            if (buffer[p] == 0xFF && buffer[p + 1] == 0xD8) {
              sawJpegStart = true;
              break;
            }
          }
        }
        if (sawJpegStart && received > 4 &&
            buffer[received - 2] == 0xFF && buffer[received - 1] == 0xD9) {
          break;
        }
        if (strcmp(paths[i], "/capture.hex") == 0 && ipCamHexPayloadComplete(buffer, received)) {
          break;
        }
      }
    }
    client.stop();
    bool decoded = strcmp(paths[i], "/capture.hex") == 0 ? ipCamDecodeHexJpeg(buffer, received)
                                                         : ipCamExtractJpeg(buffer, received);
    if (!decoded) {
      heap_caps_free(buffer);
      continue;
    }
    if ((ipCamLiveFrames % 20U) == 0U) {
      debugPrint("IPCAM: frame %s:%u %u bytes path=%s", host.c_str(),
                 static_cast<unsigned>(device.port), static_cast<unsigned>(received), paths[i]);
    }
    *out = buffer;
    *outSize = received;
    return true;
  }
  ipCamStatus = ipCamIsDeployCam(device) ? "DEPLOY CAM NEEDS UPDATE" : "NO LOCAL JPEG/MJPEG FRAME";
  return false;
}

static bool ipCamReadHttpLine(WiFiClient &client, char *line, size_t lineSize,
                              uint32_t timeoutMs) {
  if (!line || lineSize == 0) return false;
  size_t used = 0;
  uint32_t deadline = millis() + timeoutMs;
  while (static_cast<int32_t>(deadline - millis()) > 0) {
    int available = client.available();
    if (available <= 0) {
      if (!client.connected()) break;
      vTaskDelay(pdMS_TO_TICKS(2));
      continue;
    }
    int c = client.read();
    if (c < 0) continue;
    if (c == '\r') continue;
    if (c == '\n') {
      line[used] = '\0';
      return true;
    }
    if (used + 1 < lineSize) {
      line[used++] = static_cast<char>(c);
    }
  }
  line[used] = '\0';
  return used > 0;
}

static bool ipCamOpenDeployRawStream(const IpCamDevice &device, WiFiClient &client) {
  String host = ipCamAddress(device);
  IPAddress ip;
  if (!ip.fromString(host)) return false;
  client.stop();
  if (!client.connect(ip, device.port, 750)) {
    ipCamStatus = "DEPLOY CAM STREAM CONNECT FAILED";
    return false;
  }
  client.setNoDelay(true);
  client.print("GET /stream.raw HTTP/1.0\r\nHost: ");
  client.print(host);
  client.print("\r\nConnection: close\r\n\r\n");

  char line[96];
  uint32_t deadline = millis() + 1400;
  bool okStatus = false;
  while (static_cast<int32_t>(deadline - millis()) > 0) {
    if (!ipCamReadHttpLine(client, line, sizeof(line), 250)) continue;
    if (strncmp(line, "HTTP/", 5) == 0 && strstr(line, "200")) okStatus = true;
    if (line[0] == '\0') break;
  }
  if (!okStatus) {
    client.stop();
    ipCamStatus = "DEPLOY CAM STREAM UNAVAILABLE";
    return false;
  }
  debugPrint("IPCAM: deploy raw stream open %s:%u", host.c_str(),
             static_cast<unsigned>(device.port));
  return true;
}

static bool ipCamReadDeployRawStreamFrame(WiFiClient &client, uint8_t **out, size_t *outSize) {
  if (!out || !outSize) return false;
  *out = nullptr;
  *outSize = 0;
  char line[64];
  size_t jpegBytes = 0;
  uint32_t headerDeadline = millis() + 1600;
  while (static_cast<int32_t>(headerDeadline - millis()) > 0) {
    if (!ipCamReadHttpLine(client, line, sizeof(line), 350)) continue;
    if (strncmp(line, "JPG ", 4) != 0) continue;
    jpegBytes = static_cast<size_t>(strtoul(line + 4, nullptr, 10));
    break;
  }
  if (jpegBytes == 0 || jpegBytes > min<size_t>(kIpCamSnapshotMax, 192 * 1024)) {
    ipCamStatus = "DEPLOY CAM STREAM FRAME BAD";
    return false;
  }

  uint8_t *buffer = static_cast<uint8_t *>(
      heap_caps_malloc(jpegBytes, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
  if (!buffer) {
    ipCamStatus = "CAM FRAME MEMORY FAILED";
    return false;
  }

  size_t received = 0;
  uint32_t deadline = millis() + 1400;
  while (received < jpegBytes && static_cast<int32_t>(deadline - millis()) > 0) {
    int available = client.available();
    if (available <= 0) {
      if (!client.connected()) break;
      vTaskDelay(pdMS_TO_TICKS(1));
      continue;
    }
    size_t chunk = min<size_t>(static_cast<size_t>(available), jpegBytes - received);
    int count = client.read(buffer + received, chunk);
    if (count <= 0) continue;
    received += static_cast<size_t>(count);
    deadline = millis() + 1400;
  }

  if (received != jpegBytes || received < 4 || buffer[0] != 0xFF || buffer[1] != 0xD8 ||
      buffer[received - 2] != 0xFF || buffer[received - 1] != 0xD9) {
    heap_caps_free(buffer);
    ipCamStatus = "DEPLOY CAM STREAM INCOMPLETE";
    return false;
  }

  if ((ipCamLiveFrames % 20U) == 0U) {
    debugPrint("IPCAM: stream frame %u bytes path=/stream.raw",
               static_cast<unsigned>(received));
  }
  *out = buffer;
  *outSize = received;
  return true;
}

static void ipCamSaveRecordingFrame(const uint8_t *data, size_t len) {
  if (!ipCamRecording || !data || len == 0 || !sdReady) return;
  if (ipCamRecordDir.isEmpty()) return;
  char path[96];
  snprintf(path, sizeof(path), "%s/frame_%05lu.jpg", ipCamRecordDir.c_str(),
           static_cast<unsigned long>(ipCamRecordFrame++));
  if (!lockSd(250)) return;
  FsFile f = SD.open(path, FILE_WRITE);
  if (f) {
    f.write(data, len);
    f.close();
  }
  unlockSd();
}

static void ipCamStartRecording() {
  if (!sdReady) {
    ipCamStatus = "SD REQUIRED FOR RECORDING";
    return;
  }
  if (!lockSd(500)) {
    ipCamStatus = "SD BUSY";
    return;
  }
  if (!SD.exists(kIpCamRecordRoot)) SD.mkdir(kIpCamRecordRoot);
  ipCamRecordId = millis();
  ipCamRecordFrame = 0;
  ipCamRecordDir = String(kIpCamRecordRoot) + "/rec_" + String(ipCamRecordId);
  bool ok = SD.mkdir(ipCamRecordDir.c_str());
  unlockSd();
  if (!ok) {
    ipCamStatus = "RECORD FOLDER FAILED";
    ipCamRecordDir = "";
    return;
  }
  ipCamRecording = true;
  ipCamStatus = "RECORDING JPEG FRAMES";
}

static void ipCamStopRecording() {
  ipCamRecording = false;
  ipCamStatus = ipCamRecordFrame ? String("REC SAVED ") + String(ipCamRecordFrame) + " FRAMES"
                                 : "REC STOPPED";
}

static void ipCamScanTask(void *) {
  ipCamScanBusy = true;
  ipCamShowingSnapshot = false;
  ipCamDeviceCount = 0;
  ipCamSelected = -1;
  ipCamStatus = "FAST DEPLOY CAM SCAN";
  IPAddress local = WiFi.localIP();
  IPAddress gateway = WiFi.gatewayIP();
  debugPrint("IPCAM: scan start local=%s gateway=%s", local.toString().c_str(),
             gateway.toString().c_str());
  IPAddress candidates[] = {
      IPAddress(192, 168, 4, 1),          // DeployCam hotspot default
      IPAddress(local[0], local[1], local[2], 132), // current known DeployCam DHCP lease
      gateway,
  };
  for (IPAddress target : candidates) {
    if (target[0] == 0 || target == local) continue;
    ipCamStatus = String("CHECK ") + target.toString();
    debugPrint("IPCAM: direct probe %s", target.toString().c_str());
    waypointsDirty = true;
    if (ipCamAddIfDeployCam(target, 80, true)) {
      ipCamStatus = String("DEPLOY CAM FOUND ") + target.toString();
      debugPrint("IPCAM: deploy cam found direct %s", target.toString().c_str());
      ipCamScanBusy = false;
      ipCamTaskHandle = nullptr;
      waypointsDirty = true;
      vTaskDelete(nullptr);
      return;
    }
  }
  ipCamStatus = "NO DEPLOY CAM - LIGHT PORT SCAN OFF";
  debugPrint("IPCAM: direct deploy probes failed; generic subnet scan skipped for stability");
  ipCamScanBusy = false;
  ipCamTaskHandle = nullptr;
  waypointsDirty = true;
  vTaskDelete(nullptr);
  return;
#if 0
  ipCamStatus = "SCANNING CAMERA PORTS";
  const uint16_t ports[] = {80, 443, 554, 8000, 8080, 8554, 8899};
  for (int host = 1; host < 255 && WiFi.status() == WL_CONNECTED; ++host) {
    if (host == local[3]) continue;
    IPAddress target(local[0], local[1], local[2], host);
    if ((host % 16) == 0) {
      ipCamStatus = String("PORT SCAN ") + String(host) + "/254";
      waypointsDirty = true;
    }
    for (uint16_t port : ports) {
      WiFiClient probe;
      if (!probe.connect(target, port, 35)) continue;
      probe.stop();
      String hostText = target.toString();
      bool deployCam = ipCamProbeDeployCam(hostText, port);
      const char *service = deployCam ? "DEPLOY CAM" :
                            (port == 554 || port == 8554 ? "RTSP" :
                            (port == 443 ? "HTTPS" : (port == 8899 ? "ONVIF" : "HTTP")));
      ipCamAddDevice(local[0], local[1], local[2], static_cast<uint8_t>(host), port,
                     service, deployCam);
      if (deployCam) {
        ipCamStatus = String("DEPLOY CAM FOUND ") + hostText;
        debugPrint("IPCAM: deploy cam found port scan %s:%u", hostText.c_str(),
                   static_cast<unsigned>(port));
        ipCamScanBusy = false;
        ipCamTaskHandle = nullptr;
        waypointsDirty = true;
        vTaskDelete(nullptr);
        return;
      }
    }
  }
  bool deployFound = false;
  for (size_t i = 0; i < ipCamDeviceCount; ++i) {
    if (strcmp(ipCamDevices[i].service, "DEPLOY CAM") == 0) {
      deployFound = true;
      break;
    }
  }
  ipCamStatus = deployFound ? "DEPLOY CAM FOUND" :
                (ipCamDeviceCount ? String(ipCamDeviceCount) + " CAMERA SERVICES" :
                                    "NO DEPLOY CAM / CAMERA PORTS");
  ipCamScanBusy = false;
  ipCamTaskHandle = nullptr;
  waypointsDirty = true;
  vTaskDelete(nullptr);
#endif
}

static bool ipCamReadSnapshot(const IpCamDevice &device) {
  uint8_t *buffer = nullptr;
  size_t received = 0;
  if (!ipCamFetchJpegFrame(device, &buffer, &received)) {
    return false;
  }
  if (ensureIpCamFrameMutex() && xSemaphoreTake(ipCamFrameMutex, pdMS_TO_TICKS(200)) == pdTRUE) {
    ipCamFreeSnapshotLocked();
    ipCamSnapshot = buffer;
    ipCamSnapshotSize = received;
    ipCamShowingSnapshot = true;
    ipCamLiveFrameFileReady = ipCamWriteLiveFrameFileLocked(buffer, received);
    ipCamFrameDirty = true;
    xSemaphoreGive(ipCamFrameMutex);
  } else {
    heap_caps_free(buffer);
    return false;
  }
  ipCamLastFrameBytes = received;
  ipCamLastFrameMs = millis();
  ipCamStatus = String(device.service) + " " + ipCamAddress(device) + " FRAME";
  return true;
}

static void ipCamViewTask(void *) {
  ipCamViewBusy = true;
  int selected = ipCamSelected;
  if (selected >= 0 && selected < static_cast<int>(ipCamDeviceCount)) {
    ipCamReadSnapshot(ipCamDevices[selected]);
  }
  ipCamViewBusy = false;
  ipCamTaskHandle = nullptr;
  waypointsDirty = true;
  vTaskDelete(nullptr);
}

static void ipCamLiveTask(void *) {
  ipCamViewBusy = true;
  ipCamLiveActive = true;
  ipCamLiveStopRequested = false;
  ipCamLiveFrames = 0;
  ipCamLiveBytes = 0;
  ipCamLiveStartMs = millis();
  ipCamDisplayedFrames = 0;
  ipCamDisplayStartMs = ipCamLiveStartMs;
  ipCamLiveBackoffUntilMs = 0;
  ipCamLiveLastStatusMs = 0;
  ipCamLiveConsecutiveFails = 0;
  int selected = ipCamSelected;
  ipCamStatus = "LIVE CONNECTING";
  debugPrint("IPCAM: live task start selected=%d count=%u", selected,
             static_cast<unsigned>(ipCamDeviceCount));
  // Prefer the compact binary stream. It avoids a new TCP handshake for every frame
  // and halves the traffic of the legacy hexadecimal stream. Bounded /capture remains
  // the automatic fallback if the companion camera does not support /stream.raw.
  bool useDeployStream = selected >= 0 && selected < static_cast<int>(ipCamDeviceCount) &&
                         ipCamIsDeployCam(ipCamDevices[selected]);
  uint8_t deployStreamOpenFailures = 0;
  WiFiClient deployStreamClient;
  bool deployStreamOpen = false;
  while (!ipCamLiveStopRequested && selected >= 0 &&
         selected < static_cast<int>(ipCamDeviceCount) && WiFi.status() == WL_CONNECTED) {
    uint32_t freeDma = heap_caps_get_free_size(MALLOC_CAP_DMA);
    uint32_t now = millis();
    if (freeDma < 3200 || static_cast<int32_t>(ipCamLiveBackoffUntilMs - now) > 0) {
      if (now - ipCamLiveLastStatusMs > 1800) {
        ipCamLiveLastStatusMs = now;
        ipCamStatus = "LIVE PAUSED - WIFI RECOVERY";
        waypointsDirty = true;
        debugPrint("IPCAM: live paused dma=%u backoff=%ld",
                   static_cast<unsigned>(freeDma),
                   static_cast<long>(ipCamLiveBackoffUntilMs - now));
      }
      vTaskDelay(pdMS_TO_TICKS(250));
      continue;
    }
    uint8_t *buffer = nullptr;
    size_t received = 0;
    bool ok = false;
    if (useDeployStream) {
      if (!deployStreamOpen) {
        deployStreamClient.stop();
        deployStreamOpen = ipCamOpenDeployRawStream(ipCamDevices[selected], deployStreamClient);
        if (!deployStreamOpen) {
          deployStreamOpenFailures++;
          if (deployStreamOpenFailures >= 2) {
            useDeployStream = false;
            ipCamStatus = "STREAM FALLBACK - LIVE JPEG";
            debugPrint("IPCAM: raw stream unavailable; using bounded capture fallback");
          }
          ipCamLiveConsecutiveFails++;
          ipCamLiveBackoffUntilMs = millis() + min<uint32_t>(2500, 600 + ipCamLiveConsecutiveFails * 120U);
          vTaskDelay(pdMS_TO_TICKS(180));
          continue;
        }
      }
      ok = ipCamReadDeployRawStreamFrame(deployStreamClient, &buffer, &received);
      if (!ok) {
        deployStreamClient.stop();
        deployStreamOpen = false;
      } else {
        deployStreamOpenFailures = 0;
      }
    } else {
      ok = ipCamFetchJpegFrame(ipCamDevices[selected], &buffer, &received);
    }
    if (ok && buffer && received) {
      if (ensureIpCamFrameMutex() &&
          xSemaphoreTake(ipCamFrameMutex, pdMS_TO_TICKS(100)) == pdTRUE) {
        uint16_t frameW = 0;
        uint16_t frameH = 0;
        ipCamJpegSize(buffer, received, frameW, frameH);
        ipCamFreeSnapshotLocked();
        ipCamSnapshot = buffer;
        ipCamSnapshotSize = received;
        ipCamFrameWidth = frameW;
        ipCamFrameHeight = frameH;
        ipCamShowingSnapshot = true;
        ipCamLiveFrameFileReady = false;
        ipCamFrameDirty = true;
        xSemaphoreGive(ipCamFrameMutex);
        ipCamLiveFrames++;
        ipCamLiveBytes += received;
        ipCamLiveConsecutiveFails = 0;
        ipCamLiveBackoffUntilMs = 0;
        ipCamLastFrameBytes = received;
        ipCamLastFrameMs = millis();
        ipCamStatus = ipCamRecording ? "LIVE RECORDING" : "LIVE";
        ipCamSaveRecordingFrame(buffer, received);
        if ((ipCamLiveFrames % 60U) == 0U) {
          uint32_t elapsedMs = max<uint32_t>(1U, millis() - ipCamLiveStartMs);
          uint32_t fps10 = static_cast<uint32_t>((static_cast<uint64_t>(ipCamLiveFrames) * 10000ULL) /
                                                 elapsedMs);
          uint32_t kbps = static_cast<uint32_t>((static_cast<uint64_t>(ipCamLiveBytes) * 8ULL) /
                                                elapsedMs);
          debugPrint("IPCAM: live perf frames=%u fps=%u.%u kbps=%u dma=%u",
                     static_cast<unsigned>(ipCamLiveFrames),
                     static_cast<unsigned>(fps10 / 10U),
                     static_cast<unsigned>(fps10 % 10U),
                     static_cast<unsigned>(kbps),
                     static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_DMA)));
        }
        vTaskDelay(pdMS_TO_TICKS(kIpCamLiveFrameDelayMs));
      } else {
        heap_caps_free(buffer);
        vTaskDelay(pdMS_TO_TICKS(120));
      }
    } else {
      if (buffer) heap_caps_free(buffer);
      ipCamLiveConsecutiveFails++;
      if (ipCamLiveConsecutiveFails >= 3) {
        ipCamLiveBackoffUntilMs = millis() + min<uint32_t>(2500, 600 + ipCamLiveConsecutiveFails * 120U);
      }
      vTaskDelay(pdMS_TO_TICKS(180));
    }
  }
  deployStreamClient.stop();
  ipCamLiveActive = false;
  ipCamViewBusy = false;
  ipCamLiveStopRequested = false;
  if (ipCamRecording) ipCamStopRecording();
  if (WiFi.status() != WL_CONNECTED) ipCamStatus = "WI-FI DISCONNECTED";
  else if (ipCamStatus == "LIVE" || ipCamStatus == "LIVE RECORDING") ipCamStatus = "LIVE STOPPED";
  ipCamTaskHandle = nullptr;
  waypointsDirty = true;
  vTaskDelete(nullptr);
}

static void startIpCamScan() {
  if (ipCamLiveActive) {
    ipCamLiveStopRequested = true;
    ipCamStatus = "STOPPING LIVE";
    waypointsDirty = true;
    return;
  }
  if (ipCamTaskHandle || ipCamScanBusy || ipCamViewBusy) return;
  if (!wifiEnabled || !wifiAvailable || WiFi.status() != WL_CONNECTED) {
    ipCamStatus = "CONNECT WI-FI FIRST";
    return;
  }
  if (xTaskCreatePinnedToCore(ipCamScanTask, "ipcam_scan", 3072, nullptr, 1,
                              &ipCamTaskHandle, 0) != pdPASS) {
    ipCamStatus = "SCAN TASK FAILED";
  }
}

static void startIpCamView() {
  if (ipCamLiveActive) {
    ipCamLiveStopRequested = true;
    ipCamStatus = "STOPPING LIVE";
    waypointsDirty = true;
    return;
  }
  if (ipCamTaskHandle || ipCamScanBusy || ipCamViewBusy) {
    ipCamStatus = "WAIT FOR CURRENT SCAN";
    waypointsDirty = true;
    return;
  }
  if (ipCamSelected < 0 || ipCamSelected >= static_cast<int>(ipCamDeviceCount)) {
    ipCamStatus = "SCAN AND SELECT A CAMERA FIRST";
    waypointsDirty = true;
    return;
  }
  ensureIpCamFrameMutex();
  ipCamShowingSnapshot = false;
  ipCamMode = IpCamMode::LIVE;
  ipCamStatus = "STARTING LIVE VIEW";
  if (xTaskCreatePinnedToCore(ipCamLiveTask, "ipcam_live", 2560, nullptr, 1,
                              &ipCamTaskHandle, 0) != pdPASS) {
    ipCamStatus = "VIEW TASK FAILED";
  }
}
#endif

