  M5.Display.setTextColor(ipCamScanBusy || ipCamViewBusy ? colors.amberDim : colors.amber,
                          colors.black);
  M5.Display.drawString(ipCamStatus, 14, top);
  int16_t listTop = static_cast<int16_t>(top + M5.Display.fontHeight() + 10);
  int16_t sideW = 320;
