  uint32_t lastPacket;
  uint16_t calibration;
  float baseline;
  float noise;
  float score;
  float threshold;
  portENTER_CRITICAL(&wifiMotionMux);
  enabled = wifiMotionEnabled;
  detected = wifiMotionDetected;
  available = wifiMotionAvailable;
  packets = wifiMotionPackets;
  lastPacket = wifiMotionLastPacketMs;
  calibration = wifiMotionCalibrationSamples;
  baseline = wifiMotionBaseline;
  noise = wifiMotionNoise;
