static void saveGameBoyRam() {
  // Game Boy / Game Boy Color emulation has been removed from the firmware.
}

static void gameBoyTask(void *) {
  gameBoyStopRequested = true;
  gameBoyRunning = false;
  gameBoyPaused = false;
  gameBoyTaskHandle = nullptr;
  vTaskDelete(nullptr);
}

static void freeGameBoyRuntime() {
  if (gameBoy.rom) heap_caps_free(gameBoy.rom);
  if (gameBoy.cartRam) heap_caps_free(gameBoy.cartRam);
  for (uint8_t i = 0; i < 2; ++i) {
    if (gameBoy.frames[i]) heap_caps_free(gameBoy.frames[i]);
    gameBoy.frames[i] = nullptr;
  }
  if (gameBoy.scaledFrame) heap_caps_free(gameBoy.scaledFrame);
  gameBoy.scaledFrame = nullptr;
  gameBoy.rom = nullptr;
  gameBoy.romSize = 0;
  gameBoy.cartRam = nullptr;
  gameBoy.cartRamSize = 0;
  gameBoy.romPath = "";
  gameBoy.savePath = "";
  gameBoyFrameReady = false;
  gameBoyFrames = 0;
  gameBoyDrawFrames = 0;
  gameBoyFrameTimeUs = 0;
  gameBoyFrameTimeMaxUs = 0;
  gameBoyFps = 0.0f;
  gameBoyDrawFps = 0.0f;
}

void stopGameBoyEmulator() {
  if (gameBoyTaskHandle || gameBoyRunning) {
    gameBoyStopRequested = true;
    uint32_t started = millis();
    while (gameBoyTaskHandle && millis() - started < 1000) vTaskDelay(pdMS_TO_TICKS(10));
    if (gameBoyTaskHandle) {
      gameStatus = "EMULATOR STOP TIMEOUT";
      gamesView = GAMES_VIEW_ERROR;
      debugPrint("GAMEBOY: stop timeout; runtime retained");
      return;
    }
  }
  saveGameBoyRam();
  freeGameBoyRuntime();
  gameBoyRunning = false;
  gameBoyStopRequested = false;
  gameBoyPaused = false;
  gameBoyJoypad = 0xFF;
  if (activeGameSystem == GAME_SYSTEM_GB) activeGameSystem = GAME_SYSTEM_NONE;
  gamesView = GAMES_VIEW_ROMS;
}

bool refreshGameRomList() {
  gameRomCount = 0;
  gameRomSelected = -1;
  gameRomScroll = 0;
  gameStatus = "EMULATORS REMOVED";
  debugPrint("GAME: emulator ROM scan disabled");
  return true;
  if (!sdReady || usbMscActive || !lockSd(600)) {
    gameStatus = "SD NOT READY";
    debugPrint("GAMEBOY: scan failed sd=%d msc=%d", sdReady ? 1 : 0, usbMscActive ? 1 : 0);
    return false;
  }
  if (!SD.exists(kGameDirectory)) SD.mkdir(kGameDirectory);
  if (!SD.exists(kGameSaveDirectory)) SD.mkdir(kGameSaveDirectory);
  FsFile dir = SD.open(kGameDirectory);
  if (dir && dir.isDirectory()) {
    while (gameRomCount < kGameMaxRoms) {
      FsFile file = dir.openNextFile();
      if (!file) break;
      if (!file.isDirectory()) {
        char name[kGameNameLen] = {};
        if (file.getName(name, sizeof(name)) > 0) {
          String lower = name;
          lower.toLowerCase();
          if (lower.endsWith(".gba")) {
            strncpy(gameRomNames[gameRomCount++], name, kGameNameLen - 1);
          }
        }
      }
      file.close();
    }
    dir.close();
  }
  unlockSd();
  for (size_t i = 0; i + 1 < gameRomCount; ++i) {
    for (size_t j = i + 1; j < gameRomCount; ++j) {
      if (strcasecmp(gameRomNames[i], gameRomNames[j]) > 0) {
        char temp[kGameNameLen];
        memcpy(temp, gameRomNames[i], sizeof(temp));
        memcpy(gameRomNames[i], gameRomNames[j], kGameNameLen);
        memcpy(gameRomNames[j], temp, sizeof(temp));
      }
    }
  }
  if (gameRomCount > 0) gameRomSelected = 0;
  gameStatus = gameRomCount ? String(gameRomCount) + " ROMS" : "EMULATORS REMOVED";
  debugPrint("GAME: scan count=%u path=%s", static_cast<unsigned>(gameRomCount),
             kGameDirectory);
  return true;
}

bool startSelectedGameBoyRom() {
  gameStatus = "EMULATORS REMOVED";
  gamesView = GAMES_VIEW_ERROR;
  return false;
  if (gameRomSelected < 0 || gameRomSelected >= static_cast<int>(gameRomCount)) {
    gameStatus = "SELECT A ROM";
    return false;
  }
  stopUsbGameStorage();
  String name = gameRomNames[gameRomSelected];
  String lower = name;
  lower.toLowerCase();
  if (!lower.endsWith(".gba")) {
    gameStatus = "GAME BOY REMOVED - USE .GBA";
    gamesView = GAMES_VIEW_ERROR;
    return false;
  }
  EmulatorControlSystem launchSystem = CONTROL_SYSTEM_GBA;
  if (!gameFirstRunBypass && !emulatorControlAccepted[launchSystem]) {
    pendingLaunchControlSystem = launchSystem;
    emulatorControlSystem = launchSystem;
    gameControlsReturnView = GAMES_VIEW_FIRST_RUN;
    gamesView = GAMES_VIEW_FIRST_RUN;
    gameStatus = "REVIEW CONTROLS BEFORE FIRST LAUNCH";
    debugPrint("GAME: first-run controls system=%s", emulatorControlSystemName(launchSystem));
    waypointsDirty = true;
    return true;
  }
  gameFirstRunBypass = false;
  emulatorControlSystem = launchSystem;
  gameStatus = String("LOADING ") + name;
  gamesView = GAMES_VIEW_LOADING;
  drawGamesApp();
  delay(20);
  return startSelectedGbaRom();
}

static bool writeGbaDataFile(const String &path, const uint8_t *data, size_t size) {
  if (!data || !size || !sdReady || usbMscActive || !lockSd(1200)) return false;
  FsFile file = SD.open(path.c_str(), O_WRONLY | O_CREAT | O_TRUNC);
  bool ok = file && file.write(data, size) == size;
  if (file) file.close();
  unlockSd();
  return ok;
}

bool saveGbaBattery() {
  if (!gbaRunning || gbaSavePath.length() == 0 || !gbaCoreMutex) return false;
  if (xSemaphoreTake(gbaCoreMutex, pdMS_TO_TICKS(500)) != pdTRUE) return false;
  bool ok = writeGbaDataFile(gbaSavePath, vba_embed_battery_data(), vba_embed_battery_size());
  xSemaphoreGive(gbaCoreMutex);
  if (ok) {
    gbaLastBatterySaveMs = millis();
    debugPrint("GBA: battery save bytes=%u path=%s",
               static_cast<unsigned>(vba_embed_battery_size()), gbaSavePath.c_str());
  }
  return ok;
}

bool saveGbaState() {
  if (!gbaRunning || !gbaCoreMutex) return false;
  size_t capacity = vba_embed_state_size();
  uint8_t *state = static_cast<uint8_t *>(
      heap_caps_malloc(capacity, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
  if (!state) return false;
  size_t written = 0;
  bool ok = false;
  if (xSemaphoreTake(gbaCoreMutex, pdMS_TO_TICKS(1000)) == pdTRUE) {
    ok = vba_embed_write_state(state, capacity, &written);
    xSemaphoreGive(gbaCoreMutex);
  }
  if (ok) ok = writeGbaDataFile(gbaStatePath, state, written);
  heap_caps_free(state);
  gameStatus = ok ? "STATE SAVED" : "STATE SAVE FAILED";
  debugPrint("GBA: state save ok=%u bytes=%u", ok ? 1U : 0U,
             static_cast<unsigned>(written));
  return ok;
}

bool loadGbaState() {
  if (!gbaRunning || !gbaCoreMutex || !sdReady || usbMscActive || !lockSd(1000)) return false;
  FsFile file = SD.open(gbaStatePath.c_str());
  size_t size = file ? static_cast<size_t>(file.fileSize()) : 0;
  uint8_t *state = size && size <= vba_embed_state_size()
                       ? static_cast<uint8_t *>(heap_caps_malloc(
                             size, MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT))
                       : nullptr;
  bool readOk = state && file.read(state, size) == static_cast<int>(size);
  if (file) file.close();
  unlockSd();
  bool ok = false;
  if (readOk && xSemaphoreTake(gbaCoreMutex, pdMS_TO_TICKS(1000)) == pdTRUE) {
    ok = vba_embed_read_state(state, size);
    xSemaphoreGive(gbaCoreMutex);
  }
  if (state) heap_caps_free(state);
  gameStatus = ok ? "STATE LOADED" : "NO VALID STATE";
  debugPrint("GBA: state load ok=%u bytes=%u", ok ? 1U : 0U,
             static_cast<unsigned>(size));
  return ok;
}

static void gbaAudioCallback(const int16_t *samples, int count) {
  if (!gbaSoundEnabled || !gbaAudioReady || !samples || count <= 0) return;
  if (count > 1088 || M5.Speaker.isPlaying(2) >= 2) {
    ++gbaAudioDropped;
    return;
  }
  uint8_t index = gbaAudioBufferIndex;
  if (!gbaAudioBuffers[index]) return;
  memcpy(gbaAudioBuffers[index], samples, static_cast<size_t>(count) * sizeof(int16_t));
  if (M5.Speaker.playRaw(gbaAudioBuffers[index], static_cast<size_t>(count), 32000,
                         true, 1, 2, false)) {
    gbaAudioBufferIndex = static_cast<uint8_t>((index + 1) % 3);
  } else {
    ++gbaAudioDropped;
    gbaAudioReady = false;
  }
}

static void gbaTask(void *) {
  (void)esp_task_wdt_add(nullptr);
  int64_t nextFrameUs = esp_timer_get_time();
  while (!gbaStopRequested) {
    if (gbaPaused) {
      vTaskDelay(pdMS_TO_TICKS(20));
      nextFrameUs = esp_timer_get_time();
      continue;
    }
    int64_t started = esp_timer_get_time();
    if (gbaCoreMutex && xSemaphoreTake(gbaCoreMutex, pdMS_TO_TICKS(100)) == pdTRUE) {
      vba_embed_run_frame(gbaButtons);
      xSemaphoreGive(gbaCoreMutex);
    }
    esp_task_wdt_reset();
    uint32_t elapsed = static_cast<uint32_t>(esp_timer_get_time() - started);
    gbaFrameTimeUs = elapsed;
    if (elapsed > gbaFrameTimeMaxUs) gbaFrameTimeMaxUs = elapsed;
    ++gbaFrames;
    nextFrameUs += 16742;
    int64_t waitUs = nextFrameUs - esp_timer_get_time();
    if (waitUs > 1500) {
      vTaskDelay(pdMS_TO_TICKS(static_cast<uint32_t>(waitUs / 1000)));
    } else if (waitUs < -16742) {
      ++gbaMissedFrames;
      nextFrameUs = esp_timer_get_time();
      vTaskDelay(pdMS_TO_TICKS(3));
    } else if (elapsed > 12000) {
      vTaskDelay(1);
    } else {
      taskYIELD();
    }
  }
  gbaRunning = false;
  gbaPaused = false;
  gbaTaskHandle = nullptr;
  esp_task_wdt_delete(nullptr);
  vTaskDelete(nullptr);
}

void stopGbaEmulator() {
  if (gbaTaskHandle || gbaRunning) {
    saveGbaBattery();
    gbaStopRequested = true;
    uint32_t started = millis();
    while (gbaTaskHandle && millis() - started < 2000) vTaskDelay(pdMS_TO_TICKS(10));
    if (gbaTaskHandle) {
      gameStatus = "GBA STOP TIMEOUT";
      gamesView = GAMES_VIEW_ERROR;
      return;
    }
  }
  vba_embed_close();
  vba_embed_set_audio_callback(nullptr);
  M5.Speaker.stop(2);
  for (int i = 0; i < 3; ++i) {
    if (gbaAudioBuffers[i]) heap_caps_free(gbaAudioBuffers[i]);
    gbaAudioBuffers[i] = nullptr;
  }
  gbaAudioReady = false;
  if (gbaSpeakerOwned) {
    M5.Speaker.end();
    gbaSpeakerOwned = false;
  }
  gbaRunning = false;
  gbaStopRequested = false;
  gbaPaused = false;
  gbaButtons = 0;
  gbaRomPath = "";
  gbaSavePath = "";
  gbaStatePath = "";
  if (activeGameSystem == GAME_SYSTEM_GBA) activeGameSystem = GAME_SYSTEM_NONE;
#if ENABLE_WIFI
  if (wifiSuspendedForGames) {
    wifiSuspendedForGames = false;
    debugPrint("GAME: Wi-Fi performance pause cleared");
  }
#endif
  gamesView = GAMES_VIEW_ROMS;
}

bool startSelectedGbaRom() {
  if (gameRomSelected < 0 || gameRomSelected >= static_cast<int>(gameRomCount)) return false;
  stopUsbGameStorage();
  stopGameBoyEmulator();
  stopGbaEmulator();
#if ENABLE_WIFI
  if (wifiScanInProgress) {
    stopWifiScan();
    debugPrint("GAME: Wi-Fi scan stopped for GBA emulator");
  }
  abortTileDownload();
  if (mapDownload.active) {
    stopMapDownload();
  }
  if (wifiEnabled || wifiBootEnablePending) {
    wifiSuspendedForGames = true;
    debugPrint("GAME: Wi-Fi left online; background work paused for GBA");
  }
#endif
  if (mapDownload.active || tileDownloadActive || tileDownloadQueued) {
    debugPrint("GAME: map/tile downloads paused while emulator is active");
  }
  String name = gameRomNames[gameRomSelected];
  gbaRomPath = String(kGameDirectory) + "/" + name;
  vba_embed_set_rom_path(gbaRomPath.c_str());
  String base = name.substring(0, name.length() - 4);
  gbaSavePath = String(kGameSaveDirectory) + "/" + base + ".sav";
  gbaStatePath = String(kGameSaveDirectory) + "/" + base + ".state0";
  gbaAudioReady = false;
  if (gbaSoundEnabled) {
    gbaAudioReady = M5.Speaker.begin();
    gbaSpeakerOwned = gbaAudioReady;
    for (int i = 0; i < 3; ++i) {
      gbaAudioBuffers[i] = static_cast<int16_t *>(heap_caps_malloc(
          1088 * sizeof(int16_t), MALLOC_CAP_SPIRAM | MALLOC_CAP_8BIT));
      if (!gbaAudioBuffers[i]) gbaAudioReady = false;
    }
  }
  if (gbaSoundEnabled && !gbaAudioReady) {
    debugPrint("GBA: audio unavailable internal=%u dma=%u",
               static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)),
               static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_DMA)));
  }
  if (!sdReady || usbMscActive || !lockSd(2000)) {
    gameStatus = "SD BUSY";
    return false;
  }
  FsFile romFile = SD.open(gbaRomPath.c_str());
  size_t romSize = romFile ? static_cast<size_t>(romFile.fileSize()) : 0;
  if (!romFile || romSize < 0xC0 || romSize > 0x2000000) {
    if (romFile) romFile.close();
    unlockSd();
    gameStatus = "INVALID GBA ROM";
    return false;
  }
  uint8_t *target = vba_embed_prepare_rom(romSize);
  bool loaded = target && romFile.read(target, romSize) == static_cast<int>(romSize);
  romFile.close();
  unlockSd();
  if (!loaded || !vba_embed_finalize_rom(romSize)) {
    vba_embed_close();
    gameStatus = "GBA CORE LOAD FAILED";
    gamesView = GAMES_VIEW_ERROR;
    return false;
  }
  if (lockSd(500)) {
    FsFile save = SD.open(gbaSavePath.c_str());
    if (save) {
      size_t amount = min<size_t>(save.fileSize(), vba_embed_battery_size());
      save.read(vba_embed_battery_data(), amount);
      save.close();
      debugPrint("GBA: battery loaded bytes=%u", static_cast<unsigned>(amount));
    }
    unlockSd();
  }
  if (!gbaCoreMutex) gbaCoreMutex = xSemaphoreCreateMutex();
  if (!gbaCoreMutex) {
    vba_embed_close();
    gameStatus = "GBA LOCK FAILED";
    return false;
  }
  gbaFrameSkip = static_cast<uint8_t>(constrain(gbaFrameSkip, 0, 10));
  vba_embed_set_frameskip(gbaFrameSkip);
  gbaStopRequested = false;
  gbaRunning = true;
  gbaFrames = 0;
  gbaMissedFrames = 0;
  gbaFrameTimeUs = 0;
  gbaFrameTimeMaxUs = 0;
  gbaFps = 0;
  gbaStatsLastMs = millis();
  gbaStatsLastFrames = 0;
  gbaLastBatterySaveMs = millis();
  gbaAudioBufferIndex = 0;
  gbaAudioDropped = 0;
  vba_embed_set_audio_callback(gbaAudioReady ? gbaAudioCallback : nullptr);
  activeGameSystem = GAME_SYSTEM_GBA;
  gamesView = GAMES_VIEW_RUNNING;
  gameStatus = name;
  BaseType_t created = xTaskCreatePinnedToCore(gbaTask, "gba", 12288, nullptr, 5,
                                               &gbaTaskHandle, 0);
  if (created != pdPASS) {
    gbaTaskHandle = nullptr;
    gbaRunning = false;
    vba_embed_close();
    activeGameSystem = GAME_SYSTEM_NONE;
    gamesView = GAMES_VIEW_ERROR;
    gameStatus = "GBA TASK FAILED";
    return false;
  }
  debugPrint("GBA: start core=%s rom=%s bytes=%u cpu=%uMHz psram=%u free=%u",
             vba_embed_core_name(), name.c_str(),
             static_cast<unsigned>(romSize), static_cast<unsigned>(getCpuFrequencyMhz()),
             static_cast<unsigned>(ESP.getPsramSize()), static_cast<unsigned>(ESP.getFreePsram()));
  return true;
}

static void drawGameBoyFrame() {
  if (!gameBoyRunning || !gameBoy.frames[gameBoy.frontFrame] || !gameBoyFrameMutex) return;
  int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 4);
  int16_t contentBottom = static_cast<int16_t>(appPrimaryButton.y - 8);
  int16_t centerX = static_cast<int16_t>(screenW / 2);
  int16_t centerY = static_cast<int16_t>((contentTop + contentBottom) / 2);
  if (xSemaphoreTake(gameBoyFrameMutex, pdMS_TO_TICKS(2)) == pdTRUE) {
    bool previousSwap = M5.Display.getSwapBytes();
    M5.Display.setSwapBytes(true);
    if (gameBoyFastDrawMode && gameBoy.scaledFrame) {
      const uint16_t *src = gameBoy.frames[gameBoy.frontFrame];
      uint16_t *dst = gameBoy.scaledFrame;
      for (uint16_t y = 0; y < 144; ++y) {
        const uint16_t *srcRow = src + static_cast<size_t>(y) * 160;
        uint16_t *row0 = dst + static_cast<size_t>(y) * 2 * 320;
        uint16_t *row1 = row0 + 320;
        for (uint16_t x = 0; x < 160; ++x) {
          uint16_t px = srcRow[x];
          uint16_t dx = static_cast<uint16_t>(x * 2);
          row0[dx] = px;
          row0[dx + 1] = px;
          row1[dx] = px;
          row1[dx + 1] = px;
        }
      }
      M5.Display.pushImage(static_cast<int16_t>(centerX - 160),
                           static_cast<int16_t>(centerY - 144), 320, 288,
                           gameBoy.scaledFrame);
    } else {
      M5.Display.pushImage(static_cast<int16_t>(centerX - 80),
                           static_cast<int16_t>(centerY - 72), 160, 144,
                           gameBoy.frames[gameBoy.frontFrame]);
    }
    M5.Display.setSwapBytes(previousSwap);
    gameBoyFrameReady = false;
    ++gameBoyDrawFrames;
    xSemaphoreGive(gameBoyFrameMutex);
  }
}

static void drawGbaFrame() {
  if (!gbaRunning || !vba_embed_frame_ready()) return;
  const int16_t panelW = 250;
  const int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 4);
  const int16_t contentBottom = static_cast<int16_t>(screenH - navH - 4);
  const int16_t gameAreaW = static_cast<int16_t>(screenW - panelW - 8);
  const int16_t centerX = gameAreaW / 2;
  const int16_t centerY = static_cast<int16_t>((contentTop + contentBottom) / 2);
  const int16_t availableW = static_cast<int16_t>(max<int16_t>(240, gameAreaW - 8));
  const int16_t availableH = static_cast<int16_t>(max<int16_t>(160, contentBottom - contentTop - 8));
  const float fitZoom = min<float>(availableW / 240.0f, availableH / 160.0f);
  const float zoom = max<float>(1.0f, floorf(fitZoom));
  const uint16_t *frame = vba_embed_lock_frame();
  if (frame) {
    bool previousSwap = M5.Display.getSwapBytes();
    // The camera and emulator cores both provide RGB565 in wire byte order.
    M5.Display.setSwapBytes(true);
    if (gbaFastDrawMode && zoom <= 1.0f) {
      M5.Display.pushImage(static_cast<int16_t>(centerX - 120),
                           static_cast<int16_t>(centerY - 80), 240, 160, frame);
    } else {
      M5.Display.pushImageRotateZoom(centerX, centerY, 120.0f, 80.0f, 0.0f, zoom, zoom,
                                     240, 160, frame);
    }
    M5.Display.setSwapBytes(previousSwap);
    vba_embed_unlock_frame();
  }
}

static void drawGbaSideOverlay() {
  const int16_t panelW = 250;
  const int16_t x = static_cast<int16_t>(screenW - panelW);
  const int16_t top = static_cast<int16_t>(appTopBarRect.h + 8);
  const int16_t bottom = static_cast<int16_t>(screenH - navH - 8);
  M5.Display.fillRect(x, top, panelW, bottom - top, colors.black);
  M5.Display.drawFastVLine(x, top, bottom - top, colors.amberDim);
  const int16_t margin = 14;
  const int16_t buttonH = 62;
  gbaSaveStateButton = {static_cast<int16_t>(x + margin), top,
                        static_cast<int16_t>(panelW - margin * 2), buttonH};
  gbaLoadStateButton = {gbaSaveStateButton.x, static_cast<int16_t>(top + buttonH + 10),
                        gbaSaveStateButton.w, buttonH};
  gbaChangeGameButton = {gbaSaveStateButton.x,
                         static_cast<int16_t>(top + (buttonH + 10) * 2),
                         gbaSaveStateButton.w, buttonH};
  gbaOptionsButton = {gbaSaveStateButton.x,
                      static_cast<int16_t>(top + (buttonH + 10) * 3),
                      gbaSaveStateButton.w, buttonH};
  auto sideButton = [&](const Rect &r, const char *label) {
    M5.Display.drawRect(r.x, r.y, r.w, r.h, colors.amberDim);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(colors.amber, colors.black);
    M5.Display.drawString(label, r.x + r.w / 2, r.y + r.h / 2);
  };
  sideButton(gbaSaveStateButton, "SAVE STATE");
  sideButton(gbaLoadStateButton, "LOAD STATE");
  sideButton(gbaChangeGameButton, "CHANGE GAME");
  sideButton(gbaOptionsButton, "OPTIONS");
  if (!gbaShowStats) return;
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  int16_t sy = static_cast<int16_t>(gbaOptionsButton.y + gbaOptionsButton.h + 18);
  M5.Display.drawString((String("EMU ") + String(gbaFps * (gbaFrameSkip + 1), 1) + " FPS").c_str(),
                        x + margin, sy);
  sy += M5.Display.fontHeight() + 4;
  M5.Display.drawString((String("DRAW ") + String(gbaFps, 1) + " FPS").c_str(), x + margin, sy);
  sy += M5.Display.fontHeight() + 4;
  M5.Display.drawString((String("FRAME ") + String(gbaFrameTimeUs / 1000.0f, 1) + " ms").c_str(),
                        x + margin, sy);
  sy += M5.Display.fontHeight() + 4;
  M5.Display.drawString((String("PSRAM ") + String(ESP.getFreePsram() / 1048576.0f, 1) + " MB").c_str(),
                        x + margin, sy);
  sy += M5.Display.fontHeight() + 4;
    M5.Display.drawString((String("LATE ") + String(gbaMissedFrames) + "  AUD " +
                           String(gbaAudioDropped)).c_str(), x + margin, sy);
}

void updateGameBoy(uint32_t now) {
  if (gameBoyInputReleaseMs && now >= gameBoyInputReleaseMs) {
    gameBoyJoypad = 0xFF;
    gameBoyInputReleaseMs = 0;
  }
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppGamesIndex &&
      gamesView == GAMES_VIEW_RUNNING && gameBoyFrameReady &&
      (gameBoyLastFrameDrawMs == 0 || now - gameBoyLastFrameDrawMs >= 16)) {
    gameBoyLastFrameDrawMs = now;
    drawGameBoyFrame();
  }
  if (gameBoyRunning && now - gameBoyStatsLastMs >= 2000) {
    uint32_t elapsed = now - gameBoyStatsLastMs;
    uint32_t frames = gameBoyFrames - gameBoyStatsLastFrames;
    uint32_t draws = gameBoyDrawFrames - gameBoyStatsLastDrawFrames;
    gameBoyFps = elapsed ? (frames * 1000.0f / elapsed) : 0.0f;
    gameBoyDrawFps = elapsed ? (draws * 1000.0f / elapsed) : 0.0f;
    gameBoyStatsLastMs = now;
    gameBoyStatsLastFrames = gameBoyFrames;
    gameBoyStatsLastDrawFrames = gameBoyDrawFrames;
    debugPrint("GAMEBOY: draw=%.2f emu=%.2f frame=%luus max=%luus fast=%u psram=%u internal=%u",
               gameBoyDrawFps, gameBoyFps,
               static_cast<unsigned long>(gameBoyFrameTimeUs),
               static_cast<unsigned long>(gameBoyFrameTimeMaxUs),
               gameBoyFastDrawMode ? 1U : 0U,
               static_cast<unsigned>(ESP.getFreePsram()),
               static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)));
  }
  if (gamesView == GAMES_VIEW_RUNNING && !gameBoyRunning && gameBoyError) {
    gamesView = GAMES_VIEW_ERROR;
    waypointsDirty = true;
  }
  if (gbaInputReleaseMs && now >= gbaInputReleaseMs) {
    gbaButtons = 0;
    gbaInputReleaseMs = 0;
  }
  if (gbaRunning && now - gbaStatsLastMs >= 2000) {
    uint32_t elapsed = now - gbaStatsLastMs;
    uint32_t frames = gbaFrames - gbaStatsLastFrames;
    gbaFps = elapsed ? (frames * 1000.0f / elapsed) : 0.0f;
    gbaStatsLastMs = now;
    gbaStatsLastFrames = gbaFrames;
    debugPrint("GBA: draw=%.2f emu=%.2f frame=%luus max=%luus late=%lu fast=%u psram=%u internal=%u",
               gbaFps, gbaFps * (gbaFrameSkip + 1), static_cast<unsigned long>(gbaFrameTimeUs),
               static_cast<unsigned long>(gbaFrameTimeMaxUs),
               static_cast<unsigned long>(gbaMissedFrames), gbaFastDrawMode ? 1U : 0U,
               static_cast<unsigned>(ESP.getFreePsram()),
               static_cast<unsigned>(heap_caps_get_free_size(MALLOC_CAP_INTERNAL | MALLOC_CAP_8BIT)));
    if (gamesView == GAMES_VIEW_RUNNING) drawGbaSideOverlay();
  }
  if (gbaRunning && now - gbaLastBatterySaveMs >= 30000) saveGbaBattery();
  if (screen == SCREEN_WAYPOINTS && appSelected == kAppGamesIndex && gbaRunning &&
      gamesView == GAMES_VIEW_RUNNING && vba_embed_frame_ready() &&
      (gbaLastDrawMs == 0 || now - gbaLastDrawMs >= 16)) {
    gbaLastDrawMs = now;
    drawGbaFrame();
  }
}

