static bool resetCurrentEmulatorGame() {
  if (!gbaRunning && !gameBoyRunning) return false;
  if (gbaRunning) stopGbaEmulator(); else stopGameBoyEmulator();
  gameFirstRunBypass = true;
  return startSelectedGameBoyRom();
}

static const uint16_t kTetrisShapes[7][4] = {
    {0x0F00, 0x2222, 0x00F0, 0x4444},
    {0x8E00, 0x6440, 0x0E20, 0x44C0},
    {0x2E00, 0x4460, 0x0E80, 0xC440},
    {0x6600, 0x6600, 0x6600, 0x6600},
    {0x6C00, 0x4620, 0x06C0, 0x8C40},
    {0x4E00, 0x4640, 0x0E40, 0x4C40},
    {0xC600, 0x2640, 0x0C60, 0x4C80},
};

static bool tetrisShapeCell(uint8_t piece, uint8_t rotation, uint8_t x, uint8_t y) {
  return (kTetrisShapes[piece % 7][rotation % 4] & (0x8000U >> (y * 4U + x))) != 0;
}

static bool tetrisCollides(int8_t pieceX, int8_t pieceY, uint8_t rotation) {
  for (uint8_t y = 0; y < 4; ++y) {
    for (uint8_t x = 0; x < 4; ++x) {
      if (!tetrisShapeCell(tetrisPiece, rotation, x, y)) continue;
      int8_t boardX = static_cast<int8_t>(pieceX + x);
      int8_t boardY = static_cast<int8_t>(pieceY + y);
      if (boardX < 0 || boardX >= kTetrisCols || boardY >= kTetrisRows) return true;
      if (boardY >= 0 && tetrisBoard[boardY][boardX] != 0) return true;
    }
  }
  return false;
}

static void tetrisSpawnPiece() {
  tetrisPiece = tetrisNextPiece;
  tetrisNextPiece = static_cast<uint8_t>(random(0, 7));
  tetrisRotation = 0;
  tetrisPieceX = 3;
  tetrisPieceY = -1;
  if (tetrisCollides(tetrisPieceX, tetrisPieceY, tetrisRotation)) tetrisGameOver = true;
}

void startTetrisGame() {
  memset(tetrisBoard, 0, sizeof(tetrisBoard));
  tetrisNextPiece = static_cast<uint8_t>(random(0, 7));
  tetrisScore = 0;
  tetrisLines = 0;
  tetrisLevel = tetrisStartLevel;
  tetrisPaused = false;
  tetrisGameOver = false;
  tetrisInitialized = true;
  tetrisUiView = TetrisUiView::PLAYING;
  tetrisLastDropMs = millis();
  tetrisSpawnPiece();
  tetrisPlayfieldDirty = true;
  waypointsDirty = true;
  waypointsNeedsFullRedraw = true;
  gameStatus = "TETRIS READY";
  gamesView = GAMES_VIEW_ROMS;
  debugPrint("TETRIS: new game");
}

static void tetrisPlaySound(float frequency, uint32_t durationMs) {
  if (tetrisSoundEnabled) M5.Speaker.tone(frequency, durationMs, 3, true);
}

static void tetrisLockPiece() {
  for (uint8_t y = 0; y < 4; ++y) {
    for (uint8_t x = 0; x < 4; ++x) {
      if (!tetrisShapeCell(tetrisPiece, tetrisRotation, x, y)) continue;
      int8_t boardX = static_cast<int8_t>(tetrisPieceX + x);
      int8_t boardY = static_cast<int8_t>(tetrisPieceY + y);
      if (boardX >= 0 && boardX < kTetrisCols && boardY >= 0 && boardY < kTetrisRows) {
        tetrisBoard[boardY][boardX] = static_cast<uint8_t>(tetrisPiece + 1);
      }
    }
  }
  uint8_t cleared = 0;
  for (int y = kTetrisRows - 1; y >= 0; --y) {
    bool full = true;
    for (uint8_t x = 0; x < kTetrisCols; ++x) {
      if (tetrisBoard[y][x] == 0) {
        full = false;
        break;
      }
    }
    if (!full) continue;
    for (int moveY = y; moveY > 0; --moveY) {
      memcpy(tetrisBoard[moveY], tetrisBoard[moveY - 1], kTetrisCols);
    }
    memset(tetrisBoard[0], 0, kTetrisCols);
    ++cleared;
    ++y;
  }
  if (cleared != 0) {
    static const uint16_t kLineScores[] = {0, 100, 300, 500, 800};
    tetrisScore += static_cast<uint32_t>(kLineScores[min<uint8_t>(cleared, 4)]) * tetrisLevel;
    tetrisLines = static_cast<uint16_t>(tetrisLines + cleared);
    tetrisLevel = static_cast<uint8_t>(min<uint16_t>(20, tetrisStartLevel + tetrisLines / 10));
    debugPrint("TETRIS: cleared=%u score=%lu lines=%u level=%u",
               static_cast<unsigned>(cleared), static_cast<unsigned long>(tetrisScore),
               static_cast<unsigned>(tetrisLines), static_cast<unsigned>(tetrisLevel));
    tetrisPlaySound(cleared == 4 ? 1180.0f : 880.0f, 70);
  } else {
    tetrisPlaySound(240.0f, 18);
  }
  tetrisSpawnPiece();
}

static void tetrisStepDown(bool scoreSoftDrop) {
  if (!tetrisInitialized || tetrisPaused || tetrisGameOver) return;
  if (!tetrisCollides(tetrisPieceX, static_cast<int8_t>(tetrisPieceY + 1), tetrisRotation)) {
    ++tetrisPieceY;
    if (scoreSoftDrop) ++tetrisScore;
  } else {
    tetrisLockPiece();
  }
  tetrisPlayfieldDirty = true;
}

static void tetrisMoveHorizontal(int8_t amount) {
  if (!tetrisInitialized || tetrisPaused || tetrisGameOver) return;
  int8_t nextX = static_cast<int8_t>(tetrisPieceX + amount);
  if (!tetrisCollides(nextX, tetrisPieceY, tetrisRotation)) {
    tetrisPieceX = nextX;
    tetrisPlayfieldDirty = true;
  }
}

static void tetrisRotatePiece() {
  if (!tetrisInitialized || tetrisPaused || tetrisGameOver) return;
  uint8_t nextRotation = static_cast<uint8_t>((tetrisRotation + 1) & 3U);
  static const int8_t kKickOffsets[] = {0, -1, 1, -2, 2};
  for (int8_t offset : kKickOffsets) {
    int8_t nextX = static_cast<int8_t>(tetrisPieceX + offset);
    if (!tetrisCollides(nextX, tetrisPieceY, nextRotation)) {
      tetrisPieceX = nextX;
      tetrisRotation = nextRotation;
      tetrisPlayfieldDirty = true;
      tetrisPlaySound(620.0f, 18);
      return;
    }
  }
}

static void tetrisHardDrop() {
  if (!tetrisInitialized || tetrisPaused || tetrisGameOver) return;
  uint16_t distance = 0;
  while (!tetrisCollides(tetrisPieceX, static_cast<int8_t>(tetrisPieceY + 1),
                         tetrisRotation)) {
    ++tetrisPieceY;
    ++distance;
  }
  tetrisScore += static_cast<uint32_t>(distance) * 2U;
  tetrisLockPiece();
  tetrisPlaySound(360.0f, 24);
  tetrisLastDropMs = millis();
  tetrisPlayfieldDirty = true;
}

void updateTetrisGame(uint32_t now) {
  if (!isWaypointAppVisible(kAppGamesIndex) || tetrisUiView != TetrisUiView::PLAYING ||
      !tetrisInitialized || tetrisPaused || tetrisGameOver) {
    return;
  }
  uint32_t baseInterval = max<uint32_t>(90, 720 - static_cast<uint32_t>(tetrisLevel - 1) * 48);
  uint32_t dropInterval = tetrisSpeedSetting == 0 ? baseInterval * 5U / 4U
                          : tetrisSpeedSetting == 2 ? max<uint32_t>(70, baseInterval * 3U / 4U)
                                                    : baseInterval;
  if (now - tetrisLastDropMs >= dropInterval) {
    tetrisLastDropMs = now;
    tetrisStepDown(false);
  }
}

static void tetrisLayout(int16_t &boardX, int16_t &boardY, int16_t &cell,
                         int16_t &sideX, int16_t &contentBottom) {
  int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 8);
  contentBottom = static_cast<int16_t>(screenH - navH);
  int16_t availableH = static_cast<int16_t>(contentBottom - contentTop - 24);
  cell = min<int16_t>(28, max<int16_t>(12, availableH / kTetrisRows));
  int16_t boardW = static_cast<int16_t>(cell * kTetrisCols);
  int16_t boardH = static_cast<int16_t>(cell * kTetrisRows);
  int16_t totalW = static_cast<int16_t>(boardW + 34 + min<int16_t>(420, screenW / 3));
  boardX = max<int16_t>(20, static_cast<int16_t>((screenW - totalW) / 2));
  boardY = static_cast<int16_t>(contentTop + max<int16_t>(8, (availableH - boardH) / 2));
  sideX = static_cast<int16_t>(boardX + boardW + 34);
}

static void tetrisDrawBlock(int16_t x, int16_t y, int16_t cell, uint16_t fill,
                            uint16_t edge) {
  M5.Display.fillRect(x + 1, y + 1, cell - 2, cell - 2, fill);
  M5.Display.drawFastHLine(x + 2, y + 2, cell - 4, edge);
  M5.Display.drawFastVLine(x + 2, y + 2, cell - 4, edge);
  M5.Display.drawFastHLine(x + 2, y + cell - 3, cell - 4, colors.amberDim);
  M5.Display.drawFastVLine(x + cell - 3, y + 2, cell - 4, colors.amberDim);
}

void drawTetrisDynamic() {
  if (!tetrisInitialized) startTetrisGame();
  int16_t boardX, boardY, cell, sideX, contentBottom;
  tetrisLayout(boardX, boardY, cell, sideX, contentBottom);
  int16_t boardW = static_cast<int16_t>(cell * kTetrisCols);
  int16_t boardH = static_cast<int16_t>(cell * kTetrisRows);
  M5.Display.fillRect(boardX, boardY, boardW, boardH, colors.black);
  if (tetrisGridEnabled) {
    for (uint8_t x = 1; x < kTetrisCols; ++x) {
      M5.Display.drawFastVLine(static_cast<int16_t>(boardX + x * cell), boardY, boardH,
                               colors.amberDim);
    }
    for (uint8_t y = 1; y < kTetrisRows; ++y) {
      M5.Display.drawFastHLine(boardX, static_cast<int16_t>(boardY + y * cell), boardW,
                               colors.amberDim);
    }
  }
  for (uint8_t y = 0; y < kTetrisRows; ++y) {
    for (uint8_t x = 0; x < kTetrisCols; ++x) {
      if (tetrisBoard[y][x] != 0) {
        tetrisDrawBlock(static_cast<int16_t>(boardX + x * cell),
                        static_cast<int16_t>(boardY + y * cell), cell, colors.amberDim,
                        colors.amber);
      }
    }
  }
  int8_t ghostY = tetrisPieceY;
  if (tetrisGhostEnabled) {
    while (!tetrisCollides(tetrisPieceX, static_cast<int8_t>(ghostY + 1), tetrisRotation)) {
      ++ghostY;
    }
  }
  for (uint8_t y = 0; y < 4; ++y) {
    for (uint8_t x = 0; x < 4; ++x) {
      if (!tetrisShapeCell(tetrisPiece, tetrisRotation, x, y)) continue;
      int8_t ghostX = static_cast<int8_t>(tetrisPieceX + x);
      int8_t drawGhostY = static_cast<int8_t>(ghostY + y);
      if (tetrisGhostEnabled && ghostX >= 0 && ghostX < kTetrisCols && drawGhostY >= 0 &&
          drawGhostY < kTetrisRows) {
        int16_t gx = static_cast<int16_t>(boardX + ghostX * cell);
        int16_t gy = static_cast<int16_t>(boardY + drawGhostY * cell);
        M5.Display.drawRect(gx + 3, gy + 3, cell - 6, cell - 6, colors.amberDim);
      }
      int8_t activeX = static_cast<int8_t>(tetrisPieceX + x);
      int8_t activeY = static_cast<int8_t>(tetrisPieceY + y);
      if (activeX >= 0 && activeX < kTetrisCols && activeY >= 0 && activeY < kTetrisRows) {
        tetrisDrawBlock(static_cast<int16_t>(boardX + activeX * cell),
                        static_cast<int16_t>(boardY + activeY * cell), cell, colors.amber,
                        colors.amber);
      }
    }
  }

  int16_t valueW = min<int16_t>(400, static_cast<int16_t>(screenW - sideX - 24));
  M5.Display.fillRect(sideX, boardY + 42, valueW, 180, colors.black);
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.drawString("SCORE  " + String(tetrisScore), sideX, boardY + 48);
  M5.Display.drawString("LINES  " + String(tetrisLines), sideX, boardY + 86);
  M5.Display.drawString("LEVEL  " + String(tetrisLevel), sideX, boardY + 124);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.drawString("NEXT", sideX, boardY + 170);
  int16_t previewCell = max<int16_t>(10, min<int16_t>(18, cell - 5));
  M5.Display.fillRect(sideX, boardY + 202, previewCell * 4, previewCell * 4, colors.black);
  for (uint8_t y = 0; y < 4; ++y) {
    for (uint8_t x = 0; x < 4; ++x) {
      if (tetrisShapeCell(tetrisNextPiece, 0, x, y)) {
        tetrisDrawBlock(static_cast<int16_t>(sideX + x * previewCell),
                        static_cast<int16_t>(boardY + 202 + y * previewCell), previewCell,
                        colors.amberDim, colors.amber);
      }
    }
  }
  if (tetrisPaused || tetrisGameOver) {
    Rect modal = {static_cast<int16_t>(boardX + 18), static_cast<int16_t>(boardY + boardH / 2 - 48),
                  static_cast<int16_t>(boardW - 36), 96};
    M5.Display.fillRect(modal.x, modal.y, modal.w, modal.h, colors.black);
    uint16_t modalColor = tetrisGameOver ? colors.red : colors.amber;
    M5.Display.drawRect(modal.x, modal.y, modal.w, modal.h, modalColor);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextSize(kButtonTextSize);
    M5.Display.setTextColor(modalColor, colors.black);
    M5.Display.drawString(tetrisGameOver ? "GAME OVER" : "PAUSED",
                          modal.x + modal.w / 2, modal.y + modal.h / 2 - 10);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.drawString(tetrisGameOver ? "ENTER: NEW GAME" : "P: RESUME",
                          modal.x + modal.w / 2, modal.y + modal.h / 2 + 24);
  }
  M5.Display.setTextDatum(TL_DATUM);
  tetrisPlayfieldDirty = false;
}

static const char *tetrisControlActionName(uint8_t action) {
  static const char *kNames[] = {"MOVE LEFT", "MOVE RIGHT", "ROTATE", "SOFT DROP",
                                 "HARD DROP", "PAUSE", "NEW GAME"};
  return action < static_cast<uint8_t>(TetrisControlAction::COUNT) ? kNames[action] : "UNKNOWN";
}

static String tetrisKeyName(uint8_t keycode) {
  if (keycode == 0x50) return "LEFT ARROW";
  if (keycode == 0x4F) return "RIGHT ARROW";
  if (keycode == 0x52) return "UP ARROW";
  if (keycode == 0x51) return "DOWN ARROW";
  if (keycode == 0x28) return "ENTER";
  if (keycode == 0x29) return "ESC";
  if (keycode >= 0x04 && keycode <= 0x1D) {
    char text[2] = {static_cast<char>('A' + keycode - 0x04), 0};
    return String(text);
  }
  if (keycode >= 0x1E && keycode <= 0x26) return String(static_cast<int>(keycode - 0x1D));
  if (keycode == 0x27) return "0";
  char text[12] = {};
  snprintf(text, sizeof(text), "HID 0x%02X", keycode);
  return String(text);
}

