static void drawTetrisSettings(int16_t contentTop, int16_t contentBottom) {
  static const char *kLabels[] = {"START LEVEL", "GAME SPEED", "GHOST PIECE", "PLAYFIELD GRID",
                                  "SOUND EFFECTS", "CONTROLS", "BACK"};
  int16_t listX = max<int16_t>(34, static_cast<int16_t>((screenW - 850) / 2));
  int16_t listW = min<int16_t>(850, static_cast<int16_t>(screenW - 68));
  int16_t rowGap = 8;
  int16_t rowH = min<int16_t>(66, static_cast<int16_t>((contentBottom - contentTop - 42 - 6 * rowGap) / 7));
  int16_t y = static_cast<int16_t>(contentTop + 20);
  for (uint8_t i = 0; i < 7; ++i) {
    tetrisMenuRows[i] = {listX, y, listW, rowH};
    const Rect &row = tetrisMenuRows[i];
    bool selected = tetrisSettingsSelection == i;
    if (selected) M5.Display.fillRoundRect(row.x, row.y, row.w, row.h, 8, colors.black);
    M5.Display.drawRoundRect(row.x, row.y, row.w, row.h, 8,
                             selected ? colors.amber : colors.amberDim);
    M5.Display.setTextDatum(ML_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(selected ? colors.amber : colors.amberDim, colors.black);
    M5.Display.drawString(kLabels[i], row.x + 18, row.y + row.h / 2);
    String value;
    if (i == 0) value = String(tetrisStartLevel);
    else if (i == 1) value = tetrisSpeedSetting == 0 ? "RELAXED" : (tetrisSpeedSetting == 2 ? "FAST" : "NORMAL");
    else if (i == 2) value = tetrisGhostEnabled ? "ON" : "OFF";
    else if (i == 3) value = tetrisGridEnabled ? "ON" : "OFF";
    else if (i == 4) value = tetrisSoundEnabled ? "ON" : "OFF";
    else value = i == 5 ? "EDIT >" : "RETURN";
    M5.Display.setTextDatum(MR_DATUM);
    M5.Display.setTextColor(selected ? colors.amber : colors.amberDim, colors.black);
    M5.Display.drawString(value, row.x + row.w - 18, row.y + row.h / 2);
    y = static_cast<int16_t>(y + rowH + rowGap);
  }
}

