static void drawTetrisApp() {
  const char *title = tetrisUiView == TetrisUiView::LIBRARY ? "GAMES"
                      : tetrisUiView == TetrisUiView::SETTINGS ? "GAME SETTINGS"
                      : (tetrisUiView == TetrisUiView::CONTROLS || tetrisUiView == TetrisUiView::REMAP)
                            ? "TETRIS CONTROLS"
                            : "TETRIS";
  drawAppTopBar(title);
  int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 8);
  int16_t contentBottom = static_cast<int16_t>(screenH - navH);
  M5.Display.fillRect(0, contentTop, screenW,
                      static_cast<int16_t>(contentBottom - contentTop), colors.black);
  if (tetrisUiView == TetrisUiView::LIBRARY) {
    drawTetrisLibrary(contentTop, contentBottom);
    drawNavBar();
    waypointsDirty = false;
    waypointsNeedsFullRedraw = false;
    return;
  }
  if (tetrisUiView == TetrisUiView::SETTINGS) {
    drawTetrisSettings(contentTop, contentBottom);
    drawNavBar();
    waypointsDirty = false;
    waypointsNeedsFullRedraw = false;
    return;
  }
  if (tetrisUiView == TetrisUiView::CONTROLS || tetrisUiView == TetrisUiView::REMAP) {
    drawTetrisControls(contentTop, contentBottom);
    drawNavBar();
    waypointsDirty = false;
    waypointsNeedsFullRedraw = false;
    return;
  }
  if (!tetrisInitialized) startTetrisGame();
  int16_t boardX, boardY, cell, sideX;
  tetrisLayout(boardX, boardY, cell, sideX, contentBottom);
  int16_t boardW = static_cast<int16_t>(cell * kTetrisCols);
  int16_t boardH = static_cast<int16_t>(cell * kTetrisRows);
  M5.Display.drawRect(boardX - 3, boardY - 3, boardW + 6, boardH + 6, colors.amber);
  M5.Display.drawRect(boardX - 6, boardY - 6, boardW + 12, boardH + 12, colors.amberDim);
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.drawString("WASTELAND BLOCK CONTROL", sideX, boardY);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.drawString("ARROWS: MOVE / ROTATE", sideX, boardY + 288);
  M5.Display.drawString("ENTER: HARD DROP", sideX, boardY + 322);
  M5.Display.drawString("P: PAUSE   ESC: SETTINGS", sideX, boardY + 356);

  int16_t buttonW = max<int16_t>(72, min<int16_t>(118, (screenW - sideX - 58) / 3));
  int16_t buttonH = 54;
  int16_t gap = 10;
  int16_t buttonY = min<int16_t>(static_cast<int16_t>(boardY + 410),
                                 static_cast<int16_t>(contentBottom - buttonH * 2 - gap - 12));
  const char *labels[6] = {"LEFT", "ROTATE", "RIGHT", "DOWN", "DROP", "SETTINGS"};
  for (uint8_t i = 0; i < 6; ++i) {
    int col = i % 3;
    int row = i / 3;
    tetrisTouchButtons[i] = {static_cast<int16_t>(sideX + col * (buttonW + gap)),
                             static_cast<int16_t>(buttonY + row * (buttonH + gap)),
                             buttonW, buttonH};
    const Rect &button = tetrisTouchButtons[i];
    M5.Display.drawRect(button.x, button.y, button.w, button.h,
                        i == 5 ? colors.amberDim : colors.amber);
    M5.Display.setTextDatum(MC_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(i == 5 ? colors.amberDim : colors.amber, colors.black);
    M5.Display.drawString(labels[i], button.x + button.w / 2, button.y + button.h / 2);
  }
  drawTetrisDynamic();
  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
  waypointsDirty = false;
  waypointsNeedsFullRedraw = false;
}

void handleTetrisKeyboard(uint8_t keycode) {
  if (keycode == 0) return;
  if (tetrisUiView == TetrisUiView::REMAP) {
    if (keycode == 0x29) {
      tetrisUiView = TetrisUiView::CONTROLS;
    } else {
      uint8_t displacedKey = tetrisControlKeys[tetrisRemapAction];
      for (uint8_t i = 0; i < static_cast<uint8_t>(TetrisControlAction::COUNT); ++i) {
        if (i != tetrisRemapAction && tetrisControlKeys[i] == keycode) {
          tetrisControlKeys[i] = displacedKey;
          break;
        }
      }
      tetrisControlKeys[tetrisRemapAction] = keycode;
      tetrisUiView = TetrisUiView::CONTROLS;
      storeUiSettings();
      debugPrint("TETRIS: control action=%u key=0x%02X", tetrisRemapAction, keycode);
    }
    waypointsDirty = true;
    return;
  }
  if (tetrisUiView == TetrisUiView::LIBRARY) {
    if (keycode == 0x29) {
      leaveCurrentAppToMenu();
    } else if (keycode == 0x28) {
      startTetrisGame();
    }
    return;
  }
  if (tetrisUiView == TetrisUiView::SETTINGS) {
    if (keycode == 0x29) {
      tetrisPaused = false;
      tetrisUiView = TetrisUiView::PLAYING;
      tetrisLastDropMs = millis();
    } else if (keycode == 0x52) {
      tetrisSettingsSelection = static_cast<uint8_t>((tetrisSettingsSelection + 6) % 7);
    } else if (keycode == 0x51) {
      tetrisSettingsSelection = static_cast<uint8_t>((tetrisSettingsSelection + 1) % 7);
    } else if (keycode == 0x50 || keycode == 0x4F || keycode == 0x28) {
      int8_t direction = keycode == 0x50 ? -1 : 1;
      if (tetrisSettingsSelection == 0) {
        int next = constrain(static_cast<int>(tetrisStartLevel) + direction, 1, 10);
        tetrisStartLevel = static_cast<uint8_t>(next);
      } else if (tetrisSettingsSelection == 1) {
        int next = (static_cast<int>(tetrisSpeedSetting) + direction + 3) % 3;
        tetrisSpeedSetting = static_cast<uint8_t>(next);
      } else if (tetrisSettingsSelection == 2) tetrisGhostEnabled = !tetrisGhostEnabled;
      else if (tetrisSettingsSelection == 3) tetrisGridEnabled = !tetrisGridEnabled;
      else if (tetrisSettingsSelection == 4) tetrisSoundEnabled = !tetrisSoundEnabled;
      else if (tetrisSettingsSelection == 5 && keycode == 0x28) {
        tetrisUiView = TetrisUiView::CONTROLS;
      } else if (tetrisSettingsSelection == 6 && keycode == 0x28) {
        tetrisPaused = false;
        tetrisUiView = TetrisUiView::PLAYING;
        tetrisLastDropMs = millis();
      }
      storeUiSettings();
    }
    waypointsDirty = true;
    return;
  }
  if (tetrisUiView == TetrisUiView::CONTROLS) {
    if (keycode == 0x29) {
      tetrisUiView = TetrisUiView::SETTINGS;
    } else if (keycode == 0x52) {
      tetrisControlsSelection = static_cast<uint8_t>(
          (tetrisControlsSelection + static_cast<uint8_t>(TetrisControlAction::COUNT) - 1) %
          static_cast<uint8_t>(TetrisControlAction::COUNT));
    } else if (keycode == 0x51) {
      tetrisControlsSelection = static_cast<uint8_t>(
          (tetrisControlsSelection + 1) % static_cast<uint8_t>(TetrisControlAction::COUNT));
    } else if (keycode == 0x28) {
      tetrisRemapAction = tetrisControlsSelection;
      tetrisUiView = TetrisUiView::REMAP;
    }
    waypointsDirty = true;
    return;
  }
  if (tetrisUiView != TetrisUiView::PLAYING) return;
  if (keycode == 0x29) {
    tetrisPaused = true;
    tetrisUiView = TetrisUiView::SETTINGS;
    waypointsDirty = true;
    return;
  }
  if (tetrisGameOver && keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::HARD_DROP)]) {
    startTetrisGame();
    return;
  }
  if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::LEFT)]) {
    tetrisMoveHorizontal(-1);
  } else if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::RIGHT)]) {
    tetrisMoveHorizontal(1);
  } else if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::SOFT_DROP)]) {
    tetrisStepDown(true);
  } else if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::ROTATE)]) {
    tetrisRotatePiece();
  } else if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::HARD_DROP)]) {
    tetrisHardDrop();
  } else if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::PAUSE)]) {
    tetrisPaused = !tetrisPaused;
    tetrisLastDropMs = millis();
    tetrisPlayfieldDirty = true;
  } else if (keycode == tetrisControlKeys[static_cast<uint8_t>(TetrisControlAction::NEW_GAME)]) {
    startTetrisGame();
  }
}

void handleTetrisTouch(int16_t x, int16_t y) {
  if (tetrisUiView == TetrisUiView::LIBRARY) {
    for (uint8_t i = 0; i < 1; ++i) {
      if (!inRect(tetrisLibraryCards[i], x, y)) continue;
      tetrisLibrarySelection = i;
      startTetrisGame();
      return;
    }
    return;
  }
  if (tetrisUiView == TetrisUiView::SETTINGS) {
    for (uint8_t i = 0; i < 7; ++i) {
      if (!inRect(tetrisMenuRows[i], x, y)) continue;
      tetrisSettingsSelection = i;
      handleTetrisKeyboard(0x28);
      return;
    }
    return;
  }
  if (tetrisUiView == TetrisUiView::CONTROLS) {
    for (uint8_t i = 0; i < static_cast<uint8_t>(TetrisControlAction::COUNT); ++i) {
      if (!inRect(tetrisMenuRows[i], x, y)) continue;
      tetrisControlsSelection = i;
      tetrisRemapAction = i;
      tetrisUiView = TetrisUiView::REMAP;
      waypointsDirty = true;
      return;
    }
    return;
  }
  if (tetrisUiView != TetrisUiView::PLAYING) return;
  for (uint8_t i = 0; i < 6; ++i) {
    if (!inRect(tetrisTouchButtons[i], x, y)) continue;
    if (i == 0) tetrisMoveHorizontal(-1);
    else if (i == 1) tetrisRotatePiece();
    else if (i == 2) tetrisMoveHorizontal(1);
    else if (i == 3) tetrisStepDown(true);
    else if (i == 4) tetrisHardDrop();
    else {
      tetrisPaused = true;
      tetrisUiView = TetrisUiView::SETTINGS;
      waypointsDirty = true;
    }
    return;
  }
}

