void handleGamesTouch(int16_t x, int16_t y) {
  handleTetrisTouch(x, y);
  return;
  if (gamesView == GAMES_VIEW_RUNNING) {
    if (activeGameSystem == GAME_SYSTEM_GBA) {
      if (inRect(gbaSaveStateButton, x, y)) {
        saveGbaState();
      } else if (inRect(gbaLoadStateButton, x, y)) {
        loadGbaState();
      } else if (inRect(gbaChangeGameButton, x, y)) {
        stopGbaEmulator();
        refreshGameRomList();
      } else if (inRect(gbaOptionsButton, x, y)) {
        gbaPaused = true;
        gamesView = GAMES_VIEW_OPTIONS;
      }
      waypointsDirty = true;
      return;
    }
    if (inRect(appPrimaryButton, x, y)) {
      gamesView = GAMES_VIEW_OPTIONS;
    } else if (inRect(appTertiaryButton, x, y)) {
      stopGameBoyEmulator();
      refreshGameRomList();
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_OPTIONS) {
    for (int i = 0; i < gameMenuButtonCount; ++i) {
      if (!inRect(gameMenuButtons[i], x, y)) continue;
      if (i == 0) {
        gbaPaused = false;
        gameBoyPaused = false;
        gamesView = GAMES_VIEW_RUNNING;
      }
      else if (i == 1 && activeGameSystem == GAME_SYSTEM_GBA) saveGbaState();
      else if (i == 2 && activeGameSystem == GAME_SYSTEM_GBA) loadGbaState();
      else if (i == 3) resetCurrentEmulatorGame();
      else if (i == 4) {
        emulatorControlSystem = activeGameSystem == GAME_SYSTEM_GBA
                                    ? CONTROL_SYSTEM_GBA : CONTROL_SYSTEM_GB;
        gameControlsReturnView = GAMES_VIEW_OPTIONS;
        gamesView = GAMES_VIEW_CONTROLS;
      } else if (i == 5) {
        stopGameBoyEmulator();
        stopGbaEmulator();
        refreshGameRomList();
      }
      break;
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_FIRST_RUN) {
    if (inRect(gameMenuButtons[0], x, y)) {
      emulatorControlAccepted[pendingLaunchControlSystem] = true;
      saveEmulatorControlProfile(pendingLaunchControlSystem);
      gameFirstRunBypass = true;
      startSelectedGameBoyRom();
    } else if (inRect(gameMenuButtons[1], x, y)) {
      emulatorControlSystem = pendingLaunchControlSystem;
      gameControlsReturnView = GAMES_VIEW_FIRST_RUN;
      gamesView = GAMES_VIEW_CONTROLS;
    } else if (inRect(gameMenuButtons[2], x, y)) {
      gamesView = GAMES_VIEW_ROMS;
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_CONTROLS) {
    for (int i = 0; i < gameMenuButtonCount; ++i) {
      if (!inRect(gameMenuButtons[i], x, y)) continue;
      if (i == 0) gamesView = GAMES_VIEW_PROFILES;
      else if (i == 1) gamesView = GAMES_VIEW_EDIT_CONTROLS;
      else if (i == 2) {
        resetEmulatorControlProfile(emulatorControlSystem);
        saveEmulatorControlProfile(emulatorControlSystem);
        setAppToast("CONTROL PROFILE RESET");
      } else if (i == 3) {
        emulatorTestButtons = 0;
        emulatorTestModifier = 0;
        emulatorTestKeycode = 0;
        gamesView = GAMES_VIEW_TEST_CONTROLS;
      } else if (i == 4) gamesView = gameControlsReturnView;
      break;
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_PROFILES) {
    for (int i = 0; i < gameMenuButtonCount; ++i) {
      if (!inRect(gameMenuButtons[i], x, y)) continue;
      if (i < CONTROL_SYSTEM_COUNT)
        emulatorControlSystem = static_cast<EmulatorControlSystem>(i);
      else
        gamesView = GAMES_VIEW_CONTROLS;
      break;
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_EDIT_CONTROLS) {
    for (int i = 0; i < gameMenuButtonCount; ++i) {
      if (!inRect(gameMenuButtons[i], x, y)) continue;
      if (i < CONTROL_ACTION_COUNT) {
        emulatorControlSelectedAction = i;
        gamesView = GAMES_VIEW_REMAP_PROMPT;
      } else {
        gamesView = GAMES_VIEW_CONTROLS;
      }
      break;
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_REMAP_PROMPT) {
    if (inRect(gameMenuButtons[0], x, y)) gamesView = GAMES_VIEW_EDIT_CONTROLS;
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_DUPLICATE_CONFIRM) {
    if (inRect(gameMenuButtons[0], x, y)) applyPendingEmulatorBinding(true);
    else if (inRect(gameMenuButtons[1], x, y)) gamesView = GAMES_VIEW_EDIT_CONTROLS;
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_TEST_CONTROLS) {
    if (inRect(gameMenuButtons[0], x, y)) {
      emulatorTestButtons = 0;
      gamesView = GAMES_VIEW_CONTROLS;
    }
    waypointsDirty = true;
    return;
  }
  if (gamesView == GAMES_VIEW_TRANSFER) {
    if (inRect(usbGameImportButton, x, y)) {
      gameStatus = "USB IMPORT DISABLED - USE WEB FILE TRANSFER";
    } else if (inRect(usbGameRescanButton, x, y)) {
      gameStatus = "WEB FILE TRANSFER IS IN UTILITIES > FILES";
    } else if (inRect(usbGameBackButton, x, y)) {
      stopUsbGameStorage();
      gbaPaused = false;
      gamesView = gbaRunning ? GAMES_VIEW_OPTIONS : GAMES_VIEW_ROMS;
    } else if (inRect(usbGameListRect, x, y) && usbGameFileCount > 0) {
      M5.Display.setTextSize(kSmallTextSize);
      int16_t rowH = static_cast<int16_t>(M5.Display.fontHeight() + 10);
      int index = usbGameScroll + (y - usbGameListRect.y - 2) / max<int16_t>(1, rowH);
      if (index >= 0 && index < static_cast<int>(usbGameFileCount)) usbGameSelected = index;
    }
    waypointsDirty = true;
    return;
  }
  if (inRect(appPrimaryButton, x, y)) {
    startSelectedGameBoyRom();
  } else if (inRect(appSecondaryButton, x, y)) {
    gameStatus = "USE UTILITIES > FILES FOR SD CARD ACCESS";
    waypointsDirty = true;
  } else if (inRect(appTertiaryButton, x, y)) {
    refreshGameRomList();
  } else if (inRect(gameRomListRect, x, y)) {
    M5.Display.setTextSize(kSmallTextSize);
    int16_t rowH = static_cast<int16_t>(M5.Display.fontHeight() + 10);
    int index = gameRomScroll + (y - gameRomListRect.y - 2) / max<int16_t>(1, rowH);
    if (index >= 0 && index < static_cast<int>(gameRomCount)) gameRomSelected = index;
  }
  waypointsDirty = true;
}


void openApp(uint8_t index) {
  if (index < kAppCount && !isAppVisibleInMenu(index)) {
    debugPrint("APP: blocked hidden optional app index=%u package=%s",
               static_cast<unsigned>(index),
               optionalAppPackageId(index) ? optionalAppPackageId(index) : "none");
    appSelected = kAppMenuIndex;
    screen = SCREEN_WAYPOINTS;
    waypointsDirty = true;
    waypointsNeedsFullRedraw = true;
    return;
  }
  if (bleExclusiveBootMode && index != kAppBleKeyboardIndex) {
    requestWifiBoot();
    return;
  }
  if (usbExclusiveBootMode && !isUsbExclusiveTargetApp(index)) {
    if (index == kAppMenuIndex) {
      if (screen == SCREEN_WAYPOINTS && isUsbExclusiveTargetApp(appSelected)) {
        responderAppRegistry.stopByLegacyIndex(appSelected);
        requestUsbAccessoryRelease("usb exclusive menu");
        stopRtlSdrHost();
      }
      appSelected = kAppMenuIndex;
      screen = SCREEN_WAYPOINTS;
      usbExclusiveWifiRestorePending = usbExclusiveRestoreWifiOnExit;
      usbExclusiveExitRestoreModal = usbExclusiveWifiRestorePending;
      if (usbExclusiveWifiRestorePending) {
        enterWifiRestoreModal("USB app closed");
      } else {
        waypointsDirty = true;
        waypointsNeedsFullRedraw = true;
      }
      debugPrint(usbExclusiveWifiRestorePending
                     ? "USBHOST: exited USB-exclusive app; Wi-Fi restore modal active"
                     : "USBHOST: exited USB-exclusive app to menu; Wi-Fi was off on entry");
      return;
    }
    requestWifiBoot();
    return;
  }
  if (!usbExclusiveBootMode && isUsbExclusiveTargetApp(index)) {
#if ENABLE_WIFI
    if (wifiEnabled || wifiStackReady || wifiBootEnablePending) {
      requestExclusiveUsbBoot(index);
      return;
    }
#endif
  }
  screen = SCREEN_WAYPOINTS;
  appSelected = index;
  if (index < kAppCount) {
    appMenuKeyboardSelection = index;
    int visiblePos = appMenuVisiblePositionForIndex(index);
    if (visiblePos >= 0) {
      appMenuPage = static_cast<uint8_t>(visiblePos / kAppsPerPage);
    }
  }
  if (appLaunchCanBlock(index)) {
    const char *detail = "PREPARING APP RESOURCES";
    if (index == kAppRfScanIndex || index == kAppDroneIndex || index == kAppGhostIndex ||
        index == kAppAirplanesIndex || index == kAppCarIndex) {
      detail = "PREPARING USB HOST";
    } else if (index == kAppIpCamsIndex || index == kAppWifiMotionIndex ||
               index == kAppRfWatchIndex) {
      detail = "PREPARING RADIO SERVICES";
    } else if (index == kAppBleKeyboardIndex) {
      detail = "PREPARING BLUETOOTH";
    } else if (index == kAppGamesIndex) {
      detail = "STARTING TETRIS";
    } else if (index == kAppAudioIndex || index == kAppNotesIndex ||
               index == kAppGalleryIndex) {
      detail = "SCANNING STORAGE";
    }
    drawAppLaunchLoadingScreen(index, detail);
    debugPrint("APP: loading screen index=%u title=%s", static_cast<unsigned>(index),
               appLaunchTitle(index));
  }
  responderAppRegistry.launchByLegacyIndex(index, responderAppContext);
  if (index == kAppRfScanIndex || index == kAppDroneIndex) {
    rfAutoStartSuppressed = false;
    rtlSdrAutoRecoveries = 0;
    rtlSdrLastAutoRecoverMs = 0;
    usbAccessoryDetachCooldownUntilMs = 0;
    if (!rtlSdrDeviceHandle && !rtlSdrStreaming) {
      rtlSdrSetStatus(index == kAppDroneIndex ? "DRONE SENSOR WAITING FOR RTL-SDR"
                                              : "WAITING FOR RTL-SDR USB");
    }
  }
  waypointsDirty = true;
  waypointsNeedsFullRedraw = true;
  if (index == kAppSystemHealthIndex) {
    systemHealthNeedsFullRedraw = true;
  }
  if (index == kAppCameraIndex) {
    prepareForCameraApp();
    cameraView = CAMERA_VIEW_PREVIEW;
    cameraNeedsFullRedraw = true;
    cameraPreviewDirty = true;
    cameraUiDirty = true;
  } else if (index == kAppGalleryIndex) {
    requestCameraPreviewStop();
    cameraView = CAMERA_VIEW_GALLERY;
    cameraNeedsFullRedraw = true;
    cameraGalleryDirty = true;
    cameraViewerDirty = true;
    cameraUiDirty = true;
  } else if (index == kAppAudioIndex) {
    refreshAudioFileList();
    audioPreviewPlaying = false;
    audioPlayPos = 0;
  } else if (index == kAppAirplanesIndex) {
    aircraftView = AIRCRAFT_VIEW_RADAR;
    aircraftAdsbActive = false;
    aircraftAdsbRequested = false;
    if (!aircraftCacheLoaded) loadAircraftCache();
    aircraftLastFetchMs = millis();
    if (aircraftSourceStatus == "NO SOURCE") {
      aircraftSourceStatus = "WI-FI READY - TAP REFRESH";
    }
  } else if (index == kAppLoraIndex) {
    ensureLoraP2pConfigured();
  } else if (index == kAppNotesIndex) {
    notesView = NOTES_VIEW_FILES;
    refreshNoteFileList();
  } else if (index == kAppCarIndex) {
    elmClearConfirmUntilMs = 0;
    elmCancelRequested = false;
    elmLiveRequestMs = 0;
    elmLiveRequestIndex = 0;
    elmLiveRpmValid = false;
    elmLiveSpeedValid = false;
    elmLiveCoolantValid = false;
    elmLiveIntakeValid = false;
    elmLiveVoltageValid = false;
    elmSetStatus(elmConnected ? "READY - IGNITION ON" : "WAITING FOR ELM327 USB");
    ensureRtlSdrHost();
  } else if (index == kAppRfWatchIndex || index == kAppWifiMotionIndex ||
             index == kAppIpCamsIndex) {
#if ENABLE_WIFI
    if (!bleExclusiveBootMode) prepareWifiForRadioApp();
#endif
    if (index == kAppIpCamsIndex) {
#if ENABLE_WIFI
      prepareForDeployCamApp();
      ipCamMode = ipCamLiveActive ? IpCamMode::LIVE : IpCamMode::LIST;
      ensureIpCamFrameMutex();
#endif
    }
  } else if (index == kAppBleKeyboardIndex) {
#if HAS_HOSTED_BLE
    if (!hostedBleBootReady) requestExclusiveBleBoot(kAppBleKeyboardIndex);
    else initBleKeyboard();
#endif
  } else if (index == kAppGamesIndex) {
    gamesView = GAMES_VIEW_ROMS;
    tetrisUiView = TetrisUiView::LIBRARY;
    tetrisLibrarySelection = 0;
    gameStatus = "TETRIS INSTALLED";
  } else if (index == kAppTripsIndex) {
    tripLogCacheCount = readTripLogTail(tripLogCache, kTripLogMaxLines);
  }
}

void leaveCurrentAppToMenu() {
  if (bleExclusiveBootMode &&
      (appSelected == kAppRfWatchIndex || appSelected == kAppBleKeyboardIndex)) {
    requestWifiBoot(false, appSelected == kAppBleKeyboardIndex);
    return;
  }
  if (usbExclusiveBootMode && isUsbExclusiveTargetApp(appSelected)) {
    uint8_t exitingUsbApp = appSelected;
    responderAppRegistry.stopByLegacyIndex(appSelected);
    requestUsbAccessoryRelease("usb exclusive app");
    stopRtlSdrHost();
    appSelected = kAppMenuIndex;
    usbExclusiveWifiRestorePending = usbExclusiveRestoreWifiOnExit;
    usbExclusiveExitRestoreModal = usbExclusiveWifiRestorePending;
    if (usbExclusiveWifiRestorePending) {
      enterWifiRestoreModal(exitingUsbApp == kAppCarIndex ? "Car Scanner closed" : "USB app closed");
    } else {
      waypointsDirty = true;
      waypointsNeedsFullRedraw = true;
    }
    debugPrint(usbExclusiveWifiRestorePending
                   ? "USBHOST: physical exit from USB-exclusive app; Wi-Fi restore modal active"
                   : "USBHOST: physical exit from USB-exclusive app; Wi-Fi was off on entry");
    return;
  }
  if (appSelected == kAppNotesIndex && notesView == NOTES_VIEW_EDITOR) {
    notesView = NOTES_VIEW_FILES;
    refreshNoteFileList();
    waypointsDirty = true;
    waypointsNeedsFullRedraw = true;
    return;
  }
  if (appSelected == kAppCalendarIndex && calendarEventEditor) {
    calendarEventInput = "";
    calendarEventEditor = false;
    waypointsDirty = true;
    return;
  }
  if (appSelected == kAppCameraIndex) {
    requestCameraPreviewStop();
    restoreWifiAfterCameraApp();
  } else if (appSelected == kAppGalleryIndex) {
    if (cameraView == CAMERA_VIEW_VIEWER) {
      cameraView = CAMERA_VIEW_GALLERY;
      cameraGalleryDirty = true;
      cameraNeedsFullRedraw = true;
      waypointsDirty = true;
      return;
    }
    restoreWifiAfterCameraApp();
  } else if (appSelected == kAppAudioIndex) {
    closeAudioPlayback();
  } else if (appSelected == kAppCarIndex) {
    elmClearConfirmUntilMs = 0;
    elmSetStatus(elmConnected ? "IDLE" : "ELM327 NOT CONNECTED");
    elmCancelRequested = true;
    elmRequest = ElmRequest::NONE;
    requestUsbAccessoryRelease("elm app");
    usbHostManager.release(UsbHostOwner::ELM327, millis());
  } else if (appSelected == kAppGamesIndex) {
    stopUsbGameStorage();
    gbaPaused = false;
    stopGameBoyEmulator();
    stopGbaEmulator();
  } else if (appSelected == kAppWifiMotionIndex) {
#if ENABLE_WIFI
    stopWifiMotion();
#endif
  } else if (appSelected == kAppIpCamsIndex) {
#if ENABLE_WIFI
    if (ipCamLiveActive) {
      ipCamLiveStopRequested = true;
      uint32_t stopStart = millis();
      while (ipCamTaskHandle && millis() - stopStart < 900) {
        delay(10);
      }
    }
    if (ipCamRecording) ipCamStopRecording();
    releaseIpCamRenderCanvas();
    ipCamMode = IpCamMode::LIST;
#endif
  } else if (appSelected == kAppBleKeyboardIndex) {
#if HAS_HOSTED_BLE
    if (rfWatchBleScanner && rfWatchBleScanning) rfWatchBleScanner->stop();
    rfWatchBleScanning = false;
    if (bleKeyboardReady && !bleKeyboardConnected) {
      BLEDevice::startAdvertising();
      bleKeyboardAdvertising = true;
    }
    if (hostedBleWifiRestorePending) {
      hostedBleWifiRestorePending = false;
      if (kHostedWifiRuntimeSafe) {
        wifiBootEnablePending = true;
        wifiBootEnableAfterMs = millis() + 1500;
      } else {
        wifiBootEnablePending = false;
        wifiBootEnableAfterMs = 0;
        debugPrint("WIFI: BLE exit restore blocked; hosted SDIO DMA unsafe");
      }
    }
#endif
  } else if (appSelected == kAppAirplanesIndex || appSelected == kAppGhostIndex ||
             appSelected == kAppRfScanIndex || appSelected == kAppDroneIndex) {
    releaseSdrAppResources();
  }
  responderAppRegistry.stopByLegacyIndex(appSelected);
  beginMenuTransition(true);
  appSelected = kAppMenuIndex;
  waypointsDirty = true;
  waypointsNeedsFullRedraw = true;
}

void drawSdrLivePanel(bool force) {
  if (appSelected == kAppRfScanIndex && rfAudioSettingsOpen) return;
  if (appSelected != kAppAirplanesIndex && appSelected != kAppGhostIndex &&
      appSelected != kAppRfScanIndex && appSelected != kAppDroneIndex &&
      appSelected != kAppRecorderIndex) {
    return;
  }
  uint32_t now = millis();
  if (!force && sdrUiLastMs != 0 && now - sdrUiLastMs < 120) {
    return;
  }
  sdrUiLastMs = now;
  if (sdrVizRect.w < 16 || sdrVizRect.h < 16) {
    return;
  }
  int levelPct = 0;
  if (appSelected == kAppGhostIndex) {
    levelPct = max(0, min(100, ghostLevel));
  } else if (appSelected == kAppRfScanIndex || appSelected == kAppDroneIndex) {
    levelPct = max(0, min(100, (rfScanLevel + 120) * 4));
  } else {
    levelPct = max(0, min(100, (airplanesStrongCount * 10)));
  }
  if (force) {
    M5.Display.drawRect(sdrVizRect.x, sdrVizRect.y, sdrVizRect.w, sdrVizRect.h, colors.amberDim);
    M5.Display.fillRect(static_cast<int16_t>(sdrVizRect.x + 1), static_cast<int16_t>(sdrVizRect.y + 1),
                        static_cast<int16_t>(sdrVizRect.w - 2), static_cast<int16_t>(sdrVizRect.h - 2),
                        colors.black);
    sdrWaterfallCol = 0;
  }
  int16_t meterH = 12;
  int16_t meterY = static_cast<int16_t>(sdrVizRect.y + 4);
  if (appSelected == kAppGhostIndex) {
    int16_t readoutH = static_cast<int16_t>(M5.Display.fontHeight() + 6);
    M5.Display.fillRect(static_cast<int16_t>(sdrVizRect.x + 4), meterY,
                        static_cast<int16_t>(sdrVizRect.w - 8), readoutH, colors.black);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextColor(colors.amber, colors.black);
    M5.Display.drawString(String("LIVE ") + formatRfFrequency(ghostSweepFreqHz) +
                              (ghostSweepHeld ? "  HOLD" : ""),
                          static_cast<int16_t>(sdrVizRect.x + 6), meterY);
    M5.Display.setTextDatum(TR_DATUM);
    M5.Display.drawString(String("VOL ") + String((rfAudioVolume * 100) / 255) + "%",
                          static_cast<int16_t>(sdrVizRect.x + sdrVizRect.w - 6), meterY);
    meterY = static_cast<int16_t>(meterY + readoutH);
  }
  int16_t meterX = static_cast<int16_t>(sdrVizRect.x + 4);
  int16_t meterW = static_cast<int16_t>(sdrVizRect.w - 8);
  M5.Display.drawRect(meterX, meterY, meterW, meterH, colors.amberDim);
  int16_t fillW = static_cast<int16_t>(((meterW - 2) * levelPct) / 100);
  M5.Display.fillRect(static_cast<int16_t>(meterX + 1), static_cast<int16_t>(meterY + 1),
                      static_cast<int16_t>(meterW - 2), static_cast<int16_t>(meterH - 2), colors.black);
  if (fillW > 0) {
    M5.Display.fillRect(static_cast<int16_t>(meterX + 1), static_cast<int16_t>(meterY + 1), fillW,
                        static_cast<int16_t>(meterH - 2), colors.amber);
  }
  int16_t wfY = static_cast<int16_t>(meterY + meterH + 6);
  int16_t wfH = static_cast<int16_t>(sdrVizRect.h - (wfY - sdrVizRect.y) - 4);
  int16_t wfW = static_cast<int16_t>(sdrVizRect.w - 8);
  int16_t wfX = static_cast<int16_t>(sdrVizRect.x + 4);
  if (wfH < 16 || wfW < 16) {
    return;
  }
  int16_t colX = static_cast<int16_t>(wfX + sdrWaterfallCol);
  M5.Display.drawFastVLine(colX, wfY, wfH, colors.black);
  int bars = max(1, (wfH * levelPct) / 100);
  uint16_t hitColor = (levelPct >= 70) ? colors.red : colors.amber;
  M5.Display.drawFastVLine(colX, static_cast<int16_t>(wfY + wfH - bars), bars, hitColor);
  sdrWaterfallCol = static_cast<uint8_t>((sdrWaterfallCol + 1) % max<int16_t>(1, wfW));
}

static bool beginAtomicMenuFrame(M5Canvas *background) {
  if (!background) return false;
  if (!menuCompositeCanvas) {
    menuCompositeCanvas = new (std::nothrow) M5Canvas(&M5.Display);
    if (!menuCompositeCanvas) return false;
    menuCompositeCanvas->setColorDepth(16);
    menuCompositeCanvas->setPsram(true);
  }
  if (menuCompositeCanvas->width() != screenW || menuCompositeCanvas->height() != screenH) {
    menuCompositeCanvas->deleteSprite();
    if (!menuCompositeCanvas->createSprite(screenW, screenH)) return false;
  }
  menuCompositeCanvas->fillScreen(colors.black);
  background->pushSprite(menuCompositeCanvas, 0, 0);
  return true;
}

static void drawAtomicMenuHeader(M5Canvas &canvas, const char *title, int16_t headerH) {
  canvas.fillRect(0, 0, screenW, headerH, colors.black);
  canvas.drawFastHLine(0, static_cast<int16_t>(headerH - 2), screenW, colors.amberDim);
  canvas.setTextDatum(ML_DATUM);
  canvas.setTextColor(colors.amber, colors.black);
  canvas.setTextSize(kButtonTextSize + 1);
  canvas.drawString(title, 12, static_cast<int16_t>(headerH / 2 - 1));
}

static void drawAtomicNavBar(M5Canvas &canvas, uint8_t activeIndex) {
  const char *labels[4] = {"MAP", "APPS", "UTILITIES", "LOCK"};
  for (uint8_t i = 0; i < 4; ++i) {
    bool active = i == activeIndex;
    uint16_t bg = active ? colors.redDim : colors.black;
    uint16_t fg = active ? colors.red : colors.amber;
    const Rect &button = navButtons[i];
    canvas.fillRect(button.x, button.y, button.w, button.h, bg);
    canvas.drawRect(button.x, button.y, button.w, button.h, fg);
    canvas.setTextDatum(MC_DATUM);
    canvas.setTextColor(fg, bg);
    canvas.setTextSize(kNavTextSize);
    canvas.drawString(labels[i], button.x + button.w / 2, button.y + button.h / 2);
    if (i == 1 && calendarHasReminder()) {
      canvas.setTextDatum(TR_DATUM);
      canvas.setTextColor(colors.red, bg);
      canvas.drawString("*", button.x + button.w - 8, button.y + 4);
    }
  }
}

static bool composeAppsMenuFrame() {
  if (appMenuVisibleDirty) rebuildAppMenuVisibleList();
  if (!beginAtomicMenuFrame(appsMenuBackgroundCanvas)) return false;
  M5Canvas &canvas = *menuCompositeCanvas;
  int16_t headerH = static_cast<int16_t>(max<int16_t>(36, appButtons[0].y - 4));
  drawAtomicMenuHeader(canvas, "APPS", headerH);

  const char *appLabels[kAppCount] = {"TRIPS/LOC", "CALENDAR", "CAMERA", "GALLERY", "WEATHER",
                                      "AIRPLANES", "GHOST", "RF SCAN", "RECORDER", "AUDIO",
                                      "MESHCORE", "NOTES", "CAR SCANNER", "RF WATCH",
                                      "WI-FI MOTION", "BLE KEYBOARD", "GAMES", "DEPLOY CAM",
                                      "SYS HEALTH", "FILE XFER", "DRONE DETECT"};
  int pageStart = appMenuPage * kAppsPerPage;
  int pageEnd = min<int>(appMenuVisibleCount, pageStart + kAppsPerPage);
  for (int pos = pageStart; pos < pageEnd; ++pos) {
    uint8_t index = appMenuVisibleIndices[pos];
    int slot = pos % kAppsPerPage;
    const Rect &button = appButtons[slot];
    bool selected = index == appMenuKeyboardSelection;
    uint16_t bg = selected ? colors.amberDim : colors.black;
    canvas.fillRect(button.x, button.y, button.w, button.h, bg);
    canvas.drawRect(button.x, button.y, button.w, button.h, colors.amber);
    canvas.setTextDatum(MC_DATUM);
    canvas.setTextColor(colors.amber, bg);
    canvas.setTextSize(kButtonTextSize + 1);
    const char *label = responderAppRegistry.titleForLegacyIndex(index, appLabels[index]);
    canvas.drawString(label, button.x + button.w / 2, button.y + button.h / 2);
    if (index == kAppCalendarIndex && calendarHasReminder()) {
      canvas.setTextDatum(TR_DATUM);
      canvas.setTextColor(colors.red, bg);
      canvas.drawString("*", button.x + button.w - 8, button.y + 4);
    }
  }

  int16_t footerY = static_cast<int16_t>(appMenuPrevPageButton.y - 5);
  int16_t footerH = static_cast<int16_t>(appMenuPrevPageButton.h + 10);
  int16_t pageCenterX = static_cast<int16_t>(
      (appMenuPrevPageButton.x + appMenuPrevPageButton.w + appMenuNextPageButton.x) / 2);
  int16_t pageCenterY = static_cast<int16_t>(appMenuPrevPageButton.y + appMenuPrevPageButton.h / 2);
  canvas.fillRect(0, footerY, screenW, footerH, colors.black);
  canvas.drawFastHLine(0, footerY, screenW, colors.amberDim);
  canvas.drawRect(appMenuPrevPageButton.x, appMenuPrevPageButton.y,
                  appMenuPrevPageButton.w, appMenuPrevPageButton.h, colors.amber);
  canvas.drawRect(appMenuNextPageButton.x, appMenuNextPageButton.y,
                  appMenuNextPageButton.w, appMenuNextPageButton.h, colors.amber);
  canvas.setTextDatum(MC_DATUM);
  canvas.setTextColor(colors.amber, colors.black);
  canvas.setTextSize(kSmallTextSize);
  canvas.drawString("<", appMenuPrevPageButton.x + appMenuPrevPageButton.w / 2, pageCenterY);
  canvas.drawString(">", appMenuNextPageButton.x + appMenuNextPageButton.w / 2, pageCenterY);
  canvas.drawString(String(appMenuPage + 1) + "/" + String(appMenuVisiblePageCount),
                    pageCenterX, pageCenterY);
  drawAtomicNavBar(canvas, 1);
  return true;
}

static bool composeUtilitiesMenuFrame() {
  if (!beginAtomicMenuFrame(utilitiesMenuBackgroundCanvas)) return false;
  M5Canvas &canvas = *menuCompositeCanvas;
  int16_t headerH = static_cast<int16_t>(max<int16_t>(36, appMenuButtonsArea.y - 4));
  drawAtomicMenuHeader(canvas, "UTILITIES", headerH);
  uint16_t btnBg = colors.black;
  auto drawButton = [&](const Rect &button, const String &label, uint16_t fg) {
    canvas.fillRect(button.x, button.y, button.w, button.h, btnBg);
    canvas.drawRect(button.x, button.y, button.w, button.h, fg);
    canvas.setTextDatum(MC_DATUM);
    canvas.setTextColor(fg, btnBg);
    canvas.setTextSize(kButtonTextSize);
    canvas.drawString(label, button.x + button.w / 2, button.y + button.h / 2);
  };
  drawButton(downloadMapButton, "MAP DOWNLOADS", colors.amber);
  drawButton(downloadFilesButton, "FILES", colors.amber);
  drawButton(downloadSettingsButton, "SETTINGS", colors.amber);

  uint16_t wifiFg = colors.amber;
  String wifiStatus = "OFF";
#if ENABLE_WIFI
  if (!wifiAvailable) {
    wifiStatus = "N/A";
    wifiFg = colors.amberDim;
  } else if (wifiEnabled && WiFi.status() == WL_CONNECTED) {
    wifiStatus = "CONNECTED";
  } else if (wifiEnabled) {
    wifiStatus = "DISCONNECTED";
  }
#else
  wifiStatus = "DISABLED";
  wifiFg = colors.amberDim;
#endif
  const Rect &wifiButton = downloadWifiButton;
  canvas.fillRect(wifiButton.x, wifiButton.y, wifiButton.w, wifiButton.h, btnBg);
  canvas.drawRect(wifiButton.x, wifiButton.y, wifiButton.w, wifiButton.h, wifiFg);
  canvas.setTextDatum(MC_DATUM);
  canvas.setTextColor(wifiFg, btnBg);
  canvas.setTextSize(kButtonTextSize);
  int16_t labelH = canvas.fontHeight();
  canvas.setTextSize(kSmallTextSize);
  int16_t statusH = canvas.fontHeight();
  int16_t totalH = static_cast<int16_t>(labelH + statusH + 4);
  int16_t topY = static_cast<int16_t>(wifiButton.y + (wifiButton.h - totalH) / 2);
  canvas.setTextSize(kButtonTextSize);
  canvas.drawString("WIFI", wifiButton.x + wifiButton.w / 2,
                    static_cast<int16_t>(topY + labelH / 2));
  canvas.setTextSize(kSmallTextSize);
  canvas.drawString(wifiStatus, wifiButton.x + wifiButton.w / 2,
                    static_cast<int16_t>(topY + labelH + 4 + statusH / 2));

  int16_t footerY = static_cast<int16_t>(appMenuPrevPageButton.y - 5);
  int16_t footerH = static_cast<int16_t>(appMenuPrevPageButton.h + 10);
  canvas.fillRect(0, footerY, screenW, footerH, colors.black);
  canvas.drawFastHLine(0, footerY, screenW, colors.amberDim);
  canvas.drawRect(downloadApiKeysButton.x, downloadApiKeysButton.y,
                  downloadApiKeysButton.w, downloadApiKeysButton.h, colors.amber);
  canvas.drawRect(downloadAboutButton.x, downloadAboutButton.y,
                  downloadAboutButton.w, downloadAboutButton.h, colors.amber);
  canvas.setTextDatum(MC_DATUM);
  canvas.setTextColor(colors.amber, colors.black);
  canvas.setTextSize(kSmallTextSize);
  canvas.drawString("API KEYS", downloadApiKeysButton.x + downloadApiKeysButton.w / 2,
                    downloadApiKeysButton.y + downloadApiKeysButton.h / 2);
  canvas.drawString("ABOUT", downloadAboutButton.x + downloadAboutButton.w / 2,
                    downloadAboutButton.y + downloadAboutButton.h / 2);
  drawAtomicNavBar(canvas, 2);
  return true;
}

void drawWaypointsScreen() {
  if (appSelected == kAppMenuIndex) {
    bool revealAfterDraw = appsMenuTransitionPending;
    if (revealAfterDraw && millis() - menuTransitionShownMs < 120) {
      return;
    }
    if (revealAfterDraw && composeAppsMenuFrame()) {
      menuCompositeCanvas->pushSprite(0, 0);
      appsMenuTransitionPending = false;
      appMenuNavigationRedraw = false;
      appMenuPageRedraw = false;
      waypointsDirty = false;
      waypointsNeedsFullRedraw = false;
      debugPrint("UI: apps atomic transition reveal complete");
      return;
    }
    if (appMenuVisibleDirty) rebuildAppMenuVisibleList();
    const char *appLabels[kAppCount] = {"TRIPS/LOC", "CALENDAR", "CAMERA", "GALLERY", "WEATHER",
                                        "AIRPLANES", "GHOST", "RF SCAN", "RECORDER", "AUDIO",
                                        "MESHCORE", "NOTES", "CAR SCANNER", "RF WATCH",
                                        "WI-FI MOTION", "BLE KEYBOARD", "GAMES", "DEPLOY CAM",
                                        "SYS HEALTH", "FILE XFER", "DRONE DETECT"};
    auto drawAppMenuButton = [&](int visiblePos) {
      if (visiblePos < 0 || visiblePos >= appMenuVisibleCount) return;
      uint8_t index = appMenuVisibleIndices[visiblePos];
      int slot = visiblePos % kAppsPerPage;
      bool selected = index == appMenuKeyboardSelection;
      uint16_t background = selected ? colors.amberDim : colors.black;
      M5.Display.fillRect(appButtons[slot].x, appButtons[slot].y,
                          appButtons[slot].w, appButtons[slot].h, background);
      M5.Display.drawRect(appButtons[slot].x, appButtons[slot].y,
                          appButtons[slot].w, appButtons[slot].h, colors.amber);
      M5.Display.setTextDatum(MC_DATUM);
      M5.Display.setTextColor(colors.amber, background);
      M5.Display.setTextSize(kButtonTextSize + 1);
      const char *label = responderAppRegistry.titleForLegacyIndex(index, appLabels[index]);
      M5.Display.drawString(label, appButtons[slot].x + appButtons[slot].w / 2,
                            appButtons[slot].y + appButtons[slot].h / 2);
      if (index == kAppCalendarIndex && calendarHasReminder()) {
        M5.Display.setTextDatum(TR_DATUM);
        M5.Display.setTextColor(colors.red, background);
        M5.Display.drawString("*", appButtons[slot].x + appButtons[slot].w - 8,
                              appButtons[slot].y + 4);
      }
    };
    auto drawAppMenuFooter = [&]() {
      int16_t pageCenterX = static_cast<int16_t>(
          (appMenuPrevPageButton.x + appMenuPrevPageButton.w + appMenuNextPageButton.x) / 2);
      int16_t pageCenterY =
          static_cast<int16_t>(appMenuPrevPageButton.y + appMenuPrevPageButton.h / 2);
      int16_t footerY = static_cast<int16_t>(appMenuPrevPageButton.y - 5);
      int16_t footerH = static_cast<int16_t>(appMenuPrevPageButton.h + 10);
      M5.Display.fillRect(0, footerY, screenW, footerH, colors.black);
      drawTextureRect({0, footerY, screenW, footerH});
      M5.Display.setTextDatum(MC_DATUM);
      M5.Display.setTextColor(colors.amber, colors.black);
      M5.Display.setTextSize(kSmallTextSize);
      M5.Display.drawRect(appMenuPrevPageButton.x, appMenuPrevPageButton.y,
                          appMenuPrevPageButton.w, appMenuPrevPageButton.h, colors.amber);
      M5.Display.drawRect(appMenuNextPageButton.x, appMenuNextPageButton.y,
                          appMenuNextPageButton.w, appMenuNextPageButton.h, colors.amber);
      M5.Display.drawString("<", appMenuPrevPageButton.x + appMenuPrevPageButton.w / 2,
                            pageCenterY);
      M5.Display.drawString(">", appMenuNextPageButton.x + appMenuNextPageButton.w / 2,
                            pageCenterY);
      M5.Display.drawString(String(appMenuPage + 1) + "/" + String(appMenuVisiblePageCount),
                            pageCenterX, pageCenterY);
    };
    if (appMenuPageRedraw && !waypointsNeedsFullRedraw) {
      for (int slot = 0; slot < kAppsPerPage; ++slot) {
        M5.Display.fillRect(appButtons[slot].x, appButtons[slot].y,
                            appButtons[slot].w, appButtons[slot].h, colors.black);
      }
      int pageStart = appMenuPage * kAppsPerPage;
      int pageEnd = min<int>(appMenuVisibleCount, pageStart + kAppsPerPage);
      for (int pos = pageStart; pos < pageEnd; ++pos) drawAppMenuButton(pos);
      drawAppMenuFooter();
      appMenuPageRedraw = false;
      appMenuNavigationRedraw = false;
      appMenuPreviousKeyboardSelection = -1;
      waypointsDirty = false;
      debugPrint("UI: apps page partial page=%u", static_cast<unsigned>(appMenuPage + 1));
      return;
    }
    if (appMenuNavigationRedraw && !waypointsNeedsFullRedraw) {
      int previousPos = appMenuVisiblePositionForIndex(
          static_cast<uint8_t>(appMenuPreviousKeyboardSelection));
      int selectedPos = appMenuVisiblePositionForIndex(appMenuKeyboardSelection);
      int pageStart = appMenuPage * kAppsPerPage;
      int pageEnd = min<int>(appMenuVisibleCount, pageStart + kAppsPerPage);
      if (previousPos >= pageStart && previousPos < pageEnd &&
          selectedPos >= pageStart && selectedPos < pageEnd) {
        drawAppMenuButton(previousPos);
        drawAppMenuButton(selectedPos);
        appMenuNavigationRedraw = false;
        appMenuPreviousKeyboardSelection = -1;
        waypointsDirty = false;
        debugPrint("UI: apps selection partial old=%d new=%d", previousPos, selectedPos);
        return;
      }
      appMenuNavigationRedraw = false;
      appMenuPreviousKeyboardSelection = -1;
    }
    debugPrint("UI: apps menu render full=%u", waypointsNeedsFullRedraw ? 1U : 0U);
    if (waypointsNeedsFullRedraw) {
      M5.Display.fillRect(0, 0, screenW, static_cast<int16_t>(screenH - navH), colors.black);
      waypointsNeedsFullRedraw = false;
    } else {
      M5.Display.fillRect(0, 0, screenW, static_cast<int16_t>(screenH - navH), colors.black);
    }

    int16_t headerH = static_cast<int16_t>(max<int16_t>(36, appButtons[0].y - 4));
    if (appMenuArtArea.w > 12 && appMenuArtArea.h > 12) {
      drawAppMenuArt(appMenuArtArea);
    }
    drawMenuSectionHeader("APPS", headerH);

    int pageStart = appMenuPage * kAppsPerPage;
    int pageEnd = min<int>(appMenuVisibleCount, pageStart + kAppsPerPage);
    for (int pos = pageStart; pos < pageEnd; ++pos) {
      drawAppMenuButton(pos);
    }

    drawAppMenuFooter();

    drawNavBar();
    appMenuPageRedraw = false;
    appMenuNavigationRedraw = false;
    waypointsDirty = false;
    if (revealAfterDraw) {
      appsMenuTransitionPending = false;
      debugPrint("UI: apps transition reveal complete");
    }
    return;
  }

  if (waypointsNeedsFullRedraw) {
    M5.Display.fillScreen(colors.black);
    waypointsNeedsFullRedraw = false;
  } else {
    int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 8);
    int16_t contentH = static_cast<int16_t>(screenH - navH - contentTop);
    bool isSdrApp = appSelected == kAppAirplanesIndex || appSelected == kAppGhostIndex ||
                    appSelected == kAppRfScanIndex || appSelected == kAppDroneIndex ||
                    appSelected == kAppRecorderIndex ||
                    appSelected == kAppAudioIndex;
    if (contentH > 0) {
      if (appSelected != kAppCameraIndex && appSelected != kAppGalleryIndex && !isSdrApp &&
          !responderAppRegistry.appByLegacyIndex(appSelected)) {
        M5.Display.fillRect(0, contentTop, screenW, contentH, colors.black);
      }
    }
  }

  const char *appTitle = "TRIPS/LOC";
  if (appSelected == kAppCalendarIndex) {
    appTitle = "CALENDAR";
  } else if (appSelected == kAppCameraIndex) {
    appTitle = "CAMERA";
  } else if (appSelected == kAppGalleryIndex) {
    appTitle = "GALLERY";
  } else if (appSelected == kAppWeatherIndex) {
    appTitle = "WEATHER";
  } else if (appSelected == kAppAirplanesIndex) {
    appTitle = "AIRPLANES";
  } else if (appSelected == kAppGhostIndex) {
    appTitle = "GHOST FIELD UNIT";
  } else if (appSelected == kAppRfScanIndex) {
    appTitle = "RF SCAN";
  } else if (appSelected == kAppDroneIndex) {
    appTitle = "DRONE DETECTION";
  } else if (appSelected == kAppRecorderIndex) {
    appTitle = "RECORDER";
  } else if (appSelected == kAppAudioIndex) {
    appTitle = "AUDIO";
  } else if (appSelected == kAppLoraIndex) {
    appTitle = "MESHCORE";
  } else if (appSelected == kAppNotesIndex) {
    appTitle = "NOTES";
  } else if (appSelected == kAppCarIndex) {
    appTitle = "CAR SCANNER";
  } else if (appSelected == kAppRfWatchIndex) {
    appTitle = "RF WATCH";
  } else if (appSelected == kAppWifiMotionIndex) {
    appTitle = "WI-FI MOTION";
  } else if (appSelected == kAppBleKeyboardIndex) {
    appTitle = "BLE KEYBOARD";
  } else if (appSelected == kAppGamesIndex) {
    appTitle = "GAMES";
  } else if (appSelected == kAppIpCamsIndex) {
    appTitle = "DEPLOY CAM";
  } else if (appSelected == kAppSystemHealthIndex) {
    appTitle = "SYSTEM HEALTH";
  } else if (appSelected == kAppFileTransferIndex) {
    appTitle = "FILE TRANSFER";
  }
  appTitle = responderAppRegistry.titleForLegacyIndex(appSelected, appTitle);

  if (responderAppRegistry.appByLegacyIndex(appSelected)) {
    responderDisplayCanvas.setSize(screenW, static_cast<int16_t>(screenH - navH));
    responderAppRegistry.renderByLegacyIndex(appSelected, responderDisplayCanvas);
    waypointsDirty = false;
    return;
  }

  if (appSelected == kAppCalendarIndex) {
    drawAppTopBar(appTitle);
    drawCalendarApp();
    drawNavBar();
    drawBusyIndicatorTopCenter(kSmallTextSize);
    waypointsDirty = false;
    return;
  }
  if (appSelected == kAppCameraIndex) {
    drawCameraApp();
    return;
  }
  if (appSelected == kAppGalleryIndex) {
    drawGalleryApp();
    return;
  }
  if (appSelected == kAppWeatherIndex) {
    drawAppTopBar(appTitle);
    drawWeatherApp();
    drawNavBar();
    drawBusyIndicatorTopCenter(kSmallTextSize);
    waypointsDirty = false;
    return;
  }
  if (appSelected == kAppLoraIndex) {
    drawLoraApp();
    return;
  }
  if (appSelected == kAppNotesIndex) {
    drawNotesApp();
    return;
  }
  if (appSelected == kAppCarIndex) {
    drawCarScannerApp();
    return;
  }
  if (appSelected == kAppRfWatchIndex) {
    drawRfWatchApp();
    return;
  }
  if (appSelected == kAppWifiMotionIndex) {
    drawWifiMotionApp();
    return;
  }
  if (appSelected == kAppBleKeyboardIndex) {
    drawBleKeyboardApp();
    return;
  }
  if (appSelected == kAppGamesIndex) {
    drawGamesApp();
    return;
  }
  if (appSelected == kAppIpCamsIndex) {
    drawIpCamsApp();
    return;
  }
  if (appSelected == kAppSystemHealthIndex) {
    drawSystemHealthApp();
    return;
  }
  if (appSelected == kAppAirplanesIndex) {
    drawAircraftApp();
    return;
  }
  if (appSelected == kAppGhostIndex ||
      appSelected == kAppRfScanIndex || appSelected == kAppDroneIndex ||
      appSelected == kAppRecorderIndex ||
      appSelected == kAppAudioIndex) {
    drawSdrAppScreen(appSelected, appTitle);
    return;
  }
  drawAppTopBar(appTitle);

  int16_t contentTop = static_cast<int16_t>(appTopBarRect.h + 8);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.setTextDatum(TL_DATUM);
  M5.Display.setTextColor(colors.amberDim, colors.black);
  M5.Display.drawString("FIELD LOCATIONS // TRIP HISTORY", 16, contentTop);

  int16_t lineH = static_cast<int16_t>(M5.Display.fontHeight() + 4);
  int16_t listStart = static_cast<int16_t>(contentTop + lineH + 4);
  int16_t contentBottom = static_cast<int16_t>(min<int16_t>(screenH - navH - 8,
                                                           static_cast<int16_t>(waypointsDeleteButton.y - 6)));
  int16_t tripSectionH = static_cast<int16_t>(lineH * (static_cast<int>(kTripLogMaxLines) + 5));
  int16_t locMaxY = max<int16_t>(listStart + lineH, static_cast<int16_t>(contentBottom - tripSectionH));

  auto drawSectionHeader = [&](const String &label, int16_t y) -> int16_t {
    Rect band = {12, y, static_cast<int16_t>(screenW - 24), lineH};
    M5.Display.fillRect(band.x, band.y, band.w, band.h, colors.black);
    M5.Display.fillRect(band.x, static_cast<int16_t>(band.y + 2), 4,
                        max<int16_t>(1, static_cast<int16_t>(band.h - 4)), colors.amberDim);
    M5.Display.setTextColor(colors.amber, colors.black);
    M5.Display.setTextSize(kSmallTextSize);
    M5.Display.setTextDatum(TL_DATUM);
    M5.Display.drawString(label, 24, y);
    return static_cast<int16_t>(y + lineH);
  };

  int16_t y = listStart;
  y = drawSectionHeader(String("LOCATIONS (") + String(waypointCount) + ")", y);
  int16_t listTop = y;
  int16_t listBottom = max<int16_t>(static_cast<int16_t>(listTop + lineH), locMaxY);
  int16_t listH = max<int16_t>(0, static_cast<int16_t>(listBottom - listTop));
  int16_t listInsetX = 12;
  int16_t listInsetRight = 12;
  int16_t arrowGap = 6;
  int16_t arrowW = 56;
  int16_t listW =
      static_cast<int16_t>(screenW - listInsetX - listInsetRight - arrowW - arrowGap);
  if (listW < 120) {
    arrowW = 0;
    arrowGap = 0;
    listW = static_cast<int16_t>(screenW - listInsetX - listInsetRight);
  }
  waypointsListRect = {listInsetX, listTop, listW, listH};
  if (isRectValid(waypointsListRect)) {
    M5.Display.drawRect(waypointsListRect.x, waypointsListRect.y,
                        waypointsListRect.w, waypointsListRect.h, colors.amberDim);
  }
  if (listH > 0 && arrowW > 0) {
    int16_t arrowX = static_cast<int16_t>(waypointsListRect.x + waypointsListRect.w + arrowGap);
    int16_t arrowPad = 4;
    int16_t arrowH = static_cast<int16_t>(
        max<int16_t>(36, (waypointsListRect.h - arrowPad * 3) / 2));
    if (arrowH * 2 + arrowPad * 3 > waypointsListRect.h) {
      arrowH = static_cast<int16_t>((waypointsListRect.h - arrowPad * 3) / 2);
    }
    waypointsUpButton = {arrowX, static_cast<int16_t>(waypointsListRect.y + arrowPad), arrowW,
                         arrowH};
    int16_t downY = static_cast<int16_t>(waypointsListRect.y + waypointsListRect.h - arrowPad - arrowH);
    waypointsDownButton = {arrowX, downY, arrowW, arrowH};
  } else {
    waypointsUpButton = {0, 0, 0, 0};
    waypointsDownButton = {0, 0, 0, 0};
  }

  if (waypointsSelectedIndex >= static_cast<int>(waypointCount)) {
    waypointsSelectedIndex = waypointCount > 0 ? static_cast<int>(waypointCount - 1) : -1;
  }
  bool twoLine = listH >= static_cast<int16_t>(lineH * 2);
  int16_t rowH = twoLine ? static_cast<int16_t>(lineH * 2) : lineH;
  int visibleRows = rowH > 0 ? static_cast<int>(listH / rowH) : 0;
  if (visibleRows < 1) {
    visibleRows = 1;
  }
  int maxScroll = max<int>(0, static_cast<int>(waypointCount) - visibleRows);
  if (waypointsScrollIndex > maxScroll) {
    waypointsScrollIndex = maxScroll;
  }
  if (waypointsScrollIndex < 0) {
    waypointsScrollIndex = 0;
  }

  if (waypointCount == 0) {
    M5.Display.setTextColor(colors.amberDim, colors.black);
    M5.Display.drawString("NO LOCATIONS SAVED", listInsetX, listTop);
    M5.Display.setTextColor(colors.amber, colors.black);
    y = static_cast<int16_t>(listTop + lineH);
  } else {
    for (int row = 0; row < visibleRows; ++row) {
      int index = waypointsScrollIndex + row;
      if (index >= static_cast<int>(waypointCount)) {
        break;
      }
      int16_t rowY = static_cast<int16_t>(listTop + row * rowH);
      bool selected = index == waypointsSelectedIndex;
      if (selected) {
        M5.Display.drawRect(waypointsListRect.x, rowY, waypointsListRect.w, rowH, colors.amberDim);
      }
      String nameLine = String(index + 1) + ") " + String(waypoints[index].name);
      if (twoLine) {
        M5.Display.setTextColor(colors.amber, colors.black);
        M5.Display.drawString(nameLine, waypointsListRect.x + 6, rowY);
        M5.Display.setTextColor(selected ? colors.amber : colors.amberDim, colors.black);
        String coordLine = "LAT " + String(waypoints[index].lat, 4) + "  LON " +
                           String(waypoints[index].lon, 4);
        M5.Display.drawString(coordLine, waypointsListRect.x + 14,
                              static_cast<int16_t>(rowY + lineH));
      } else {
        String line = nameLine + " " + String(waypoints[index].lat, 4) + "," +
                      String(waypoints[index].lon, 4);
        M5.Display.setTextColor(colors.amber, colors.black);
        M5.Display.drawString(line, waypointsListRect.x + 6, rowY);
      }
      y = static_cast<int16_t>(rowY + rowH);
    }
  }

  if (isRectValid(waypointsUpButton)) {
    bool canScrollUp = waypointsScrollIndex > 0;
    bool canScrollDown = waypointsScrollIndex < maxScroll;
    uint16_t upFg = canScrollUp ? colors.amber : colors.amberDim;
    uint16_t downFg = canScrollDown ? colors.amber : colors.amberDim;
    drawTerminalButton(waypointsUpButton, "^", upFg);
    drawTerminalButton(waypointsDownButton, "v", downFg);
    M5.Display.setTextDatum(TL_DATUM);
  }

  int16_t tripY =
      max<int16_t>(static_cast<int16_t>(y + 6), static_cast<int16_t>(listBottom + 6));
  if (tripY + lineH < contentBottom) {
    tripY = drawSectionHeader("TRIP LOGS", tripY);
    if (tripY + lineH < contentBottom) {
      M5.Display.setTextColor(colors.amberDim, colors.black);
      String statusLine = String("STATUS: ") + (tripActive ? "ACTIVE" : "IDLE");
      M5.Display.drawString(statusLine, 12, tripY);
      tripY = static_cast<int16_t>(tripY + lineH);
    }
    if (tripY + lineH < contentBottom) {
      String stepLine =
          String("STEPS: ") + String(tripSteps) + "  DIST: " + String(tripDistanceMeters, 1) + "m";
      M5.Display.drawString(stepLine, 12, tripY);
      tripY = static_cast<int16_t>(tripY + lineH);
    }
    if (tripY + lineH < contentBottom) {
      M5.Display.setTextColor(colors.amber, colors.black);
      M5.Display.drawString("RECENT:", 12, tripY);
      tripY = static_cast<int16_t>(tripY + lineH);
    }

    size_t logCount = tripLogCacheCount;
    if (logCount == 0) {
      M5.Display.setTextColor(colors.amberDim, colors.black);
      M5.Display.drawString(sdReady ? "NO LOGS YET" : "SD NOT READY", 12, tripY);
      M5.Display.setTextColor(colors.amber, colors.black);
    } else {
      for (size_t i = 0; i < logCount; ++i) {
        M5.Display.drawString(tripLogCache[i], 20, tripY);
        tripY = static_cast<int16_t>(tripY + lineH);
        if (tripY > contentBottom) {
          break;
        }
      }
    }
  }

  bool canView = waypointsSelectedIndex >= 0 &&
                 waypointsSelectedIndex < static_cast<int>(waypointCount);
  uint16_t viewFg = canView ? colors.amber : colors.amberDim;
  drawTerminalButton(waypointsViewButton, "VIEW", viewFg);

  uint16_t btnFg = waypointCount > 0 ? colors.red : colors.amberDim;
  drawTerminalButton(waypointsDeleteButton, "DEL LOC", btnFg);

  drawNavBar();
  drawBusyIndicatorTopCenter(kSmallTextSize);
  waypointsDirty = false;
}

void drawDownloadMenuScreen() {
  bool revealAfterDraw = utilitiesMenuTransitionPending;
  if (revealAfterDraw && millis() - menuTransitionShownMs < 120) {
    return;
  }
  if (revealAfterDraw && composeUtilitiesMenuFrame()) {
    menuCompositeCanvas->pushSprite(0, 0);
    utilitiesMenuTransitionPending = false;
    downloadMenuDirty = false;
    downloadMenuBusyDirty = false;
    downloadMenuNeedsFullRedraw = false;
    debugPrint("UI: utilities atomic transition reveal complete");
    return;
  }
  if (!revealAfterDraw && downloadMenuBusyDirty && !downloadMenuDirty &&
      !downloadMenuNeedsFullRedraw) {
    drawBusyIndicatorTopCenter(kSmallTextSize);
    downloadMenuBusyDirty = false;
    return;
  }
  int16_t headerH = static_cast<int16_t>(max<int16_t>(36, appMenuButtonsArea.y - 4));
  debugPrint("UI: utilities menu render full=%u", downloadMenuNeedsFullRedraw ? 1U : 0U);
  if (downloadMenuNeedsFullRedraw) {
    M5.Display.fillRect(0, 0, screenW, static_cast<int16_t>(screenH - navH), colors.black);
    downloadMenuNeedsFullRedraw = false;
  } else {
    M5.Display.fillRect(0, 0, screenW, static_cast<int16_t>(screenH - navH), colors.black);
  }
  drawCachedMenuBackground(kUtilitiesMenuBackgroundPath,
                           utilitiesMenuBackgroundCanvas, "UTILITIES");
  drawMenuSectionHeader("UTILITIES", headerH);

  uint16_t btnBg = colors.black;
  uint16_t btnFg = colors.amber;

  M5.Display.fillRect(downloadMapButton.x, downloadMapButton.y, downloadMapButton.w, downloadMapButton.h, btnBg);
  M5.Display.drawRect(downloadMapButton.x, downloadMapButton.y, downloadMapButton.w, downloadMapButton.h, btnFg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(btnFg, btnBg);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("MAP DOWNLOADS", downloadMapButton.x + downloadMapButton.w / 2,
                        downloadMapButton.y + downloadMapButton.h / 2);

  uint16_t wifiFg = colors.amber;
  String wifiStatus = "OFF";
#if ENABLE_WIFI
  if (!wifiAvailable) {
    wifiStatus = "N/A";
    wifiFg = colors.amberDim;
  } else if (wifiEnabled && WiFi.status() == WL_CONNECTED) {
    wifiStatus = "CONNECTED";
  } else if (wifiEnabled) {
    wifiStatus = "DISCONNECTED";
  }
#else
  wifiStatus = "DISABLED";
  wifiFg = colors.amberDim;
#endif
  M5.Display.fillRect(downloadWifiButton.x, downloadWifiButton.y, downloadWifiButton.w, downloadWifiButton.h, btnBg);
  M5.Display.drawRect(downloadWifiButton.x, downloadWifiButton.y, downloadWifiButton.w, downloadWifiButton.h, wifiFg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(wifiFg, btnBg);
  M5.Display.setTextSize(kButtonTextSize);
  int16_t labelH = M5.Display.fontHeight();
  M5.Display.setTextSize(kSmallTextSize);
  int16_t statusH = M5.Display.fontHeight();
  int16_t totalH = static_cast<int16_t>(labelH + statusH + 4);
  int16_t topY = static_cast<int16_t>(downloadWifiButton.y + (downloadWifiButton.h - totalH) / 2);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("WIFI", downloadWifiButton.x + downloadWifiButton.w / 2,
                        static_cast<int16_t>(topY + labelH / 2));
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.drawString(wifiStatus, downloadWifiButton.x + downloadWifiButton.w / 2,
                        static_cast<int16_t>(topY + labelH + 4 + statusH / 2));

  M5.Display.fillRect(downloadFilesButton.x, downloadFilesButton.y, downloadFilesButton.w,
                      downloadFilesButton.h, btnBg);
  M5.Display.drawRect(downloadFilesButton.x, downloadFilesButton.y, downloadFilesButton.w,
                      downloadFilesButton.h, btnFg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(btnFg, btnBg);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("FILES", downloadFilesButton.x + downloadFilesButton.w / 2,
                        downloadFilesButton.y + downloadFilesButton.h / 2);

  M5.Display.fillRect(downloadSettingsButton.x, downloadSettingsButton.y, downloadSettingsButton.w,
                      downloadSettingsButton.h, btnBg);
  M5.Display.drawRect(downloadSettingsButton.x, downloadSettingsButton.y, downloadSettingsButton.w,
                      downloadSettingsButton.h, btnFg);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(btnFg, btnBg);
  M5.Display.setTextSize(kButtonTextSize);
  M5.Display.drawString("SETTINGS", downloadSettingsButton.x + downloadSettingsButton.w / 2,
                        downloadSettingsButton.y + downloadSettingsButton.h / 2);

  int16_t footerY = static_cast<int16_t>(appMenuPrevPageButton.y - 5);
  int16_t footerH = static_cast<int16_t>(appMenuPrevPageButton.h + 10);
  M5.Display.fillRect(0, footerY, screenW, footerH, colors.black);
  drawTextureRect({0, footerY, screenW, footerH});
  M5.Display.drawRect(downloadApiKeysButton.x, downloadApiKeysButton.y,
                      downloadApiKeysButton.w, downloadApiKeysButton.h, colors.amber);
  M5.Display.drawRect(downloadAboutButton.x, downloadAboutButton.y,
                      downloadAboutButton.w, downloadAboutButton.h, colors.amber);
  M5.Display.setTextDatum(MC_DATUM);
  M5.Display.setTextColor(colors.amber, colors.black);
  M5.Display.setTextSize(kSmallTextSize);
  M5.Display.drawString("API KEYS", downloadApiKeysButton.x + downloadApiKeysButton.w / 2,
                        downloadApiKeysButton.y + downloadApiKeysButton.h / 2);
  M5.Display.drawString("ABOUT", downloadAboutButton.x + downloadAboutButton.w / 2,
                        downloadAboutButton.y + downloadAboutButton.h / 2);

  drawNavBar();
  downloadMenuDirty = false;
  downloadMenuBusyDirty = false;
  if (revealAfterDraw) {
    utilitiesMenuTransitionPending = false;
    debugPrint("UI: utilities transition reveal complete");
  }
}

